      COMPLEX FUNCTION C9LGMC(ZIN)
!***BEGIN PROLOGUE  C9LGMC
!***DATE WRITTEN   780401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C7A
!***KEYWORDS  COMPLETE GAMMA FUNCTION,COMPLEX,CORRECTION TERM,
!             GAMMA FUNCTION,LOGARITHM,SPECIAL FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Computes the LOG GAMMA correction term for most Z so that
!            CLOG(CGAMMA(Z)) = 0.5*LOG(2.*PI) + (Z-0.5)*CLOG(Z) - Z
!            + C9LGMC(Z)
!***DESCRIPTION
!
! Compute the LOG GAMMA correction term for large CABS(Z) when REAL(Z)
! .GE. 0.0 and for large ABS(AIMAG(Y)) when REAL(Z) .LT. 0.0.  We find
! C9LGMC so that
!   CLOG((Z)) = 0.5*LOG(2.*PI) + (Z-0.5)*CLOG(Z) - Z + C9LGMC(Z)
!***REFERENCES  (NONE)
!***ROUTINES CALLED  R1MACH,XERROR
!***END PROLOGUE  C9LGMC
      COMPLEX ZIN, Z, Z2INV
      DIMENSION BERN(11)
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA BERN( 1) /    .083333333333333333E0   /
      DATA BERN( 2) /   -.0027777777777777778E0  /
      DATA BERN( 3) /    .00079365079365079365E0 /
      DATA BERN( 4) /   -.00059523809523809524E0 /
      DATA BERN( 5) /    .00084175084175084175E0 /
      DATA BERN( 6) /   -.0019175269175269175E0  /
      DATA BERN( 7) /    .0064102564102564103E0  /
      DATA BERN( 8) /   -.029550653594771242E0   /
      DATA BERN( 9) /    .17964437236883057E0    /
      DATA BERN(10) /  -1.3924322169059011E0     /
      DATA BERN(11) /  13.402864044168392E0      /
      DATA NTERM, BOUND, XBIG, XMAX / 0, 3*0.0 /
!***FIRST EXECUTABLE STATEMENT  C9LGMC
!
      C9LGMC = (0.0, 0.0)
!
!CCCC IERR2=0
      IF (NTERM.NE.0) GO TO 10
!
      NTERM = INT(-0.30*LOG(R1MACH(3)))
      BOUND = 0.1170*FLOAT(NTERM)*   &
        (0.1*R1MACH(3))**(-1./(2.*FLOAT(NTERM)-1.))
      XBIG = 1.0/SQRT(R1MACH(3))
      XMAX = EXP (AMIN1(LOG(R1MACH(2)/12.0), -LOG(12.*R1MACH(1))) )
!
 10   Z = ZIN
      X = REAL (Z)
      Y = AIMAG(Z)
      CABSZ = CABS(Z)
!
      IF (X.LT.0.0 .AND. ABS(Y).LT.BOUND)THEN
!CCCC CALL XERROR (  'C9LGMC  C9LGMC
!CCCC1 NOT VALID FOR NEGATIVE REAL(Z) AND SMALL ABS(AIMAG(Z))', 69, 2,2)
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,12)
        CALL DPWRST('XXX','BUG ')
!CCCC   IERR2=1
        RETURN
      ENDIF
   11 FORMAT('***** INTERNAL ERROR FROM C9LGMC: C9LGMC NOT ',   &
             'VALID FOR NEGATIVE REAL(Z) AND')
   12 FORMAT('      SMALL ABS(AIMZ(Z))')
!
      IF (CABSZ.LT.BOUND) THEN
!CCCC CALL XERROR ( 'C9LGMC  C9LGMC NOT VALID FOR SM
!CCCC1ALL CABS(Z)', 42, 3, 2)
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
!CCCC   IERR2=1
        RETURN
      ENDIF
   21 FORMAT('***** INTERNAL ERROR FROM C9LGMC: C9LGMC NOT ',   &
             'VALID FOR SMALL ABS(AIMZ(Z))')
!
      IF (CABSZ.GE.XMAX) GO TO 50
!
      IF (CABSZ.GE.XBIG) C9LGMC = 1.0/(12.0*Z)
      IF (CABSZ.GE.XBIG) RETURN
!
      Z2INV = 1.0/Z**2
      C9LGMC = (0.0, 0.0)
      DO 40 I=1,NTERM
        NDX = NTERM + 1 - I
        C9LGMC = BERN(NDX) + C9LGMC*Z2INV
 40   CONTINUE
!
      C9LGMC = C9LGMC/Z
      RETURN
!
 50   C9LGMC = (0.0, 0.0)
!CCCC CALL XERROR ( 'C9LGMC  Z SO BIG C9LGMC UNDERFLOWS', 34, 1, 1)
      WRITE(ICOUT,51)
      CALL DPWRST('XXX','BUG ')
!CCCC IERR2=2
   51 FORMAT('***** INTERNAL WARNING FROM C9LGMC: Z SO BIG ',   &
             'THAT C9LGMC UNDERFLOWS')
      RETURN
!
      END FUNCTION C9LGMC
      SUBROUTINE CALCPT(PX1,PY1,AX1,AY1,ISUBN0)
!
!     THIS ROUTINE IS A MODIFIED VERSION OF CALCPT.  IT IS USED
!     ONLY BY THE "CALCOMP" DEVICES (CALCOMP, ZETA) USING THE
!     STANDARD "CALCOMP ROUTINES".
!     CALCPT CONVERTS FROM DATAPLOT
!     UNITS TO DEVICE INTEGER UNITS, BUT IT ALSO APPLIES "WINDOW"
!     TRANSFORMATIONS NEEDED BY THE "MULTI-PLOT" AND "WINDOW
!     COORDINATE" COMMANDS.  THE CALCOMP COORDINATES NEED TO BE
!     TRANSLATED TO INCHES.
!
!     PURPOSE--TRANSLATE THE STANDARDIZED (0.0 TO 100.0) COORDINATES (PX1,PY1)
!              INTO (INTEGER PICTURE POINT) DEVICE COORDINATES (AX1,AY1)
!     ISUBN0 = NAME OF SUBROUTINE WHICH CALLED GRWRST.
!              (AND THEREBY HAVE WALKBACK INFORMATION).
!     NOTE--THE ONLY VARIABLES IN THE    PLOT CONTROL COMMON
!           THAT ARE USED HEREIN ARE THE ONES IN /RWIND/
!
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!     UPDATED--SEPTEMBER 1986.
!     UPDATED--APRIL     1992.  COMMENT OUT PWX1 LINES
!     UPDATED--APRIL     1992.  COMMENT OUT 9000 CONTINUE
!     UPDATED--APRIL     1992.  GIVE VALUES TO X1 AND Y1
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ISUBN0
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOPC.INC'
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!CCCC THE FOLLOWING 2 LINES WERE ADDED APRIL 1992
      X1=-999.0
      Y1=-999.0
!
      IERRG4='NO'
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'LCPT')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF CALCPT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)ISUBN0
   52 FORMAT('ISUBN0 (NAME OF THE CALLING SUBROUTINE) = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IMANUF,IMODEL
   53 FORMAT('IMANUF,IMODEL = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMHPP,NUMVPP
   54 FORMAT('NUMHPP,NUMVPP = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,55)ANUMHP,ANUMVP
   55 FORMAT('ANUMHP,ANUMVP = ',E15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,56)PX1,PY1
   56 FORMAT('PX1,PY1 = ',E15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)PWXMIN,PWXMAX,PWYMIN,PWYMAX
   61 FORMAT('PWXMIN,PWXMAX,PWYMIN,PWYMAX = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,69)IBUGG4
   69 FORMAT('IBUGG4 = ',A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!              **************************************
!              **  STEP 0--                        **
!              **  DETERMINE THE DIMENSION OF THE  **
!              **  IN INCHES                       **
!              **************************************
!
      DOTPPI=1000.
      XPAGE=ANUMHP/DOTPPI
      YPAGE=ANUMVP/DOTPPI
!
!               *************************************
!               **  STEP 1--                       **
!               **  CARRY OUT THE TRANSFORMATION.  **
!               *************************************
!
      AX1=PWXMIN+(PX1/100.0)*(PWXMAX-PWXMIN)
      IF(AX1.LE.0.0)AX1=0.0
      IF(AX1.GE.100.)AX1=100.
!
      AY1=PWYMIN+(PY1/100.0)*(PWYMAX-PWYMIN)
      IF(AY1.LE.0.0)AY1=0.0
      IF(AY1.GE.100.)AY1=100.
!
!              **************************************
!              **  STEP 2--                        **
!              **  CONVERT TO INCH FORMAT          **
!              **************************************
!
      AX1=XPAGE*(AX1/100.)
      AY1=YPAGE*(AY1/100.)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
!CCCC THE FOLLOWING LINE WAS COMMENTED OUT APRIL 1992
!9000 CONTINUE
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'LCPT')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF CALCPT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IMANUF,IMODEL
 9012 FORMAT('IMANUF,IMODEL = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)NUMHPP,NUMVPP
 9013 FORMAT('NUMHPP,NUMVPP = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)ANUMHP,ANUMVP
 9014 FORMAT('ANUMHP,ANUMVP = ',E15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)PX1,PY1
 9015 FORMAT('PX1,PY1   = ',E15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
!CCCC THE FOLLOWING 2 LINES WERE COMMENTED OUT  APRIL 1992 (ALAN)
!CCCC WRITE(ICOUT,9016)PWX1,PWY1
!9016 FORMAT('PWX1,PWY1 = ',E15.7,E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)X1,Y1
 9017 FORMAT('X1,Y1     = ',E15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9018)AX1,AY1
 9018 FORMAT('AX1,AY1   = ',I8,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)PWXMIN,PWXMAX,PWYMIN,PWYMAX
 9021 FORMAT('PWXMIN,PWXMAX,PWYMIN,PWYMAX = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9029)IBUGG4,ISUBG4,IERRG4
 9029 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE CALCPT
      SUBROUTINE CALCTR(IA,IH,NLEN)
!
!  CALCTR WILL CONVERT A CHARACTER VARIABLE OR QUOTED STRING
!  TO HOLLERITH FORMAT.  IT IS REQUIRED FOR THE CALCOMP LIBRARY
!  ROUTINES SINCE A FEW FORTRAN COMPILERS WILL NOT ALLOW CHARACTER
!  VARIABLES TO BE PASSED TO HOLLERITH ARRAYS (E.G., NOS/VE FORTRAN).
!  THE DIMENSION OF "ITEMP" IS MACHINE DEPENDENT
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      CHARACTER*10 FMT1,FMT2
      CHARACTER*(*) IA
      INTEGER IH(*)
!
!  DIMENSION ITEMP TO "NUMCPW", I.E., THE NUMBER OF CHARACTERS PER WORD
!
      CHARACTER*8 ITEMP
!
!CCCC NLEN=LEN(IA)
      NWORDS=NLEN/NUMCPW
      NREM=MOD(NLEN,NUMCPW)
      ITEMP=' '
      IF(NWORDS.GT.99)NWORDS=99
      IF(NWORDS.LT.0)NWORDS=0
      IF(NREM.GT.0)ITEMP(1:NREM)=IA(NWORDS*NUMCPW+1:NWORDS*NUMCPW+NREM)
      FMT1='(  A  )'
      WRITE(FMT1(2:3),'(I2)')NWORDS
      WRITE(FMT1(5:6),'(I2)')NUMCPW
      FMT2='(A  )'
      WRITE(FMT2(3:4),'(I2)')NREM
!
      IF(NWORDS.GE.1)READ(IA,FMT1)(IH(J),J=1,NWORDS)
      IF(NREM.GT.0)READ(ITEMP,FMT2)IH(NWORDS+1)
!
      RETURN
      END SUBROUTINE CALCTR
      SUBROUTINE CANDIS(X,Y,N,IWRITE,STATVA,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CANBERRA DISTANCE BETWEEN THE
!              TWO SETS OF DATA IN THE INPUT VECTORS X AND Y.  THE
!              SAMPLE CANBERRA DISTANCE WILL BE A SINGLE PRECISION VALUE
!              CALCULATED AS:
!
!                 DISTANCE = SUM[i=1 to n][(|X(i) - Y(i)|)/(|X(i)| + |Y(i)|)]
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS WHICH
!                                CONSTITUTE THE FIRST SET OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS WHICH
!                                CONSTITUTE THE SECOND SET OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTORS X AND Y.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE COSINE DISTANCE
!                                BETWEEN THE TWO SETS OF DATA IN THE
!                                INPUT VECTORS X AND Y.  THIS SINGLE
!                                PRECISION VALUE WILL BE BETWEEN 0.0
!                                AND 1.0 (INCLUSIVELY).
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE CANBERRA DISTANCE BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ABS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--Lance, G. N.; Williams, W. T. (1966). "Computer programs for
!                 hierarchical polythetic classification ("similarity
!                 analysis")", Computer Journal, Vol. 9, No. 1, pp. 60-64.
!               --Lance, G. N.; Williams, W. T. (1967). "Mixed-data
!                 classificatory programs I.) Agglomerative Systems",
!                 Australian Computer Journal, pp. 15-20.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018/08
!     ORIGINAL VERSION--AUGUST    2018.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CAND'
      ISUBN2='IS  '
      IERROR='NO'
      STATVA=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NDIS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF CANDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      AN=N
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN CANBERRA DISTANCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLES IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS HERE = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE MANHATTAN DISTANCE.           **
!               ************************************************
!
      STATVA=0.0
      DO 200 I=1,N
        TERM1=ABS(X(I) - Y(I))
        TERM2=ABS(X(I))
        TERM3=ABS(Y(I))
        STATVA=STATVA + TERM1/(TERM2 + TERM3)
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,STATVA
  811   FORMAT('THE CANBERRA DISTANCE OF THE ',I8,   &
                 ' OBSERVATIONS = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'NDIS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CANDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,STATVA
 9012   FORMAT('IERROR,STATVA = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CANDIS
      SUBROUTINE CANTOR(N,X,P,ANUM,IERROR)
!
!CCCC ***** NOTE--THIS SUBROUTINE IS CURRENTLY (APRIL 1989)
!CCCC             ONLY VALID FOR P = 0.33333.
!CCCC             TO BE DONE--GENERALIZE FOR ALL P BETWEEN 0 AND 1.
!
!     PURPOSE--THIS SUBROUTINE GENERATES N CANTOR NUMBERS
!              (A CLASSIC CHAOS THEORY SET)
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF CANTOR SET NUMBERS
!                                TO BE GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                CANTOR NUMBERS
!                                WILL BE PLACED.
!                     --P      = THE FRACTIONAL SIZE OF THE HOLE
!                                IN THE MIDDLE OF THE UNIT INTERVAL
!                                (P MUST BE BETWEEN 0 AND 1).
!     OUTPUT--N CANTOR SET NUMBERS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89.6
!     ORIGINAL VERSION--APRIL 1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION ANUM(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      CPUMA3=CPUMAX/3.0
!
!               ******************************************
!               **  TREAT THE CANTOR SET CASE    **
!               ******************************************
!
!               *******************************************
!               **  STEP 1--                             **
!               **  TEST THE INPUT ARGUMENTS FOR ERRORS  **
!               *******************************************
!
      IF(N.GE.1)GO TO 190
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
  101 FORMAT('***** ERROR IN CANTOR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,102)
  102 FORMAT('      THE SIZE OF THE DESIRED SET')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,103)
  103 FORMAT('      OF CANTOR NUMBERS MUST BE 1 OR LARGER;')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,104)
  104 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,105)N
  105 FORMAT('      N = ',I8)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
  190 CONTINUE
!
!               ******************************
!               **  STEP 2--                **
!               **  GENERATE THE SET   **
!               ******************************
!
!CCCC ***** CURRENTLY ONLY VALID FOR P = 1/3
!CCCC ***** UPDATE THIS FOR GENERAL P
!
!CCCC PLOCAL=P
      IF(P.NE.0.33333)THEN
        PLOCAL=0.33333
      ELSE
        PLOCAL=P
      ENDIF
      R=2.0/(1.0-PLOCAL)
      ICOUNT=0
!
      K=1
      DENOM=R**K
      ANUM(1)=1.0
      ICOUNT=ICOUNT+1
      X(ICOUNT)=ANUM(1)/DENOM
      IF(N.LE.1)GO TO 1900
!
      DO 1100 K=2,20
      DENOM=R**K
      LMAX=2**(K-1)
      LMIN=(LMAX/2)+1
      L2=0
      DO 1200 L=LMIN,LMAX
      L2=L2+1
      L3=LMIN-L2
      AMIRRO=ANUM(L3)
      ANUM(L)=DENOM-1.0-AMIRRO
 1200 CONTINUE
      DO 1300 L=1,LMAX
      ICOUNT=ICOUNT+1
      RATIO=ANUM(L)/DENOM
      IF(X(ICOUNT).GE.CPUMA3)GO TO 1350
      X(ICOUNT)=RATIO
      IF(ICOUNT.GE.N)GO TO 1900
 1300 CONTINUE
 1100 CONTINUE
!
 1350 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1351)
