      FUNCTION CARG(Z)
!***BEGIN PROLOGUE  CARG
!***DATE WRITTEN   770401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  A4A
!***KEYWORDS  ARGUMENT,COMPLEX,COMPLEX NUMBER,ELEMENTARY FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Computes the argument of a complex number.
!***DESCRIPTION
!
! CARG(Z) calculates the argument of the complex number Z.  Note
! that CARG returns a real result.  If Z = X+iY, then CARG is ATAN(Y/X),
! except when both X and Y are zero, in which case the result
! will be zero.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  CARG
      COMPLEX Z
!***FIRST EXECUTABLE STATEMENT  CARG
      CARG = 0.0
      IF (REAL(Z).NE.0. .OR. AIMAG(Z).NE.0.) CARG =   &
        ATAN2 (AIMAG(Z), REAL(Z))
!
      RETURN
      END FUNCTION CARG
      SUBROUTINE CATCHR(AMAT1,AMAT2,AMAT3,Y1,Y2,INDX,   &
      MAXROM,MAXCOM,NR1,NC1,   &
      IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              CATCHER MATRIX:
!              C = X(X'X)**(-1)
!              THIS MATRIX IS USEFUL FOR MANY REGRESSION DIAGNOSTIC
!              CAPABILITIES.
!     INPUT  ARGUMENTS--AMAT1  = THE DESIGN MATRIX (X)
!                     --AMAT2  = A SCRATCH MATRIX
!                     --Y1     = A SCRATCH VECTOR
!                     --Y2     = A SCRATCH VECTOR
!                     --INDX   = A SCRATCH INTEGER) VECTOR
!                     --MAXROM = THE INTEGER ROW DIMENSION OF AMAT1
!                     --MAXCOM = THE INTEGER COUMN DIMENSION OF AMAT1
!                     --NR1    = THE INTEGER NUMBER OF ROWS OF AMAT1
!                     --NC1    = THE INTEGER NUMBER OF COLUMNS OF AMAT1
!     OUTPUT ARGUMENTS--AMAT3  = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED CATCHER MATRTIX
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUES OF THE
!             CATCHER MATRIX.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002.6
!     ORIGINAL VERSION--JUNE      2002.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION AMAT1(MAXROM,MAXCOM)
      DIMENSION AMAT2(MAXROM,MAXCOM)
      DIMENSION AMAT3(MAXROM,MAXCOM)
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      INTEGER   INDX(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO /0.0/
      DATA ONE  /1.0/
      DATA EPS  /1.0E-20/
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON')THEN
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF CATCHR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)MAXROM,MAXCOM,NR1,NC1
   53 FORMAT('MAXROM, MAXCOM, NR1, NC1 = ',4I8)
      CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **********************************
!               **  COMPUTE CATCHER MATRIX      **
!               **  1) COMPUTE X'X              **
!               **  2) COMPUTE INVERSE OF X'X   **
!               **  3) COMPUTE X TIMES INVERSE  **
!               **********************************
!
      DO 110 J=1,MAXCOM
        DO 120 I=1,MAXROM
          AMAT2(I,J)=ZERO
  120   CONTINUE
  110 CONTINUE
!
      CALL SGEMM ('T', 'N', NC1, NC1, NR1, ONE, AMAT1, MAXROM,   &
                   AMAT1, MAXROM, ZERO, AMAT2, MAXROM, IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,151)
  151   FORMAT('***** IN CATCHR, AFTER CALL SGEMM--')
        CALL DPWRST('XXX','BUG ')
        DO 152 I=1,NC1
          WRITE(ICOUT,153)I,(AMAT2(I,J),J=1,MIN(5,NC1))
  153     FORMAT('***** I,AMAT2(I,1..MIN(NC1,5)',I8,5E15.7)
          CALL DPWRST('XXX','BUG ')
  152   CONTINUE
      ENDIF
!
      RCOND=0.0
      CALL SGECO(AMAT2,MAXROM,NC1,INDX,RCOND,Y1)
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,171)RCOND
  171   FORMAT('***** IN CATCHR, AFTER CALL SGECO, RCOND=',E15.7)
        CALL DPWRST('XXX','BUG ')
        DO 172 I=1,NC1
          WRITE(ICOUT,173)I,(AMAT2(I,J),J=1,MIN(5,NC1))
  173     FORMAT('***** I,AMAT2(I,1..MIN(NC1,5)',I8,5E15.7)
          CALL DPWRST('XXX','BUG ')
  172   CONTINUE
      ENDIF
!
      IF(RCOND.LE.EPS)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','ERRO')
        WRITE(ICOUT,5171)
        CALL DPWRST('XXX','ERRO ')
        WRITE(ICOUT,5172)
        CALL DPWRST('XXX','ERRO ')
        WRITE(ICOUT,5173)
        CALL DPWRST('XXX','ERRO ')
        IERROR='YES'
        GO TO 9000
      ENDIF
 5171 FORMAT('*** ERROR FROM CATCHR: UNABLE TO COMPUTE THE INVERSE OF ',   &
             'THE X-TRANSPOSE*X MATRIX.')
 5172 FORMAT('    PROBLEM: SOME COLUMNS ARE LINEARLY DEPDENDENT ON ',   &
             ' OTHER COLUMNS.')
 5173 FORMAT('    SUGGESTED SOLUTION: WORK WITH A SUBSET OF THE ',   &
             'ORIGINAL COLUMNS.')
!
      IJOB=1
      CALL SGEDI(AMAT2,MAXROM,NC1,INDX,Y1,Y2,IJOB)
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,181)
  181   FORMAT('***** IN CATCHR, AFTER CALL SGEDI')
        CALL DPWRST('XXX','BUG ')
        DO 182 I=1,NC1
          WRITE(ICOUT,183)I,(AMAT2(I,J),J=1,MIN(5,NC1))
  183     FORMAT('***** I,AMAT2(I,1..MIN(NC1,5)',I8,5E15.7)
          CALL DPWRST('XXX','BUG ')
  182   CONTINUE
      ENDIF
!
      CALL SGEMM ('N', 'N', NR1, NC1, NC1, ONE, AMAT1, MAXROM,   &
                   AMAT2, MAXROM, ZERO, AMAT3, MAXROM, IERROR)
      IF(IERROR.EQ.'YES')RETURN
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF CATCHR--')
      CALL DPWRST('XXX','BUG ')
      DO 9022 I=1,NR1
        WRITE(ICOUT,9023)I,(AMAT3(I,J),J=1,MIN(5,NC1))
 9023   FORMAT('***** I,AMAT3(I,1..MIN(NC1,5)',I8,5E15.7)
        CALL DPWRST('XXX','BUG ')
 9022 CONTINUE
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE CATCHR
      SUBROUTINE CATLAN(DX,DCATLN)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CATLAN BETA FUNCTION
!              FOR REAL ARGUMENTS GREATER THAN OR EQUAL TO 1 USING
!              EULER-MACMACLAURIN SUMMATION.
!              CATLAN(X)=SUM((-1)**(K-1)/(2*K+1)**X)  WHERE THE SUM IS FROM
!                      0 TO INFINITY
!              FOR BETTER COMPUTATIONAL ACCURACY, ACTUALLY
!              COMPUTE CATLAN(X) - 1.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CATLAN
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--DCATLN  = THE DOUBLE PRECISION ZETA
!                                FUNCTION VALUE.
!     OUTPUT--THE DOUBLE PRECISION CATLAN
!             FUNCTION VALUE DCATLN.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964.
!               --THOMPSON, "ATLAS FOR COMPUTING MATHEMATICAL
!                 FUNCTIONS", WILEY, 1997.  THIS ROUTINE IS A
!                 FORTRAN TRANSLATION OF THE C FUNCTION ON PAGE 150
!                 OF THIS BOOK.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--97.9
!     ORIGINAL VERSION--SEPTEMBER 1997.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA DEPS/1.0D-20/
!
!-----START POINT-----------------------------------------------------
!
      IF(DX.EQ.1.0D0)THEN
        DCATLN=-0.214601836603
        RETURN
      ENDIF
      DP=1.0
      CALL CATLN2(DEPS,DP,DX,DTERM1)
      DP=-1.0
      CALL CATLN2(DEPS,DP,DX,DTERM2)
!
!CCCC COMPUTE CATLAN(X) - 1 FOR BETTER ACCURACY.
!CCCC DCATLN=DSUM+1.0D0
      DCATLN=DTERM1 - DTERM2
      RETURN
      END SUBROUTINE CATLAN
      SUBROUTINE CATLN2(DEPS,DP,DX,DSUM)
!
!     PURPOSE--THIS SUBROUTINE IS USED THE CATLAN SUBROUTINE
!              IN COMPUTING THE CATLAN BETA FUNCTION.
!     INPUT  ARGUMENTS--DX     = THE DOUBLE PRECISION VALUE AT
!                                WHICH THE CATLAN
!                                FUNCTION IS TO BE EVALUATED.
!                       DP     = EITHER +1 OR -1
!                       DEPS   = USED TO CONTROL PREFISION
!     OUTPUT ARGUMENTS--DSUM    = SUM RETURNED TO TO THE CATLAN ROUTINE
!     OUTPUT--THE DOUBLE PRECISION DSUM
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964.
!               --THOMPSON, "ATLAS FOR COMPUTING MATHEMATICAL
!                 FUNCTIONS", WILEY, 1997.  THIS ROUTINE IS A
!                 FORTRAN TRANSLATION OF THE C FUNCTION ON PAGE 150
!                 OF THIS BOOK.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--97.9
!     ORIGINAL VERSION--SEPTEMBER 1997.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      IMPLICIT DOUBLE PRECISION (A-H, O-Z)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      DTERM=32.0D0*DX*(DX+1.0D0)*(DX+2.0D0)*(DX+3.0D0)*   &
            (DX+4.0D0)/945.0D0
      DN=(DTERM/DEPS)**(1.0D0/(DX+5.0D0))
      IF(DN.LE.5.5D0)THEN
        N=5
      ELSEIF(DN.GE.9999.5)THEN
        N=10000
      ELSE
        N=INT(DN)
      ENDIF
!
      FN=DBLE(N)
      FK=0.0D0
      DNEGX=-DX
      DSUM=0.0D0
      DO 100 K=1,N-1
        FK=FK+1.0D0
        DSUM=DSUM + (4.0D0*FK+DP)**DNEGX
  100 CONTINUE
!
!  ADD EULER-MACLAURIN CORRECTION TERMS
!
      F4NP=4.0D0*FN+DP
      DSUM=DSUM + (F4NP**DNEGX)*(0.5D0 + 0.25D0*F4NP/(DX-1.0D0)   &
           + DX*(1.0D0 -   &
           4.0D0*(DX+1.0D0)*(DX+2.0D0)/(15.0D0*F4NP*F4NP))/   &
           (3.0D0*F4NP))+DTERM/(F4NP**(DX+5.0D0))
!
      RETURN
      END SUBROUTINE CATLN2
      SUBROUTINE CAUCDF(X,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE CAUCHY DISTRIBUTION
!              WITH MEDIAN = 0 AND 75% POINT = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/PI)*(1/(1+X*X)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ATAN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 154-165.
!     WRITTEN BY--JAMES F. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DATA PI/3.14159265358979/
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      CDF=0.5+((1.0/PI)*ATAN(X))
!
      RETURN
      END SUBROUTINE CAUCDF
      SUBROUTINE CAUFUN (N, X, FVEC, IFLAG, XDATA, NOBS)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE FUNCTIONS FOR THE
!              CAUCHY MAXIMUM LIKELIHOOD EQUATIONS (FROM
!              P. 310 OF JOHNSON, KOTZ, AND BALKRISHNAN (VOLUME 1).
!
!      SUM[i=1 to n][2*(X(i)-ahat)/(bhat^2+(X(i)-ahat)^2) = 0
!
!      N/BAT - SUM[i=1 to n][2*bhat/(bhat^2 + (X(i)-ahat))^2)] = 0
!
!              FOR COMPUTATIONAL PURPOSES, THESE EQUATIONS ARE
!              REWRITTEN AS:
!
!      SUM[i=1 to n][1/(1 + ((X(i) - THETAHAT)/LAMBDA^2)^2)] - N/2 = 0
!      SUM[i=1 to n][X(i)/(1 + ((X(i) - THETAHAT)/LAMBDA)^2)]
!                    - (N/2)*THETAHAT = 0
!
!              THE MAXIMUM LIKELIHOOD EQUATIONS GIVEN IN HAAS,
!              BAIN, AND ANTLE ARE
!
!      SUM[i=1 to n][((X(i)-AHAT)/BHAT)/(1+(X(I)-AHAT)/BHAT)^2)] = 0
!      SUM[i=1 to n][{1 + (X(i)-AHAT)/BHAT)^2}^(-1)] - (1/2)*N = 0
!
!              CALLED BY SNSQE ROUTINE FOR SOLVING SIMULTANEOUS
!              NONLINEAR EQUATIONS.  NOTE THAT THE CALLING SEQUENCE
!              DID NOT ACCOMODATE A DATA ARRAY (AND ASSCIATED NUMBER OF
!              OBSERVATIONS), SO THESE WERE ADDED TO THE CALL LIST.
!     EXAMPLE--CAUCHY MAXIMUM LIKELIHOOD Y
!     REFERENCE--GERALD HAAS, LEE BAIN, CHARLES ANTLE, (1970).
!                "INFERENCES FOR THE CAUCHY DISTRIBUTION BASED ON
!                MAXIMUM LIKELIHOOD ESTIMATORS", BIOMETRIKA,
!                PP. 403-408.
!              --"CONTINUOUS UNIVARIATE DISTRIBUTIONS--VOLUME I",
!                SECOND EDITION, JOHNSON, KOTZ, AND BALAKRISHNAN,
!                WILEY, 1994,, PP. 310-311.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 CENTER FOR APPLIED MATHEMATICS
!                 NATIONAL BUREAU OF STANDARDS
!                 WASHINGTON, D. C. 20234
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2004/3
!     ORIGINAL VERSION--MARCH     2004.
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION X(*)
      DOUBLE PRECISION FVEC(*)
      REAL XDATA(*)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DA
      DOUBLE PRECISION DB
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  SET IFLAG = 0 FOR JOHNSON, KOTZ, BALAKRISHNAN FORM
!      IFLAG = 1 FOR HAAS, BAIN, AND ANTLE
!
!  COMPUTE SOME SUMS
!
      N=2
!
      DN=DBLE(NOBS)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DA=X(1)
      DB=X(2)
      IFLAG=0
!
      IF(IFLAG.EQ.0)THEN
        DO 100 I=1,NOBS
          DX=DBLE(XDATA(I))
          DSUM1=DSUM1 + 1.0D0/(1.0D0 + ((DX-DA)/DB)**2)
          DSUM2=DSUM2 + DX/(1.0D0 + ((DX-DA)/DB)**2)
  100   CONTINUE
        FVEC(1) = DSUM1 - DN/2.0D0
        FVEC(2) = DSUM2 - (DN/2.0D0)*DA
      ELSE
        DO 200 I=1,NOBS
          DX=(DBLE(XDATA(I))-DA)/DB
          DSUM1=DSUM1 + DX/(1.0D0 + DX*DX)
          DSUM2=DSUM2 + 1.0D0/(1.0D0 + DX*DX)
  200   CONTINUE
        FVEC(1) = DSUM1
        FVEC(2) = DSUM2 - 0.5D0*DN
      ENDIF
!
      RETURN
      END SUBROUTINE CAUFUN 
      SUBROUTINE CAULI1(Y,N,ALOC,SCALE,   &
                        ALIK,AIC,AICC,BIC,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE LIKELIHOOD FUNCTION FOR
!              THE CAUCHY DISTRIBUTION.  THIS IS FOR THE RAW DATA
!              CASE (I.E., NO GROUPING AND NO CENSORING).
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/6
!     ORIGINAL VERSION--JUNE      2010.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DS
      DOUBLE PRECISION DU
!CCCC DOUBLE PRECISION DN
      DOUBLE PRECISION DPI
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA DPI / 3.141592653589793238462643383279503D0 /
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CAUL'
      ISUBN2='I1  '
!
      IERROR='NO'
!
      ALIK=-99.0
      AIC=-99.0
      AICC=-99.0
      BIC=-99.0
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ULI1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF CAULI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO
   52   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,ALOC,SCALE
   55   FORMAT('N,ALOC,SCALE = ',I8,2G15.7)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  COMPUTE LIKELIHOOD FUNCTION         **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ULI1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERFLG=0
      IERROR='NO'
      IWRITE='OFF'
!
!     CAUCHY LOG-LIKELIHOOD FUNCTION IS:
!
!     N*LOG(SCALE) - N*LOG(PI) -
!     SUM[i=1 TO N][LOG{SCALE**2 + (X(i) - LOC)**2}]
!
      DN=DBLE(N)
      DS=DBLE(SCALE)
      DU=DBLE(ALOC)
      DTERM1=DN*DLOG(DS) - DN*DLOG(DPI)
      DSUM1=0.0D0
      DO 1000 I=1,N
        DX=DBLE(Y(I))
        DTERM2=DS**2 + (DX - DU)**2
        DSUM1=DSUM1 + DLOG(DTERM2)
 1000 CONTINUE
!
      DLIK=DTERM1 - DSUM1
      ALIK=REAL(DLIK)
      DNP=2.0D0
      AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
      DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
      AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
      BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ULI1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF CAULI1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9013)DSUM1,DTERM1,DTERM3
 9013   FORMAT('DSUM1,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9014)ALIK,AIC,AICC,BIC
 9014   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE CAULI1
      SUBROUTINE CAUML1(Y,N,TEMP1,TEMP2,DTEMP1,MAXNXT,   &
      XMEAN,XMED,XSD,XMAD,XIQ,XMIN,XMAX,   &
      ALOC,ASCALE,ALOCOS,ASCLOS,ALOWOS,SCAWOS,   &
      ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE COMPUTES THE ORDER STATISTICS, THE WEIGHTED
!              ORDER STATISTICS, AND THE MAXIMUM LIKELIHOOD ESTIMATES
!              FOR THE CAUCHY DISTRIBUTION FOR THE RAW DATA CASE (I.E.,
!              NO CENSORING AND NO GROUPING).  IT WILL OPTIONALLY RETURN
!              THE CONFIDENCE INTERVALS FOR THE LOCATION AND SCALE
!              PARAMETERS BASED ON THE ANTLE METHOD.
!
!              IT IS ASSUMED THAT BASIC ERROR CHECKING HAS ALREADY BEEN
!              PERFORMED.
!
!              PUT THIS IN A SEPARATE ROUTINE AS IT MAY BE CALLED
!              FROM MULTIPLE PLACES (DPMLDE WILL GENERATE THE OUTPUT
!              FOR THE CAUCHY MLE COMMAND).
!
!     REFERENCE--GERALD HAAS, LEE BAIN, CHARLES ANTLE, (1970).
!                "INFERENCES FOR THE CAUCHY DISTRIBUTION BASED ON
!                MAXIMUM LIKELIHOOD ESTIMATORS", BIOMETRIKA,
!                PP. 403-407.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE (FROM DPMLDE)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      INTEGER IFLAG
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DOUBLE PRECISION DTEMP1(*)
!
!CCCC DOUBLE PRECISION DN
      DOUBLE PRECISION DSUM1
      DOUBLE PRECISION DSUM2
      DOUBLE PRECISION TOL
      DOUBLE PRECISION XPAR(2)
      DOUBLE PRECISION FVEC(2)
!
      EXTERNAL CAUFUN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA PI/3.14159265358979/
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CAUM'
      ISUBN2='L1  '
      IWRITE='OFF'
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'UML1')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF CAUML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,MAXNXT
   52   FORMAT('IBUGA3,ISUBRO,N,MAXNXT = ',2(A4,2X),3I8)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,Y(I)
   57     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 1--                            **
!               **  CARRY OUT CALCULATIONS              **
!               **  FOR CAUCHY MLE ESTIMATE             **
!               ******************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'UML1')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IDIST='CAUCHY'
      IFLAG=0
      CALL SUMRAW(Y,N,IDIST,IFLAG,   &
                  XMEAN,XVAR,XSD,XMIN,XMAX,   &
                  ISUBRO,IBUGA3,IERROR)
!
      P1=55.65
      CALL PERCEN(P1,Y,N,IWRITE,TEMP2,MAXNXT,XUPPQU,IBUGA3,IERROR)
      P2=100.0 - P1
      CALL PERCEN(P2,Y,N,IWRITE,TEMP2,MAXNXT,XLOWQU,IBUGA3,IERROR)
      CALL MEDIAN(Y,N,IWRITE,TEMP2,MAXNXT,XMED,IBUGA3,IERROR)
      CALL MAD(Y,N,IWRITE,TEMP1,TEMP2,MAXNXT,XMAD,IBUGA3,IERROR)
      CALL LOWQUA(Y,N,IWRITE,TEMP2,MAXNXT,ALOWQU,IBUGA3,IERROR)
      CALL UPPQUA(Y,N,IWRITE,TEMP2,MAXNXT,AUPPQU,IBUGA3,IERROR)
      XIQ=AUPPQU - ALOWQU
!
      ALOCOS=0.5*(XUPPQU + XLOWQU)
      P2Q=P2/100.0
      ASCLOS=0.5*(XUPPQU - XLOWQU)*TAN(PI*P2Q)
      AN=REAL(N)
!
      CALL SORT(Y,N,Y)
      DSUM1=0.0D0
      DSUM2=0.0D0
      DO 3210 I=1,N
        TERM1=REAL(I)/REAL(N+1) - 0.5
        ANUM=SIN(4.0*PI*TERM1)
        ADENOM=REAL(N)*SIN(PI*TERM1)/COS(PI*TERM1)
        DSUM1=DSUM1 + DBLE(ANUM/ADENOM)*DBLE(Y(I))
        ANUM=8.0*SIN(PI*TERM1)/COS(PI*TERM1)
        TERM2=COS(PI*TERM1)
        IF(TERM2.NE.0.0)THEN
          TERM2=1.0/TERM2
        ELSE
          TERM2=1.0/0.0000001
        ENDIF
        ADENOM=REAL(N)*TERM2**4
        DSUM2=DSUM2 + DBLE(ANUM/ADENOM)*DBLE(Y(I))
 3210 CONTINUE
      ALOWOS=REAL(DSUM1)
      SCAWOS=REAL(DSUM2)
!
      IF(N.EQ.3)THEN
        CALL SORT(Y,N,Y)
        X1=Y(1)
        X2=Y(2)
        X3=Y(3)
        TERM1=X1*(X3-X2)**2 + X2*(X3-X1)**2 + X3*(X2-X1)**2
        TERM2=(X3-X2)**2 + (X3-X1)**2 + (X2-X1)**2
        ALOC=TERM1/TERM2
        TERM1=SQRT(3.0)*(X3-X2)*(X3-X1)*(X2-X1)
        ASCALE=TERM1/TERM2
      ELSEIF(N.EQ.3)THEN
        CALL SORT(Y,N,Y)
        X1=Y(1)
        X2=Y(2)
        X3=Y(3)
        X4=Y(4)
        TERM1=X2*X4 - X1*X3
        TERM2=X4 - X3 + X2 - X1
        ALOC=TERM1/TERM2
        TERM1=(X4-X3)*(X3-X2)*(X2-X1)*(X4-X1)
        TERM2=(X4 - X3 + X2 - X1)**2
        ASCALE=TERM1/TERM2
      ELSE
        XPAR(1)=DBLE(XMED)
        XPAR(2)=DBLE(XMAD)
!
        IOPT=2
        TOL=1.0D-6
        NVAR=2
        NPRINT=-1
        INFO=0
        JAC=0
        LWA=MAXNXT
        CALL DNSQE(CAUFUN,JAC,IOPT,NVAR,XPAR,FVEC,TOL,NPRINT,INFO,   &
                   DTEMP1,MAXNXT,Y,N)
!
        ALOC=REAL(XPAR(1))
        ASCALE=REAL(XPAR(2))
      ENDIF
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'UML1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF CAUML1--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9055)N,XMEAN,XMED,XSD,XMAD,XMIN,XMAX
 9055   FORMAT('N,XMEAN,XMED,XSD,XMAD,XMIN,XMAX = ',I8,6G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9056)ALOC,ASCALE,ALOCOS,ASCLOS,ALOWOS,SCAWOS
 9056   FORMAT('ALOC,ASCALE,ALOCOS,ASCLOS,ALOWOS,SCAWOS = ',6G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE CAUML1
      SUBROUTINE CAUPDF(X,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE CAUCHY DISTRIBUTION
!              WITH MEDIAN = 0 AND 75% POINT = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/PI)*(1/(1+X*X)).
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF.
!     PRINTING--NONE.
!     RESTRICTIONS--NONE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 154-165.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DATA C/.31830988618379/
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS.
!     NO INPUT ARGUMENT ERRORS POSSIBLE
!     FOR THIS DISTRIBUTION.
!
!-----START POINT-----------------------------------------------------
!
      PDF=C*(1.0/(1.0+X*X))
!
      RETURN
      END SUBROUTINE CAUPDF
      SUBROUTINE CAUPPF(P,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE CAUCHY DISTRIBUTION
!              WITH MEDIAN = 0 AND 75% POINT = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/PI)*(1/(1+X*X)).
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT
!             FUNCTION VALUE PPF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 154-165.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-----------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    1 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      ' CAUPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
      ARG=PI*P
      PPF=-COS(ARG)/SIN(ARG)
!
      RETURN
      END SUBROUTINE CAUPPF
      SUBROUTINE CAURAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE CAUCHY DISTRIBUTION
!              WITH MEDIAN = 0 AND 75% POINT = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/PI)*(1/(1+X*X)).
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FUNCTION VALUE FOR THE CAUCHY DISTRIBUTION
!             WITH MEDIAN = 0 AND 75% POINT = 1.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGE 15.
!               --HAMMERSLEY AND HANDSCOMB, MONTE CARLO METHODS,
!                 1964, PAGE 36.
!               --FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGE 231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 154-165.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)GO TO 50
      GO TO 90
   50 WRITE(ICOUT, 5)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)N
      CALL DPWRST('XXX','BUG ')
      RETURN
   90 CONTINUE
    5 FORMAT('***** FATAL ERROR--THE 1ST INPUT ARGUMENT TO THE ',   &
      'CAURAN SUBROUTINE IS NON-POSITIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8   ,' *****')
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N CAUCHY RANDOM NUMBERS
!     USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
      ARG=PI*X(I)
      X(I)=-COS(ARG)/SIN(ARG)
  100 CONTINUE
!
      RETURN
      END SUBROUTINE CAURAN
      SUBROUTINE CAUSF(P,SF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE SPARSITY
!              FUNCTION VALUE FOR THE CAUCHY DISTRIBUTION
!              WITH MEDIAN = 0 AND 75% POINT = 1.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X AND HAS
!              THE PROBABILITY DENSITY FUNCTION
!              F(X) = (1/PI)*(1/(1+X*X)).
!              NOTE THAT THE SPARSITY FUNCTION OF A DISTRIBUTION
!              IS THE DERIVATIVE OF THE PERCENT POINT FUNCTION,
!              AND ALSO IS THE RECIPROCAL OF THE PROBABILITY
!              DENSITY FUNCTION (BUT IN UNITS OF P RATHER THAN X).
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 AND 1.0)
!                                AT WHICH THE SPARSITY
!                                FUNCTION IS TO BE EVALUATED.
!     OUTPUT ARGUMENTS--SF     = THE SINGLE PRECISION
!                                SPARSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION SPARSITY
!             FUNCTION VALUE SF.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--P SHOULD BE BETWEEN 0.0 AND 1.0, EXCLUSIVELY.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--SIN.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--FILLIBEN, SIMPLE AND ROBUST LINEAR ESTIMATION
!                 OF THE LOCATION PARAMETER OF A SYMMETRIC
!                 DISTRIBUTION (UNPUBLISHED PH.D. DISSERTATION,
!                 PRINCETON UNIVERSITY), 1969, PAGES 21-44, 229-231.
!               --FILLIBEN, 'THE PERCENT POINT FUNCTION',
!                 (UNPUBLISHED MANUSCRIPT), 1970, PAGES 28-31.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 154-165.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-921-2315
!     ORIGINAL VERSION--APRIL     1994.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!---------------------------------------------------------------------
!
      DATA PI/3.14159265358979/
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(P.LE.0.0.OR.P.GE.1.0)GO TO 50
      GO TO 90
   50 CONTINUE
      WRITE(ICOUT,1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,3)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)P
      RETURN
    1 FORMAT('***** FATAL ERROR--THE FIRST  INPUT ARGUMENT TO THE')
    2 FORMAT('      CAUPPF SUBROUTINE IS OUTSIDE THE ALLOWABLE (0,1)')
    3 FORMAT('       INTERVAL *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
!
   90 CONTINUE
!
!-----START POINT-----------------------------------------------------
!
      ARG=PI*P
      SF=PI/((SIN(ARG))**2)
!
      RETURN
      END SUBROUTINE CAUSF
      COMPLEX FUNCTION CBETA(A,B,IERR2)
!***BEGIN PROLOGUE  CBETA
!***DATE WRITTEN   770701   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C7B
!***KEYWORDS  BETA FUNCTION,COMPLETE BETA FUNCTION,COMPLEX,
!             SPECIAL FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  CBETA computes the complete Beta function of complex
!            parameters A and B.
!***DESCRIPTION
!
! CBETA computes the complete beta function of complex parameters A
! and B.
! Input Parameters:
!       A   complex and the real part of A positive
!       B   complex and the real part of B positive
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CGAMMA,CLBETA,GAMLIM,XERROR
!***END PROLOGUE  CBETA
!
      INCLUDE 'DPCOP2.INC'
!
      COMPLEX A, B, CGAMMA, CLBETA, CEXP
!
      DATA XMAX / 0.0 /
!
!***FIRST EXECUTABLE STATEMENT  CBETA
      CBETA = (0.0, 0.0)
      IERR2=0
      IF (XMAX.EQ.0.0) CALL GAMLIM (XMIN, XMAX)
!
      IF (REAL(A).LE.0.0 .OR. REAL(B).LE.0.0) THEN
!CCCC   CALL XERROR ( 'CBETA   REA
!CCCC1L PART OF BOTH ARGUMENTS MUST BE GT 0', 48, 1, 2)
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
      ENDIF
   11 FORMAT('***** ERROR FROM CBETA: REAL PARTS OF PARAMETER',   &
             'MUST BE POSITIVE')
!
      IF (REAL(A)+REAL(B).LT.XMAX) CBETA = CGAMMA(A) * (CGAMMA(B)/   &
        CGAMMA(A+B) )
      IF (REAL(A)+REAL(B).LT.XMAX) RETURN
!
      CBETA = CEXP (CLBETA(A, B))
!
      RETURN
      END FUNCTION CBETA
      SUBROUTINE CC(X,N,ENGLSL,ENGUSL,TARGET,IWRITE,XCC,   &
                    IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE
!              SAMPLE CC (PROCESS CAPABILITY INDEX)
!              OF THE DATA IN THE INPUT VECTOR X.
!              CC = MAX((TARGET-MU)/(TARGET-LSL),(MU-TARGET)/(USL))
!     NOTE--CC IS A MEASURE OF PROCESS ACCURACY--
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --ENGLSL = LOWER (ENGINEERING) SPEC LIMIT
!                     --ENGUSL = UPPER (ENGINEERING) SPEC LIMIT
!                     --TARGET = TARGET (ENGINEERING) SPEC LIMIT
!     OUTPUT ARGUMENTS--CC    = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE CC
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE CC INDEX
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--MEAN AND SD.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NORMA HUBELE, ARIZONA STATE
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--98.11
!     ORIGINAL VERSION--NOVEMBER  1998.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DX
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
!
      DOUBLE PRECISION DUSL
      DOUBLE PRECISION DLSL
      DOUBLE PRECISION DTARG
      DOUBLE PRECISION DNUM
      DOUBLE PRECISION DDEN
      DOUBLE PRECISION DCC
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
!
      DMEAN=0.0D0
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF CC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)N
   53 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)ENGUSL,ENGLSL
   54 FORMAT('ENGUSL,ENGLSL = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,N
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************************
!               **  COMPUTE PROCESS CAPABILITY INDEX CC  **
!               ********************************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.GE.1)GO TO 119
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,111)
  111 FORMAT('***** ERROR IN CC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,112)
  112 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,113)
  113 FORMAT('      IN THE VARIABLE FOR WHICH')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,114)
  114 FORMAT('      THE CC STATISTIC IS TO BE COMPUTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,115)
  115 FORMAT('      MUST BE 1 OR LARGER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,116)
  116 FORMAT('      SUCH WAS NOT THE CASE HERE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,117)N
  117 FORMAT('      THE INPUT NUMBER OF OBSERVATIONS HERE = ',I8,   &
      '.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  119 CONTINUE
!
!               ***************************************
!               **  STEP 2--                         **
!               **  COMPUTE THE STANDARD DEVIATION.  **
!               ***************************************
!
      DN=N
      DSUM=0.0D0
      DO 200 I=1,N
      DX=X(I)
      DSUM=DSUM+DX
  200 CONTINUE
      DMEAN=DSUM/DN
!
!               **************************************************
!               **  STEP 3--                                    **
!               **  COMPUTE THE CC RATIO                       **
!               **************************************************
!
      DUSL=ENGUSL
      DLSL=ENGLSL
      DTARG=TARGET
!
      DNUM=(DTARG-DMEAN)/(DTARG-DLSL)
      DDEN=(DMEAN-DTARG)/DUSL
!
      DCC=MAX(DNUM,DDEN)
      XCC=REAL(DCC)
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'OFF')GO TO 890
      IF(IWRITE.EQ.'OFF')GO TO 890
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)N,XCC
  811 FORMAT('THE CC OF THE ',I8,' OBSERVATIONS = ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
  890 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF CC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGA3,IERROR
 9012 FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)N
 9013 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)DMEAN
 9014 FORMAT('DMEAN = ',D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)DUSL,DLSL
 9016 FORMAT('DUSL,DLSL = ',2D15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)DNUM,DDEN,DCC,XCC
 9017 FORMAT('DNUM,DDEN,DCC,XCC = ',3D15.7,E15.7)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE CC
      COMPLEX FUNCTION CCOT(Z)
!***BEGIN PROLOGUE  CCOT
!***DATE WRITTEN   770401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C4A
!***KEYWORDS  COMPLEX,COTANGENT,ELEMENTARY FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Computes the complex Cotangent.
!***DESCRIPTION
!
! CCOT(Z) calculates the comlex trigonometric cotangent of Z.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  R1MACH,XERCLR,XERROR
!***END PROLOGUE  CCOT
      COMPLEX Z
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA SQEPS /0./
!***FIRST EXECUTABLE STATEMENT  CCOT
      CCOT = (0., 0.)
!
      IF (SQEPS.EQ.0.) SQEPS = SQRT (R1MACH(4))
!
      X2 = 2.0*REAL(Z)
      Y2 = 2.0*AIMAG(Z)
!
      SN2X = SIN (X2)
!CCCC CALL XERCLR
!
      DEN = COSH(Y2) - COS(X2)
      IF (DEN.EQ.0.) THEN
!CCCC   CALL XERROR (  'CCOT    COT IS SINGULAR FOR INPUT Z
!CCCC1 (X IS 0 OR PI AND Y IS 0)'  , 61, 2, 2)
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
        RETURN
      ENDIF
 102  FORMAT('***** INTERNAL ERROR FROM CCOT: COT IS SINGULAR')
!
      IF (ABS(DEN).GT.AMAX1(ABS(X2),1.)*SQEPS) GO TO 10
!CCCC CALL XERCLR
!CCCC CALL XERROR ( 'CCOT    ANSWER LT HALF PRECISION, ABS(X) TOO BIG OR
!CCCC1 X TOO NEAR 0 OR PI', 70, 1, 1)
      WRITE(ICOUT,202)
      CALL DPWRST('XXX','BUG ')
 202  FORMAT('***** INTERNAL WARNING FROM CCOT: ANSWER IS LESS THAN'   &
      ,' HALF PRECISION BECAUSE ABS(X) IS TOO LARGE')
      WRITE(ICOUT,203)
      CALL DPWRST('XXX','BUG ')
 203  FORMAT('      OR X IS TOO NEAR 0 OR PI')
!
 10   CCOT = CMPLX (SN2X/DEN, -SINH(Y2)/DEN)
!
      RETURN
      END FUNCTION CCOT
      DOUBLE PRECISION FUNCTION CDFGLO(X,PARA)
!===================================================== CDFGLO.FOR
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  DISTRIBUTION FUNCTION OF THE GENERALIZED LOGISTIC DISTRIBUTION
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(3)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0.0D0/,ONE/1.0D0/
!
!         SMALL IS USED TO TEST WHETHER X IS EFFECTIVELY AT
!         THE ENDPOINT OF THE DISTRIBUTION
!
      DATA SMALL/1.0D-15/
!
      U=PARA(1)
      A=PARA(2)
      G=PARA(3)
!
      IF(A.LE.ZERO)THEN
        CDFGLO=ZERO
        WRITE(ICOUT,7000)
 7000   FORMAT('***** ERROR IN GL5CDF--NON-POSITIVE SCALE ',   &
               'PARAMETER IS INVALID.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,7005)
 7005   FORMAT('      L-MOMENTS INVALID')
        CALL DPWRST('XXX','WRIT')
        GO TO  9000
      ENDIF
!
      Y=(X-U)/A
      IF(G.EQ.ZERO)GO TO  20
      ARG=ONE-G*Y
      IF(ARG.GT.SMALL)GO TO  10
      IF(G.LT.ZERO)CDFGLO=ZERO
      IF(G.GT.ZERO)CDFGLO=ONE
      GO TO 9000
!
   10 CONTINUE
      Y=-DLOG(ARG)/G
   20 CONTINUE
      CDFGLO=ONE/(ONE+DEXP(-Y))
!
 9000 CONTINUE
      RETURN
      END FUNCTION CDFGLO
!===================================================== CDFKAP.FOR
      DOUBLE PRECISION FUNCTION CDFKAP(X,PARA)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  DISTRIBUTION FUNCTION OF THE KAPPA DISTRIBUTION
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(4)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,ONE/1D0/
!
!         SMALL IS A SMALL NUMBER, USED TO TEST WHETHER X IS
!         EFFECTIVELY AT AN ENDPOINT OF THE DISTRIBUTION
!
      DATA SMALL/1D-15/
!
      U=PARA(1)
      A=PARA(2)
      G=PARA(3)
      H=PARA(4)
!
      IF(A.LE.ZERO)THEN
        WRITE(ICOUT,7000)
 7000   FORMAT('***** ERROR FROM ROUTINE CDFKAP: SCALE PARAMETER IS ',   &
               'NON-POSITIVE.')
        CDFKAP=ZERO
        GO TO  9000
      ENDIF
!
      Y=(X-U)/A
      IF(G.EQ.ZERO)GO TO  20
      ARG=ONE-G*Y
      IF(ARG.GT.SMALL)GO TO  10
      IF(G.LT.ZERO)CDFKAP=ZERO
      IF(G.GT.ZERO)CDFKAP=ONE
      GO TO 9000
!
   10 Y=-DLOG(ARG)/G
   20 Y=DEXP(-Y)
      IF(H.EQ.ZERO)GO TO  40
      ARG=ONE-H*Y
      IF(ARG.GT.SMALL)GO TO  30
      CDFKAP=ZERO
      GO TO 9000
   30 Y=-DLOG(ARG)/H
   40 CDFKAP=DEXP(-Y)
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION CDFKAP
!===================================================== CDFPE3.FOR
      DOUBLE PRECISION FUNCTION CDFPE3(X,PARA)
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  DISTRIBUTION FUNCTION OF THE PEARSON TYPE 3 DISTRIBUTION
!
!  OTHER ROUTINES USED: DERF,DLGAMA (DLGADP),GAMIND
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(3)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0D0/,HALF/0.5D0/,ONE/1D0/,TWO/2D0/,FOUR/4D0/
      DATA RTHALF/0.707106781186547524D0/
!
!         SMALL IS USED TO TEST WHETHER SKEWNESS IS EFFECTIVELY ZERO
!
      DATA SMALL/1D-6/
!
      CDFPE3=ZERO
      IF(PARA(2).LE.ZERO)THEN
        WRITE(ICOUT,7000)
 7000   FORMAT('***** ERROR FROM ROUTINE CDFPE3: SCALE PARAMETER IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','WRIT')
        GO TO 9000
      ENDIF
!
      GAMMA=PARA(3)
      IF(DABS(GAMMA).LE.SMALL)GO TO  10
      ALPHA=FOUR/(GAMMA*GAMMA)
      Z=TWO*(X-PARA(1))/(PARA(2)*GAMMA)+ALPHA
!CCCC IF(Z.GT.ZERO)CDFPE3=GAMIND(Z,ALPHA,DLGAMA(ALPHA))
      IF(Z.GT.ZERO)CDFPE3=GAMIND(Z,ALPHA,DLGADP(ALPHA))
      IF(GAMMA.LT.ZERO)CDFPE3=ONE-CDFPE3
      GO TO 9000
!
!         ZERO SKEWNESS
!
   10 Z=(X-PARA(1))/PARA(2)
      CDFPE3=HALF+HALF*DERFDP(Z*RTHALF)
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION CDFPE3
      DOUBLE PRECISION FUNCTION CDFWAK(X,PARA)
!===================================================== CDFWAK.FOR
!***********************************************************************
!*                                                                     *
!*  FORTRAN CODE WRITTEN FOR INCLUSION IN IBM RESEARCH REPORT RC20525, *
!*  'FORTRAN ROUTINES FOR USE WITH THE METHOD OF L-MOMENTS, VERSION 3' *
!*                                                                     *
!*  J. R. M. HOSKING                                                   *
!*  IBM RESEARCH DIVISION                                              *
!*  T. J. WATSON RESEARCH CENTER                                       *
!*  YORKTOWN HEIGHTS                                                   *
!*  NEW YORK 10598, U.S.A.                                             *
!*                                                                     *
!*  VERSION 3     AUGUST 1996                                          *
!*                                                                     *
!***********************************************************************
!
!  CUMULATIVE DISTRIBUTION FUNCTION OF THE WAKEBY DISTRIBUTION
!
!  OTHER ROUTINES USED: QUAWAK
!
!  METHOD: THE EQUATION X=G(Z), WHERE G(Z) IS THE WAKEBY QUANTILE
!  EXPRESSED AS A FUNCTION OF Z=-LOG(1-F), IS SOLVED USING HALLEY'S
!  METHOD (THE 2ND-ORDER ANALOGUE OF NEWTON-RAPHSON ITERATION).
!
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
      DOUBLE PRECISION PARA(5)
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO/0.0D0/,HALF/0.5D0/,ONE/1.0D0/
      DATA P1/0.1D0/,P7/0.7D0/,P99/0.99D0/
!
!         EPS,MAXIT CONTROL THE TEST FOR CONVERGENCE OF THE ITERATION
!         ZINCMX IS THE LARGEST PERMITTED ITERATIVE STEP
!         ZMULT CONTROLS WHAT HAPPENS WHEN THE ITERATION STEPS BELOW ZERO
!         UFL SHOULD BE CHOSEN SO THAT DEXP(UFL) JUST DOES NOT CAUSE
!           UNDERFLOW
!
      DATA EPS/1.0D-8/,MAXIT/20/,ZINCMX/3.0D0/,ZMULT/0.2D0/
      DATA UFL/-170.0D0/
!
      XI=PARA(1)
      A=PARA(2)
      B=PARA(3)
      C=PARA(4)
      D=PARA(5)
!
!         TEST FOR VALID PARAMETERS
!
      IF(B+D.LE.ZERO.AND.(B.NE.ZERO.OR.C.NE.ZERO.OR.D.NE.ZERO))GO TO  1000
      IF(A.EQ.ZERO.AND.B.NE.ZERO)GO TO  1000
      IF(C.EQ.ZERO.AND.D.NE.ZERO)GO TO  1000
      IF(C.LT.ZERO.OR.A+C.LT.ZERO)GO TO  1000
      IF(A.EQ.ZERO.AND.C.EQ.ZERO)GO TO  1000
!
      CDFWAK=ZERO
      IF(X.LE.XI)RETURN
!
!         TEST FOR SPECIAL CASES
!
      IF(B.EQ.ZERO.AND.C.EQ.ZERO.AND.D.EQ.ZERO)GO TO  100
      IF(C.EQ.ZERO)GO TO  110
      IF(A.EQ.ZERO)GO TO  120
!
!         GENERAL CASE
!
      CDFWAK=ONE
      IF(D.LT.ZERO.AND.X.GE.XI+A/B-C/D)GO TO 9000
!
!         INITIAL VALUES FOR ITERATION:
!         IF X IS IN THE LOWEST DECILE OF THE DISTRIBUTION, START AT Z=0
!           (F=0);
!         IF X IS IN THE HIGHEST PERCENTILE OF THE DISTRIBUTION,
!           STARTING VALUE IS OBTAINED FROM ASYMPTOTIC FORM OF THE
!           DISTRIBUTION FOR LARGE Z (F NEAR 1);
!         OTHERWISE START AT Z=0.7 (CLOSE TO F=0.5).
!
      Z=P7
      IF(X.LT.QUAWAK(P1,PARA))Z=ZERO
      IF(X.LT.QUAWAK(P99,PARA))GO TO  10
      IF(D.LT.ZERO)Z=DLOG((X-XI-A/B)*D/C+ONE)/D
      IF(D.EQ.ZERO)Z=(X-XI-A/B)/C
      IF(D.GT.ZERO)Z=DLOG((X-XI)*D/C+ONE)/D
   10 CONTINUE
!
!         HALLEY'S METHOD, WITH MODIFICATIONS:
!         IF HALLEY ITERATION WOULD MOVE IN WRONG DIRECTION
!           (TEMP.LE.ZERO), USE ORDINARY NEWTON-RAPHSON INSTEAD;
!         IF STEP GOES TOO FAR (ZINC.GT.ZINCMX OR ZNEW.LE.ZERO),
!            LIMIT ITS LENGTH.
!
      DO 30 IT=1,MAXIT
        EB=ZERO
        BZ=-B*Z
        IF(BZ.GE.UFL)EB=DEXP(BZ)
        GB=Z
        IF(DABS(B).GT.EPS)GB=(ONE-EB)/B
        ED=DEXP(D*Z)
        GD=-Z
        IF(DABS(D).GT.EPS)GD=(ONE-ED)/D
        XEST=XI+A*GB-C*GD
        FUNC=X-XEST
        DERIV1=A*EB+C*ED
        DERIV2=-A*B*EB+C*D*ED
        TEMP=DERIV1+HALF*FUNC*DERIV2/DERIV1
        IF(TEMP.LE.ZERO)TEMP=DERIV1
        ZINC=FUNC/TEMP
        IF(ZINC.GT.ZINCMX)ZINC=ZINCMX
        ZNEW=Z+ZINC
        IF(ZNEW.LE.ZERO)GO TO  20
          Z=ZNEW
          IF(DABS(ZINC).LE.EPS)GO TO  200
          GO TO  30
   20   CONTINUE
        Z=Z*ZMULT
   30 CONTINUE
!
!         NOT CONVERGED
!
      WRITE(ICOUT,7010)
 7010 FORMAT('***** WARNING IN WAKCDF--')
      CALL DPWRST('XXX','WRIT')
      WRITE(ICOUT,7012)
 7012 FORMAT('      ITERATION HAS NOT CONVERGED.  THE RESULT ',   &
             'MAY NOT BE RELIABLE.')
      CALL DPWRST('XXX','WRIT')
      GO TO  200
!
!         SPECIAL CASE B=C=D=0: WAKEBY IS EXPONENTIAL
!
  100 CONTINUE
      Z=(X-XI)/A
      GO TO  200
!
!         SPECIAL CASE C=0: WAKEBY IS GENERALIZED PARETO, BOUNDED ABOVE
!
  110 CONTINUE
      CDFWAK=ONE
      IF(X.GE.XI+A/B)RETURN
      Z=-DLOG(ONE-(X-XI)*B/A)/B
      GO TO  200
!
!         SPECIAL CASE A=0: WAKEBY IS GENERALIZED PARETO, NO UPPER BOUND
!
  120 CONTINUE
      Z=DLOG(ONE+(X-XI)*D/C)/D
      GO TO  200
!
!         CONVERT Z VALUE TO PROBABILITY
!
  200 CDFWAK=ONE
      IF(-Z.LT.UFL)GO TO 9000
      CDFWAK=ONE-DEXP(-Z)
      GO TO 9000
!
 1000 CONTINUE
      WRITE(ICOUT,7000)
 7000 FORMAT('***** ERROR IN WAKCDF--PARAMETERS INVALID.')
      CALL DPWRST('XXX','WRIT')
      CDFWAK=ZERO
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END FUNCTION CDFWAK
      SUBROUTINE CHASE(A,X,Y,IMX,JMX,I,J,NS,CN,XC,YC,NMX,N,BOX,   &
                       ISUBRO,IBUGG3)
!
!     PURPOSE--XX
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!     UPDATED         --JANUARY   1989.  MORE CHANGES TO STANDARD FORTRAN 77--
!                                        BYTE TO CHARACTER*1,
!                                        DO WHILE/END DO (ALAN HECKERT).
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOCP.INC'
!
!---------------------------------------------------------------------
!
!CCCC BYTE BOX(4,IMX,JMX)                JANUARY 1989
!CCCC DIMENSION A(IMX,JMX),X(IMX),Y(JMX),XC(NMX),YC(NMX)
!CCCC DIMENSION XP(3),YP(3),LP(3)
!
!CCCC BYTE BOX                           JANUARY 1989
      CHARACTER*1 BOX
      CHARACTER*1 ITEMP
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGG3
!
      DIMENSION A(MAXIMX,MAXJMX)
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION XC(*)
      DIMENSION YC(*)
      DIMENSION BOX(4,MAXIMX,MAXJMX)
!
      DIMENSION XP(3)
      DIMENSION YP(3)
      DIMENSION LP(3)
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBRO.EQ.'HASE' .OR. IBUGG3.EQ.'ON')THEN
        WRITE(ICOUT,101)IMX,JMX,MAXIMX,MAXJMX,NMX
  101   FORMAT('FROM CHASE: IMX,JMX,MAXIMX,MAXJMX,NMX = ',   &
               5I8)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IO=0
!CCCC DO WHILE ((BOX(NS,I,J).EQ.0.OR.BOX(NS,I,J).EQ.2).AND.IO.EQ.0)
  99  CONTINUE
      IF((BOX(NS,I,J).EQ.'0'.OR.BOX(NS,I,J).EQ.'2').AND.IO.EQ.0)GO TO 100
        GO TO 199
 100    CONTINUE
        ITEMP=BOX(NS,I,J)
        CALL DPCOAN(ITEMP,IJUNK)
        IJUNK=IJUNK+1
        CALL DPCONA(IJUNK,ITEMP)
        BOX(NS,I,J)=ITEMP
!CCCC   BOX(NS,I,J)=BOX(NS,I,J)+1
        DO 110 L=1,3
          XP(L)=0.
          YP(L)=0.
 110    CONTINUE
        NXT=0
        DO 120 LL=NS+1,NS+3
          L=MOD((LL-1),4)+1
          IF (BOX(L,I,J).EQ.'0'.OR.BOX(L,I,J).EQ.'2') THEN
            IF (L.EQ.1) THEN
              DNM=A(I,J+1)-A(I,J)
              IF (DNM.NE.0.) THEN
                R=(CN-A(I,J))/DNM
              ELSE
                R=-1.
              END IF
              IF ((R.GT.0..AND.R.LT.1.).OR.   &
                 (R.EQ.0..AND.DNM.LT.0.).OR.   &
                 (R.EQ.1..AND.DNM.GT.0.)) THEN
                NXT=NXT+1
                LP(NXT)=1
                XP(NXT)=X(I)
                YP(NXT)=Y(J)+R*(Y(J+1)-Y(J))
              END IF
            ELSE IF (L.EQ.2) THEN
              DNM=A(I+1,J+1)-A(I,J+1)
              IF (DNM.NE.0.) THEN
                R=(CN-A(I,J+1))/DNM
              ELSE
                R=-1.
              END IF
              IF ((R.GT.0..AND.R.LT.1.).OR.   &
                 (R.EQ.0..AND.DNM.LT.0.).OR.   &
                 (R.EQ.1..AND.DNM.GT.0.)) THEN
                NXT=NXT+1
                LP(NXT)=2
                XP(NXT)=X(I)+R*(X(I+1)-X(I))
                YP(NXT)=Y(J+1)
              END IF
            ELSE IF (L.EQ.3) THEN
              DNM=A(I+1,J)-A(I+1,J+1)
              IF (DNM.NE.0.) THEN
                R=(CN-A(I+1,J+1))/DNM
              ELSE
                R=-1.
              END IF
              IF ((R.GT.0..AND.R.LT.1.).OR.   &
                 (R.EQ.0..AND.DNM.LT.0.).OR.   &
                 (R.EQ.1..AND.DNM.GT.0.)) THEN
                NXT=NXT+1
                LP(NXT)=3
                XP(NXT)=X(I+1)
                YP(NXT)=Y(J+1)+R*(Y(J)-Y(J+1))
              END IF
            ELSE IF (L.EQ.4) THEN
              DNM=A(I,J)-A(I+1,J)
              IF (DNM.NE.0.) THEN
                R=(CN-A(I+1,J))/DNM
              ELSE
                R=-1.
              END IF
              IF ((R.GT.0..AND.R.LT.1.).OR.   &
                 (R.EQ.0..AND.DNM.LT.0.).OR.   &
                 (R.EQ.1..AND.DNM.GT.0.)) THEN
                NXT=NXT+1
                LP(NXT)=4
                XP(NXT)=X(I+1)+R*(X(I)-X(I+1))
                YP(NXT)=Y(J)
              END IF
            END IF
          END IF
 120    CONTINUE
        IF (NXT.EQ.0) THEN
          NS=-1
          GO TO 9000
        ELSE IF (NXT.EQ.1) THEN
          LN=1
        ELSE IF (NXT.EQ.2) THEN
          LN=1
          PRINT *,'  WARNING! CELL HAS 2 EXITS!'
        ELSE
          D1=(XC(N)-XP(1))**2+(YC(N)-YP(1))**2
          D2=(XC(N)-XP(3))**2+(YC(N)-YP(3))**2
            IF (D1.LE.D2) THEN
            LN=1
          ELSE
            LN=3
          END IF
        END IF
        N=N+1
        XC(N)=XP(LN)
        YC(N)=YP(LN)
        L=LP(LN)
        ITEMP=BOX(L,I,J)
        CALL DPCOAN(ITEMP,IJUNK)
        IJUNK=IJUNK+1
        CALL DPCONA(IJUNK,ITEMP)
        BOX(L,I,J)=ITEMP
!CCCC   BOX(L,I,J)=BOX(L,I,J)+1
        IF (BOX(L,I,J).EQ.'3') THEN
          IO=1
        ELSE
          ML2=MOD(L,2)
          I=I+ML2*(L-2)
          J=J+(ML2-1)*(L-3)
          NS=MOD((L+ML2),4)+2-ML2
          IO=0
        END IF
      GO TO 99
 199  CONTINUE
      NS=-1
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE CHASE
      SUBROUTINE CDIV(AR,AI,BR,BI,CR,CI)
!***BEGIN PROLOGUE  CDIV
!***REFER TO  EISDOC
!
!     Complex division, (CR,CI) = (AR,AI)/(BR,BI)
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  CDIV
      REAL AR,AI,BR,BI,CR,CI
!
      REAL S,ARS,AIS,BRS,BIS
!***FIRST EXECUTABLE STATEMENT  CDIV
      S = ABS(BR) + ABS(BI)
      ARS = AR/S
      AIS = AI/S
      BRS = BR/S
      BIS = BI/S
      S = BRS**2 + BIS**2
      CR = (ARS*BRS + AIS*BIS)/S
      CI = (AIS*BRS - ARS*BIS)/S
      RETURN
      END SUBROUTINE CDIV
      SUBROUTINE CFFTB(N,C,WSAVE)
!***BEGIN PROLOGUE  CFFTB
!***DATE WRITTEN   790601   (YYMMDD)
!***REVISION DATE  860115   (YYMMDD)
!***CATEGORY NO.  J1A2
!***KEYWORDS  FOURIER TRANSFORM
!***AUTHOR  SWARZTRAUBER, P. N., (NCAR)
!***PURPOSE  Unnormalized inverse of CFFTF.
!***DESCRIPTION
!           From the book, "Numerical Methods and Software" by
!                D. Kahaner, C. Moler, S. Nash
!                Prentice Hall, 1988
!
!  Subroutine CFFTB computes the backward complex discrete Fourier
!  transform (the Fourier synthesis).  Equivalently, CFFTB computes
!  a complex periodic sequence from its Fourier coefficients.
!  The transform is defined below at output parameter C.
!
!  A call of CFFTF followed by a call of CFFTB will multiply the
!  sequence by N.
!
!  The array WSAVE which is used by subroutine CFFTB must be
!  initialized by calling subroutine CFFTI(N,WSAVE).
!
!  Input Parameters
!
!
!  N      the length of the complex sequence C.  The method is
!         more efficient when N is the product of small primes.
!
!  C      a complex array of length N which contains the sequence
!
!  WSAVE   a real work array which must be dimensioned at least 4*N+15
!          in the program that calls CFFTB.  The WSAVE array must be
!          initialized by calling subroutine CFFTI(N,WSAVE), and a
!          different WSAVE array must be used for each different
!          value of N.  This initialization does not have to be
!          repeated so long as N remains unchanged.  Thus subsequent
!          transforms can be obtained faster than the first.
!          The same WSAVE array can be used by CFFTF and CFFTB.
!
!  Output Parameters
!
!  C      For J=1,...,N
!
!             C(J)=the sum from K=1,...,N of
!
!                   C(K)*EXP(I*J*K*2*PI/N)
!
!                         where I=SQRT(-1)
!
!  WSAVE   contains initialization calculations which must not be
!          destroyed between calls of subroutine CFFTF or CFFTB
!
!  *   References                                                      *
!  *                                                                   *
!  *   1. P.N. Swarztrauber, Vectorizing the FFTs, in Parallel         *
!  *      Computations (G. Rodrigue, ed.), Academic Press, 1982,       *
!  *      pp. 51-83.                                                   *
!  *   2. B.L. Buzbee, The SLATEC Common Math Library, in Sources      *
!  *      and Development of Mathematical Software (W. Cowell, ed.),   *
!  *      Prentice-Hall, 1984, pp. 302-318.                            *
!  *                                                                   *
!  *********************************************************************
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CFFTB1
!***END PROLOGUE  CFFTB
      DIMENSION       C(*)       ,WSAVE(*)
!***FIRST EXECUTABLE STATEMENT  CFFTB
      IF (N .EQ. 1) RETURN
      IW1 = N+N+1
      IW2 = IW1+N+N
      CALL CFFTB1 (N,C,WSAVE,WSAVE(IW1),WSAVE(IW2))
      RETURN
      END SUBROUTINE CFFTB
      SUBROUTINE CFFTB1(N,C,CH,WA,IFAC)
!***BEGIN PROLOGUE  CFFTB1
!***REFER TO  CFFTB
!***ROUTINES CALLED  PASSB,PASSB2,PASSB3,PASSB4,PASSB5
!***END PROLOGUE  CFFTB1
!CCCC DECEMBER 2009 (ALAN HECKERT): MAKE IFAC REAL TO AVOID
!CCCC COMPILATION ERRORS FOR NEW INTEL 11 COMPILER
!
      DIMENSION       CH(*)      ,C(*)       ,WA(*)
      REAL            IFAC(*)
!***FIRST EXECUTABLE STATEMENT  CFFTB1
      NF = INT(IFAC(2)+0.01)
      NA = 0
      L1 = 1
      IW = 1
      DO 116 K1=1,NF
         IP = INT(IFAC(K1+2) + 0.1)
         L2 = IP*L1
         IDO = N/L2
         IDOT = IDO+IDO
         IDL1 = IDOT*L1
         IF (IP .NE. 4) GO TO 103
         IX2 = IW+IDOT
         IX3 = IX2+IDOT
         IF (NA .NE. 0) GO TO 101
         CALL PASSB4 (IDOT,L1,C,CH,WA(IW),WA(IX2),WA(IX3))
         GO TO 102
  101    CALL PASSB4 (IDOT,L1,CH,C,WA(IW),WA(IX2),WA(IX3))
  102    NA = 1-NA
         GO TO 115
  103    IF (IP .NE. 2) GO TO 106
         IF (NA .NE. 0) GO TO 104
         CALL PASSB2 (IDOT,L1,C,CH,WA(IW))
         GO TO 105
  104    CALL PASSB2 (IDOT,L1,CH,C,WA(IW))
  105    NA = 1-NA
         GO TO 115
  106    IF (IP .NE. 3) GO TO 109
         IX2 = IW+IDOT
         IF (NA .NE. 0) GO TO 107
         CALL PASSB3 (IDOT,L1,C,CH,WA(IW),WA(IX2))
         GO TO 108
  107    CALL PASSB3 (IDOT,L1,CH,C,WA(IW),WA(IX2))
  108    NA = 1-NA
         GO TO 115
  109    IF (IP .NE. 5) GO TO 112
         IX2 = IW+IDOT
         IX3 = IX2+IDOT
         IX4 = IX3+IDOT
         IF (NA .NE. 0) GO TO 110
         CALL PASSB5 (IDOT,L1,C,CH,WA(IW),WA(IX2),WA(IX3),WA(IX4))
         GO TO 111
  110    CALL PASSB5 (IDOT,L1,CH,C,WA(IW),WA(IX2),WA(IX3),WA(IX4))
  111    NA = 1-NA
         GO TO 115
  112    IF (NA .NE. 0) GO TO 113
         CALL PASSB (NAC,IDOT,IP,L1,IDL1,C,C,C,CH,CH,WA(IW))
         GO TO 114
  113    CALL PASSB (NAC,IDOT,IP,L1,IDL1,CH,CH,CH,C,C,WA(IW))
  114    IF (NAC .NE. 0) NA = 1-NA
  115    L1 = L2
         IW = IW+(IP-1)*IDOT
  116 CONTINUE
      IF (NA .EQ. 0) RETURN
      N2 = N+N
      DO 117 I=1,N2
         C(I) = CH(I)
  117 CONTINUE
      RETURN
      END SUBROUTINE CFFTB1
      SUBROUTINE CFFTF(N,C,WSAVE)
!***BEGIN PROLOGUE  CFFTF
!***DATE WRITTEN   790601   (YYMMDD)
!***REVISION DATE  860115   (YYMMDD)
!***CATEGORY NO.  J1A2
!***KEYWORDS  FOURIER TRANSFORM
!***AUTHOR  SWARZTRAUBER, P. N., (NCAR)
!***PURPOSE  Forward transform of a complex, periodic sequence.
!***DESCRIPTION
!           From the book, "Numerical Methods and Software" by
!                D. Kahaner, C. Moler, S. Nash
!                Prentice Hall, 1988
!
!  Subroutine CFFTF computes the forward complex discrete Fourier
!  transform (the Fourier analysis).  Equivalently, CFFTF computes
!  the Fourier coefficients of a complex periodic sequence.
!  The transform is defined below at output parameter C.
!
!  The transform is not normalized.  To obtain a normalized transform
!  the output must be divided by N.  Otherwise a call of CFFTF
!  followed by a call of CFFTB will multiply the sequence by N.
!
!  The array WSAVE which is used by subroutine CFFTF must be
!  initialized by calling subroutine CFFTI(N,WSAVE).
!
!  Input Parameters
!
!
!  N      the length of the complex sequence C.  The method is
!         more efficient when N is the product of small primes.
!
!  C      a complex array of length N which contains the sequence
!
!  WSAVE   a real work array which must be dimensioned at least 4*N+15
!          in the program that calls CFFTF.  The WSAVE array must be
!          initialized by calling subroutine CFFTI(N,WSAVE), and a
!          different WSAVE array must be used for each different
!          value of N.  This initialization does not have to be
!          repeated so long as N remains unchanged.  Thus subsequent
!          transforms can be obtained faster than the first.
!          The same WSAVE array can be used by CFFTF and CFFTB.
!
!  Output Parameters
!
!  C      for J=1,...,N
!
!             C(J)=the sum from K=1,...,N of
!
!                   C(K)*EXP(-I*J*K*2*PI/N)
!
!                         where I=SQRT(-1)
!
!  WSAVE   contains initialization calculations which must not be
!          destroyed between calls of subroutine CFFTF or CFFTB
!
!  *   References                                                      *
!  *                                                                   *
!  *   1. P.N. Swarztrauber, Vectorizing the FFTs, in Parallel         *
!  *      Computations (G. Rodrigue, ed.), Academic Press, 1982,       *
!  *      pp. 51-83.                                                   *
!  *   2. B.L. Buzbee, The SLATEC Common Math Library, in Sources      *
!  *      and Development of Mathematical Software (W. Cowell, ed.),   *
!  *      Prentice-Hall, 1984, pp. 302-318.                            *
!  *                                                                   *
!  *********************************************************************
!
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CFFTF1
!***END PROLOGUE  CFFTF
      DIMENSION       C(*)       ,WSAVE(*)
!***FIRST EXECUTABLE STATEMENT  CFFTF
      IF (N .EQ. 1) RETURN
      IW1 = N+N+1
      IW2 = IW1+N+N
      CALL CFFTF1 (N,C,WSAVE,WSAVE(IW1),WSAVE(IW2))
      RETURN
      END SUBROUTINE CFFTF
      SUBROUTINE CFFTF1(N,C,CH,WA,IFAC)
!***BEGIN PROLOGUE  CFFTF1
!***REFER TO  CFFTF
!***ROUTINES CALLED  PASSF,PASSF2,PASSF3,PASSF4,PASSF5
!***END PROLOGUE  CFFTF1
!CCCC DECEMBER 2009 (ALAN HECKERT): MAKE IFAC REAL TO AVOID
!CCCC COMPILATION ERRORS FOR NEW INTEL 11 COMPILER
      DIMENSION       CH(*)      ,C(*)       ,WA(*)
      REAL            IFAC(*)
!***FIRST EXECUTABLE STATEMENT  CFFTF1
      NF = INT(IFAC(2) + 0.01)
      NA = 0
      L1 = 1
      IW = 1
      DO 116 K1=1,NF
         IP = INT(IFAC(K1+2) + 0.01)
         L2 = IP*L1
         IDO = N/L2
         IDOT = IDO+IDO
         IDL1 = IDOT*L1
         IF (IP .NE. 4) GO TO 103
         IX2 = IW+IDOT
         IX3 = IX2+IDOT
         IF (NA .NE. 0) GO TO 101
         CALL PASSF4 (IDOT,L1,C,CH,WA(IW),WA(IX2),WA(IX3))
         GO TO 102
  101    CALL PASSF4 (IDOT,L1,CH,C,WA(IW),WA(IX2),WA(IX3))
  102    NA = 1-NA
         GO TO 115
  103    IF (IP .NE. 2) GO TO 106
         IF (NA .NE. 0) GO TO 104
         CALL PASSF2 (IDOT,L1,C,CH,WA(IW))
         GO TO 105
  104    CALL PASSF2 (IDOT,L1,CH,C,WA(IW))
  105    NA = 1-NA
         GO TO 115
  106    IF (IP .NE. 3) GO TO 109
         IX2 = IW+IDOT
         IF (NA .NE. 0) GO TO 107
         CALL PASSF3 (IDOT,L1,C,CH,WA(IW),WA(IX2))
         GO TO 108
  107    CALL PASSF3 (IDOT,L1,CH,C,WA(IW),WA(IX2))
  108    NA = 1-NA
         GO TO 115
  109    IF (IP .NE. 5) GO TO 112
         IX2 = IW+IDOT
         IX3 = IX2+IDOT
         IX4 = IX3+IDOT
         IF (NA .NE. 0) GO TO 110
         CALL PASSF5 (IDOT,L1,C,CH,WA(IW),WA(IX2),WA(IX3),WA(IX4))
         GO TO 111
  110    CALL PASSF5 (IDOT,L1,CH,C,WA(IW),WA(IX2),WA(IX3),WA(IX4))
  111    NA = 1-NA
         GO TO 115
  112    IF (NA .NE. 0) GO TO 113
         CALL PASSF (NAC,IDOT,IP,L1,IDL1,C,C,C,CH,CH,WA(IW))
         GO TO 114
  113    CALL PASSF (NAC,IDOT,IP,L1,IDL1,CH,CH,CH,C,C,WA(IW))
  114    IF (NAC .NE. 0) NA = 1-NA
  115    L1 = L2
         IW = IW+(IP-1)*IDOT
  116 CONTINUE
      IF (NA .EQ. 0) RETURN
      N2 = N+N
      DO 117 I=1,N2
         C(I) = CH(I)
  117 CONTINUE
      RETURN
      END SUBROUTINE CFFTF1
      SUBROUTINE CFFTI(N,WSAVE)
!***BEGIN PROLOGUE  CFFTI
!***DATE WRITTEN   790601   (YYMMDD)
!***REVISION DATE  860115   (YYMMDD)
!***CATEGORY NO.  J1A2
!***KEYWORDS  FOURIER TRANSFORM
!***AUTHOR  SWARZTRAUBER, P. N., (NCAR)
!***PURPOSE  Initialize for CFFTF and CFFTB.
!***DESCRIPTION
!           From the book, "Numerical Methods and Software" by
!                D. Kahaner, C. Moler, S. Nash
!                Prentice Hall, 1988
!
!  Subroutine CFFTI initializes the array WSAVE which is used in
!  both CFFTF and CFFTB.  The prime factorization of N together with
!  a tabulation of the trigonometric functions are computed and
!  stored in WSAVE.
!
!  Input Parameter
!
!  N       the length of the sequence to be transformed
!
!  Output Parameter
!
!  WSAVE   a work array which must be dimensioned at least 4*N+15.
!          The same work array can be used for both CFFTF and CFFTB
!          as long as N remains unchanged.  Different WSAVE arrays
!          are required for different values of N.  The contents of
!          WSAVE must not be changed between calls of CFFTF or CFFTB.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CFFTI1
!***END PROLOGUE  CFFTI
      DIMENSION       WSAVE(*)
!***FIRST EXECUTABLE STATEMENT  CFFTI
!
      IF (N .EQ. 1) RETURN
      IW1 = N+N+1
      IW2 = IW1+N+N
      CALL CFFTI1 (N,WSAVE(IW1),WSAVE(IW2))
      RETURN
      END SUBROUTINE CFFTI
      SUBROUTINE CFFTI1(N,WA,IFAC)
!***BEGIN PROLOGUE  CFFTI1
!***REFER TO  CFFTI
!***ROUTINES CALLED  (NONE)
!***END PROLOGUE  CFFTI1
!CCCC DECEMBER 2009 (ALAN HECKERT): MAKE IFAC REAL TO AVOID
!CCCC COMPILATION ERRORS FOR NEW INTEL 11 COMPILER
      DIMENSION       WA(*)      ,NTRYH(4)
      REAL            IFAC(*)
      DATA NTRYH(1),NTRYH(2),NTRYH(3),NTRYH(4)/3,4,2,5/
!
      NTRY = 0
!
!***FIRST EXECUTABLE STATEMENT  CFFTI1
      NL = N
      NF = 0
      J = 0
  101 J = J+1
!
!CCCC 7/2008: MODIFY FOLLOWING LINE SO THAT IT DOES NOT
!CCCC         GENERATE A WARNING MESSAGE FOR FORTRAN 95
!CCCC         COMPILER.
!
!CCCC IF (J-4) 102,102,103
      IF (J-4.GT.0) GO TO  103
      NTRY = NTRYH(J)
      GO TO 104
  103 NTRY = NTRY+2
  104 NQ = NL/NTRY
      NR = NL-NTRY*NQ
!
!CCCC 7/2008: MODIFY FOLLOWING LINE SO THAT IT DOES NOT
!CCCC         GENERATE A WARNING MESSAGE FOR FORTRAN 95
!CCCC         COMPILER.
!
!CCCC IF (NR) 101,105,101
      IF (NR.NE.0) GO TO 101
      NF = NF+1
      IFAC(NF+2) = REAL(NTRY)
      NL = NQ
      IF (NTRY .NE. 2) GO TO 107
      IF (NF .EQ. 1) GO TO 107
      DO 106 I=2,NF
         IB = NF-I+2
         IFAC(IB+2) = IFAC(IB+1)
  106 CONTINUE
      IFAC(3) = REAL(2)
  107 IF (NL .NE. 1) GO TO 104
      IFAC(1) = REAL(N)
      IFAC(2) = REAL(NF)
      TPI = 8.*ATAN(1.)
      ARGH = TPI/REAL(N)
      I = 2
      L1 = 1
      DO 110 K1=1,NF
         IP = INT(IFAC(K1+2) + 0.01)
         LD = 0
         L2 = L1*IP
         IDO = N/L2
         IDOT = IDO+IDO+2
         IPM = IP-1
         DO 109 J=1,IPM
            I1 = I
            WA(I-1) = 1.
            WA(I) = 0.
            LD = LD+L1
            FI = 0.
            ARGLD = REAL(LD)*ARGH
            DO 108 II=4,IDOT,2
               I = I+2
               FI = FI+1.
               ARG = FI*ARGLD
               WA(I-1) = COS(ARG)
               WA(I) = SIN(ARG)
  108       CONTINUE
            IF (IP .LE. 5) GO TO 109
            WA(I1-1) = WA(I-1)
            WA(I1) = WA(I)
  109    CONTINUE
         L1 = L2
  110 CONTINUE
      RETURN
      END SUBROUTINE CFFTI1
      DOUBLE PRECISION FUNCTION CHEVAL(N,A,T)
!
!   This function evaluates a Chebyshev series, using the
!   Clenshaw method with Reinsch modification, as analysed
!   in the paper by Oliver.
!
!   INPUT PARAMETERS
!
!       N - INTEGER - The no. of terms in the sequence
!
!       A - DOUBLE PRECISION ARRAY, dimension 0 to N - The coefficients of
!           the Chebyshev series
!
!       T - DOUBLE PRECISION - The value at which the series is to be
!           evaluated
!
!
!   REFERENCES
!
!        "An error analysis of the modified Clenshaw method for
!         evaluating Chebyshev and Fourier series" J. Oliver,
!         J.I.M.A., vol. 20, 1977, pp379-391
!
!
! MACHINE-DEPENDENT CONSTANTS: NONE
!
!
! INTRINSIC FUNCTIONS USED;
!
!    ABS
!
!
! AUTHOR:  Dr. Allan J. MacLeod,
!          Dept. of Mathematics and Statistics,
!          University of Paisley ,
!          High St.,
!          PAISLEY,
!          SCOTLAND
!
!
! LATEST MODIFICATION:   21 December , 1992
!
!
      INTEGER I,N
      DOUBLE PRECISION A(0:N),D1,D2,HALF,T,TEST,TT,TWO,U0,U1,U2,ZERO
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO,HALF/ 0.0D0 , 0.5D0 /
      DATA TEST,TWO/ 0.6D0 , 2.0D0 /
!
      CHEVAL =  DBLE(CPUMIN)
      D1=0.0D0
      D2=0.0D0
!
      U1 = ZERO
      U2 = ZERO
!
!   If ABS ( T )  < 0.6 use the standard Clenshaw method
!
      IF ( ABS( T ) .LT. TEST ) THEN
         U0 = ZERO
         TT = T + T
         DO 100 I = N , 0 , -1
            U2 = U1
            U1 = U0
            U0 = TT * U1 + A( I ) - U2
 100     CONTINUE
         CHEVAL =  ( U0 - U2 ) / TWO
      ELSE
!
!   If ABS ( T )  > =  0.6 use the Reinsch modification
!
         D1 = ZERO
!
!   T > =  0.6 code
!
         IF ( T .GT. ZERO ) THEN
            TT =  ( T - HALF ) - HALF
            TT = TT + TT
            DO 200 I = N , 0 , -1
               D2 = D1
               U2 = U1
               D1 = TT * U2 + A( I ) + D2
               U1 = D1 + U2
 200        CONTINUE
            CHEVAL =  ( D1 + D2 ) / TWO
         ELSE
!
!   T < =  -0.6 code
!
            TT =  ( T + HALF ) + HALF
            TT = TT + TT
            DO 300 I = N , 0 , -1
               D2 = D1
               U2 = U1
               D1 = TT * U2 + A( I ) - D2
               U1 = D1 - U2
 300        CONTINUE
            CHEVAL =  ( D1 - D2 ) / TWO
         ENDIF
      ENDIF
      RETURN
      END FUNCTION CHEVAL
      SUBROUTINE CGAMA(X,Y,KF,GR,GI)
!
!       =========================================================
!       Purpose: Compute the gamma function ‰(z) or ln[‰(z)]
!                for a complex argument
!       Input :  x  --- Real part of z
!                y  --- Imaginary part of z
!                KF --- Function code
!                       KF=0 for ln[‰(z)]
!                       KF=1 for ‰(z)
!       Output:  GR --- Real part of ln[‰(z)] or ‰(z)
!                GI --- Imaginary part of ln[‰(z)] or ‰(z)
!       ========================================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
        DIMENSION A(10)
!
        DATA A/8.333333333333333D-02,-2.777777777777778D-03,   &
               7.936507936507937D-04,-5.952380952380952D-04,   &
               8.417508417508418D-04,-1.917526917526918D-03,   &
               6.410256410256410D-03,-2.955065359477124D-02,   &
               1.796443723688307D-01,-1.39243221690590D+00/
!
        PI=3.141592653589793D0
        X1=0.0
        Y1=0.0
        NA=0
!
        IF (Y.EQ.0.0D0.AND.X.EQ.INT(X).AND.X.LE.0.0D0) THEN
           GR=1.0D+300
           GI=0.0D0
           RETURN
        ELSE IF (X.LT.0.0D0) THEN
           X1=X
           Y1=Y
           X=-X
           Y=-Y
        ENDIF
        X0=X
        IF (X.LE.7.0) THEN
           NA=INT(7-X)
           X0=X+NA
        ENDIF
        Z1=DSQRT(X0*X0+Y*Y)
        TH=DATAN(Y/X0)
        GR=(X0-.5D0)*DLOG(Z1)-TH*Y-X0+0.5D0*DLOG(2.0D0*PI)
        GI=TH*(X0-0.5D0)+Y*DLOG(Z1)-Y
        DO 10 K=1,10
           T=Z1**(1-2*K)
           GR=GR+A(K)*T*DCOS((2.0D0*K-1.0D0)*TH)
           GI=GI-A(K)*T*DSIN((2.0D0*K-1.0D0)*TH)
10      CONTINUE
        IF (X.LE.7.0) THEN
           GR1=0.0D0
           GI1=0.0D0
           DO 15 J=0,NA-1
              GR1=GR1+.5D0*DLOG((X+J)**2+Y*Y)
              GI1=GI1+DATAN(Y/(X+J))
15         CONTINUE
           GR=GR-GR1
           GI=GI-GI1
        ENDIF
        IF (X1.LT.0.0D0) THEN
           Z1=DSQRT(X*X+Y*Y)
           TH1=DATAN(Y/X)
           SR=-DSIN(PI*X)*DCOSH(PI*Y)
           SI=-DCOS(PI*X)*DSINH(PI*Y)
           Z2=DSQRT(SR*SR+SI*SI)
           TH2=DATAN(SI/SR)
           IF (SR.LT.0.0D0) TH2=PI+TH2
           GR=DLOG(PI/(Z1*Z2))-GR
           GI=-TH1-TH2-GI
           X=X1
           Y=Y1
        ENDIF
        IF (KF.EQ.1) THEN
           G0=DEXP(GR)
           GR=G0*DCOS(GI)
           GI=G0*DSIN(GI)
        ENDIF
      RETURN
      END SUBROUTINE CGAMA
      COMPLEX FUNCTION CGAMMA(Z)
!***FOR DATAPLOT, THIS ROUTINE IS USED IN CALCULATION OF CBETA FUNCTION,
!***WE USE CGAMA ABOVE FOR CGAMMA FUNCTION.
!***BEGIN PROLOGUE  CGAMMA
!***DATE WRITTEN   770701   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C7A
!***KEYWORDS  COMPLETE GAMMA FUNCTION,COMPLEX,GAMMA FUNCTION,
!             SPECIAL FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Computes the Gamma function of complex argument.
!***DESCRIPTION
!
! CGAMMA(Z) calculates the complete gamma function for COMPLEX
! argument Z.  This is a preliminary version that is portable
! but not accurate.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CLNGAM
!***END PROLOGUE  CGAMMA
      COMPLEX Z, CLNGAM, CEXP
!***FIRST EXECUTABLE STATEMENT  CGAMMA
      CGAMMA = CEXP (CLNGAM(Z))
!
      RETURN
      END FUNCTION CGAMMA
      SUBROUTINE CHEBT(X,AN,CN)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CHEBYSHEV T
!              POLYNOMIAL OF ORDER N.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION INPUT ARGUMENT
!                       CN     = THE SINGLE PRECISION VALUE FOR THE
!                                ORDER OF THE FUNCTION (SHOULD BE
!                                NON-NEGATIVE ORDER)
!     OUTPUT ARGUMENTS--CN    = THE SINGLE PRECISION VALUE OF THE
!                                CHEBYSHEV T POLYNOMIAL.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SOME DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"HANDBOOK OF MATHEMATICAL FUNCTIONS, AMS 55",
!                 ABRAMOWITZ AND STEGUM.
!                 USE FOLLOWING RECURRENCE FORMULA:
!                    T(N+1) = 2.0*X*T(N-1)-T(N-2)
!                 FIRST FEW TERMS ARE FROM TABLE 22.3 OF ABRAMOWITZ
!                 AND STEGUM.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JULY       1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCN, DCN1, DCN2
!
!-----START POINT-----------------------------------------------------
!
      IF(X.LT.-1.0.OR.X.GT.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 1ST INPUT ARGUMENT ',   &
      'TO THE CHEBT SUBROUTINE IS OUTSIDE THE (-1,1) INTERVAL *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
      N=INT(AN+0.5)
      IF(N.LT.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    6 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 2ND INPUT ARGUMENT ',   &
      'TO THE CHEBT SUBROUTINE IS NEGATIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
      DX=DBLE(X)
!
      IF(N.LE.0)THEN
        CN=1.0
      ELSEIF(N.EQ.1)THEN
        CN=X
      ELSEIF(N.EQ.2)THEN
        CN=2.0*X**2-1.0
      ELSEIF(N.EQ.3)THEN
        DCN=4.0D0*DX**3 - 3.0*DX
        CN=REAL(DCN)
      ELSE
        DCN1=4.0D0*DX**3 - 3.0*DX
        DCN2=2.0D0*DX**2-1.0D0
        DO 1000 I=4,N
          DCN=2.0D0*DX*DCN1-DCN2
          DCN2=DCN1
          DCN1=DCN
 1000   CONTINUE
        CN=REAL(DCN)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE CHEBT
      SUBROUTINE CHEBU(X,AN,CN)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CHEBYSHEV U
!              POLYNOMIAL OF ORDER N.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION INPUT ARGUMENT
!                       CN     = THE SINGLE PRECISION VALUE FOR THE
!                                ORDER OF THE FUNCTION (SHOULD BE
!                                NON-NEGATIVE ORDER)
!     OUTPUT ARGUMENTS--CN    = THE SINGLE PRECISION VALUE OF THE
!                                CHEBYSHEV U POLYNOMIAL.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE
!     MODE OF INTERNAL OPERATIONS--SOME DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN.
!     REFERENCES--"HANDBOOK OF MATHEMATICAL FUNCTIONS, AMS 55",
!                 ABRAMOWITZ AND STEGUM.
!                 USE FOLLOWING RECURRENCE FORMULA:
!                    U(N+1) = 2.0*X*U(N-1)-U(N-2)
!                 FIRST FEW TERMS ARE FROM TABLE 22.5 OF ABRAMOWITZ
!                 AND STEGUM.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING LABORATORY (205.03)
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE:  301-975-2855
!     ORIGINAL VERSION--JULY       1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCN, DCN1, DCN2
!
!-----START POINT-----------------------------------------------------
!
      IF(X.LT.-1.0.OR.X.GT.1.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 1ST INPUT ARGUMENT ',   &
      'TO THE CHEBU SUBROUTINE IS OUTSIDE THE (-1,1) INTERVAL *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
      N=INT(AN+0.5)
      IF(N.LT.0)THEN
        WRITE(ICOUT,6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
    6 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 2ND INPUT ARGUMENT ',   &
      'TO THE CHEBU SUBROUTINE IS NEGATIVE *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,' *****')
!
      DX=DBLE(X)
!
      IF(N.LE.0)THEN
        CN=1.0
      ELSEIF(N.EQ.1)THEN
        CN=2.0*X
      ELSEIF(N.EQ.2)THEN
        CN=4.0*X**2-1.0
      ELSEIF(N.EQ.3)THEN
        DCN=8.0D0*DX**3 - 4.0*DX
        CN=REAL(DCN)
      ELSE
        DCN1=8.0D0*DX**3 - 4.0*DX
        DCN2=4.0D0*DX**2-1.0D0
        DO 1000 I=4,N
          DCN=2.0D0*DX*DCN1-DCN2
          DCN2=DCN1
          DCN1=DCN
 1000   CONTINUE
        CN=REAL(DCN)
      ENDIF
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE CHEBU
      SUBROUTINE CHEDI2(X,Y,N,IWRITE,STATVA,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CHEBYCHEV DISTANCE BETWEEN THE
!              TWO SETS OF DATA IN THE INPUT VECTORS X AND Y.  THE
!              SAMPLE CHEBYSHEV DISTANCE WILL BE A SINGLE PRECISION VALUE
!              CALCULATED AS:
!
!                 D = MAX[i=1 to N][ABS|(X(i) - Y(i))|]
!
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS WHICH
!                                CONSTITUTE THE FIRST SET OF DATA.
!                     --Y      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED) OBSERVATIONS WHICH
!                                CONSTITUTE THE SECOND SET OF DATA.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTORS X AND Y.
!     OUTPUT ARGUMENTS--STATVA = THE SINGLE PRECISION VALUE OF THE
!                                COMPUTED SAMPLE CHEBYSHEV DISTANCE
!                                BETWEEN THE TWO SETS OF DATA IN THE
!                                INPUT VECTORS X AND Y.  THIS SINGLE
!                                PRECISION VALUE WILL BE BETWEEN 0.0
!                                AND 1.0 (INCLUSIVELY).
!     OUTPUT--THE COMPUTED SINGLE PRECISION VALUE OF THE
!             SAMPLE CHEBYSHEV DISTANCE BETWEEN THE 2 SETS
!             OF DATA IN THE INPUT VECTORS X AND Y.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--ABS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--XXX
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGYS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2017/08
!     ORIGINAL VERSION--AUGUST    2017.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CHED'
      ISUBN2='I2  '
      IERROR='NO'
      STATVA=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'EDI2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF CHEDI2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,P
   52   FORMAT('IBUGA3,ISUBRO,N,P = ',2(A4,2X),I8,F7.2)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I),Y(I)
   56     FORMAT('I,X(I),Y(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN CHEBYSHEV DISTANCE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      VARIABLES IS LESS THAN 1.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  COMPUTE THE MINKOWSKI DISTANCE.           **
!               ************************************************
!
      STATVA=CPUMIN
      DO 200 I=1,N
        AVAL=ABS(X(I) - Y(I))
        IF(AVAL.GT.STATVA)STATVA=AVAL
  200 CONTINUE
!
!               *******************************
!               **  STEP 3--                 **
!               **  WRITE OUT A LINE         **
!               **  OF SUMMARY INFORMATION.  **
!               *******************************
!
      IF(IFEEDB.EQ.'ON' .AND. IWRITE.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,811)N,STATVA
  811   FORMAT('THE CHEBYSHEV DISTANCE OF THE ',I8,   &
                 ' OBSERVATIONS  = ',G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'EDI2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CHEDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,STATVA
 9012   FORMAT('IERROR,STATVA = ',A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CHEDI2
      SUBROUTINE CHCDF(X,ANU,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE CHI DISTRIBUTION
!              WITH POSITIVE DEGREES OF FREEDOM PARAMETER = NU.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!              THE CDF IS CAN BE COMPUTED WITH THE SLATEC ROUTINE
!              DGAMIC.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ANU    = THE POSITIVE NUMBER OF DEGREES
!                                OF FREEDOM.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE CHI DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = ANU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 417.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM1, DTERM2
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DGAMIP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ANU.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)ANU
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO CHCDF ',   &
      'IS NON-POSITIVE')
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        CDF=0.0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO CHCDF ',   &
      'IS NEGATIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(X.LE.R1MACH(1))THEN
        CDF=0.0
        RETURN
      ENDIF
!
      DTERM1=DBLE(ANU/2.0)
      DTERM2=DBLE(X**2/2.0)
      DCDF=DGAMIP(DTERM1,DTERM2)
      CDF=REAL(DCDF)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE CHCDF
      SUBROUTINE CHCDF2(DX,DNU,DCDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE CHI DISTRIBUTION
!              WITH POSITIVE DEGREES OF FREEDOM PARAMETER = NU.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!              THE CDF IS CAN BE COMPUTED WITH THE SLATEC ROUTINE
!              DGAMIC.
!     NOTE--THIS IS A DOUBLE PRECISION VERSION OF CHCDF USED BY
!           CHPPF FOR GREATER ACCURACY.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ANU    = THE POSITIVE NUMBER OF DEGREES
!                                OF FREEDOM.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE CHI DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = ANU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 417.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DTERM1, DTERM2
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
      DOUBLE PRECISION DNU
      DOUBLE PRECISION DGAMIP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(DNU.LE.0.0D0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)ANU
        CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO CHCDF ',   &
      'IS NON-POSITIVE')
      IF(DX.LT.0.0D0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)DX
        CALL DPWRST('XXX','BUG ')
        DCDF=0.0D0
        GO TO 9000
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO CHCDF ',   &
      'IS NEGATIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      IF(DX.LE.D1MACH(1))THEN
        DCDF=0.0D0
        RETURN
      ENDIF
!
      DTERM1=DNU/2.0D0
      DTERM2=DX**2/2.0D0
      DCDF=DGAMIP(DTERM1,DTERM2)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE CHCDF2
      SUBROUTINE CHFDV(X1,X2,F1,F2,D1,D2,NE,XE,FE,DE,NEXT,IERR)
!***BEGIN PROLOGUE  CHFDV
!     THIS PROLOGUE HAS BEEN REMOVED FOR REASONS OF SPACE
!     FOR A COMPLETE COPY OF THIS ROUTINE CONTACT THE AUTHORS
!     From the book "Numerical Methods and Software"
!          by  D. Kahaner, C. Moler, S. Nash
!               Prentice Hall 1988
!***END PROLOGUE  CHFDV
!
!  DECLARE ARGUMENTS.
!
      INTEGER  NE, NEXT(2), IERR
      REAL  X1, X2, F1, F2, D1, D2, XE(NE), FE(NE), DE(NE)
!
!  DECLARE LOCAL VARIABLES.
!
      INTEGER  I
      REAL  C2, C2T2, C3, C3T3, DEL1, DEL2, DELTA, H, X, XMI, XMA, ZERO
!
      INCLUDE 'DPCOP2.INC'
!
      DATA  ZERO /0./
!
!  VALIDITY-CHECK ARGUMENTS.
!
!***FIRST EXECUTABLE STATEMENT  CHFDV
      IF (NE .LT. 1)  GO TO 5001
      H = X2 - X1
      IF (H .EQ. ZERO)  GO TO 5002
!
!  INITIALIZE.
!
      IERR = 0
      NEXT(1) = 0
      NEXT(2) = 0
      XMI = AMIN1(ZERO, H)
      XMA = AMAX1(ZERO, H)
!
!  COMPUTE CUBIC COEFFICIENTS (EXPANDED ABOUT X1).
!
      DELTA = (F2 - F1)/H
      DEL1 = (D1 - DELTA)/H
      DEL2 = (D2 - DELTA)/H
!                                           (DELTA IS NO LONGER NEEDED.)
      C2 = -(DEL1+DEL1 + DEL2)
      C2T2 = C2 + C2
      C3 = (DEL1 + DEL2)/H
!                               (H, DEL1 AND DEL2 ARE NO LONGER NEEDED.)
      C3T3 = C3+C3+C3
!
!  EVALUATION LOOP.
!
      DO 500  I = 1, NE
         X = XE(I) - X1
         FE(I) = F1 + X*(D1 + X*(C2 + X*C3))
         DE(I) = D1 + X*(C2T2 + X*C3T3)
!          COUNT EXTRAPOLATION POINTS.
         IF ( X.LT.XMI )  NEXT(1) = NEXT(1) + 1
         IF ( X.GT.XMA )  NEXT(2) = NEXT(2) + 1
!        (NOTE REDUNDANCY--IF EITHER CONDITION IS TRUE, OTHER IS FALSE.)
  500 CONTINUE
!
!  NORMAL RETURN.
!
      RETURN
!
!  ERROR RETURNS.
!
 5001 CONTINUE
!     NE.LT.1 RETURN.
      IERR = -1
!NIST CALL XERROR ('CHFDV -- NUMBER OF EVALUATION POINTS LESS THAN ONE'
!NIST*           , 50, IERR, 1)
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
 5011 FORMAT('****** ERROR IN CHFDV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5012)
 5012 FORMAT('       THE NUMBER OF EVALUATION POINTS IS LESS THAN ONE.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!
 5002 CONTINUE
!     X1.EQ.X2 RETURN.
      IERR = -2
!NIST CALL XERROR ('CHFDV -- INTERVAL ENDPOINTS EQUAL'
!NIST*           , 33, IERR, 1)
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5022)
 5022 FORMAT('       THE INTERVAL ENDPOINTS ARE EQUAL.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!------------- LAST LINE OF CHFDV FOLLOWS ------------------------------
      END SUBROUTINE CHFDV
      REAL FUNCTION CHFIV(X1,X2,F1,F2,D1,D2,A,B,IERR)
!***BEGIN PROLOGUE  CHFIV
!***REFER TO  PCHIA
!***ROUTINES CALLED  XERROR
!***REVISION DATE  870707   (YYMMDD)
!***END PROLOGUE  CHFIV
!
!  DECLARE ARGUMENTS.
!
      INTEGER  IERR
      REAL  X1, X2, F1, F2, D1, D2, A, B
!
!  DECLARE LOCAL VARIABLES.
!
      REAL  DTERM, FOUR, FTERM, H, HALF, PHIA1, PHIA2, PHIB1, PHIB2,   &
            PSIA1, PSIA2, PSIB1, PSIB2, TA1, TA2, TB1, TB2, THREE, TWO,   &
            UA1, UA2, UB1, UB2
!
      INCLUDE 'DPCOP2.INC'
!
!  INITIALIZE.
!
      DATA  HALF /0.5/,  TWO /2./,  THREE /3./,  FOUR /4./,  SIX /6./
!
!  VALIDITY CHECK INPUT.
!
!***FIRST EXECUTABLE STATEMENT  CHFIV
      CHFIV=CPUMIN
      IF (X1 .EQ. X2)  GO TO 5001
      IERR = 0
!
!  COMPUTE INTEGRAL.
!
      H = X2 - X1
      TA1 = (A - X1) / H
      TA2 = (X2 - A) / H
      TB1 = (B - X1) / H
      TB2 = (X2 - B) / H
!
      UA1 = TA1**3
      PHIA1 = UA1 * (TWO - TA1)
      PSIA1 = UA1 * (THREE*TA1 - FOUR)
      UA2 = TA2**3
      PHIA2 =  UA2 * (TWO - TA2)
      PSIA2 = -UA2 * (THREE*TA2 - FOUR)
!
      UB1 = TB1**3
      PHIB1 = UB1 * (TWO - TB1)
      PSIB1 = UB1 * (THREE*TB1 - FOUR)
      UB2 = TB2**3
      PHIB2 =  UB2 * (TWO - TB2)
      PSIB2 = -UB2 * (THREE*TB2 - FOUR)
!
      FTERM =   F1*(PHIA2 - PHIB2) + F2*(PHIB1 - PHIA1)
      DTERM = ( D1*(PSIA2 - PSIB2) + D2*(PSIB1 - PSIA1) )*(H/SIX)
!
!  RETURN VALUE.
!
      CHFIV = (HALF*H) * (FTERM + DTERM)
      RETURN
!
!  ERROR RETURN.
!
 5001 CONTINUE
      IERR = -1
!NIST CALL XERROR ('CHFIV -- X1 EQUAL TO X2'
!NIST*           , 23, IERR, 1)
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5011)
 5011 FORMAT('****** ERROR IN CHFIV--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5012)
 5012 FORMAT('       X1 EQUAL TO X2.')
      CALL DPWRST('XXX','BUG ')
      RETURN
!------------- LAST LINE OF CHFIV FOLLOWS ------------------------------
      END FUNCTION CHFIV
      SUBROUTINE CHM(A,B,X,HG,IERROR)
!
!       ===================================================
!       Purpose: Compute confluent hypergeometric function
!                M(a,b,x)
!       Input  : a  --- Parameter
!                b  --- Parameter ( b <> 0,-1,-2,... )
!                x  --- Argument
!       Output:  HG --- M(a,b,x)
!                IERROR REPORT ERROR CONDITIONS
!       ===================================================
!
        IMPLICIT DOUBLE PRECISION (A-H,O-Z)
        CHARACTER*4 IERROR
!
        IERROR='NO'
        Y1=0.0D0
        LA=0
!
        PI=3.141592653589793D0
        A0=A
        A1=A
        X0=X
        HG=0.0D0
        IF (B.EQ.0.0D0.OR.B.EQ.-ABS(INT(B))) THEN
           HG=1.0D+300
        ELSE IF (A.EQ.0.0D0.OR.X.EQ.0.0D0) THEN
           HG=1.0D0
        ELSE IF (A.EQ.-1.0D0) THEN
           HG=1.0D0-X/B
        ELSE IF (A.EQ.B) THEN
           HG=DEXP(X)
        ELSE IF (A-B.EQ.1.0D0) THEN
           HG=(1.0D0+X/B)*DEXP(X)
        ELSE IF (A.EQ.1.0D0.AND.B.EQ.2.0D0) THEN
           HG=(DEXP(X)-1.0D0)/X
        ELSE IF (A.EQ.INT(A).AND.A.LT.0.0D0) THEN
           M=INT(-A)
           R=1.0D0
           HG=1.0D0
           DO 10 K=1,M
              R=R*(A+K-1.0D0)/K/(B+K-1.0D0)*X
              HG=HG+R
10         CONTINUE
        ENDIF
        IF (HG.NE.0.0D0) RETURN
        IF (X.LT.0.0D0) THEN
           A=B-A
           A0=A
           X=DABS(X)
        ENDIF
        IF (A.LT.2.0D0) NL=0
        IF (A.GE.2.0D0) THEN
           NL=1
           LA=INT(A)
           A=A-LA-1.0D0
        ENDIF
        DO 30 N=0,NL
           IF (A0.GE.2.0D0) A=A+1.0D0
           IF (X.LE.30.0D0+DABS(B).OR.A.LT.0.0D0) THEN
              HG=1.0D0
              RG=1.0D0
              DO 15 J=1,500
                 RG=RG*(A+J-1.0D0)/(J*(B+J-1.0D0))*X
                 HG=HG+RG
                 IF (DABS(RG/HG).LT.1.0D-15) GO TO 25
15            CONTINUE
           ELSE
              TA=DGAMMA(A)
              TB=DGAMMA(B)
              XG=B-A
              TBA=DGAMMA(XG)
              SUM1=1.0D0
              SUM2=1.0D0
              R1=1.0D0
              R2=1.0D0
              DO 20 I=1,8
                 R1=-R1*(A+I-1.0D0)*(A-B+I)/(X*I)
                 R2=-R2*(B-A+I-1.0D0)*(A-I)/(X*I)
                 SUM1=SUM1+R1
                 SUM2=SUM2+R2
20            CONTINUE
              HG1=TB/TBA*X**(-A)*DCOS(PI*A)*SUM1
              HG2=TB/TA*DEXP(X)*X**(A-B)*SUM2
              HG=HG1+HG2
           ENDIF
25         CONTINUE
           IF (N.EQ.0) Y0=HG
           IF (N.EQ.1) Y1=HG
30      CONTINUE
        IF (A0.GE.2.0D0) THEN
           DO 35 I=1,LA-1
              HG=((2.0D0*A-B+X)*Y1+(B-A)*Y0)/A
              Y0=Y1
              Y1=HG
              A=A+1.0D0
35         CONTINUE
        ENDIF
        IF (X0.LT.0.0D0) HG=HG*DEXP(X0)
        A=A1
        X=X0
        RETURN
        END
      SUBROUTINE CHPDF(X,ANU,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE CHI DISTRIBUTION
!              WITH POSITIVE DEGREES OF FREEDOM PARAMETER = NU.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --ANU    = THE POSITIVE NUMBER OF DEGREES
!                                OF FREEDOM.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE PDF FOR THE CHI DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = ANU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORPDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1994, PAGE 417.
!               --"STATISTICAL DISTRIBUTIONS", EVANS, HASTINGS,
!                 PEACOCK.  WILEY, 1993.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
!
      DOUBLE PRECISION DTERM1, DTERM2, DTERM3, DTERM4, DTERM5
      DOUBLE PRECISION DARG1, DARG2
      DOUBLE PRECISION DPDF
      DOUBLE PRECISION DLNGAM
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(ANU.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)ANU
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
   15 FORMAT('***** ERROR--THE SECOND INPUT ARGUMENT TO CHPDF ',   &
      'IS NON-POSITIVE')
      IF(X.LT.0.0)THEN
        WRITE(ICOUT,4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        PDF=0.0
        GO TO 9999
      ENDIF
    4 FORMAT('***** ERROR--THE FIRST INPUT ARGUMENT TO CHPDF ',   &
      'IS NEGATIVE')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      DARG1=DBLE(X)
      DARG2=DBLE(ANU)
!
      DTERM1=(DARG2-1.0D0)*DLOG(DARG1)
      DTERM2=-DARG1*DARG1/2.0D0
!
      IF(DABS(DTERM2).GE.DLOG(D1MACH(2)))THEN
        PDF=0.0
        GO TO 9999
      ENDIF
!
      DTERM3=(DARG2/2.0D0-1.0D0)*DLOG(2.0D0)
      DTERM4=DLNGAM(DARG2/2.0D0)
      DTERM5=DTERM1+DTERM2-DTERM3-DTERM4
      IF(DTERM5.GE.DLOG(D1MACH(2)))THEN
        WRITE(ICOUT,101)X,ANU
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)X
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ANU
        CALL DPWRST('XXX','BUG ')
        PDF=LOG(R1MACH(2))
        GO TO 9999
      ELSE
        DPDF=DEXP(DTERM5)
      ENDIF
      PDF=REAL(DPDF)
      GO TO 9999
 101  FORMAT('***** ERROR--THE CHPDF ROUTINE OVERFLOWS.  PDF ',   &
       'SET TO LOG OF LARGEST VALUE.')
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE CHPDF
      SUBROUTINE CHPPF(P,NU,PPF)
!
!     PURPOSE   --PERCENT POINT FUNCTION FOR THE CHI
!                 DISTRIBUTION.  USES A BISECTION METHOD.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--95/4
!     ORIGINAL VERSION--APRIL     1995.
!     UPDATED         --OCTOBER   2006. CONVERT TO DOUBLE PRECISION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      REAL NU
!
      DOUBLE PRECISION DNU
      DOUBLE PRECISION DP
      DOUBLE PRECISION EPS
      DOUBLE PRECISION SIG
      DOUBLE PRECISION ZERO
      DOUBLE PRECISION DMEAN
      DOUBLE PRECISION DSD
      DOUBLE PRECISION XL
      DOUBLE PRECISION XR
      DOUBLE PRECISION XINC
      DOUBLE PRECISION CDFL
      DOUBLE PRECISION CDFR
      DOUBLE PRECISION FXL
      DOUBLE PRECISION FXR
      DOUBLE PRECISION FCS
      DOUBLE PRECISION P1
      DOUBLE PRECISION DX
      DOUBLE PRECISION DCDF
!
      DOUBLE PRECISION DGAMMA
      EXTERNAL DGAMMA
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
      DATA EPS /0.000001/
      DATA SIG /1.0D-7/
      DATA ZERO /0.0D0/
      DATA MAXIT /1000/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR--THE FIRST ARGUMENT TO CHPPF ',   &
             'IS OUTSIDE THE ALLOWABLE (0,1) INTERVAL.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ELSEIF(NU.LE.0.0)THEN
        WRITE(ICOUT,11)
   11   FORMAT('***** ERROR--THE SECOND ARGUMENT TO CHPPF ',   &
               'IS LESS THAN OR EQUAL TO 0.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)NU
        CALL DPWRST('XXX','BUG ')
        GO TO 9999
      ENDIF
!
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
!  FIND BRACKETING INTERVAL.
!
!  1) USE 0 AS THE LOWER LIMIT
!  2) START WITH THE MEAN AS THE UPPER LIMIT AND INCREMENT
!     BY 1 SD.
!
!     MEAN = SQRT(2)*GAMMA((NU+1)/2)/GAMMA(NU/2)
!     VARI = NU - MEAN**2
!
      IF(P.EQ.0.0)THEN
        PPF=0.0
        GO TO 9999
      ENDIF
!
      DNU=DBLE(NU)
      DP=DBLE(P)
      DMEAN=DSQRT(2.0D0)*DGAMMA((DNU+1.0D0)/2.0D0)/DGAMMA(DNU/2.0D0)
      DSD=DNU - DMEAN**2
      IF(DSD.GT.0.0D0)THEN
        DSD=DSQRT(DSD)
      ELSE
        DSD=20.0D0
      ENDIF
!
      XL=0.0D0
      XINC=DSD
      ICOUNT=0
      MAXCNT=10000
!
   91 CONTINUE
      XR=XL+XINC
      IF(XL.LE.0.0D0)XL=0.0D0
      IF(XR.LE.0.0D0)XR=XL+1.0D0
      CALL CHCDF2(XL,DNU,CDFL)
      CALL CHCDF2(XR,DNU,CDFR)
      IF(CDFL.LT.DP .AND. CDFR.LT.DP)THEN
        XL=XR
      ELSEIF(CDFL.GT.DP .AND. CDFR.GT.DP)THEN
        XL=XL-XINC
      ELSE
        GO TO 99
      ENDIF
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.MAXCNT)THEN
        WRITE(ICOUT,96)
        CALL DPWRST('XXX','BUG ')
        PPF=0.0
        GO TO 9999
      ENDIF
   96 FORMAT('***** ERROR--CHPPF UNABLE TO FIND BRACKETING ',   &
             'INTERVAL.')
      GO TO 91
!
!  BISECTION METHOD
!
   99 CONTINUE
      IC = 0
      FXL = -DP
      FXR = 1.0D0 - DP
  105 CONTINUE
      DX = (XL+XR)*0.5D0
      CALL CHCDF2(DX,DNU,DCDF)
      P1=DCDF
      PPF=REAL(DX)
      FCS = P1 - DP
      IF(FCS*FXL.GT.ZERO)THEN
        XL = DX
        FXL = FCS
      ELSE
        XR = DX
        FXR = FCS
      ENDIF
      XRML = XR - XL
      IF(XRML.LE.SIG .AND. ABS(FCS).LE.EPS)GO TO 9999
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 105
      WRITE(ICOUT,130)
      CALL DPWRST('XXX','BUG ')
  130 FORMAT('***** ERROR--CHPPF ROUTINE DID NOT CONVERGE.')
      GO TO 9999
!
 9999 CONTINUE
      RETURN
      END SUBROUTINE CHPPF
      SUBROUTINE CHRAN(N,ANU,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE CHI DISTRIBUTION
!              WITH TAIL LENGTH PARAMETER VALUE = ANU.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ANU    = THE SINGLE PRECISION VALUE OF THE
!                                DEGREES OF FREEDOM PARAMETER.
!                                ANU SHOULD BE A POSITIVE INTEGER.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE CHI DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER VALUE = ANU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --ANU SHOULD BE POSITIVE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--2003.7
!     ORIGINAL VERSION--JULY      2003.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT, 5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
      IF(ANU.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)ANU
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF CHI RANDOM',   &
             ' NUMBERS IS NON-POSITIVE.')
   15 FORMAT('***** ERROR--THE DEGREES OF FREEDOM PARAMETER FOR',   &
             ' CHI RANDOM NUMBERS IS NON-POSITIVE.')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
!
!     GENERATE N UNIFORM (0,1) RANDOM NUMBERS;
!
      CALL UNIRAN(N,ISEED,X)
!
!     GENERATE N CHI DISTRIBUTION RANDOM
!     NUMBERS USING THE PERCENT POINT FUNCTION TRANSFORMATION METHOD.
!
      DO 100 I=1,N
        CALL CHPPF(X(I),ANU,XTEMP)
        X(I)=XTEMP
  100 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE CHRAN
      SUBROUTINE CHECKA(NUMARG,MINNA,MAXNA,IANS,IWIDTH,ISUBN1,ISUBN2,   &
                        IERROR)
!
!     PURPOSE--CHECK TO SEE IF THE NUMBER OF INPUT ARGUMENTS
!              TO THE CALLING SUBROUTINES IS BETWEEN ALLOWABLE LIMITS.
!     OUTPUT--A VALUE OF 'NO' OR 'YES' IS STORED
!             IN THE HOLLERITH VARIABLE IERROR
!             DEPENDING ON WHETHER THE NUMBER OF ARGUMENTS
!             IS WITHIN ALLOWABLE LIMITS
!             OR OUTSIDE OF ALLOWABLE LIMITS, RESPECTIVELY.
!     NOTE--THIS CHECKING SUBROUTINE IS PARTICULARLY
!           USEFUL FOR THOSE SUBROUTINES WHICH
!           WOULD RESULT IN A TERMINATION IF THE ANALYST
!           FORGOT TO ENTER ANY ARGUMENTS AT ALL
!           FOR A COMMAND WHICH REQUIRES AT LEAST 1
!           (LIKE HISTOGRAM, NORMAL PROBABILITY PLOT, ETC.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER 28, 1977.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --FEBRUARY  1982.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IANS
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IANS(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(MINNA.LE.NUMARG.AND.NUMARG.LE.MAXNA)GO TO 1200
!
      WRITE(ICOUT,1102)ISUBN1,ISUBN2
 1102 FORMAT('***** ERROR IN ',A4,A4,'--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1104)
 1104 FORMAT('      THE NUMBER OF ARGUMENTS ACCOMPANYING')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1106)
 1106 FORMAT('      THE LAST COMMAND WAS IMPROPER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)NUMARG
 1112 FORMAT('      THE ENTERED NUMBER OF ARGUMENTS WAS ',I6)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1108)
 1108 FORMAT('      A VALID NUMBER OF ARGUMENTS FOR THIS COMMAND ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1110)MINNA,MAXNA
 1110 FORMAT('      IS BETWEEN ',I6,' AND ',I6,' (INCLUSIVELY).')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1124)
 1124 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,1126)(IANS(I),I=1,MIN(100,IWIDTH))
 1126   FORMAT('      ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      RETURN
!
 1200 CONTINUE
      IERROR='NO'
      RETURN
!
      END SUBROUTINE CHECKA
      SUBROUTINE CHECKF(IHWORD,IHWOR2,IHWUSE,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,ITYPE)
!
!     PURPOSE--CHECK TO SEE IF THE HOLLERITH NAME IN (IHWORD,IHWOR2)
!              EXISTS IN THE CURRENT TABLE OF AVAILABLE NAMES AND RETURN
!              THE TYPE (PARAMETER, VARIABLE, STRING, OR MATRIX).
!     OUTPUT--ITYPE = THE TYPE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2002/7
!     ORIGINAL VERSION--JULY      2002.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHWORD
      CHARACTER*4 IHWOR2
      CHARACTER*4 IHWUSE
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 MESSAG
      CHARACTER*4 IANS
!
      CHARACTER*8 ITYPE
!
!---------------------------------------------------------------------
!
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION IN(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
!
      DIMENSION IANS(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBG4.EQ.'ECKF')THEN
        WRITE(ICOUT,61)IHWUSE,MESSAG,ISUBN1,ISUBN2,MAXNAM,IWIDTH
   61   FORMAT('IHWUSE,MESSAG,ISUBN1,ISUBN2,MAXNAM,IWIDTH = ',   &
               4(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IANS(1),IANS(2),IANS(3),IANS(4)
   63   FORMAT('IANS(1),IANS(2),IANS(3),IANS(4) = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        DO 67 I=1,NUMNAM
          WRITE(ICOUT,68)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I),   &
                         VALUE(I)
   68     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I)',   &
                 'VALUE(I) = ',I8,2X,A4,A4,2X,A4,2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   67   CONTINUE
      ENDIF
!
!     NOTE: RETURNING ITYPE = "NONE" MEANS NAME NOT FOUND IN CURRENT
!           NAME LIST TABLE.
!
      ITYPE='NONE'
      ILOC=0
!
      DO 150 I=1,NUMNAM
        I2=I
        IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I))THEN
          ILOC=I2
          IF(IUSE(I).EQ.'P')THEN
            ITYPE='PARAMETE'
          ELSEIF(IUSE(I).EQ.'V')THEN
            ITYPE='VARIBLE'
          ELSEIF(IUSE(I).EQ.'F')THEN
            ITYPE='STRING'
          ELSEIF(IUSE(I).EQ.'M')THEN
            ITYPE='MATRIX'
          ELSE
            ITYPE='UNKN'
          ENDIF
          GO TO 9000
        ENDIF
  150 CONTINUE
!
 9000 CONTINUE
      IF(MESSAG.EQ.'ON')THEN
        WRITE(ICOUT,51)IHNAME(ILOC),IHNAM2(ILOC),ITYPE
   51   FORMAT('***** VARIABLE ',A4,A4,' FOUND AS A ',A8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
!
      END SUBROUTINE CHECKF
      SUBROUTINE CHECKN(IHWORD,IHWOR2,IHWUSE,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
!
!     PURPOSE--CHECK TO SEE IF THE HOLLERITH NAME IN (IHWORD,IHWOR2)
!              EXISTS IN THE CURRENT TABLE OF AVAILABLE PARAMETER AND
!              VARIABLE NAMES AS GIVEN IN IHNAME(.) AND IHNAM2(I).
!     OUTPUT--THE LOCATION (THAT IS, THE LINE OR ROW) IN THE TABLE
!             WHERE THE NAME WAS FOUND (IF FOUND).
!             THIS LOCATION IS STORED IN THE VARIABLE ILOC.
!             ALSO, A VALUE OF 'YES' OR 'NO' IS STORED
!             IN THE HOLLERITH VARIABLE IERROR
!             DEPENDING ON WHETHER THE NAME WAS NOT FOUND
!             OR WAS FOUND, RESPECTIVELY.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER 28, 1977.
!     UPDATED         --JUNE 8, 1978.
!     UPDATED         --NOVEMBER  1980.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --JULY      1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   1988. (UPDATED ERROR MESSAGES)
!     UPDATED         --JANUARY   2010. CHECK FOR MATRIX
!     UPDATED         --JANUARY   2019. CHECK FOR CHARACTER VARIABLE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHWORD
      CHARACTER*4 IHWOR2
      CHARACTER*4 IHWUSE
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 MESSAG
      CHARACTER*4 IANS
      CHARACTER*4 IERROR
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
!
!---------------------------------------------------------------------
!
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION IN(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
!
      DIMENSION IANS(*)
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 IFILE2
      CHARACTER (LEN=MAXFNC) :: IFILE2
      CHARACTER*12 ISTAT2
      CHARACTER*12 IFORM2
      CHARACTER*12 IACCE2
      CHARACTER*12 IPROT2
      CHARACTER*12 ICURS2
      CHARACTER*4  IREWI2
      CHARACTER*4  IERRF2
      CHARACTER*4  ISUBN0
      CHARACTER*8  IH
!
      INCLUDE 'DPCOFO.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOBE.INC'
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(ISUBG4.EQ.'ECKN')THEN
        WRITE(ICOUT,61)MAXNAM,IWIDTH
   61   FORMAT('MAXNAM,IWIDTH = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 67 I=1,NUMNAM
          WRITE(ICOUT,68)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I),   &
                         VALUE(I)
   68     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I)',   &
                 'VALUE(I) = ',I8,2X,2A4,2X,A4,2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   67   CONTINUE
        WRITE(ICOUT,69)IANS(1),IANS(2),IANS(3),IANS(4)
   69   FORMAT('IANS(1),IANS(2),IANS(3),IANS(4) = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IERROR='NO'
      IF(NUMNAM.LE.0)THEN
        ILOC=0
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IHWUSE.EQ.'C' .OR. IHWUSE.EQ.'VC  ')THEN
        IOUNI2=IZCHNU
        IFILE2=IZCHNA
        ISTAT2=IZCHST
        IFORM2=IZCHFO
        IACCE2=IZCHAC
        IPROT2=IZCHPR
        ICURS2=IZCHCS
        IFLAGC=1
!
        ISUBN0='WRIT'
        IERRF2='NO'
        IBUGS2='OFF'
        ISUBRO='XXXX'
        IFLAGC=1
        CALL DPOPFI(IOUNI2,IFILE2,ISTAT2,IFORM2,IACCE2,IPROT2,   &
                    ICURS2,   &
                    IREWI2,ISUBN0,IERRF2,IBUGS2,ISUBRO,IERROR)
        IF(IERRF2.EQ.'YES')THEN
          IFLAGC=0
          ILOC=0
          IERROR='YES'
          GO TO 9000
        ELSE
          REWIND(IOUNI2)
          READ(IOUNI2,'(I8)',END=71,ERR=71)NCVAR
          IFLAGC=1
          GO TO 79
!
   71     CONTINUE
          IFLAGC=0
          IF(IHWUSE.EQ.'C')THEN
            ILOC=0
            IERROR='YES'
          ENDIF
   79     CONTINUE
        ENDIF
        IF(IHWUSE.EQ.'C')GO TO 159
      ENDIF
!
      DO 150 I=1,NUMNAM
!
        I2=I
!
        IF(IHWUSE.EQ.'P')THEN
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'P')GO TO 800
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I))THEN
            IF(MESSAG.EQ.'YES')THEN
              WRITE(ICOUT,111)IHWORD,IHWOR2
  111         FORMAT('     A COMMAND OR EXPRESSION EXPECTED THE NAME ',   &
                     2A4,' TO BE USED ')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,113)
  113         FORMAT('     AS A PARAMETER.  THE NAME WAS FOUND IN THE ',   &
                     'INTERNAL TABLE,')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,114)
  114         FORMAT('     BUT NOT AS A PARAMETER.  PLEASE RECHECK ',   &
                     'THE COMMAND SYNTAX.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,999)
  999         FORMAT(1X)
              CALL DPWRST('XXX','BUG ')
            ENDIF
            ILOC=0
            IERROR='YES'
            GO TO 9000
          ENDIF
!
        ELSEIF(IHWUSE.EQ.'V' .OR. IHWUSE.EQ.'VC')THEN
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I).AND.   &
            IUSE(I).EQ.'V')GO TO 800
          IF(IHWUSE.EQ.'VC')GO TO 159
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I))THEN
!
            IF(MESSAG.EQ.'YES')THEN
              WRITE(ICOUT,211)IHWORD,IHWOR2
  211         FORMAT('     A COMMAND OR EXPRESSION EXPECTED THE NAME ',   &
                     2A4,' TO BE USED')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,213)
  213         FORMAT('     AS A VARIABLE.  THE NAME WAS FOUND IN THE ',   &
                     'INTERNAL TABLE,')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,214)
  214         FORMAT('     BUT NOT AS A VARIABLE.  PLEASE RECHECK THE ',   &
                     'COMMAND SYNTAX.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
            ENDIF
            ILOC=0
            IERROR='YES'
            GO TO 9000
          ENDIF
!
        ELSEIF(IHWUSE.EQ.'EITH' .OR. IHWUSE.EQ.'PORV' .OR.   &
               IHWUSE.EQ.'VORP' .OR. IHWUSE.EQ.'PV'   .OR.   &
               IHWUSE.EQ.'VP')THEN
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'P')GO TO 800
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'V')GO TO 800
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I))THEN
            IF(MESSAG.EQ.'YES')THEN
              WRITE(ICOUT,311)IHWORD,IHWOR2
  311         FORMAT('     A COMMAND OR EXPRESSION EXPECTED THE NAME ',   &
                     2A4,' TO BE USED')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,313)
  313         FORMAT('     AS A PARAMETER OR VARIABLE.  THE NAME ',   &
                     'WAS FOUND IN THE INTERNAL TABLE,')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,314)
  314         FORMAT('     BUT NEITHER AS A PARAMETER NOR A VARIABLE.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,315)
  315         FORMAT('     PLEASE RECHECK THE COMMAND SYNTAX.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
            ENDIF
            ILOC=0
            IERROR='YES'
            GO TO 9000
          ENDIF
!
        ELSEIF(IHWUSE.EQ.'M')THEN
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I).AND.   &
            IUSE(I).EQ.'M')GO TO 800
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I))THEN
!
            IF(MESSAG.EQ.'YES')THEN
              WRITE(ICOUT,411)IHWORD,IHWOR2
  411         FORMAT('     A COMMAND OR EXPRESSION EXPECTED THE NAME ',   &
                     2A4,' TO BE USED')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,413)
  413         FORMAT('     AS A MATRIX.  THE NAME WAS FOUND IN THE ',   &
                     'INTERNAL TABLE,')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,414)
  414         FORMAT('     BUT NOT AS A MATRIX.  PLEASE RECHECK THE ',   &
                     'COMMAND SYNTAX.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
            ENDIF
            ILOC=0
            IERROR='YES'
            GO TO 9000
          ENDIF
!
        ELSEIF(IHWUSE.EQ.'F')THEN
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'F')GO TO 800
          IF(IHWORD.EQ.IHNAME(I).AND.IHWOR2.EQ.IHNAM2(I))THEN
            IF(MESSAG.EQ.'YES')THEN
              WRITE(ICOUT,111)IHWORD,IHWOR2
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,513)
  513         FORMAT('     AS A STRING.  THE NAME WAS FOUND IN THE ',   &
                     'INTERNAL TABLE,')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,514)
  514         FORMAT('     BUT NOT AS A STRING.  PLEASE RECHECK ',   &
                     'THE COMMAND SYNTAX.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
            ENDIF
            ILOC=0
            IERROR='YES'
            GO TO 9000
          ENDIF
!
        ELSEIF(IHWUSE.EQ.'C')THEN
!
!         CHECK FOR CHARACTER VARIABLE
!
        ENDIF
!
  150 CONTINUE
      IF(IHWUSE.EQ.'VC')GO TO 159
      GO TO 700
  159 CONTINUE
!
!     FOR 'C' OR 'VC' OPTION CHECK FOR CHARACTER VARIABLE
!
      REWIND(IOUNI2)
      READ(IOUNI2,'(I8)',END=691,ERR=691)NCVAR
      DO 610 KK=1,NCVAR
        READ(IOUNI2,'(A8)',END=691,ERR=691)IH
        IF(IHWORD.EQ.IH(1:4) .AND. IHWOR2.EQ.IH(5:8))THEN
!
!         FOR CHARACTER VARIABLE, USE "-" TO INDICATE LOCATION OF
!         CHARACTER VARIABLE RATHER THAN NUMERIC VARIABLE.
!
          ILOC=-KK
          IERROR='NO'
          GO TO 9000
        ENDIF
  610 CONTINUE
  691 CONTINUE
!
      IF(MESSAG.EQ.'YES')THEN
        WRITE(ICOUT,211)IHWORD,IHWOR2
        CALL DPWRST('XXX','BUG ')
        IF(IHWUSE.EQ.'C')THEN
          WRITE(ICOUT,613)
  613     FORMAT('     AS A CHARACTER VARIABLE.  THE NAME WAS NOT ',   &
                 'FOUND IN THE LIST')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,614)
  614     FORMAT('     OF CHARACTER VARIABLE NAMES.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
        ELSE
          WRITE(ICOUT,623)
  623     FORMAT('     AS A NUMERIC OR CHARACTER VARIABLE.  THE NAME ',   &
                 'WAS NOT FOUND IN THE LIST')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,624)
  624     FORMAT('     OF NUMERIC AND CHARACTER VARIABLE NAMES.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
      ILOC=0
      IERROR='YES'
      GO TO 9000
!
  700 CONTINUE
      IF(MESSAG.EQ.'YES')THEN
        WRITE(ICOUT,702)ISUBN1,ISUBN2
  702   FORMAT('***** ERROR IN CHECKN AS CALLED FROM ',2A4,'--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,703)
  703   FORMAT('      A VARIABLE, PARAMETER, OR MATRIX NAME USED ',   &
               '(OR NEEDED)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,704)
  704   FORMAT('      IN A COMMAND OR AN EXPRESSION WAS NOT FOUND ',   &
               'IN THE CURRENT')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,706)
  706   FORMAT('      LIST OF AVAILABLE PARAMETER AND VARIABLE NAMES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,707)IHWORD,IHWOR2
  707   FORMAT('      THE VARIABLE OR PARAMETER IN QUESTION WAS ',2A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      ILOC=0
      IERROR='YES'
      GO TO 9000
!
  800 CONTINUE
      ILOC=I2
      IERROR='NO'
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE CHECKN
      SUBROUTINE CHECN2(IHTEST,IHTES2,ITTEST,   &
                        IHNAME,IHNAM2,IUSE,IVALUE,VALUE,IN,NUMNAM,   &
                        ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,   &
                        JVALUE,AVALUE,JUSE,JN,   &
                        IOLDNA,IOLDN2,IOLDNI,   &
                        IFOUND,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--SEARCH THE INTERNAL LIST IHNAME(.)
!              FOR THE NAME GIVEN BY IHTEST.
!              CHECK FOR PRESENCE IN LIST.
!              CHECK FOR VARIABLES HAVING SAME LENGTH.
!              CHECK FOR VARIABLES HAVING POSITIVE LENGTH.
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IHTEST
      CHARACTER*4 IHTES2
      CHARACTER*4 ITTEST
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 MESSAG
      CHARACTER*4 IANS
      CHARACTER*4 JUSE
      CHARACTER*4 IOLDNA
      CHARACTER*4 IOLDN2
      CHARACTER*4 IFOUND
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
      DIMENSION IUSE(*)
      DIMENSION IN(*)
      DIMENSION IANS(*)
!
!-----COMMON VARIABLES (GENERAL)-----------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      I=(-999)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'ECN2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF CHECN2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,NUMNAM,IWIDTH
   52   FORMAT('IBUGA3,ISUBRO,NUMNAM,IWIDTH = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IHTEST,IHTES2,ITTEST
   53   FORMAT('IHTEST,IHTES2,ITTEST = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)(IANS(I),I=1,MIN(100,IWIDTH))
   62   FORMAT('IANS(.) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        DO 67 I=1,NUMNAM
          WRITE(ICOUT,68)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I),   &
                         VALUE(I)
   68     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),IVALUE(I)',   &
                 'VALUE(I) = ',I8,2X,A4,A4,2X,A4,2I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   67   CONTINUE
      ENDIF
!
      IF(NUMNAM.LE.0)GO TO 1010
      DO 1000 I=1,NUMNAM
      I2=I
      IF(IHTEST.EQ.IHNAME(I).AND.IHTES2.EQ.IHNAM2(I))GO TO 1100
      GO TO 1000
!
 1100 CONTINUE
      IFOUND='YES'
      ILOC=I2
      IF(ITTEST.EQ.'P')GO TO 1200
      IF(ITTEST.EQ.'V')GO TO 1300
      IF(ITTEST.EQ.'PV')GO TO 1400
      IF(ITTEST.EQ.'VP')GO TO 1400
      IF(ITTEST.EQ.'EITH')GO TO 1400
      IF(ITTEST.EQ.'BOTH')GO TO 1400
!
 1200 CONTINUE
      IF(IUSE(ILOC).EQ.'P')GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      JVALUE=IVALUE(ILOC)
      AVALUE=VALUE(ILOC)
      JUSE=IUSE(ILOC)
      JN=IN(ILOC)
      GO TO 9000
!
 1220 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1231
      IF(IPRINT.EQ.'OFF')GO TO 1231
      IF(MESSAG.EQ.'NO')GO TO 1231
      WRITE(ICOUT,1221)ISUBN1,ISUBN2
 1221 FORMAT('***** ERROR IN ',A4,A4,'--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1222)
 1222 FORMAT('      A NAME WHICH SHOULD BE A PARAMETER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1223)
 1223 FORMAT('      HAS BEEN FOUND IN THE NAME LIST,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1224)
 1224 FORMAT('      BUT AS A DIFFERENT TYPE THAN A PARAMETER.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1225)IHTEST,IHTES2
 1225 FORMAT('NAME = ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      IF(IUSE(ILOC).EQ.'V')WRITE(ICOUT,1226)
 1226 FORMAT('TYPE = VARIABLE')
      IF(IUSE(ILOC).EQ.'V')CALL DPWRST('XXX','BUG ')
      IF(IUSE(ILOC).EQ.'F')WRITE(ICOUT,1227)
 1227 FORMAT('TYPE = FUNCTION')
      IF(IUSE(ILOC).EQ.'F')CALL DPWRST('XXX','BUG ')
      IF(IUSE(ILOC).NE.'V'.AND.IUSE(ILOC).NE.'F')WRITE(ICOUT,1228)   &
      IUSE(ILOC)
 1228 FORMAT('TYPE = ',A4)
      IF(IUSE(ILOC).NE.'V'.AND.IUSE(ILOC).NE.'F')   &
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1229)
 1229 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,1230)(IANS(J),J=1,IWIDTH)
 1230 FORMAT('      ',80A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
 1231 CONTINUE
      IERROR='YES'
      GO TO 9000
!
 1300 CONTINUE
      IF(IUSE(ILOC).EQ.'V')GO TO 1310
      GO TO 1320
!
 1310 CONTINUE
      JVALUE=IVALUE(ILOC)
      AVALUE=VALUE(ILOC)
      JUSE=IUSE(ILOC)
      JN=IN(ILOC)
