      IF(IWIDTH.GE.1)WRITE(ICOUT,1370)(IANS(J),J=1,IWIDTH)
 1370 FORMAT('      ',80A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
 1371 CONTINUE
      IERROR='YES'
      GO TO 9000
!
 1400 CONTINUE
      IF(ITTEST.EQ.'P'.AND.IUSE(ILOC).NE.'P')GO TO 1420
      IF(ITTEST.EQ.'V'.AND.IUSE(ILOC).NE.'V')GO TO 1420
      IF(IUSE(ILOC).EQ.'P')GO TO 1405
      IF(IUSE(ILOC).EQ.'V')GO TO 1410
