 1471 CONTINUE
      IERROR='YES'
      GO TO 9000
!
 1000 CONTINUE
!
 1010 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1021
      IF(IPRINT.EQ.'OFF')GO TO 1021
      IF(MESSAG.EQ.'NO')GO TO 1021
      WRITE(ICOUT,1011)ISUBN1,ISUBN2
 1011 FORMAT('***** ERROR IN ',A4,A4,'--')
