      SUBROUTINE CHECN3(IHWORD,IHWOR2,IHWUSE,   &
                        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,   &
                        NUMNAM,MAXNAM,   &
                        ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
!
!     PURPOSE--CHECK TO SEE IF THE HOLLERITH NAME IN (IHWORD,IHWOR2)
!              EXISTS IN THE CURRENT TABLE OF AVAILABLE PARAMETER AND
!              VARIABLE NAMES AS GIVEN IN IHNAME(.) AND IHNAM2(I).
!     NOTE--THIS IS A SLIGHT VARIANT OF CHECKN.  IT DISTINGUISHES
!           BETWEEN THE CASE WHERE THE NAME IS NOT FOUND (ILOC=0)
!           AND WHERE THE NAME IS FOUND BUT IS OF THE WRONG TYPE
!           (ILOC=-1).
!     OUTPUT--THE LOCATION (THAT IS, THE LINE OR ROW) IN THE TABLE
!             WHERE THE NAME WAS FOUND (IF FOUND).
!             THIS LOCATION IS STORED IN THE VARIABLE ILOC.
