      SUBROUTINE CHLHSN(NR,N,A,EPSM,SX,UDIAG)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! FIND THE L(L-TRANSPOSE) [WRITTEN LL+] DECOMPOSITION OF THE PERTURBED
! MODEL HESSIAN MATRIX A+MU*I(WHERE MU\0 AND I IS THE IDENTITY MATRIX)
! WHICH IS SAFELY POSITIVE DEFINITE.  IF A IS SAFELY POSITIVE DEFINITE
! UPON ENTRY, THEN MU=0.
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(N,N)      <--> ON ENTRY; "A" IS MODEL HESSIAN (ONLY LOWER
!                  TRIANGULAR PART AND DIAGONAL STORED)
!                  ON EXIT:  A CONTAINS L OF LL+ DECOMPOSITION OF
!                  PERTURBED MODEL HESSIAN IN LOWER TRIANGULAR
!                  PART AND DIAGONAL AND CONTAINS HESSIAN IN UPPER
!                  TRIANGULAR PART AND UDIAG
! EPSM         --> MACHINE EPSILON
! SX(N)        --> DIAGONAL SCALING MATRIX FOR X
! UDIAG(N)    <--  ON EXIT: CONTAINS DIAGONAL OF HESSIAN
!
! INTERNAL VARIABLES
! ------------------
! TOL              TOLERANCE
! DIAGMN           MINIMUM ELEMENT ON DIAGONAL OF A
! DIAGMX           MAXIMUM ELEMENT ON DIAGONAL OF A
! OFFMAX           MAXIMUM OFF-DIAGONAL ELEMENT OF A
! OFFROW           SUM OF OFF-DIAGONAL ELEMENTS IN A ROW OF A
! EVMIN            MINIMUM EIGENVALUE OF A
! EVMAX            MAXIMUM EIGENVALUE OF A
!
! DESCRIPTION
! -----------
! 1. IF "A" HAS ANY NEGATIVE DIAGONAL ELEMENTS, THEN CHOOSE MU>0
! SUCH THAT THE DIAGONAL OF A:=A+MU*I IS ALL POSITIVE
! WITH THE RATIO OF ITS SMALLEST TO LARGEST ELEMENT ON THE
! ORDER OF SQRT(EPSM).
!
! 2. "A" UNDERGOES A PERTURBED CHOLESKY DECOMPOSITION WHICH
! RESULTS IN AN LL+ DECOMPOSITION OF A+D, WHERE D IS A
! NON-NEGATIVE DIAGONAL MATRIX WHICH IS IMPLICITLY ADDED TO
! "A" DURING THE DECOMPOSITION IF "A" IS NOT POSITIVE DEFINITE.
! "A" IS RETAINED AND NOT CHANGED DURING THIS PROCESS BY
! COPYING L INTO THE UPPER TRIANGULAR PART OF "A" AND THE
! DIAGONAL INTO UDIAG.  THEN THE CHOLESKY DECOMPOSITION ROUTINE
! IS CALLED.  ON RETURN, ADDMAX CONTAINS MAXIMUM ELEMENT OF D.
!
! 3. IF ADDMAX=0, "A" WAS POSITIVE DEFINITE GOING INTO STEP 2
! AND RETURN IS MADE TO CALLING PROGRAM.  OTHERWISE,
! THE MINIMUM NUMBER SDD WHICH MUST BE ADDED TO THE
! DIAGONAL OF A TO MAKE IT SAFELY STRICTLY DIAGONALLY DOMINANT
! IS CALCULATED.  SINCE A+ADDMAX*I AND A+SDD*I ARE SAFELY
! POSITIVE DEFINITE, CHOOSE MU=MIN(ADDMAX,SDD) AND DECOMPOSE
! A+MU*I TO OBTAIN L.
!
      DIMENSION A(NR,1),SX(N),UDIAG(N)
!
! SCALE HESSIAN
! PRE- AND POST- MULTIPLY "A" BY INV(SX)
!
      DO 20 J=1,N
        DO 10 I=J,N
          A(I,J)=A(I,J)/(SX(I)*SX(J))
   10   CONTINUE
   20 CONTINUE
!
! STEP1
! -----
! NOTE:  IF A DIFFERENT TOLERANCE IS DESIRED THROUGHOUT THIS
! ALGORITHM, CHANGE TOLERANCE HERE:
      TOL=SQRT(EPSM)
!
      DIAGMX=A(1,1)
      DIAGMN=A(1,1)
      IF(N.EQ.1) GO TO 35
      DO 30 I=2,N
        IF(A(I,I).LT.DIAGMN) DIAGMN=A(I,I)
        IF(A(I,I).GT.DIAGMX) DIAGMX=A(I,I)
   30 CONTINUE
   35 POSMAX=MAX(DIAGMX,0.D0)
!
! DIAGMN .LE. 0
!
      IF(DIAGMN.GT.POSMAX*TOL) GO TO 100
!     IF(DIAGMN.LE.POSMAX*TOL)
!     THEN
        AMU=TOL*(POSMAX-DIAGMN)-DIAGMN
        IF(AMU.NE.0.) GO TO 60
!       IF(AMU.EQ.0.)
!       THEN
!
! FIND LARGEST OFF-DIAGONAL ELEMENT OF A
          OFFMAX=0.D0
          IF(N.EQ.1) GO TO 50
          DO 45 I=2,N
            IM1=I-1
            DO 40 J=1,IM1
              IF(ABS(A(I,J)).GT.OFFMAX) OFFMAX=ABS(A(I,J))
   40       CONTINUE
   45     CONTINUE
   50     AMU=OFFMAX
          IF(AMU.NE.0.D0) GO TO 55
!         IF(AMU.EQ.0.D0)
!         THEN
            AMU=1.0D0
            GO TO 60
!         ELSE
   55       AMU=AMU*(1.0D0+TOL)
!         ENDIF
!       ENDIF
!
! A=A + MU*I
!
   60   DO 65 I=1,N
          A(I,I)=A(I,I)+AMU
   65   CONTINUE
        DIAGMX=DIAGMX+AMU
!     ENDIF
!
! STEP2
! -----
! COPY LOWER TRIANGULAR PART OF "A" TO UPPER TRIANGULAR PART
! AND DIAGONAL OF "A" TO UDIAG
!
  100 CONTINUE
      DO 110 J=1,N
        UDIAG(J)=A(J,J)
        IF(J.EQ.N) GO TO 110
        JP1=J+1
        DO 105 I=JP1,N
          A(J,I)=A(I,J)
  105   CONTINUE
  110 CONTINUE
!
      CALL CHOLDC(NR,N,A,DIAGMX,TOL,ADDMAX)
!
!
! STEP3
! -----
! IF ADDMAX=0, "A" WAS POSITIVE DEFINITE GOING INTO STEP 2,
! THE LL+ DECOMPOSITION HAS BEEN DONE, AND WE RETURN.
! OTHERWISE, ADDMAX>0.  PERTURB "A" SO THAT IT IS SAFELY
! DIAGONALLY DOMINANT AND FIND LL+ DECOMPOSITION
!
      IF(ADDMAX.LE.0.) GO TO 170
!     IF(ADDMAX.GT.0.)
!     THEN
!
! RESTORE ORIGINAL "A" (LOWER TRIANGULAR PART AND DIAGONAL)
!
        DO 120 J=1,N
          A(J,J)=UDIAG(J)
          IF(J.EQ.N) GO TO 120
          JP1=J+1
          DO 115 I=JP1,N
            A(I,J)=A(J,I)
  115     CONTINUE
  120   CONTINUE
!
! FIND SDD SUCH THAT A+SDD*I IS SAFELY POSITIVE DEFINITE
! NOTE:  EVMIN<0 SINCE A IS NOT POSITIVE DEFINITE;
!
        EVMIN=0.
        EVMAX=A(1,1)
        DO 150 I=1,N
          OFFROW=0.D0
          IF(I.EQ.1) GO TO 135
          IM1=I-1
          DO 130 J=1,IM1
            OFFROW=OFFROW+ABS(A(I,J))
  130     CONTINUE
  135     IF(I.EQ.N) GO TO 145
          IP1=I+1
          DO 140 J=IP1,N
            OFFROW=OFFROW+ABS(A(J,I))
  140     CONTINUE
  145     EVMIN=MIN(EVMIN,A(I,I)-OFFROW)
          EVMAX=MAX(EVMAX,A(I,I)+OFFROW)
  150   CONTINUE
        SDD=TOL*(EVMAX-EVMIN)-EVMIN
!
! PERTURB "A" AND DECOMPOSE AGAIN
!
        AMU=MIN(SDD,ADDMAX)
        DO 160 I=1,N
          A(I,I)=A(I,I)+AMU
          UDIAG(I)=A(I,I)
  160   CONTINUE
!
! "A" NOW GUARANTEED SAFELY POSITIVE DEFINITE
!
        CALL CHOLDC(NR,N,A,0.0D0,TOL,ADDMAX)
!     ENDIF
!
! UNSCALE HESSIAN AND CHOLESKY DECOMPOSITION MATRIX
!
  170 DO 190 J=1,N
        DO 175 I=J,N
          A(I,J)=SX(I)*A(I,J)
  175   CONTINUE
        IF(J.EQ.1) GO TO 185
        JM1=J-1
        DO 180 I=1,JM1
          A(I,J)=SX(I)*SX(J)*A(I,J)
  180   CONTINUE
  185   UDIAG(J)=UDIAG(J)*SX(J)*SX(J)
  190 CONTINUE
      RETURN
      END SUBROUTINE CHLHSN
      SUBROUTINE CHOLDC(NR,N,A,DIAGMX,TOL,ADDMAX)
      IMPLICIT DOUBLE PRECISION (A-H,O-Z)
!
! PURPOSE
! -------
! FIND THE PERTURBED L(L-TRANSPOSE) [WRITTEN LL+] DECOMPOSITION
! OF A+D, WHERE D IS A NON-NEGATIVE DIAGONAL MATRIX ADDED TO A IF
! NECESSARY TO ALLOW THE CHOLESKY DECOMPOSITION TO CONTINUE.
!
! PARAMETERS
! ----------
! NR           --> ROW DIMENSION OF MATRIX
! N            --> DIMENSION OF PROBLEM
! A(N,N)      <--> ON ENTRY: MATRIX FOR WHICH TO FIND PERTURBED
!                       CHOLESKY DECOMPOSITION
!                  ON EXIT:  CONTAINS L OF LL+ DECOMPOSITION
!                  IN LOWER TRIANGULAR PART AND DIAGONAL OF "A"
! DIAGMX       --> MAXIMUM DIAGONAL ELEMENT OF "A"
! TOL          --> TOLERANCE
! ADDMAX      <--  MAXIMUM AMOUNT IMPLICITLY ADDED TO DIAGONAL OF "A"
!                  IN FORMING THE CHOLESKY DECOMPOSITION OF A+D
! INTERNAL VARIABLES
! ------------------
! AMINL    SMALLEST ELEMENT ALLOWED ON DIAGONAL OF L
! AMNLSQ   =AMINL**2
! OFFMAX   MAXIMUM OFF-DIAGONAL ELEMENT IN COLUMN OF A
!
!
! DESCRIPTION
! -----------
! THE NORMAL CHOLESKY DECOMPOSITION IS PERFORMED.  HOWEVER, IF AT ANY
! POINT THE ALGORITHM WOULD ATTEMPT TO SET L(I,I)=SQRT(TEMP)
! WITH TEMP < TOL*DIAGMX, THEN L(I,I) IS SET TO SQRT(TOL*DIAGMX)
! INSTEAD.  THIS IS EQUIVALENT TO ADDING TOL*DIAGMX-TEMP TO A(I,I)
!
!
      DIMENSION A(NR,1)
!
      ADDMAX=0.D0
      AMINL=SQRT(DIAGMX*TOL)
      AMNLSQ=AMINL*AMINL
!
! FORM COLUMN J OF L
!
      DO 100 J=1,N
! FIND DIAGONAL ELEMENTS OF L
        SUM=0.D0
        IF(J.EQ.1) GO TO 20
        JM1=J-1
        DO 10 K=1,JM1
          SUM=SUM + A(J,K)*A(J,K)
   10   CONTINUE
   20   TEMP=A(J,J)-SUM
        IF(TEMP.LT.AMNLSQ) GO TO 30
!       IF(TEMP.GE.AMINL**2)
!       THEN
          A(J,J)=SQRT(TEMP)
          GO TO 40
!       ELSE
!
! FIND MAXIMUM OFF-DIAGONAL ELEMENT IN COLUMN
   30     OFFMAX=0.D0
          IF(J.EQ.N) GO TO 37
          JP1=J+1
          DO 35 I=JP1,N
            IF(ABS(A(I,J)).GT.OFFMAX) OFFMAX=ABS(A(I,J))
   35     CONTINUE
   37     IF(OFFMAX.LE.AMNLSQ) OFFMAX=AMNLSQ
!
! ADD TO DIAGONAL ELEMENT  TO ALLOW CHOLESKY DECOMPOSITION TO CONTINUE
          A(J,J)=SQRT(OFFMAX)
          ADDMAX=MAX(ADDMAX,OFFMAX-TEMP)
!       ENDIF
!
! FIND I,J ELEMENT OF LOWER TRIANGULAR MATRIX
   40   IF(J.EQ.N) GO TO 100
        JP1=J+1
        DO 70 I=JP1,N
          SUM=0.0D0
          IF(J.EQ.1) GO TO 60
          JM1=J-1
          DO 50 K=1,JM1
            SUM=SUM+A(I,K)*A(J,K)
   50     CONTINUE
   60     A(I,J)=(A(I,J)-SUM)/A(J,J)
   70   CONTINUE
  100 CONTINUE
      RETURN
      END SUBROUTINE CHOLDC
      SUBROUTINE CHOLNV(N, CHOINV)
!
!     Inverts a lower triangular matrix in situ
!
      INTEGER I, II, J, JJ, K, KK, N
      DOUBLE PRECISION CHOINV(*), T
      DOUBLE PRECISION S
      II = 0
      DO 100 I = 1,N
         T = 1/CHOINV(II+I)
         JJ = 0
         DO 200 J = 1,I-1
            S = 0
            JJ = JJ + J
            KK = JJ
            DO 300 K = J,I-1
               S = S + CHOINV(II+K)*CHOINV(KK)
               KK = KK + K
  300       CONTINUE
            CHOINV(II+J) = -S*T
  200    CONTINUE
         II = II + I
         CHOINV(II) = T
 100  CONTINUE
!
      RETURN
      END SUBROUTINE CHOLNV
      SUBROUTINE CHOLPD(N, CHOPRD)
!
!     Multiplies Choleski factors in situ
!
      INTEGER I, II, J, K, KK, N, NN
      DOUBLE PRECISION CHOPRD(*), S
      NN = (N*(N+1))/2
      KK = NN
      DO 100 K = N,1,-1
         KK = KK - K
         II = NN
         DO 200 I = N,K,-1
            II = II - I
            S = 0
            DO 300 J = 1,K
               S = S + CHOPRD(II+J)*CHOPRD(KK+J)
  300       CONTINUE
            CHOPRD(II+K) = S
  200    CONTINUE
  100 CONTINUE
!
      RETURN
      END SUBROUTINE CHOLPD
      SUBROUTINE CHOLPI(N, CHOPDI)
!
!     Multiplies Choleski inverse factors in situ
!
      INTEGER I, II, J, JJ, K, KK, N
      DOUBLE PRECISION CHOPDI(*)
      DOUBLE PRECISION S
      II = 0
      DO 100 I = 1,N
         DO 200 J = 1,I
            S = 0
            JJ = II + I
            KK = II + J
            DO 300 K = I,N
               S = S + CHOPDI(KK)*CHOPDI(JJ)
               JJ = JJ + K
               KK = KK + K
  300       CONTINUE
            CHOPDI(II+J) = S
  200    CONTINUE
         II = II + I
  100 CONTINUE
!
      RETURN
      END SUBROUTINE CHOLPI
      SUBROUTINE CHOLSK(N, CHOFAC)
!
!     Computes Choleski factor in situ
!
      INTEGER I, II, J, JJ, K, N
      DOUBLE PRECISION CHOFAC(*), T
      DOUBLE PRECISION S, ZERO
      PARAMETER ( ZERO = 0 )
!
      T=0.0
      S=0.0
      JJ = 0
!
      DO 100 J = 1,N
         II = JJ
         DO 200 I = J,N
            S = CHOFAC(II+J)
            DO 300 K = 1,J-1
               S = S - CHOFAC(II+K)*CHOFAC(JJ+K)
  300       CONTINUE
            IF ( I .EQ. J ) THEN
               T = SQRT( MAX( S, ZERO ) )
               CHOFAC(II+J) = T
            ELSE
               CHOFAC(II+J) = S/T
            ENDIF
            II = II + I
  200    CONTINUE
         JJ = JJ + J
  100 CONTINUE
!
      RETURN
      END SUBROUTINE CHOLSK
      SUBROUTINE CHSCDF(X,NU,CDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE CUMULATIVE DISTRIBUTION
!              FUNCTION VALUE FOR THE CHI-SQUARED DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM PARAMETER = NU.
!              THIS DISTRIBUTION IS DEFINED FOR ALL NON-NEGATIVE X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE CUMULATIVE DISTRIBUTION
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU     = THE INTEGER NUMBER OF DEGREES
!                                OF FREEDOM.
!                                NU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--CDF    = THE SINGLE PRECISION CUMULATIVE
!                                DISTRIBUTION FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION CUMULATIVE DISTRIBUTION
!             FUNCTION VALUE CDF FOR THE CHI-SQUARED DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--X SHOULD BE NON-NEGATIVE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NORCDF.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DEXP.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 941, FORMULAE 26.4.4 AND 26.4.5.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGE 176,
!                 FORMULA 28, AND PAGE 180, FORMULA 33.1.
!               --OWEN, HANDBOOK OF STATISTICAL TABLES,
!                 1962, PAGES 50-55.
!               --PEARSON AND HARTLEY, BIOMETRIKA TABLES
!                 FOR STATISTICIANS, VOLUME 1, 1954,
!                 PAGES 122-131.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --MAY       1974.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --OCTOBER   1976.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX,PI,CHI,SUM,TERM,AI,DCDFN
      DOUBLE PRECISION DNU
      DOUBLE PRECISION DSQRT,DEXP
      DOUBLE PRECISION DLOG
      DOUBLE PRECISION DFACT,DPOWER
      DOUBLE PRECISION DW
      DOUBLE PRECISION D1,D2,D3
      DOUBLE PRECISION TERM0,TERM1,TERM2,TERM3,TERM4
      DOUBLE PRECISION B11
      DOUBLE PRECISION B21
      DOUBLE PRECISION B31,B32
      DOUBLE PRECISION B41,B42,B43
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA NUCUT/1000/
      DATA PI/3.14159265358979D0/
      DATA DPOWER/0.33333333333333D0/
      DATA B11/0.33333333333333D0/
      DATA B21/-0.02777777777778D0/
      DATA B31/-0.00061728395061D0/
      DATA B32/-13.0D0/
      DATA B41/0.00018004115226D0/
      DATA B42/6.0D0/
      DATA B43/17.0D0/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(NU.LE.0)GO TO 50
      IF(X.LT.0.0)GO TO 55
      GO TO 90
   50 WRITE(ICOUT,15)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,47)NU
      CALL DPWRST('XXX','BUG ')
      CDF=0.0
      RETURN
   55 WRITE(ICOUT,4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,46)X
      CALL DPWRST('XXX','BUG ')
      CDF=0.0
      RETURN
   90 CONTINUE
    4 FORMAT('***** NON-FATAL DIAGNOSTIC--THE 1ST INPUT ARGUMENT ',   &
      'TO THE CHSCDF SUBROUTINE IS NEGATIVE *****')
   15 FORMAT('***** FATAL ERROR--THE 2ND INPUT ARGUMENT TO THE ',   &
      'CHSCDF SUBROUTINE IS NON-POSITIVE *****')
   46 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',E15.8,' *****')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8   ,' *****')
!
      DX=X
      ANU=NU
      DNU=NU
!
!     IF X IS NON-POSITIVE, SET CDF = 0.0 AND RETURN.
!     IF NU IS SMALLER THAN 10 AND X IS MORE THAN 200
!     STANDARD DEVIATIONS BELOW THE MEAN,
!     SET CDF = 0.0 AND RETURN.
!     IF NU IS 10 OR LARGER AND X IS MORE THAN 100
!     STANDARD DEVIATIONS BELOW THE MEAN,
!     SET CDF = 0.0 AND RETURN.
!     IF NU IS SMALLER THAN 10 AND X IS MORE THAN 200
!     STANDARD DEVIATIONS ABOVE THE MEAN,
!     SET CDF = 1.0 AND RETURN.
!     IF NU IS 10 OR LARGER AND X IS MORE THAN 100
!     STANDARD DEVIATIONS ABOVE THE MEAN,
!     SET CDF = 1.0 AND RETURN.
!
      IF(X.LE.0.0)GO TO 105
      AMEAN=ANU
      SD=SQRT(2.0*ANU)
      Z=(X-AMEAN)/SD
      IF(NU.LT.10.AND.Z.LT.-200.0)GO TO 105
      IF(NU.GE.10.AND.Z.LT.-100.0)GO TO 105
      IF(NU.LT.10.AND.Z.GT.200.0)GO TO 107
      IF(NU.GE.10.AND.Z.GT.100.0)GO TO 107
      GO TO 109
  105 CDF=0.0
      RETURN
  107 CDF=1.0
      RETURN
  109 CONTINUE
!
!     DISTINGUISH BETWEEN 3 SEPARATE REGIONS
!     OF THE (X,NU) SPACE.
!     BRANCH TO THE PROPER COMPUTATIONAL METHOD
!     DEPENDING ON THE REGION.
!     NUCUT HAS THE VALUE 1000.
!
      IF(NU.LT.NUCUT)GO TO 1000
      IF(NU.GE.NUCUT.AND.X.LE.ANU)GO TO 2000
      IF(NU.GE.NUCUT.AND.X.GT.ANU)GO TO 3000
      IBRAN=1
      WRITE(ICOUT,99)IBRAN
   99 FORMAT('*****INTERNAL ERROR IN CHSCDF SUBROUTINE--',   &
      'IMPOSSIBLE BRANCH CONDITION AT BRANCH POINT = ',I8)
      CALL DPWRST('XXX','BUG ')
      RETURN
!
!     TREAT THE SMALL AND MODERATE DEGREES OF FREEDOM CASE
!     (THAT IS, WHEN NU IS SMALLER THAN 1000).
!     METHOD UTILIZED--EXACT FINITE SUM
!     (SEE AMS 55, PAGE 941, FORMULAE 26.4.4 AND 26.4.5).
!
 1000 CONTINUE
      CHI=DSQRT(DX)
      IEVODD=NU-2*(NU/2)
      IF(IEVODD.EQ.0)GO TO 120
!
      SUM=0.0D0
      TERM=1.0/CHI
      IMIN=1
      IMAX=NU-1
      GO TO 130
!
  120 SUM=1.0D0
      TERM=1.0D0
      IMIN=2
      IMAX=NU-2
!
  130 IF(IMIN.GT.IMAX)GO TO 160
      DO 100 I=IMIN,IMAX,2
      AI=I
      TERM=TERM*(DX/AI)
      SUM=SUM+TERM
  100 CONTINUE
  160 CONTINUE
!
      SUM=SUM*DEXP(-DX/2.0D0)
      IF(IEVODD.EQ.0)GO TO 170
      SUM=(DSQRT(2.0D0/PI))*SUM
      SPCHI=CHI
      CALL NORCDF(SPCHI,CDFN)
      DCDFN=CDFN
      SUM=SUM+2.0D0*(1.0D0-DCDFN)
  170 CDF=1.0D0-SUM
      RETURN
!
!     TREAT THE CASE WHEN NU IS LARGE
!     (THAT IS, WHEN NU IS EQUAL TO OR GREATER THAN 1000)
!     AND X IS LESS THAN OR EQUAL TO NU.
!     METHOD UTILIZED--WILSON-HILFERTY APPROXIMATION
!     (SEE JOHNSON AND KOTZ, VOLUME 1, PAGE 176, FORMULA 28).
!
 2000 CONTINUE
      DFACT=4.5D0*DNU
      U=(((DX/DNU)**DPOWER)-1.0D0+(1.0D0/DFACT))*DSQRT(DFACT)
      CALL NORCDF(U,CDFN)
      CDF=CDFN
      RETURN
!
!     TREAT THE CASE WHEN NU IS LARGE
!     (THAT IS, WHEN NU IS EQUAL TO OR GREATER THAN 1000)
!     AND X IS LARGER THAN NU.
!     METHOD UTILIZED--HILL'S ASYMPTOTIC EXPANSION
!     (SEE JOHNSON AND KOTZ, VOLUME 1, PAGE 180, FORMULA 33.1).
!
 3000 CONTINUE
      DW=DSQRT(DX-DNU-DNU*DLOG(DX/DNU))
      DANU=DSQRT(2.0D0/DNU)
      D1=DW
      D2=DW**2
      D3=DW**3
      TERM0=DW
      TERM1=B11*DANU
      TERM2=B21*D1*(DANU**2)
      TERM3=B31*(D2+B32)*(DANU**3)
      TERM4=B41*(B42*D3+B43*D1)*(DANU**4)
      U=TERM0+TERM1+TERM2+TERM3+TERM4
      CALL NORCDF(U,CDFN)
      CDF=CDFN
      RETURN
!
      END SUBROUTINE CHSCDF
      SUBROUTINE CHSPDF(X,NU,PDF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PROBABILITY DENSITY
!              FUNCTION VALUE FOR THE CHI-SQUARED DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM PARAMETER = NU.
!              THIS DISTRIBUTION IS DEFINED FOR ALL X.
!              THE PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN THE REFERENCES BELOW.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VALUE AT
!                                WHICH THE PROBABILITY DENSITY
!                                FUNCTION IS TO BE EVALUATED.
!                                X SHOULD BE NON-NEGATIVE.
!                     --NU     = THE INTEGER NUMBER OF DEGREES
!                                OF FREEDOM.
!                                NU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PDF    = THE SINGLE PRECISION PROBABILITY
!                                DENSITY FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PROBABILITY DENSITY
!             FUNCTION VALUE PDF FOR THE THE CHI-SQUARED DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DSQRT, DATAN.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 941, FORMULAE 26.4.1.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGE XXX,
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DNU
      DOUBLE PRECISION DNUH
      DOUBLE PRECISION DGF
      DOUBLE PRECISION DPOWER
      DOUBLE PRECISION DCONST
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NU.LE.0)GO TO 150
      GO TO 190
  150 CONTINUE
      WRITE(ICOUT,115)
  115 FORMAT('***** FATAL ERROR--THE 2ND INPUT ARGUMENT ',   &
      'TO THE   CHSPDF   SUBROUTINE IS NON-POSITIVE *****')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,147)NU
  147 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8,   &
      ' *****')
      CALL DPWRST('XXX','BUG ')
      PDF=0.0
      GO TO 9000
  190 CONTINUE
!
!               **********************************************************
!               **  STEP 2--                                            **
!               **  COMPUTE THE CONSTANT = 1/((GAMMA(NU/2))*2**(NU/2))  **
!               **********************************************************
!
!
      DX=X
      DNU=NU
      DNUH=DNU/2.0D0
      CALL DGAMMF(DNUH,DGF)
      DPOWER=2.0D0**DNUH
      DCONST=1.0D0/(DPOWER*DGF)
!
!               ************************************
!               **  STEP 3--                      **
!               **  COMPUTE THE DENSITY FUNCTION  **
!               ************************************
!
      IF(X.LE.0.0)PDF=0.0
      IF(X.LE.0.0)GO TO 9000
!
      DTERM1=DX**(DNUH-1.0D0)
      DTERM2=DEXP(-(DX/2.0D0))
      DTERM=DTERM1*DTERM2
      PDF=DCONST*DTERM
      GO TO 9000
!
 9000 CONTINUE
!CCCC WRITE(ICOUT,9011)DX,DNUH,DNUH,DGF,DPOWER,DCONST
!9011 FORMAT('DX,DNUH,DNUH,DGF,DPOWER,DCONST = ',6D12.4)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,9012)DTERM1,DTERM2,DTERM,PDF
!9012 FORMAT('DTERM1,DTERM2,DTERM,PDF = ',3D12.4,E15.7)
!CCCC CALL DPWRST('XXX','BUG ')
      RETURN
      END SUBROUTINE CHSPDF
      SUBROUTINE CHSPPF(P,NU,PPF)
!
!     PURPOSE--THIS SUBROUTINE COMPUTES THE PERCENT POINT
!              FUNCTION VALUE FOR THE CHI-SQUARED DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM PARAMETER = NU.
!              THE CHI-SQUARED DISTRIBUTION USED
!              HEREIN IS DEFINED FOR ALL NON-NEGATIVE X,
!              AND ITS PROBABILITY DENSITY FUNCTION IS GIVEN
!              IN REFERENCES 2, 3, AND 4 BELOW.
!              NOTE THAT THE PERCENT POINT FUNCTION OF A DISTRIBUTION
!              IS IDENTICALLY THE SAME AS THE INVERSE CUMULATIVE
!              DISTRIBUTION FUNCTION OF THE DISTRIBUTION.
!     INPUT  ARGUMENTS--P      = THE SINGLE PRECISION VALUE
!                                (BETWEEN 0.0 (INCLUSIVELY)
!                                AND 1.0 (EXCLUSIVELY))
!                                AT WHICH THE PERCENT POINT
!                                FUNCTION IS TO BE EVALUATED.
!                     --NU     = THE INTEGER NUMBER OF DEGREES
!                                OF FREEDOM.
!                                NU SHOULD BE POSITIVE.
!     OUTPUT ARGUMENTS--PPF    = THE SINGLE PRECISION PERCENT
!                                POINT FUNCTION VALUE.
!     OUTPUT--THE SINGLE PRECISION PERCENT POINT FUNCTION .
!             VALUE PPF FOR THE CHI-SQUARED DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!                 --P SHOULD BE BETWEEN 0.0 (INCLUSIVELY)
!                   AND 1.0 (EXCLUSIVELY).
!     OTHER DATAPAC   SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--DEXP, DLOG.
!     MODE OF INTERNAL OPERATIONS--DOUBLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     ACCURACY--(ON THE UNIVAC 1108, EXEC 8 SYSTEM AT NBS)
!               COMPARED TO THE KNOWN NU = 2 (EXPONENTIAL)
!               RESULTS, AGREEMENT WAS HAD OUT TO 6 SIGNIFICANT
!               DIGITS FOR ALL TESTED P IN THE RANGE P = .001 TO
!               P = .999.  FOR P = .95 AND SMALLER, THE AGREEMENT
!               WAS EVEN BETTER--7 SIGNIFICANT DIGITS.
!               (NOTE THAT THE TABULATED VALUES GIVEN IN THE WILK,
!               GNANADESIKAN, AND HUYETT REFERENCE BELOW, PAGE 20,
!               ARE IN ERROR FOR AT LEAST THE GAMMA = 1 CASE--
!               THE WORST DETECTED ERROR WAS AGREEMENT TO ONLY 3
!               SIGNIFICANT DIGITS (IN THEIR 8 SIGNIFICANT DIGIT TABLE)
!               FOR P = .999.)
!     REFERENCES--WILK, GNANADESIKAN, AND HUYETT, 'PROBABILITY
!                 PLOTS FOR THE GAMMA DISTRIBUTION',
!                 TECHNOMETRICS, 1962, PAGES 1-15,
!                 ESPECIALLY PAGES 3-5.
!               --NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY APPLIED MATHEMATICS
!                 SERIES 55, 1964, PAGE 257, FORMULA 6.1.41,
!                 AND PAGES 940-943.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGES 166-206.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGES 46-51.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1966)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JUNE      1987.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DOUBLE PRECISION DP,DGAMMA
!CCCC DOUBLE PRECISION Z,Z2,Z3,Z4,Z5,DEN,A,B,C,D,G
      DOUBLE PRECISION Z,Z2,DEN,A,B,C,D
      DOUBLE PRECISION XMIN0,XMIN,AI,XMAX,DX,PCALC,XMID
      DOUBLE PRECISION XLOWER,XUPPER,XDEL
      DOUBLE PRECISION SUM,TERM,CUT1,CUT2,AJ,CUTOFF,T
      DOUBLE PRECISION DLG,DLT,DLX,DLPCAL
      DOUBLE PRECISION DLP,DLGAMM,DLXMI0
      DOUBLE PRECISION Z2INV
      DOUBLE PRECISION DEXP,DLOG
!
      DIMENSION D(10)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA C/ .918938533204672741D0/
      DATA D(1),D(2),D(3),D(4),D(5)   &
           /+.833333333333333333D-1,-.277777777777777778D-2,   &
            +.793650793650793651D-3,-.595238095238095238D-3,   &
            +.841750841750841751D-3/
      DATA D(6),D(7),D(8),D(9),D(10)   &
           /-.191752691752691753D-2,+.641025641025641025D-2,   &
            -.295506535947712418D-1,+.179644372368830573D0,   &
            -.139243221690590111D1/
!
!-----START POINT-----------------------------------------------------
!
      XMID=0.0
      XLOWER=0.0
      XUPPER=0.0
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      PPF=0.0
      IF(P.LT.0.0.OR.P.GE.1.0)THEN
        WRITE(ICOUT,1)
    1   FORMAT('***** ERROR IN CHSPPF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2)
    2   FORMAT('      THE FIRST ARGUMENT TO CHSPPF IS OUTSIDE ',   &
               'THE ALLOWABLE (0,1) INTERVAL')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,46)P
   46   FORMAT('      THE VALUE OF THE ARGUMENT IS ',G15.7)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(NU.LT.1)THEN
        WRITE(ICOUT,1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,15)
   15   FORMAT('      THE DEGREES OF FREEDOM ARGUMENT IS NON-POSITIVE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)NU
   47   FORMAT('      THE VALUE OF THE ARGUMENT IS ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     EXPRESS THE CHI-SQUARED DISTRIBUTION PERCENT POINT
!     FUNCTION IN TERMS OF THE EQUIVALENT GAMMA
!     DISTRIBUTION PERCENT POINT FUNCTION,
!     AND THEN EVALUATE THE LATTER.
!
      DP=P
      DNU=NU
      DGAMMA=DNU/2.0D0
      MAXIT=10000
!
!     COMPUTE THE GAMMA FUNCTION USING THE ALGORITHM IN THE
!     NBS APPLIED MATHEMATICS SERIES REFERENCE.
!     THIS GAMMA FUNCTION NEED BE CALCULATED ONLY ONCE.
!     IT IS USED IN THE CALCULATION OF THE CDF BASED ON
!     THE TENTATIVE VALUE OF THE PPF IN THE ITERATION.
!
      Z=DGAMMA
      DEN=1.0D0
  150 IF(Z.GE.10.0D0)GO TO 160
      DEN=DEN*Z
      Z=Z+1.0D0
      GO TO 150
  160 Z2=Z*Z
!CCCC Z3=Z*Z2
!CCCC Z4=Z2*Z2
!CCCC Z5=Z2*Z3
      A=(Z-0.5D0)*DLOG(Z)-Z+C
!CCCC B=D(1)/Z+D(2)/Z3+D(3)/Z5+D(4)/(Z2*Z5)+D(5)/(Z4*Z5)+
!CCCC1D(6)/(Z*Z5*Z5)+D(7)/(Z3*Z5*Z5)+D(8)/(Z5*Z5*Z5)+D(9)/(Z2*Z5*Z5*Z5)
      Z2INV=1.0D0/Z2
      B=D(9)
      B=Z2INV*B+D(8)
      B=Z2INV*B+D(7)
      B=Z2INV*B+D(6)
      B=Z2INV*B+D(5)
      B=Z2INV*B+D(4)
      B=Z2INV*B+D(3)
      B=Z2INV*B+D(2)
      B=Z2INV*B+D(1)
      B=(1.0D0/Z)*B
!CCCC G=DEXP(A+B)/DEN
      DLG=(A+B)-DLOG(DEN)
!
!     DETERMINE LOWER AND UPPER LIMITS ON THE DESIRED 100P
!     PERCENT POINT.
!
      ILOOP=1
!CCCC XMIN0=(DP*DGAMMA*G)**(1.0D0/DGAMMA)
      DLP=DLOG(DP)
      DLGAMM=DLOG(DGAMMA)
      DLXMI0=(1.0D0/DGAMMA)*(DLP+DLGAMM+DLG)
      XMIN0=DEXP(DLXMI0)
      XMIN=XMIN0
      ICOUNT=1
  350 AI=ICOUNT
      XMAX=AI*XMIN0
      DX=XMAX
      GO TO 1000
  360 IF(PCALC.GE.DP)GO TO 370
      XMIN=XMAX
      ICOUNT=ICOUNT+1
      IF(ICOUNT.LE.30000)GO TO 350
  370 XMID=(XMIN+XMAX)/2.0D0
!
!     NOW ITERATE BY BISECTION UNTIL THE DESIRED ACCURACY IS ACHIEVED.
!
      ILOOP=2
      XLOWER=XMIN
      XUPPER=XMAX
      ICOUNT=0
  550 DX=XMID
      GO TO 1000
  560 IF(PCALC.EQ.DP)GO TO 570
      IF(PCALC.GT.DP)GO TO 580
      XLOWER=XMID
      XMID=(XMID+XUPPER)/2.0D0
      GO TO 590
  580 XUPPER=XMID
      XMID=(XMID+XLOWER)/2.0D0
  590 XDEL=XMID-XLOWER
      IF(XDEL.LT.0.0D0)XDEL=-XDEL
      ICOUNT=ICOUNT+1
      IF(XDEL.LT.0.0000000001D0.OR.ICOUNT.GT.100)GO TO 570
      GO TO 550
  570 PPF=2.0D0*XMID
      RETURN
!
!********************************************************************
!     THIS SECTION BELOW IS LOGICALLY SEPARATE FROM THE ABOVE.
!     THIS SECTION COMPUTES A CDF VALUE FOR ANY GIVEN TENTATIVE
!     PERCENT POINT X VALUE AS DEFINED IN EITHER OF THE 2
!     ITERATION LOOPS IN THE ABOVE CODE.
!
!     COMPUTE T-SUB-Q AS DEFINED ON PAGE 4 OF THE WILK, GNANADESIKAN,
!     AND HUYETT REFERENCE
!
 1000 SUM=1.0D0/DGAMMA
      TERM=1.0D0/DGAMMA
      CUT1=DX-DGAMMA
      CUT2=DX*10000000000.0D0
      DO 700 J=1,MAXIT
      AJ=J
      TERM=DX*TERM/(DGAMMA+AJ)
      SUM=SUM+TERM
      CUTOFF=CUT1+(CUT2*TERM/SUM)
      IF(AJ.GT.CUTOFF)GO TO 750
  700 CONTINUE
      WRITE(ICOUT,705)MAXIT
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,706)P
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,707)NU
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,708)
      CALL DPWRST('XXX','BUG ')
      PPF=0.0
      RETURN
!
  750 T=SUM
      DLT=DLOG(T)
      DLX=DLOG(DX)
!CCCC WRITE(ICOUT,777)DX,DGAMMA,T,DLT,G,DLG
!C777 FORMAT('DX,DGAMMA,T,DLT,G,DLG = ',6D15.7)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC PCALC=(DX**DGAMMA)*(DEXP(-DX))*T/G
      DLPCAL=DGAMMA*DLX-DX+DLT-DLG
      PCALC=DEXP(DLPCAL)
      IF(ILOOP.EQ.1)GO TO 360
      GO TO 560
!
  705 FORMAT('*****ERROR IN INTERNAL OPERATIONS IN THE CHSPPF ',   &
      'SUBROUTINE--THE NUMBER OF ITERATIONS EXCEEDS ',I7)
  706 FORMAT(33H     THE INPUT VALUE OF P     IS ,E15.8)
  707 FORMAT(33H     THE INPUT VALUE OF NU    IS ,I8)
  708 FORMAT(48H     THE OUTPUT VALUE OF PPF HAS BEEN SET TO 0.0)
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE CHSPPF
      SUBROUTINE CHSRAN(N,ANU,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE CHI-SQUARED DISTRIBUTION
!              WITH INTEGER DEGREES OF FREEDOM PARAMETER = NU.
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --NU     = THE INTEGER DEGREES OF FREEDOM
!                                (PARAMETER) FOR THE CHI-SQUARED
!                                DISTRIBUTION.
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE CHI-SQUARED DISTRIBUTION
!             WITH DEGREES OF FREEDOM PARAMETER = NU.
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!                 --NU SHOULD BE A POSITIVE INTEGER VARIABLE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--UNIRAN.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--LOG, SQRT, SIN, COS.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     REFERENCES--TOCHER, THE ART OF SIMULATION,
!                 1963, PAGES 34-35.
!               --MOOD AND GRABLE, INTRODUCTION TO THE
!                 THEORY OF STATISTICS, 1963, PAGES 226-227.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--1, 1970, PAGE 171.
!               --HASTINGS AND PEACOCK, STATISTICAL
!                 DISTRIBUTIONS--A HANDBOOK FOR
!                 STUDENTS AND PRACTITIONERS, 1975,
!                 PAGE 48.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--FEBRUARY  1975.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MAY       2004. ALLOW REAL VALUES FOR DEGREES
!                                       OF FREEDOM PARAMETER
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION Y(2),Z(2)
!
      CHARACTER*4 ICASE
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.14159265359/
      DATA EPS/0.00001/
!
!-----START POINT-----------------------------------------------------
!
!     CHECK THE INPUT ARGUMENTS FOR ERRORS
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,47)N
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
    5 FORMAT('***** ERROR--THE REQUESTED NUMBER OF CHI-SQUARE ',   &
      'RANDOM NUMBERS IS NON-POSITIVE.')
      IF(ANU.LE.0.0)THEN
        WRITE(ICOUT,15)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,48)ANU
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
   15 FORMAT('***** ERROR--THE DEGREES OF FREEDOM PARAMETER FOR ',   &
      'CHI-SQUARE RANDOM NUMBERS IS NON-POSITIVE.')
   47 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',I8)
   48 FORMAT('***** THE VALUE OF THE ARGUMENT IS ',G15.7)
!
      NU=INT(ANU+0.1)
      ANU2=REAL(NU)
      IF(ABS(ANU-ANU2).LE.EPS)THEN
        ICASE='INTE'
        IF(NU.EQ.0)THEN
          ICASE='REAL'
          ANU=EPS
        ENDIF
      ELSE
        ICASE='REAL'
      ENDIF
!
!     CASE 1: INTEGER DEGREES OF FREEDOM
!
      IF(ICASE.EQ.'INTE')THEN
!
!       GENERATE N CHI-SQUARED RANDOM NUMBERS
!       USING THE DEFINITION THAT
!       A CHI-SQUARED VARIATE WITH NU DEGREES OF FREEDOM
!       EQUALS THE SUM OF NU SQUARED NORMAL VARIATES.
!       FIRST GENERATE 2 UNIFORM (0,1) RANDOM NUMBERS,
!       THEN GENERATE 2 NORMAL RANDOM NUMBERS,
!       THEN FORM THE SUM OF SQUARED NORMAL RANDOM NUMBERS.
!
        DO 100 I=1,N
          SUM=0.0
          DO 200 J=1,NU,2
            CALL UNIRAN(2,ISEED,Y)
            ARG1=-2.0*LOG(Y(1))
            ARG2=2.0*PI*Y(2)
            Z(1)=(SQRT(ARG1))*(COS(ARG2))
            Z(2)=(SQRT(ARG1))*(SIN(ARG2))
            SUM=SUM+Z(1)*Z(1)
            IF(J.EQ.NU)GO TO 200
            SUM=SUM+Z(2)*Z(2)
  200     CONTINUE
          X(I)=SUM
  100   CONTINUE
!
!     CASE 2: REAL DEGREES OF FREEDOM
!
!     GENERATE CHI-SQUARE RANDOM NUMBERS USING RELATIONSHIP
!     TO GAMMA DISTRIBUTION.
!
      ELSE
        GAMMA=ANU/2.0
        CALL GAMRAN(N,GAMMA,ISEED,X)
        DO 300 I=1,N
          X(I)=2.0*X(I)
  300   CONTINUE
!
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE CHSRAN
      SUBROUTINE CKARIT(IFOUNZ,IBEGIN,IANS,IWIDTH,ICASAR,   &
                        IBUGA3,ISUBRO)
!
!     PURPOSE--FOR THE LET COMMAND, DETERMINE IF AN ARITHMETIC OPERATOR
!              EXISTS ANYWHERE FROM THE BEGINNING OF THE COMMAND LINE TO
!              SUBSET/EXCEPT/FOR OR END OF LINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/1
!     ORIGINAL VERSION--JANUARY   1989.
!     UPDATED         --JULY      1989.  COMMENT OUT IERROR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFOUNZ
      CHARACTER*4 IANS
      CHARACTER*4 ICASAR
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION IFOUNZ(*)
      DIMENSION IBEGIN(*)
      DIMENSION IANS(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ARIT')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF CKARIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IFOUNZ(11),IBEGIN(11),IFOUNZ(21),IBEGIN(21)
   52   FORMAT('IFOUNZ(11),IBEGIN(11),IFOUNZ(21),IBEGIN(21) = ',   &
               2(A4,I8))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)IWIDTH
   61   FORMAT('IWIDTH = ',I8)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,62)(IANS(I),I=1,MIN(80,IWIDTH))
   62     FORMAT('IANS(.) = ',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!CCCC THE FOLLOWING LINE WAS COMMENTED OUT JULY 1989
!CCCC IERROR='NO'
      ICASAR='NO'
!
      IMAX=IWIDTH
      IF(IFOUNZ(11).EQ.'YES')IMAX=IBEGIN(11)
      IF(IFOUNZ(21).EQ.'YES')IMAX=IBEGIN(21)
!
      IF(IMAX.LE.0)GO TO 9000
      DO 1100 I=1,IMAX
        IF(IANS(I).EQ.'+')GO TO 1150
        IF(IANS(I).EQ.'-')GO TO 1150
        IF(IANS(I).EQ.'*')GO TO 1150
        IF(IANS(I).EQ.'/')GO TO 1150
 1100 CONTINUE
      ICASAR='NO'
      GO TO 9000
 1150 CONTINUE
      ICASAR='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'ARIT')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CKARIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASAR
 9012   FORMAT('ICASAR = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CKARIT
      SUBROUTINE CKCENS(TAG,XTEMP,N,IDIST,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS ROUTINE CHECKS TO SEE IF THE INPUT VARIABLE
!              IS A VALID CENSORING VARIABLE.  IT SHOULD CONTAIN
!              AT MOST 2 DISTINCT VALUES.  THESE VALUES WILL
!              BE SET TO 0 AND 1 (IF THEY ARE NOT ALREADY).
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/4
!     ORIGINAL VERSION--APRIL     2010. EXTRACTED AS A DISTINCT
!                                       SUBROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*40 IDIST
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      DIMENSION TAG(*)
      DIMENSION XTEMP(*)
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CHKC'
      ISUBN2='EN  '
      IERROR='NO'
      IWRITE='OFF'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CENS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF CKCENS--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,55)N,IDIST
   55   FORMAT('N,IDIST = ',I8,2X,A40)
        CALL DPWRST('XXX','WRIT')
        DO 56 I=1,MIN(N,100)
          WRITE(ICOUT,57)I,TAG(I)
   57     FORMAT('I,TAG(I) = ',I8,G15.7)
          CALL DPWRST('XXX','WRIT')
   56   CONTINUE
      ENDIF
!
!               ******************************************
!               **  STEP 2--                            **
!               **  CHECK CENSORING VARIABLE            **
!               ******************************************
!
      CALL DISTIN(TAG,N,IWRITE,XTEMP,NDIST,IBUGA3,IERROR)
      IF(NDIST.EQ.1)THEN
        IF(XTEMP(1).NE.0.0 .AND. XTEMP(1).NE.1.0)THEN
          DO 2102 I=1,N
            TAG(I)=1.0
 2102     CONTINUE
        ENDIF
      ELSEIF(NDIST.EQ.2)THEN
        IF(XTEMP(1).EQ.1.0 .OR. XTEMP(2).EQ.1.0)THEN
          DO 2103 I=1,N
            IF(TAG(I).NE.1.0)TAG(I)=0.0
 2103     CONTINUE
        ELSE
          ATEMP1=MIN(XTEMP(1),XTEMP(2))
          ATEMP2=MAX(XTEMP(1),XTEMP(2))
          DO 2108 I=1,N
            IF(TAG(I).EQ.ATEMP1)TAG(I)=1.0
            IF(TAG(I).EQ.ATEMP2)TAG(I)=0.0
 2108     CONTINUE
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2104)
 2104   FORMAT('***** ERROR IN CHECKING CENSORING VARIABLE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2105)
 2105   FORMAT('      FOR CENSORED DATA, THE CENSORING VARIABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2106)
 2106   FORMAT('      SHOULD CONTAIN AT MOST TWO DISTINCT VALUES.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2107)NDIST
 2107   FORMAT('      ',I8,' DISTINCT VALUES FOUND.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'CENS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF CKCENS--')
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE CKCENS
      SUBROUTINE CKDIST(Y,N,NMIN,QP,NPERC,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--FOR THE DISTRIBUTIONAL FITTING ROUTINES, THIS
!              SUBROUTINE PERFORMS THE FOLLOWING ERROR CHECKS:
!
!                 1) IS THE MINIMUM NUMBER OF OBSERVATIONS
!                    AVAILABLE?
!
!                 2) ARE ALL ELEMENTS IN THE RESPONSE VARIABLE
!                    THE SAME?
!
!                 3) ARE THE REQUESTED PERCENTILES WITHIN RANGE?
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/7
!     ORIGINAL VERSION--JULY      2010. EXTRACTED AS A SEPARATE
!                                       SUBROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION QP(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CKDI'
      ISUBN2='ST  '
!
      IERROR='NO'
      IWRITE='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'DIST')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF CKDIST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N,Y(1)
   52   FORMAT('IBUGA3,ISUBRO,N,Y(1) = ',2(A4,2X),I8,G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'DIST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LE.NMIN)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1111)
 1111   FORMAT('***** ERROR IN CKDIST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1113)NMIN
 1113   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE RESPONSE ',   &
               'VARIABLE IS LESS THAN ',I5,'.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1115)N
 1115   FORMAT('      SAMPLE SIZE = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     FOR MLE ESTIMATION, ALL RESPONSE VALUES THE SAME NOT
!     NECESSARILY AN ERROR (ESPECIALLY FOR DISCRETE DISTRIBUTIONS).
!
!CCCC HOLD=Y(1)
!CCCC DO1135I=2,N
!CCCC   IF(Y(I).NE.HOLD)GO TO 1139
!1135 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','WRIT')
!CCCC WRITE(ICOUT,1111)
!CCCC CALL DPWRST('XXX','WRIT')
!CCCC WRITE(ICOUT,1133)HOLD
!1133 FORMAT('      THE RESPONSE VARIABLE HAS ALL ELEMENTS = ',G15.7)
!CCCC CALL DPWRST('XXX','WRIT')
!CCCC IERROR='YES'
!CCCC GO TO 9000
!1139 CONTINUE
!
      IF(NPERC.GT.0)THEN
        DO 1145 I=1,NPERC
          IF(QP(I).LE.0.0 .OR. QP(I).GE.100.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1141)
 1141       FORMAT('***** WARNING IN CKDIST--')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1143)QP(I)
 1143       FORMAT('      REQUESTED PERCENTILE (',G15.7,') IS ',   &
                   'OUTSIDE THE (0,100) INTERVAL')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1144)
 1144       FORMAT('      NO PERCENTILE CONFIDENCE LIMITS WILL BE ',   &
                   'COMPUTED.')
            CALL DPWRST('XXX','WRIT')
            NPERC=0
          ENDIF
 1145   CONTINUE
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'DIST')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF CKDIST--')
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE CKDIST
      SUBROUTINE CKDIS2(Y,X,TEMP1,N,MAXGRP,NMIN,QP,NPERC,NTOT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--FOR GROUPED DATA WHERE THE DATA ARE GIVEN AS EQUI-SPACED
!              BINS, THIS SUBROUTINE PERFORMS THE FOLLOWING ERROR CHECKS:
!
!                 1) IS THE MINIMUM NUMBER OF OBSERVATIONS
!                    AVAILABLE?
!
!                 2) ARE THE BIN MID-POINTS ALL DISTINCT?
!
!                 3) ARE THE BIN MID-POINTS SORTED?
!
!                 4) FOR MAXIMUM LIKELIHOOD CASE, CHECK THAT
!                    REQUESTED PERCENTILES ARE IN AN APPROPRIATE
!                    RANGE.
!
!              ALSO RETURN "NTOT" (THE TOTAL SAMPLE SIZE).
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/8
!     ORIGINAL VERSION--AUGUST    2010. EXTRACTED AS A SEPARATE SUBROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION TEMP1(*)
      DIMENSION QP(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CKDI'
      ISUBN2='S2  '
!
      IERROR='NO'
      IWRITE='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'DIS2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF CKDIS2--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'DIS2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     CHECK THAT THERE ARE AT LEAST TWO GROUPS.
!
      IF(N.LE.1 .OR. N.GT.MAXGRP)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,146)
  146   FORMAT('***** ERROR IN CKDIS2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)
  147   FORMAT('      THE NUMBER OF GROUPS WAS LESS THAN OR EQUAL TO ',   &
               'ONE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,148)MAXGRP
  148   FORMAT('      OR GREATER THAN ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,149)N
  149   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     CHECK THAT THE BIN MID-POINTS ARE ALL DISTINCT
!
      CALL DISTIN(X,N,IWRITE,TEMP1,NDIST,IBUGA3,IERROR)
      IF(N.NE.NDIST)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,146)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,172)
  172   FORMAT('      THE CLASS VARIABLE ELEMENTS ARE NOT ALL ',   &
               'DISTINCT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     CHECK THAT THE BIN MID-POINTS ARE IN SORTED ORDER
!
      DO 183 I=1,N-1
        IF(X(I).GE.X(I+1))THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,146)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,182)I
  182     FORMAT('      ELEMENT ',I8,' OF THE BIN MID-POINTS ',   &
                 'VARIABLE IS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,185)I+1
  185     FORMAT('      LARGER THAN ELEMENT ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
  183 CONTINUE
!
!     CHECK THAT ALL FREQUENCIES ARE NON-NEGATIVE AND COMPUTE
!     TOTAL NUMBER OF OBSERVATIONS
!
      NTOT=0
      DO 193 I=1,N
        IF(Y(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,146)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,192)I
  192     FORMAT('      THE FREQUENCY FOR ELEMENT ',I8,' IS NEGATIVE.')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,195)X(I)
  195     FORMAT('      BIN MID-POINT     = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,197)Y(I)
  197     FORMAT('      FREQUENCY         = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSE
          ITEMP=INT(Y(I)+0.5)
          Y(I)=REAL(ITEMP)
          NTOT=NTOT+ITEMP
        ENDIF
  193 CONTINUE
!
      IF(NTOT.LE.NMIN)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,146)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,217)NTOT,NMIN
  217   FORMAT('      THE NUMBER OF OBSERVATIONS, (',I5,   &
               ') IS LESS THAN ',I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     FOR MAXIMUM LIKELIHOOD ROUTINES, CHECK THAT REQUESTED
!     PERCENTILES ARE WITHIN RANGE
!
      IF(NPERC.GT.0)THEN
        DO 1145 I=1,NPERC
          IF(QP(I).LE.0.0 .OR. QP(I).GE.100.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1141)
 1141       FORMAT('***** WARNING IN CKDIS2--')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1143)QP(I)
 1143       FORMAT('      REQUESTED PERCENTILE (',G15.7,') IS ',   &
                   'OUTSIDE THE (0,100) INTERVAL')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1144)
 1144       FORMAT('      NO PERCENTILE CONFIDENCE LIMITS WILL BE ',   &
                   'COMPUTED.')
            CALL DPWRST('XXX','WRIT')
            NPERC=0
          ENDIF
 1145   CONTINUE
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'DIS2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF CKDIS2--')
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE CKDIS2
      SUBROUTINE CKDIS3(Y,X1,X2,TEMP1,N,MAXGRP,NMIN,QP,NPERC,NTOT,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--FOR GROUPED DATA WHERE THE DATA ARE GIVEN WITH
!              BIN LOWER BOUNDARIES AND BIN UPPER BOUNDARIES,
!              THIS SUBROUTINE PERFORMS THE FOLLOWING ERROR CHECKS:
!
!                 1) IS THE MINIMUM NUMBER OF OBSERVATIONS
!                    AVAILABLE?
!
!                 2) ARE THE BIN BOUNDARIES ALL DISTINCT?
!
!                 3) ARE THE BIN BOUNDARIES SORTED?
!
!                 4) FOR MAXIMUM LIKELIHOOD CASE, CHECK THAT
!                    REQUESTED PERCENTILES ARE IN AN APPROPRIATE
!                    RANGE.
!
!              ALSO RETURN "NTOT" (THE TOTAL SAMPLE SIZE).
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/8
!     ORIGINAL VERSION--AUGUST    2010. EXTRACTED AS A SEPARATE SUBROUTINE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      DIMENSION Y(*)
      DIMENSION X1(*)
      DIMENSION X2(*)
      DIMENSION TEMP1(*)
      DIMENSION QP(*)
!
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='CKDI'
      ISUBN2='S3  '
!
      IERROR='NO'
      IWRITE='NO'
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'DIS3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,51)
   51   FORMAT('**** AT THE BEGINNING OF CKDIS3--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',A4,2X,A4,2X,I8)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'DIS3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     CHECK THAT THERE ARE AT LEAST TWO GROUPS.
!
      IF(N.LE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,146)
  146   FORMAT('***** ERROR IN CKDIS3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,147)
  147   FORMAT('      THE NUMBER OF GROUPS WAS LESS THAN OR EQUAL TO ',   &
               'ONE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,148)MAXGRP
  148   FORMAT('      OR GREATER THAN ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,149)N
  149   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     CHECK THAT THE BIN BOUNDARIES ARE ALL DISTINCT
!
      CALL DISTIN(X1,N,IWRITE,TEMP1,NDIST,IBUGA3,IERROR)
      IF(N.NE.NDIST)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,146)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,172)
  172   FORMAT('      THE BIN LOWER LIMITS ARE NOT ALL DISTINCT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL DISTIN(X2,N,IWRITE,TEMP1,NDIST,IBUGA3,IERROR)
      IF(N.NE.NDIST)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,146)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,177)
  177   FORMAT('      THE BIN UPPER LIMITS ARE NOT ALL DISTINCT.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     CHECK THAT LOWER LIMIT IS LESS THAN UPPER LIMIT
!
      DO 181 I=1,N
        IF(X1(I).GE.X2(I))THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,146)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,186)I
  186     FORMAT('      FOR BIN ',I8,', THE LOWER CLASS LIMIT IS ',   &
                 'GREATER THAN THE UPPER CLASS LIMIT.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,187)X1(I)
  187     FORMAT('      LOWER LIMIT   = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,188)X2(I)
  188     FORMAT('      UPPER LIMIT   = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
  181 CONTINUE
!
!     CHECK THAT BIN LIMITS ARE IN SORTED ORDER
!
      DO 191 I=1,N-1
        IF(X1(I).GE.X1(I+1))THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,146)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,192)I
  192     FORMAT('      ELEMENT ',I8,' OF THE BIN LOWER CLASS ',   &
                 'LIMITS VARIABLE IS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,193)I+1
  193     FORMAT('      LARGER THAN ELEMENT ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          IERROR='YES'
          GO TO 9000
        ENDIF
  191 CONTINUE
!
      DO 196 I=1,N-1
        IF(X2(I).GE.X2(I+1))THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,146)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,197)I
  197     FORMAT('      ELEMENT ',I8,' OF THE BIN UPPER CLASS ',   &
                 'LIMITS VARIABLE IS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,198)I+1
  198     FORMAT('      LARGER THAN ELEMENT ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          IERROR='YES'
          GO TO 9000
        ENDIF
  196 CONTINUE
!
!     CHECK THAT ALL FREQUENCIES ARE NON-NEGATIVE AND COMPUTE
!     TOTAL NUMBER OF OBSERVATIONS
!
      NTOT=0
      DO 203 I=1,N
        IF(Y(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,146)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,202)I
  202     FORMAT('      THE FREQUENCY FOR ELEMENT ',I8,' IS NEGATIVE.')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,205)X1(I)
  205     FORMAT('      BIN LOWER LIMIT   = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,206)X2(I)
  206     FORMAT('      BIN UPPER LIMIT   = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,207)Y(I)
  207     FORMAT('      FREQUENCY         = ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ELSE
          ITEMP=INT(Y(I)+0.5)
          Y(I)=REAL(ITEMP)
          NTOT=NTOT+ITEMP
        ENDIF
  203 CONTINUE
!
      IF(NTOT.LE.NMIN)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,146)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,217)NTOT,NMIN
  217   FORMAT('      THE NUMBER OF OBSERVATIONS, (',I5,   &
               ') IS LESS THAN ',I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     FOR MAXIMUM LIKELIHOOD ROUTINES, CHECK THAT REQUESTED
!     PERCENTILES ARE WITHIN RANGE
!
      IF(NPERC.GT.0)THEN
        DO 1145 I=1,NPERC
          IF(QP(I).LE.0.0 .OR. QP(I).GE.100.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1141)
 1141       FORMAT('***** WARNING IN CKDIS3--')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1143)QP(I)
 1143       FORMAT('      REQUESTED PERCENTILE (',G15.7,') IS ',   &
                   'OUTSIDE THE (0,100) INTERVAL')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,1144)
 1144       FORMAT('      NO PERCENTILE CONFIDENCE LIMITS WILL BE ',   &
                   'COMPUTED.')
            CALL DPWRST('XXX','WRIT')
            NPERC=0
          ENDIF
 1145   CONTINUE
      ENDIF
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'DIS3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9011)
 9011   FORMAT('**** AT THE END OF CKDIS3--')
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE CKDIS3
      SUBROUTINE CKCPMA(ENGUSL,ENGLSL,TARGET,IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--CHECK THE PARAMETERS NEEDED
!              FOR THE CPM STATISTIC.
                                                                                                                                  
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
