      SUBROUTINE CKFIT(ICASFI,ILOCFI,IBUGA3,IFOUND,IERROR)
!
!     PURPOSE--CHECK TO SEE THE TYPE OF FIT COMMAND
!              THAT HAS BEEN GIVEN
!              (E.G., WHAT DEGREE).
!     OUTPUT ARGUMENTS--IFOUND ('YES' OR 'NO')
!                     --IERROR ('YES' OR 'NO')
!                     --ICASFI ('FIT', '1FIT', '2FIT', '3FIT', ETC.)
!                     --ILOCFI (AN INTEGER VALUE WHICH GIVES
!                              THE ARGUMENT NUMBER (1, 2, 3, ...)
!                              OF THE WORD    FIT     .
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--AUGUST    1981.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JUNE      1987.
!     UPDATED         --JULY      2019. RECODE FOR BETTER READABILITY
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASFI
      CHARACTER*4 IBUGA3
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *************************
!               **  CHECK FOR FITTING  **
!               *************************
!
      IFOUND='NO'
      IERROR='NO'
      ICASFI='UNKN'
      ILOCFI=-99
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF CKFIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ICOM,ICOM2,NUMARG
   52   FORMAT('IBUGA3,ICOM,ICOM2,NUMARG = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMARG
          WRITE(ICOUT,56)I,IHARG(I),IHARG2(I)
   56     FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2(A4,2X))
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               *********************************
!               **  STEP 1.1--                 **
!               **  SEARCH FOR FIT             **
!               **  (WITH UNSPECIFIED DEGREE), **
!               **  OR SEARCH FOR              **
!               **  MULTILINEAR FIT            **
!               **  FIT COMMAND WITH NO PREFIX **
!               **  BUT WITH NO EQUAL SIGNS    **
!               **  AFTER                      **
!               *********************************
!
      ICASFI='    '
      ILASTC=0
!
      IF(ICOM.EQ.'FIT')THEN
        ICASFI='FIT'
        IF(NUMARG.GT.0)THEN
          DO 1110 I=1,NUMARG
            IF(IHARG(I).EQ.'=')THEN
              ICASFI='FIT'
              ILASTC=0
              GO TO 1119
            ELSEIF((IHARG(I).EQ.'SUBS'.AND.IHARG2(I).EQ.'ET  ') .OR.   &
                   (IHARG(I).EQ.'EXCE'.AND.IHARG2(I).EQ.'PT  ') .OR.   &
                   (IHARG(I).EQ.'FOR '.AND.IHARG2(I).EQ.'    '))THEN
              ICASFI='MFIT'
              ILASTC=0
              GO TO 1119
            ENDIF
 1110     CONTINUE
          ICASFI='MFIT'
          ILASTC=0
 1119     CONTINUE
        ENDIF
!
!               *********************************
!               **  STEP 1.2--                 **
!               **  SEARCH FOR ROBUST FITTING  **
!               *********************************
!
!
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'ROBU' .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='RFIT'
        ILASTC=2
!
!               *******************************************
!               **  STEP 1.20--                          **
!               **  SEARCH FOR 0-TH DEGREE    FITTING    **
!               *******************************************
!
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'0' .AND. IHARG(1).EQ.'TH' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='0FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'0TH' .OR. ICOM.EQ.'ZERO' .OR. ICOM.EQ.'0') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='0FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'0' .OR. IHARG(1).EQ.'ZERO') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='0FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1.AND.   &
            (ICOM.EQ.'CONS' .OR. ICOM.EQ.'RECT' .OR.   &
             ICOM.EQ.'FLAT') .AND. IHARG(1).EQ.'FIT')THEN
        ICASFI='0FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.21--                          **
!               **  SEARCH FOR 1-ST DEGREE    FITTING    **
!               *******************************************
!
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'1' .AND. IHARG(1).EQ.'ST' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='1FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'1ST' .OR. ICOM.EQ.'FIRS' .OR. ICOM.EQ.'1' .OR.   &
             ICOM.EQ.'ONE') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='1FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'1' .OR. IHARG(1).EQ.'ONE') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='1FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'LINE' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='1FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.22--                          **
!               **  SEARCH FOR 2-ND DEGREE    FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'2' .AND. IHARG(1).EQ.'ND' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='2FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'2ND' .OR. ICOM.EQ.'SECO' .OR. ICOM.EQ.'2' .OR.   &
             ICOM.EQ.'TWO') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='2FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'2' .OR. IHARG(1).EQ.'TWO') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='2FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'QUAD' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='2FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.23--                          **
!               **  SEARCH FOR 3-RD DEGREE    FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'3' .AND. IHARG(1).EQ.'RD' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='3FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'3RD' .OR. ICOM.EQ.'THIR' .OR. ICOM.EQ.'3' .OR.   &
             ICOM.EQ.'THRE') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='3FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'3' .OR. IHARG(1).EQ.'THRE') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='3FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'CUBI' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='3FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.24--                          **
!               **  SEARCH FOR 4-TH DEGREE    FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'4' .AND. IHARG(1).EQ.'TH' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='4FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'4TH' .OR. ICOM.EQ.'FOUR' .OR. ICOM.EQ.'4') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='4FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'4' .OR. IHARG(1).EQ.'FOUR') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='4FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'QUAR' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='4FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.25--                          **
!               **  SEARCH FOR 5-TH DEGREE    FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'5' .AND. IHARG(1).EQ.'TH' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='5FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'5TH' .OR. ICOM.EQ.'FIFT' .OR. ICOM.EQ.'5' .OR.   &
             ICOM.EQ.'FIVE') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='5FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'5' .OR. IHARG(1).EQ.'FIVE') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='5FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'QUIN' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='5FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.26--                          **
!               **  SEARCH FOR 6-TH DEGREE    FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'6' .AND. IHARG(1).EQ.'TH' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='6FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'6TH' .OR. ICOM.EQ.'SIXT' .OR. ICOM.EQ.'6' .OR.   &
             ICOM.EQ.'SIX') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='6FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'6' .OR. IHARG(1).EQ.'SIX') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='6FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'SEXT' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='6FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.27--                          **
!               **  SEARCH FOR 7-TH DEGREE    FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'7' .AND. IHARG(1).EQ.'TH' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='7FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'7TH' .OR. ICOM.EQ.'SEVE' .OR. ICOM.EQ.'7') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='7FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'7' .OR. IHARG(1).EQ.'SEVE') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='7FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'SEPT' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='7FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.28--                          **
!               **  SEARCH FOR 8-TH DEGREE    FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'8' .AND. IHARG(1).EQ.'TH' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='8FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'8TH' .OR. ICOM.EQ.'EIGH' .OR. ICOM.EQ.'8') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='8FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'8' .OR. IHARG(1).EQ.'EIGH') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='8FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'OCTI' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='8FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.29--                          **
!               **  SEARCH FOR 9-TH DEGREE    FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'9' .AND. IHARG(1).EQ.'TH' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='9FIT'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'9TH' .OR. ICOM.EQ.'NINT' .OR. ICOM.EQ.'9' .OR.   &
             ICOM.EQ.'NINE') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='9FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'9' .OR. IHARG(1).EQ.'NINT') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='9FIT'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'NONI' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='9FIT'
        ILASTC=1
!
!               *******************************************
!               **  STEP 1.20--                          **
!               **  SEARCH FOR 10-TH DEGREE   FITTING    **
!               *******************************************
!
      ELSEIF(NUMARG.GE.3 .AND. ICOM.EQ.'10' .AND. IHARG(1).EQ.'TH' .AND.   &
             IHARG(2).EQ.'DEGR' .AND. IHARG(3).EQ.'FIT')THEN
        ICASFI='10FI'
        ILASTC=3
      ELSEIF(NUMARG.GE.2 .AND.   &
            (ICOM.EQ.'10TH' .OR. ICOM.EQ.'TENT' .OR. ICOM.EQ.'10' .OR.   &
             ICOM.EQ.'TEN') .AND.   &
             IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'FIT')THEN
        ICASFI='10FI'
        ILASTC=2
      ELSEIF(NUMARG.GE.2 .AND. ICOM.EQ.'DEGR' .AND.   &
            (IHARG(1).EQ.'10' .OR. IHARG(1).EQ.'TEN') .AND.   &
             IHARG(2).EQ.'FIT')THEN
        ICASFI='10FI'
        ILASTC=2
      ELSEIF(NUMARG.GE.1 .AND. ICOM.EQ.'DEXI' .AND.   &
             IHARG(1).EQ.'FIT')THEN
        ICASFI='10FI'
        ILASTC=1
      ELSE
!
!               ********************************************
!               **  STEP 1.31--                           **
!               **  SINCE VALID COMMAND NOT FOUND, EXIT.  **
!               ********************************************
!
!
!
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      ILOCFI=ILASTC
      IFOUND='YES'
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CKFIT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,ICASFI,ILOCFI
 9012   FORMAT('IFOUND,IERROR,ICASFI,ILOCFI = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CKFIT
      SUBROUTINE CKINTE(X,EPS,ONEMEP,ONEPEP,ICINT,IX)
!
!     PURPOSE--GIVEN A FLOATING POINT VALUE X,
!          (NON-NEGATIVE)
!         DETERMINE IF IT IS WITHIN EPS OF AN INTEGER.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--83.6
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--MAY       1983.
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ICINT
      CHARACTER*4 ISIGN
      CHARACTER*4 IPATH
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'INTE')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF CKINTE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)X,EPS,ONEMEP,ONEPEP
   52 FORMAT('X,EPS,ONEMEP,ONEPEP = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,59)IBUGG4,ISUBG4,IERRG4
   59 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
      ISIGN='POS'
      IF(X.LT.0.0)ISIGN='NEG'
!
      ABSX=ABS(X)
      INTZZ=INT(ABSX)
      AINT=REAL(INTZZ)
      REM=ABSX-AINT
      ABSREM=ABS(REM)
      IF(ABSREM.LE.EPS)GO TO 1110
      IF(ONEMEP.LE.ABSREM.AND.ABSREM.LE.ONEPEP)GO TO 1120
      GO TO 1130
!
 1110 CONTINUE
      IPATH='1'
      ICINT='YES'
      IX=INT(ABSX)
      GO TO 1190
!
 1120 CONTINUE
      IPATH='2'
      ICINT='YES'
      IX=INT(ABSX)
      IX=IX+1
      GO TO 1190
!
 1130 CONTINUE
      IPATH='3'
      ICINT='NO'
      IX=INT(ABSX)
      GO TO 1190
!
 1190 CONTINUE
      IF(ISIGN.EQ.'NEG')IX=(-IX)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'INTE')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF CKINTE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)X,EPS,ONEMEP,ONEPEP
 9012 FORMAT('X,EPS,ONEMEP,ONEPEP = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)X,ABSX,INTZZ,REM,ABSREM
 9013 FORMAT('X,ABSX,INTZZ,REM,ABSREM = ',2E15.7,I8,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)EPS,ONEMEP,ONEPEP
 9014 FORMAT('EPS,ONEMEP,ONEPEP = ',3E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)IPATH,ICINT,ISIGN,IX
 9015 FORMAT('IPATH,ICINT,ISIGN,IX = ',A4,2X,A4,2X,A4,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9019)IBUGG4,ISUBG4,IERRG4
 9019 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
!CCCC DEBUG TRACE,INIT
!CCCC AT 90
!CCCC TRACE ON
      END SUBROUTINE CKINTE
