      IF(IA(IP3).EQ.'I'.AND.IA(IP4).EQ.'S'.AND.   &
         IA(IP5).EQ.'U'.AND.IA(IP6).EQ.'R'.AND.   &
         IA(IP7).EQ.'V')GO TO 7800
      IF(IA(IP3).EQ.'C'.AND.IA(IP4).EQ.'H'.AND.   &
         IA(IP5).EQ.'K')GO TO 7600
      IF(IA(IP3).EQ.'L'.AND.IA(IP4).EQ.'L'.AND.   &
         IA(IP5).EQ.'M')GO TO 7600
      IF(IA(IP3).EQ.'U'.AND.IA(IP4).EQ.'L'.AND.   &
         IA(IP5).EQ.'M')GO TO 7600
      IF(IA(IP3).EQ.'S'.AND.IA(IP4).EQ.'G'.AND.   &
         IA(IP5).EQ.'N')GO TO 7600
      GO TO 9000
!
  790 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS ADDED          APRIL    1994
!               *******************************
!               **  STEP 8--                 **
!               **  SEARCH FOR FUNCTIONS     **
!               **  STARTING WITH H--        **
!               **       HFNCDF              **
!               **       HFNPDF              **
!               **       HFNPPF              **
!               **  SEPTEMBER 1994           **
!               **       HYPCDF              **
!               **       HYPPDF              **
!               **       HYPPPF              **
!               **  MARCH     1995           **
!               **       HEAVE               **
!               **  JULY      1995           **
!               **       HERMITE             **
!               **       HERMSGN             **
!               **  OCTOBER   1995           **
!               **       HSECDF              **
!               **       HSEPDF              **
!               **       HSEPPF              **
!               **  OCTOBER   1995           **
!               **       HFCCDF              **
!               **       HFCPDF              **
!               **       HFCPPF              **
!               **  OCTOBER   1995           **
!               **       HFLCDF              **
!               **       HFLPDF              **
!               **       HFLPPF              **
!               **  MARCH     1997           **
!               **       H0                  **
!               **       H1                  **
!               **       HV                  **
!               **  AUGUST    1997           **
!               **       HYPERGEO            **
!               **  MARCH     2004           **
!               **    HERCDF, HERPDF, HERPPF **
!               **  SEPTEMBER 2004           **
!               **    HBOCDF, HBOPDF, HBOPPF **
!               **  MAY       2006           **
!               **    HBOCDF, HBOPDF, HBOPPF **
!               *******************************
!
      IF(IA(I).EQ.'H')GO TO 809
      GO TO 890
  809 CONTINUE
!
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IP5=I+5
      IP6=I+6
      IP7=I+7
      IP8=I+8
!
      IF(IA(IP1).EQ.'F'.AND.IA(IP2).EQ.'N')GO TO 810
      IF(IA(IP1).EQ.'F'.AND.IA(IP2).EQ.'C')GO TO 810
      IF(IA(IP1).EQ.'F'.AND.IA(IP2).EQ.'L')GO TO 810
      IF(IA(IP1).EQ.'E'.AND.IA(IP2).EQ.'R')GO TO 810
      IF(IA(IP1).EQ.'B'.AND.IA(IP2).EQ.'O')GO TO 810
      IF(IA(IP1).EQ.'Y'.AND.IA(IP2).EQ.'P'.AND.   &
      IA(IP3).EQ.'E'.AND.IA(IP4).EQ.'R'.AND.   &
      IA(IP5).EQ.'G'.AND.IA(IP6).EQ.'E'.AND.IA(IP7).EQ.'O')GO TO 7800
      IF(IA(IP1).EQ.'A'.AND.IA(IP2).EQ.'R'.AND.   &
      IA(IP3).EQ.'M'.AND.IA(IP4).EQ.'N'.AND.   &
      IA(IP5).EQ.'U'.AND.IA(IP6).EQ.'M'.AND.IA(IP7).EQ.'B')GO TO 7800
      IF(IA(IP1).EQ.'Y'.AND.IA(IP2).EQ.'P')GO TO 810
      IF(IA(IP1).EQ.'S'.AND.IA(IP2).EQ.'E')GO TO 810
      IF(IA(IP1).EQ.'E'.AND.IA(IP2).EQ.'A'.AND.IA(IP3).EQ.'V'.AND.   &
      IA(IP4).EQ.'E')GO TO 7500
      IF(IA(IP1).EQ.'E'.AND.IA(IP2).EQ.'R'.AND.   &
      IA(IP3).EQ.'M'.AND.IA(IP4).EQ.'I'.AND.   &
      IA(IP5).EQ.'T'.AND.IA(IP6).EQ.'E')GO TO 7700
      IF(IA(IP1).EQ.'E'.AND.IA(IP2).EQ.'R'.AND.   &
      IA(IP3).EQ.'M'.AND.IA(IP4).EQ.'S'.AND.   &
      IA(IP5).EQ.'G'.AND.IA(IP6).EQ.'N')GO TO 7700
      IF(IA(IP1).EQ.'0')GO TO 7200
      IF(IA(IP1).EQ.'1')GO TO 7200
      IF(IA(IP1).EQ.'V')GO TO 7200
      GO TO 9000
!
  810 CONTINUE
      IF(IA(IP3).EQ.'C'.AND.IA(IP4).EQ.'D'.AND.   &
         IA(IP5).EQ.'F')GO TO 7600
      IF(IA(IP3).EQ.'P'.AND.IA(IP4).EQ.'D'.AND.   &
         IA(IP5).EQ.'F')GO TO 7600
      IF(IA(IP3).EQ.'P'.AND.IA(IP4).EQ.'P'.AND.   &
         IA(IP5).EQ.'F')GO TO 7600
      GO TO 9000
!
  890 CONTINUE
!
!
!               ****************************
!               **  STEP 9--              **
!               **  SEARCH FOR FUNCTIONS  **
!               **  STARTING WITH I--     **
!               **       INTEGER          **
