!               **  NOVEMBER  2005        **
!               **       I0INT            **
!               **       I0ML0            **
!               **       I1ML1            **
!               **  MAY       2014        **
!               **       IGSURV           **
!               **       IGISURV          **
!               **       IGASURV          **
!               **       IGAISURV         **
!               **       IWESURV          **
!               **       IWEISURV         **
!               ****************************
!
      IF(IA(I).EQ.'I')GO TO 909
      GO TO 990
  909 CONTINUE
!
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IP5=I+5
      IP6=I+6
      IP7=I+7
!
!CCCC THE FOLLOWING LINE WAS ADDED MAY 1990
      IF(IA(IP1).EQ.'G'.AND.IA(IP2).EQ.'A')GO TO 920
      IF(IA(IP1).EQ.'W'.AND.IA(IP2).EQ.'E')GO TO 920
      IF(IA(IP1).EQ.'G')GO TO 910
      IF(IA(IP1).EQ.'B')GO TO 910
