      IA(IP3).EQ.'E'.AND.IA(IP4).EQ.'G'.AND.   &
      IA(IP5).EQ.'E'.AND.IA(IP6).EQ.'R')GO TO 7700
      IF(IA(IP1).EQ.'N'.AND.IA(IP2).EQ.'T')GO TO 7300
