      IA(IP3).EQ.'L'.AND.IA(IP4).EQ.'0')GO TO 7500
      IF(IA(IP1).EQ.'1'.AND.IA(IP2).EQ.'M'.AND.   &
      IA(IP3).EQ.'L'.AND.IA(IP4).EQ.'1')GO TO 7500
      GO TO 9000
