      IA(IP5).EQ.'Z')GO TO 7600
      IF(IA(IP2).EQ.'S'.AND.IA(IP3).EQ.'U'.AND.IA(IP4).EQ.'R'.AND.   &
      IA(IP5).EQ.'V')GO TO 7600
      IF(IA(IP2).EQ.'I'.AND.IA(IP3).EQ.'S'.AND.IA(IP4).EQ.'U'.AND.   &
      IA(IP5).EQ.'R'.AND.IA(IP6).EQ.'V')GO TO 7700
