!               **********************************************
!               **  STEP 70--                               **
!               **  CHECK FOR A TRAILING LEFT PARENTHESIS.  **
!               **********************************************
!
!7100 CONTINUE
!CCCC IF(IA(IP1).EQ.'(')GO TO 7110
!CCCC GO TO 9000
!7110 CONTINUE
!CCCC IFOUND='YES'
!CCCC NCLF=1
!CCCC GO TO 9000
