 7200 CONTINUE
      IF(IA(IP2).EQ.'(')GO TO 7210
      GO TO 9000
 7210 CONTINUE
      IFOUND='YES'
      NCLF=2
      GO TO 9000
!
 7300 CONTINUE
      IF(IA(IP3).EQ.'(')GO TO 7310
      GO TO 9000
 7310 CONTINUE
      IFOUND='YES'
      NCLF=3
      GO TO 9000
