      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IP5=I+5
      IP6=I+6
      IP7=I+7
!
      IF(IA(IP1).EQ.'U'.AND.IA(IP2).EQ.'L')GO TO 2420
      IF(IA(IP1).EQ.'0'.AND.IA(IP2).EQ.'I'.AND.   &
      IA(IP3).EQ.'N'.AND.IA(IP4).EQ.'T')GO TO 7500
      GO TO 9000
!
 2420 CONTINUE
      IF(IA(IP3).EQ.'C'.AND.IA(IP4).EQ.'D'.AND.IA(IP5).EQ.'F')GO TO 7600
      IF(IA(IP3).EQ.'P'.AND.IA(IP4).EQ.'D'.AND.IA(IP5).EQ.'F')GO TO 7600
      IF(IA(IP3).EQ.'P'.AND.IA(IP4).EQ.'P'.AND.IA(IP5).EQ.'F')GO TO 7600
!
 2490 CONTINUE
!
!CCCC THIS SECTION ADDED SEPTEMBER, 1997.
!               ****************************
!               **  STEP 25--             **
!               **  SEARCH FOR FUNCTIONS  **
!               **  STARTING WITH Z--     **
!               **       ZETA             **
!               ****************************
      IF(IA(I).EQ.'Z')GO TO 2509
      GO TO 2590
 2509 CONTINUE
!
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IP5=I+5
      IP6=I+6
      IP7=I+7
!
      IF(IA(IP1).EQ.'E'.AND.IA(IP2).EQ.'T'.AND.IA(IP3).EQ.'A')GO TO 7400
      IF(IA(IP1).EQ.'I'.AND.IA(IP2).EQ.'P')GO TO 2520
      IF(IA(IP1).EQ.'E'.AND.IA(IP2).EQ.'T')GO TO 2520
      GO TO 9000
 2520 CONTINUE
      IF(IA(IP3).EQ.'C'.AND.IA(IP4).EQ.'D'.AND.IA(IP5).EQ.'F')GO TO 7600
      IF(IA(IP3).EQ.'P'.AND.IA(IP4).EQ.'D'.AND.IA(IP5).EQ.'F')GO TO 7600
      IF(IA(IP3).EQ.'P'.AND.IA(IP4).EQ.'P'.AND.IA(IP5).EQ.'F')GO TO 7600
!
 2590 CONTINUE
!
!               ********************************************
!               **  STEP 30--                             **
!               **  SINCE NO LEAD CHARACTER MATCH FOUND,  **
!               **  GO TO END OF SUBROUTINE.              **
!               ********************************************
!
      GO TO 9000
!
!               **********************************************
!               **  STEP 70--                               **
!               **  CHECK FOR A TRAILING LEFT PARENTHESIS.  **
!               **********************************************
!
!7100 CONTINUE
!CCCC IF(IA(IP1).EQ.'(')GO TO 7110
!CCCC GO TO 9000
!7110 CONTINUE
!CCCC IFOUND='YES'
!CCCC NCLF=1
!CCCC GO TO 9000
!
 7200 CONTINUE
      IF(IA(IP2).EQ.'(')GO TO 7210
      GO TO 9000
 7210 CONTINUE
      IFOUND='YES'
      NCLF=2
      GO TO 9000
!
 7300 CONTINUE
      IF(IA(IP3).EQ.'(')GO TO 7310
      GO TO 9000
 7310 CONTINUE
      IFOUND='YES'
      NCLF=3
      GO TO 9000
!
 7400 CONTINUE
      IF(IA(IP4).EQ.'(')GO TO 7410
      GO TO 9000
 7410 CONTINUE
      IFOUND='YES'
      NCLF=4
      GO TO 9000
!
 7500 CONTINUE
      IF(IA(IP5).EQ.'(')GO TO 7510
      GO TO 9000
 7510 CONTINUE
      IFOUND='YES'
      NCLF=5
      GO TO 9000
!
 7600 CONTINUE
      IF(IA(IP6).EQ.'(')GO TO 7610
      GO TO 9000
 7610 CONTINUE
      IFOUND='YES'
      NCLF=6
      GO TO 9000
!
 7700 CONTINUE
      IF(IA(IP7).EQ.'(')GO TO 7710
      GO TO 9000
 7710 CONTINUE
      IFOUND='YES'
      NCLF=7
      GO TO 9000
!
 7800 CONTINUE
      IP8=I+8
      IF(IA(IP8).EQ.'(')GO TO 7810
      GO TO 9000
 7810 CONTINUE
      IFOUND='YES'
      NCLF=8
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGCK.EQ.'OFF')GO TO 9990
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9911)
 9911 FORMAT('AT THE END       OF CKLIB2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9912)IFOUND,IERROR
 9912 FORMAT('IFOUND = ',A4,'  IERROR = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9913)NCLF
 9913 FORMAT('NCLF = ',I8)
      CALL DPWRST('XXX','BUG ')
 9990 CONTINUE
!
      RETURN
      END SUBROUTINE CKLIB2
      SUBROUTINE CKLOSC(X,N,ISORSW,ICASAX,   &
      ISUBG4,IBUGG4,IERRG4)
!
!     PURPOSE--CHECK THAT ALL DATA IN X(.) ARE VALID
!              (IN THIS CASE, MEANING POSITIVE)
!              IN PREPARATION FOR A LOG SCALE TRANSFORMATION.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--88.10
!     ORIGINAL VERSION--MAY        1983.
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--SEPTEMBER 1988.
!     UPDATED         --DECEMBER  1988.  IBUGG4 FOR IBUGPL
!
!-----NON-COMMON VARIABLES (GRAPHICS)-------------------------------------------
!
      CHARACTER*4 ISORSW
      CHARACTER*4 ICASAX
!
      CHARACTER*4 ISUBG4
      CHARACTER*4 IBUGG4
      CHARACTER*4 IERRG4
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERRG4='NO'
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'LOSC')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF CKLOSC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGG4,ISUBG4,IERRG4
   52 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)ISORSW,ICASAX
   53 FORMAT('ISORSW,ICASAX = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)N
   61 FORMAT('N = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 62 I=1,N
      WRITE(ICOUT,63)I,X(I)
   63 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   62 CONTINUE
   90 CONTINUE
!
!               **************************************************
!               **  STEP 11--                                   **
!               **  CHECK THAT ALL X(.) ARE > 0                 **
!               **************************************************
!
      IF(ISORSW.EQ.'ON')GO TO 1120
      GO TO 1130
!
 1120 CONTINUE
      J=1
      IF(X(J).LE.0.0)GO TO 1150
      GO TO 9000
!
 1130 CONTINUE
      DO 1135 I=1,N
      J=I
      IF(X(J).LE.0.0)GO TO 1150
 1135 CONTINUE
      GO TO 9000
!
 1150 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN CKLOSC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      THE LOG OF A NON-POSITIVE DATA VALUE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      WAS ENCOUNTERED IN FORMING A PLOT.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)
 1154 FORMAT('      DATA MAY NOT BE ZERO OR NEGATIVE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      WHEN A LOG SCALE PLOT IS USED.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)X(J)
 1156 FORMAT('      THE VALUE = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1160)
 1160 FORMAT('      THIS VALUE CAME FROM THE ')
      CALL DPWRST('XXX','BUG ')
      IF(ICASAX.EQ.'2DHO')WRITE(ICOUT,1161)
 1161 FORMAT('      2-D HORIZONTAL AXIS VARIABLE.')
      IF(ICASAX.EQ.'2DHO')CALL DPWRST('XXX','BUG ')
      IF(ICASAX.EQ.'2DVE')WRITE(ICOUT,1162)
 1162 FORMAT('      2-D VERTICAL AXIS VARIABLE.')
      IF(ICASAX.EQ.'2DVE')CALL DPWRST('XXX','BUG ')
      IF(ICASAX.EQ.'3DH1')WRITE(ICOUT,1163)
 1163 FORMAT('      FIRST 3-D HORIZONTAL AXIS VARIABLE.')
      IF(ICASAX.EQ.'3DH1')CALL DPWRST('XXX','BUG ')
      IF(ICASAX.EQ.'3DH2')WRITE(ICOUT,1164)
 1164 FORMAT('      2ND 3-D HORIZONTAL AXIS VARIABLE.')
      IF(ICASAX.EQ.'3DH2')CALL DPWRST('XXX','BUG ')
      IF(ICASAX.EQ.'3DVE')WRITE(ICOUT,1165)
 1165 FORMAT('      3-D VERTICAL AXIS VARIABLE.')
      IF(ICASAX.EQ.'3DVE')CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1171)
 1171 FORMAT('      CORRECTIVE ACTION--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1172)
 1172 FORMAT('      CHANGE DATA OR CHANGE LIMITS.')
      CALL DPWRST('XXX','BUG ')
      IERRG4='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'LOSC')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF CKLOSC--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG4,ISUBG4,IERRG4
 9012 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',3A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)ISORSW,ICASAX
 9013 FORMAT('ISORSW,ICASAX = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9021)N,J
 9021 FORMAT('N,J = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 9022 I=1,N
      WRITE(ICOUT,9023)I,X(I)
 9023 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
 9022 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE CKLOSC
