!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUN7
      CHARACTER*4 ICASL7
      CHARACTER*4 ICASS7
      CHARACTER*4 ISTARA
      CHARACTER*4 IMSUBC
!
      CHARACTER*4 IERROR
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*8 IHTEMP
!
      CHARACTER*4  ISTADF
      CHARACTER*60 ISTANM
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
!
      IERROR='NO'
      ISUBN1='CKMA'
      ISUBN2='TH  '
!
!               *********************************************
!               **  CHECK FOR A DATA MANIPULATION SUBCASE  **
!               *********************************************
!
      IFOUN7='NO'
      ICASL7='UNKN'
      ICASS7='UNKN'
      ILOCV=-1
      ISTANR=1
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATH')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF CKMATH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,NUMARG
   52   FORMAT('IBUGA3,ISUBRO,NUMARG = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        DO 54 I=1,NUMARG
          WRITE(ICOUT,55)I,IHARG(I)
   55     FORMAT('I,IHARG(I)    = ',I8,1X,A4)
          CALL DPWRST('XXX','BUG ')
   54   CONTINUE
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  DETERMINE IF OF THIS TYPE  **
!               **  AND BRANCH ACCORDINGLY.    **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATH')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC IF(NUMARG.LE.3)GO TO 9000
      IF(NUMARG.LE.2)GO TO 9000
!
!CCCC THE FOLLOWING SECTION WERE ADDED MARCH 1992
      IF(NUMARG.GE.5.AND.   &
      IHARG(3).EQ.'SORT'.AND.IHARG2(3).EQ.'    '.AND.   &
      IHARG(4).EQ.'AND '.AND.IHARG2(4).EQ.'    '.AND.   &
      IHARG(5).EQ.'CARR'.AND.IHARG2(5).EQ.'Y   ')GO TO 1110
      IF(NUMARG.GE.4.AND.   &
      IHARG(3).EQ.'SORT'.AND.IHARG2(3).EQ.'    '.AND.   &
      IHARG(4).EQ.'CARR'.AND.IHARG2(4).EQ.'Y   ')GO TO 1120
      GO TO 1190
 1110 CONTINUE
      ISHIFT=2
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
      IBUGA3,IERROR)
      IHARG(3)='SORT'
      IHARG2(3)='C   '
      GO TO 1190
 1120 CONTINUE
      ISHIFT=1
      CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
      IBUGA3,IERROR)
      IHARG(3)='SORT'
      IHARG2(3)='C   '
      GO TO 1190
 1190 CONTINUE
