!CCCC NOTE 8/2008: CHECK FOR SOMETHING LIKE
!CCCC
!CCCC                 LET ITEMP = OUTEQMAV(3)
!CCCC
!CCCC              WHEN THE VARIABLE NAME ON THE RIGHT HAS
!CCCC              8 (OR MORE) CHARACTERS, WE NEED TO EXPLICITLY
!CCCC              CHECK FOR "(" ANYWHERE ON THE COMMAND STRING.
!CCCC NOTE 3/2012: EXPRESSIONS LIKE
!CCCC                  LET CUTOFF = SDEFFECT*12.7062
!CCCC              SHOULD NOT BE HANDLED HERE.
!
      ISTEPN='2O'
