               IUSE(I).EQ.'V')THEN
!
!              8/2008: CHECK FOR "NAME(INDEX)" SYNTAX.
!
!              3/2012: DO A MORE COMPLETE CHECK OF IANS.
!                      THE VARIABLE NAME AFTER THE "=" MUST
!                      CONTAIN THAT VARIABLE NAME AND NOTHING
!                      ELSE.  FIRST, SEARCH FOR EQUAL SIGN.
!                      THEN SEARCH FOR VARIABLE NAME.
!
!CCCC          DO77003J=1,IWIDTH
!CCCC            IF(IANS(J)(1:1).EQ.'(')GO TO 77009
!77003         CONTINUE
               DO 7703 J=1,IWIDTH
                 IF(IANS(J)(1:1).EQ.'=')THEN
                   IHTEMP=' '
                   ICNT=0
                   DO 7704 JJ=J+1,IWIDTH
                     IF(IANS(JJ).NE.' ')THEN
                       DO 7705 KK=JJ,MIN(JJ+11,IWIDTH)
                         IF(IANS(KK).EQ.' ')GO TO 7707
                         ICNT=ICNT+1
                         IF(ICNT.GT.8)GO TO 77009
                         IHTEMP(ICNT:ICNT)=IANS(KK)(1:1)
 7705                  CONTINUE
                     ENDIF
 7704              CONTINUE
 7707              CONTINUE
                   IF(IHTEMP(1:4).NE.IH(1:4) .OR.   &
                      IHTEMP(5:8).NE.IH2(1:4))GO TO 77009
                 ENDIF
 7703          CONTINUE
!
