      IF(NUMARG.GE.4.AND.   &
      IHARG(3).EQ.'MEAN'.AND.IHARG(4).EQ.'RANK')GO TO 2819
      IF(NUMARG.GE.4.AND.   &
      IHARG(3).EQ.'AVER'.AND.IHARG(4).EQ.'RANK')GO TO 2819
      IF(NUMARG.GE.4.AND.   &
      IHARG(3).EQ.'MEDI'.AND.IHARG(4).EQ.'RANK')GO TO 2821
!
