      IHARG(4).EQ.'STAC')GO TO 2824
      IF(NUMARG.GE.6.AND.   &
      IHARG(5).EQ.'REPL'.AND.IHARG(6).EQ.'STAC')GO TO 2825
      IF(NUMARG.GE.3.AND.   &
      IHARG(3).EQ.'UNST')GO TO 2826
!
!               **************************************
!               **  CHECK FOR   CROSS TABULATE      **
!               **              <STAT>              **
!               **************************************
!
!CCCC SEPTEMBER 2001: CROSS TABULATE <STAT>
!CCCC AUGUST 2002: ADD ADDITIONAL STATISTICS, ALSO SET
!CCCC ICASS7 FOR SUBSEQUENT USE IN DPMATC, DPMAT2
!CCCC MARCH 2009: USE "EXTSTA" TO PARSE.
!
!CCCC JANUARY 2013: CHECK FOR "CROSS TABULATE CUMULATIVE"
!
      ISTEPN='2P'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATH')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.5.AND.IHARG(3).EQ.'CROS'.AND.IHARG(4).EQ.'TABU'.AND.   &
         IHARG(5).EQ.'CUMU')THEN
        JMIN=6
        JMAX=MIN(NUMARG,JMIN+6)
        CALL EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,JMIN,JMAX,   &
                    ICASS7,ISTANM,ISTANR,ISTADF,ISTARA,   &
                    IFOUN7,ILOCV,ISUBRO,IBUGA3,IERROR)
!
        ICASL7='CTCU'
        IF(IFOUN7.EQ.'YES')GO TO 8020
      ENDIF
!
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'CROS'.AND.IHARG(4).EQ.'TABU')THEN
        JMIN=5
        JMAX=MIN(NUMARG,JMIN+6)
        CALL EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,JMIN,JMAX,   &
                    ICASS7,ISTANM,ISTANR,ISTADF,ISTARA,   &
                    IFOUN7,ILOCV,ISUBRO,IBUGA3,IERROR)
!
        ICASL7='CTAB'
        IF(IFOUN7.EQ.'YES')GO TO 8020
      ENDIF
!
!               **************************************
!               **  CHECK FOR   MOVING <STAT>       **
!               **************************************
!
      ISTEPN='2Q'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATH')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.3.AND.IHARG(3).EQ.'MOVI')THEN
        JMIN=4
        JMAX=MIN(NUMARG,JMIN+6)
        CALL EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,JMIN,JMAX,   &
                    ICASS7,ISTANM,ISTANR,ISTADF,ISTARA,   &
                    IFOUN7,ILOCV,ISUBRO,IBUGA3,IERROR)
!
        ICASL7='MOVI'
        IF(IFOUN7.EQ.'YES')GO TO 8020
      ENDIF
!
!               **************************************
!               **  CHECK FOR   WINDOW <STAT>       **
!               **************************************
!
      ISTEPN='2R'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATH')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.3.AND.IHARG(3).EQ.'WIND')THEN
        JMIN=4
        JMAX=MIN(NUMARG,JMIN+6)
        CALL EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,JMIN,JMAX,   &
                    ICASS7,ISTANM,ISTANR,ISTADF,ISTARA,   &
                    IFOUN7,ILOCV,ISUBRO,IBUGA3,IERROR)
!
        ICASL7='WIND'
        IF(IFOUN7.EQ.'YES')GO TO 8020
      ENDIF
!
!               **************************************
!               **  CHECK FOR   VECTOR PERCENTILE   **
!               **************************************
!
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'VECT'.AND.   &
         IHARG(4).EQ.'PERC')GO TO 2830
!
!               ********************************
!               **  IF NO MATCH, THEN RETURN  **
!               ********************************
!
      ISTEPN='2S'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATH')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFOUN7='NO'
      GO TO 9000
