      ICASL7='FNNE'
      GO TO 8008
!
 5398 CONTINUE
      ICASL7='ANNE'
      GO TO 8010
!
 5400 CONTINUE
      ICASL7='GRPS'
      GO TO 8005
!
 5402 CONTINUE
      ICASL7='RAEQ'
      GO TO 8006
!
