      GO TO 8007
!
55403 CONTINUE
      ICASL7='Y2TS'
      GO TO 8007
!
55404 CONTINUE
      ICASL7='Y2TD'
      GO TO 8007
!
55406 CONTINUE
      ICASL7='X1TS'
      GO TO 8007
!
