      GO TO 8007
!
55408 CONTINUE
      ICASL7='X2TS'
      GO TO 8007
!
55409 CONTINUE
      ICASL7='X2TD'
      GO TO 8007
!
 5408 CONTINUE
      ICASL7='XFRA'
      GO TO 8005
!
 5410 CONTINUE
      ICASL7='WSAT'
      GO TO 8007
!
 5411 CONTINUE
      ICASL7='GWSA'
      GO TO 8006
!
 5412 CONTINUE
      ICASL7='NKDM'
      GO TO 8008
!
 5414 CONTINUE
      ICASL7='EQUF'
      GO TO 8007
!
 5416 CONTINUE
      ICASL7='IQUF'
      GO TO 8007
!
 5418 CONTINUE
      ICASL7='TIQF'
      GO TO 8008
!
 5420 CONTINUE
      ICASL7='INSE'
      GO TO 8004
!
 5422 CONTINUE
      ICASL7='2WDM'
      GO TO 8008
!
!               *****************************************************
!               **  STEP 80--                                      **
!               **  DETERMINE IF THE WORD (OR COLUMN DESIGNATION)  **
!               **  AFTER THE KEY WORD (SORT, RANK, ETC.) IS A     **
!               **  VALID DATA VARIABLE OR COLUMN.                 **
!               **  DEFINE ILOCV.                                  **
!               *****************************************************
!
!8002 CONTINUE
!CCCC ILOCV=2
!CCCC GO TO 8020
!
 8003 CONTINUE
      ILOCV=3
      GO TO 8020
!
 8004 CONTINUE
      ILOCV=4
      GO TO 8020
!
 8005 CONTINUE
      ILOCV=5
      GO TO 8020
!
 8006 CONTINUE
      ILOCV=6
      GO TO 8020
!
 8007 CONTINUE
      ILOCV=7
      GO TO 8020
!CCCC JULY 1993.  FOLLOWING ADDED FOR SINGULAR VALUE DECOMPOSITION.
 8008 CONTINUE
      ILOCV=8
      GO TO 8020
!
!CCCC JUNE 1998.  FOLLOWING ADDED FOR MATRIX <ROW/COLU> <STAT>
 8009 CONTINUE
      ILOCV=9
      GO TO 8020
!
 8010 CONTINUE
      ILOCV=10
      GO TO 8020
!
!8011 CONTINUE
!CCCC ILOCV=11
!CCCC GO TO 8020
!
!8012 CONTINUE
!CCCC ILOCV=12
!CCCC GO TO 8020
!
!8013 CONTINUE
!CCCC ILOCV=13
!CCCC GO TO 8020
!
 8020 CONTINUE
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'MATH')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICASL7.EQ.'Y1TS')GO TO 8040
      IF(ICASL7.EQ.'Y1TD')GO TO 8040
      IF(ICASL7.EQ.'Y2TS')GO TO 8040
      IF(ICASL7.EQ.'Y2TD')GO TO 8040
      IF(ICASL7.EQ.'X1TS')GO TO 8040
      IF(ICASL7.EQ.'X1TD')GO TO 8040
      IF(ICASL7.EQ.'X2TS')GO TO 8040
      IF(ICASL7.EQ.'X2TD')GO TO 8040
      IF(ILOCV.GT.NUMARG)GO TO 8039
!
!     FOLLOWING ACCEPT SCALAR AS FIRST ARGUMENT
!
      IF(ICASL7.EQ.'JAIN')GO TO 8040
      IF(ICASL7.EQ.'AGCO')GO TO 8040
      IF(ICASL7.EQ.'EBLL')GO TO 8040
      IF(ICASL7.EQ.'EBUL')GO TO 8040
      IF(ICASL7.EQ.'EBCL')GO TO 8040
      IF(ICASL7.EQ.'DPCL')GO TO 8040
      IF(ICASL7.EQ.'DPTS')GO TO 8040
      IF(ICASL7.EQ.'DPLT')GO TO 8040
      IF(ICASL7.EQ.'DPUT')GO TO 8040
      IF(ICASL7.EQ.'R1TS')GO TO 8040
      IF(ICASL7.EQ.'R1LT')GO TO 8040
      IF(ICASL7.EQ.'R1UT')GO TO 8040
      IF(ICASL7.EQ.'R2TS')GO TO 8040
      IF(ICASL7.EQ.'R2LT')GO TO 8040
      IF(ICASL7.EQ.'R2UT')GO TO 8040
      IF(ICASL7.EQ.'R3TS')GO TO 8040
      IF(ICASL7.EQ.'R3LT')GO TO 8040
      IF(ICASL7.EQ.'R3UT')GO TO 8040
      IF(ICASL7.EQ.'BPSE')GO TO 8040
      IF(ICASL7.EQ.'BRAT')GO TO 8040
      IF(ICASL7.EQ.'NEXS')GO TO 8040
      IF(ICASL7.EQ.'NEXP')GO TO 8040
      IF(ICASL7.EQ.'KNSE')GO TO 8040
      IF(ICASL7.EQ.'NEXC')GO TO 8040
      IF(ICASL7.EQ.'NEPA')GO TO 8040
      IF(ICASL7.EQ.'NEXE')GO TO 8040
      IF(ICASL7.EQ.'NEYT')GO TO 8040
      IF(ICASL7.EQ.'COMB')GO TO 8040
      IF(ICASL7.EQ.'VMAT')GO TO 8040
      IF(ICASL7.EQ.'MWUF')GO TO 8040
      IF(ICASL7.EQ.'INTL')GO TO 8040
      IF(ICASL7.EQ.'PARL')GO TO 8040
      IF(ICASL7.EQ.'PERL')GO TO 8040
      IF(ICASL7.EQ.'DIGI')GO TO 8040
      IF(ICASL7.EQ.'SRNP')GO TO 8040
!
      IH=IHARG(ILOCV)
      IH2=IHARG2(ILOCV)
      DO 8030 I=1,NUMNAM
      IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.   &
        IUSE(I).EQ.'V')GO TO 8040
      IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.   &
        IUSE(I).EQ.'M')GO TO 8040
 8030 CONTINUE
 8039 CONTINUE
      IFOUN7='NO'
      ICASL7='UNKN'
      GO TO 9000
 8040 CONTINUE
      IFOUN7='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'MATH')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CKMATH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IBUGA3,ISUBRO
 9013   FORMAT('IBUGA3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IFOUN7,ICASL7,IMSUBC,ILOCV
 9014   FORMAT('IFOUN7,ICASL7,IMSUBC,ILOCV = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CKMATH
      SUBROUTINE CKPREF(ICASFI,ILOCFI,IBUGA3,IFOUND,IERROR)
!
!     PURPOSE--CHECK TO SEE THE TYPE OF PRE-FIT COMMAND
!              THAT HAS BEEN GIVEN
!              (E.G., WHAT DEGREE).
!     OUTPUT ARGUMENTS--IFOUND ('YES' OR 'NO')
!                     --IERROR ('YES' OR 'NO')
!                     --ICASFI ('FIT', '1FIT', '2FIT', '3FIT', ETC.)
!                     --ILOCFI (AN INTEGER VALUE WHICH GIVES
!                              THE ARGUMENT NUMBER (1, 2, 3, ...)
!                              OF THE WORD    FIT     .
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--AUGUST    1981.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASFI
      CHARACTER*4 IBUGA3
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               *****************************
!               **  CHECK FOR PRE-FITTING  **
!               *****************************
!
      IFOUND='NO'
      IERROR='NO'
      ICASFI='UNKN'
      ILOCFI=-99
!
      IF(IBUGA3.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF CKPREF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGA3
   52 FORMAT('IBUGA3 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NUMARG
   53 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)ICOM,ICOM2
   54 FORMAT('ICOM,ICOM2 = ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I),IHARG2(I)
   56 FORMAT('I,IHARG(I),IHARG2(I) = ',I8,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               *********************************
!               **  STEP 1.1--                 **
!               **  SEARCH FOR PRE-FIT         **
!               **  (WITH UNSPECIFIED DEGREE)  **
!               *********************************
!
      ICASFI='FIT'
!
      IF(ICOM.EQ.'PREF')GO TO 110
      IF(ICOM.EQ.'PRE ')GO TO 111
!
      DO 210 I=1,NUMARG
      I2=I
      IF(IHARG(I).EQ.'PREF'.AND.IHARG2(I).EQ.'IT  ')GO TO 219
  210 CONTINUE
      GO TO 249
  219 CONTINUE
!
      NUMARG=NUMARG+1
      I2P1=I2+1
      IF(I2P1.GT.NUMARG)GO TO 239
      DO 230 I=I2P1,NUMARG
      IREV=NUMARG-I+I2P1
      IREVM1=IREV-1
      IHARG(IREV)=IHARG(IREVM1)
      IHARG2(IREV)=IHARG2(IREVM1)
      IARGT(IREV)=IARGT(IREVM1)
      ARG(IREV)=ARG(IREVM1)
  230 CONTINUE
  239 CONTINUE
!
      IHARG(I2)='PRE '
      IHARG2(I2)='    '
      IARGT(I2)='WORD'
      IARG(I2)=-999
      ARG(I2)=-999.0
      IHARG(I2P1)='FIT '
      IHARG2(I2P1)='    '
      IARGT(I2P1)='WORD'
      IARG(I2P1)=-999
      ARG(I2P1)=-999.0
  249 CONTINUE
!
!               *********************************
!               **  STEP 1.2--                 **
!               **  SEARCH FOR ROBUST FITTING  **
!               *********************************
!
      ICASFI='RFIT'
!
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'ROBU'.AND.IHARG(2).EQ.'PRE ')GO TO 113
!
!               *******************************************
!               **  STEP 1.20--                          **
!               **  SEARCH FOR 0-TH DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='0FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'0'.AND.IHARG(1).EQ.'TH'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'0TH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'ZERO'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'0'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'0'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'ZERO'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'CONS'.AND.IHARG(1).EQ.'PRE ')GO TO 112
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'RECT'.AND.IHARG(1).EQ.'PRE ')GO TO 112
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'FLAT'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.21--                          **
!               **  SEARCH FOR 1-ST DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='1FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'1'.AND.IHARG(1).EQ.'ST'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'1ST'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'FIRS'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'1'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'ONE'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'1'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'ONE'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'LINE'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.22--                          **
!               **  SEARCH FOR 2-ND DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='2FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'2'.AND.IHARG(1).EQ.'ND'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'2ND'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'SECO'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'2'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'TWO'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'2'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'TWO'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'QUAD'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.23--                          **
!               **  SEARCH FOR 3-RD DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='3FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'3'.AND.IHARG(1).EQ.'RD'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'3RD'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'THIR'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'3'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'THRE'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'3'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'THRE'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'CUBI'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.24--                          **
!               **  SEARCH FOR 4-TH DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='4FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'4'.AND.IHARG(1).EQ.'TH'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'4TH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'FOUR'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'4'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'FOUR'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'4'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'FOUR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'QUAR'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.25--                          **
!               **  SEARCH FOR 5-TH DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='5FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'5'.AND.IHARG(1).EQ.'TH'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'5TH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'FIFT'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'5'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'FIVE'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'5'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'FIVE'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'QUIN'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.26--                          **
!               **  SEARCH FOR 6-TH DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='6FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'6'.AND.IHARG(1).EQ.'TH'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'6TH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'SIXT'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'6'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'SIX'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'6'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'SIX'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'SEXT'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.27--                          **
!               **  SEARCH FOR 7-TH DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='7FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'7'.AND.IHARG(1).EQ.'TH'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'7TH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'SEVE'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'7'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'SEVE'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'7'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'SEVE'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'SEPT'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.28--                          **
!               **  SEARCH FOR 8-TH DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='8FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'8'.AND.IHARG(1).EQ.'TH'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'8TH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'EIGH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'8'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'EIGH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'8'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'EIGH'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'OCTI'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.29--                          **
!               **  SEARCH FOR 9-TH DEGREE    FITTING     **
!               *******************************************
!
      ICASFI='9FIT'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'9'.AND.IHARG(1).EQ.'TH'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'9TH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'NINT'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'9'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'NINE'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'9'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'NINE'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'NONI'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               *******************************************
!               **  STEP 1.20--                          **
!               **  SEARCH FOR 10-TH DEGREE   FITTING     **
!               *******************************************
!
      ICASFI='10FI'
!
      IF(NUMARG.GE.3.AND.   &
      ICOM.EQ.'10'.AND.IHARG(1).EQ.'TH'.AND.IHARG(2).EQ.'DEGR'.AND.   &
      IHARG(3).EQ.'PRE ')GO TO 114
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'10TH'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'TENT'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'10'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'TEN'.AND.IHARG(1).EQ.'DEGR'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'10'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.2.AND.   &
      ICOM.EQ.'DEGR'.AND.IHARG(1).EQ.'TEN'.AND.IHARG(2).EQ.'PRE ')   &
      GO TO 113
      IF(NUMARG.GE.1.AND.   &
      ICOM.EQ.'DEXI'.AND.IHARG(1).EQ.'PRE ')GO TO 112
!
!               ********************************************
!               **  STEP 1.31--                           **
!               **  SINCE VALID COMMAND NOT FOUND, EXIT.  **
!               ********************************************
!
      ICASFI='    '
!
      IFOUND='NO'
      GO TO 9000
!
  110 CONTINUE
      ILASTC=0
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      GO TO 180
!
  111 CONTINUE
      ILASTC=1
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      GO TO 180
!
  112 CONTINUE
      ILASTC=2
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      GO TO 180
!
  113 CONTINUE
      ILASTC=3
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      GO TO 180
!
  114 CONTINUE
      ILASTC=4
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      GO TO 180
!
  180 CONTINUE
      ILOCFI=ILASTC
      IFOUND='YES'
      GO TO 190
!
  190 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF CKPREF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IFOUND,IERROR
 9012 FORMAT('IFOUND,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)ICASFI,ILOCFI
 9013 FORMAT('ICASFI,ILOCFI = ',A4,I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)NUMARG
 9016 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)ICOM,ICOM2
 9017 FORMAT('ICOM,ICOM2 = ',A4,A4)
      CALL DPWRST('XXX','BUG ')
      DO 9020 I=1,NUMARG
      WRITE(ICOUT,9021)I,IHARG(I),IHARG2(I)
 9021 FORMAT('I,IHARG(I),IHARG2(I) = ',I8,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9020 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE CKPREF
      SUBROUTINE CKPRPA(ANOPL1,ANOPL2,IBUGG3,ISUBRO,IERROR)
