!     UPDATED         --APRIL     2008.  RANDOM COMPOSITION
!     UPDATED         --APRIL     2008.  RANDOM PARTITION
!     UPDATED         --MAY       2008.  KAPPA
!     UPDATED         --MAY       2008.  PEARSON TYPE 3
!     UPDATED         --JUNE      2008.  RANDOM EQUIVALENCE RELATION
!     UPDATED         --JULY      2008.  RANDOM YOUNG TABLEAUX
!     UPDATED         --SEPTEMBER 2009.  USE "EXTDIS" TO DETERMINE
!                                        DISTRIBUTION NAME (A FEW
!                                        COMMANDS ARE HANDLED
!                                        SEPARATELY, E.G. RANDOM SUBSET)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASRA
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!
      CHARACTER*4  ISTEPN
      CHARACTER*4  ISUBN1
      CHARACTER*4  ISUBN2
      CHARACTER*60 IDIST
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!               ******************************************
!               **  CHECK FOR RANDOM NUMBER GENERATION  **
!               ******************************************
!
      IFOUND='NO'
      IERROR='NO'
      ICASRA='UNKN'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RAND')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF CKRAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,NUMARG
   52   FORMAT('IBUGA3,NUMARG = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)SHAPE1,SHAPE2,SHAPE3,SHAPE4
   53   FORMAT('SHAPE1,SHAPE2,SHAPE3,SHAPE4 = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)SHAPE5,SHAPE6,SHAPE7
   54   FORMAT('SHAPE5,SHAPE6,SHAPE7 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NUMARG
          WRITE(ICOUT,56)I,IHARG(I),IHARG2(I)
   56     FORMAT('I,IHARG(I),IHARG2(I) = ',I8,A4,2X,A4)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      IF(IHARG(3).EQ.'RAND' .AND. IHARG(4).EQ.'PART')THEN
        IF(NUMARG.LE.3)GO TO 9000
      ELSEIF(IHARG(3).EQ.'INDE' .AND. IHARG(4).EQ.'UNIF' .AND.   &
             IHARG(5).EQ.'RAND')THEN
        GO TO 9000
      ELSEIF(IHARG(3).EQ.'CORR' .AND. IHARG(4).EQ.'UNIF' .AND.   &
             IHARG(5).EQ.'RAND')THEN
        GO TO 9000
      ELSEIF(IHARG(3).EQ.'MULT' .AND. IHARG(4).EQ.'NORM' .AND.   &
             IHARG(5).EQ.'RAND')THEN
        GO TO 9000
      ELSEIF(IHARG(3).EQ.'MULT' .AND. IHARG(4).EQ.'T   ' .AND.   &
             IHARG(5).EQ.'RAND')THEN
        GO TO 9000
      ELSEIF(IHARG(3).EQ.'MULT' .AND. IHARG(4).EQ.'RAND')THEN
        GO TO 9000
      ELSEIF(IHARG(3).EQ.'WISH' .AND. IHARG(4).EQ.'RAND')THEN
        GO TO 9000
      ELSEIF(IHARG(3).EQ.'DIRC' .AND. IHARG(4).EQ.'RAND')THEN
        GO TO 9000
      ELSE
        IF(NUMARG.LE.4)GO TO 9000
      ENDIF
!
      JSTART=1
      JMAX=NUMARG-1
      DO 100 J=1,JMAX
        JP1=J+1
        JP2=J+2
        JP3=J+3
        JP4=J+4
        JP5=J+5
        IF(J.GE.4.AND.IHARG(J).EQ.'RAND'.AND.   &
           (IHARG(JP1).EQ.'NUMB' .OR. IHARG(JP1).EQ.'SAMP'))THEN
          JMIN=3
          JMAX=J-1
          GO TO 190
        ELSEIF(IHARG(J).EQ.'BOOT'.AND.IHARG(JP1).EQ.'INDE')THEN
          ICASRA='BOOT'
          ILOCNU=4
          GO TO 1190
        ELSEIF(IHARG(J).EQ.'RAND'.AND.IHARG(JP1).EQ.'INDE')THEN
          ICASRA='BOOT'
          ILOCNU=4
          GO TO 1190
        ELSEIF(IHARG(J).EQ.'RAND'.AND.IHARG(JP1).EQ.'PERM')THEN
          IF(J.GE.2 .AND. IHARG(J-1).EQ.'SAMP')GO TO 9000
          ICASRA='PERM'
          ILOCNU=4
          GO TO 1190
        ELSEIF(IHARG(J).EQ.'RAND'.AND.IHARG(JP1).EQ.'SUBS')THEN
          ICASRA='SUBS'
          ILOCNU=5
          GO TO 1190
        ELSEIF(IHARG(J).EQ.'RAND'.AND.IHARG(JP1).EQ.'COMP')THEN
          ICASRA='RANC'
          ILOCNU=5
          GO TO 1190
        ELSEIF(IHARG(J).EQ.'RAND'.AND.IHARG(JP1).EQ.'PART')THEN
          ICASRA='RANP'
          ILOCNU=5
          GO TO 1190
        ELSEIF(IHARG(J)  .EQ.'RAND' .AND. IHARG(JP1).EQ.'K   '.AND.   &
               IHARG(JP2).EQ.'SET ' .AND. IHARG(JP3).EQ.'OF  '.AND.   &
               IHARG(JP4).EQ.'N   ' .AND. IHARG(JP5).EQ.'SET ')THEN
          ICASRA='KNSE'
          ILOCNU=9
          GO TO 1190
        ELSEIF(IHARG(J).EQ.'RAND'.AND.IHARG(JP1).EQ.'EQUI'.AND.   &
           IHARG(JP2).EQ.'RELA')THEN
          ICASRA='RANE'
          ILOCNU=6
          GO TO 1190
        ELSEIF(IHARG(J).EQ.'RAND'.AND.IHARG(JP1).EQ.'YOUN'.AND.   &
           IHARG(JP2).EQ.'TABL')THEN
          ICASRA='RAYT'
          ILOCNU=6
          GO TO 1190
        ELSEIF(IHARG(J)  .EQ.'EXCL' .AND. IHARG(JP1).EQ.'ZONE'.AND.   &
               IHARG(JP2).EQ.'UNIF' .AND. IHARG(JP3).EQ.'RAND'.AND.   &
               IHARG(JP4).EQ.'NUMB')THEN
          ICASRA='UNEX'
          ILOCNU=8
          GO TO 1190
        ENDIF
!
  100 CONTINUE
      IFOUND='NO'
      GO TO 9000
  190 CONTINUE
!
!  END OF SEARCH
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RAND')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,211)JMIN,JMAX
  211   FORMAT('CKRAND: BEFORE CALL EXTDIS JMIN,JMAX=',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      CALL EXTDIS(ICOM,ICOM2,IHARG,IHARG2,NUMARG,JMIN,JMAX,   &
                  ICASRA,IDIST,NUMSHA,IFOUND,ILOCNU,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'RAND')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,251)
  251   FORMAT('***** AFTER CALL EXTDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,252)ICASRA,NUMSHA,IDIST
  252   FORMAT('ICASRA,NUMSHA,IDIST = ',A4,2X,I8,2X,A60)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO 1190
!
 1190 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'RAND')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CKRAND--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)ICASRA,ILOCNU
 9013   FORMAT('ICASRA,ILOCNU = ',A4,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CKRAND
      SUBROUTINE CKSTAT(IBUGA3,IFOUN8,ICASL8,ILOCV,ISTANR,ISTARA)
