!                                       FREQUENCY TEST CDF
!     UPDATED         --FEBRUARY  2009. FREQUENCY WITHIN A BLOCK TEST
!                                       FREQUENCY WITHIN A BLOCK TEST CDF
!     UPDATED         --MARCH     2009. FUNNEL PARSING THROUGH
!                                       EXTSTA ROUTINE
!     UPDATED         --AUGUST    2021. FOR SIZE STATISTIC, DO NOT
!                                       TREAT AS AN ERROR IF VARIABLE
!                                       NAME NOT FOUND (HAVE SIZE RETURN
!                                       A VALUE OF "0" IN THIS CASE)
!     UPDATED         --AUGUST    2023. CALL LIST TO CMPSTA
!     UPDATED         --AUGUST    2023. CALL LIST TO CKSTAT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 IFOUN8
      CHARACTER*4 ICASL8
      CHARACTER*4  ISTARA
      CHARACTER*4 IERROR
      CHARACTER*4 ISUBRO
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*60 ISTANM
      CHARACTER*4  ISTADF
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOHO.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IERROR='NO'
      ISUBRO='    '
      ISUBN1='CKST'
      ISUBN2='AT  '
      IFOUN8='NO'
      ICASL8='UNKN'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      ILOCV=-1
!
!               ***********************************
!               **  CHECK FOR A TYPE 8 LET CASE  **
!               ***********************************
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF CKSTAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,NUMARG
   52   FORMAT('IBUGA3,NUMARG = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  DETERMINE IF OF THIS TYPE  **
!               **  AND BRANCH ACCORDINGLY.    **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA3.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.3)GO TO 9000
!
      JMIN=3
      JMAX=MIN(NUMARG,JMIN+6)
      CALL EXTSTA(ICOM,ICOM2,IHARG,IHARG2,IARGT,ARG,NUMARG,JMIN,JMAX,   &
                  ICASL8,ISTANM,ISTANR,ISTADF,ISTARA,   &
                  IFOUN8,ILOCV,ISUBRO,IBUGA3,IERROR)
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,72)IFOUN8,ILOCV,NUMARG
   72   FORMAT('AFTER CALL EXTSTA: IFOUN8,ILOCV,NUMARG = ',A4,2X,2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFOUN8.EQ.'NO')GO TO 9000
!
!               *****************************************************
!               **  STEP 3--                                       **
!               **  DETERMINE IF THE WORD (OR COLUMN DESIGNATION)  **
!               **  AFTER THE KEY WORD (SORT, RANK, ETC.) IS A     **
!               **  VALID DATA VARIABLE OR COLUMN.                 **
!               *****************************************************
!
      IF(ILOCV.LE.NUMARG)THEN
        IH=IHARG(ILOCV)
        IH2=IHARG2(ILOCV)
        DO 730 I=1,NUMNAM
          IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'V')GO TO 740
          IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'M')GO TO 740
          IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'P')GO TO 740
          IF(IH.EQ.IHNAME(I).AND.IH2.EQ.IHNAM2(I).AND.   &
             IUSE(I).EQ.'F')THEN
            IFOUN8='NO'
            ICASL8='UNKN'
            GO TO 9000
          ENDIF
  730   CONTINUE
        IF(ICASL8.EQ.'NUMB')THEN
          IFOUN8='YES'
        ELSE
          IFOUN8='NO'
          ICASL8='UNKN'
        ENDIF
        GO TO 9000
      ELSE
        IFOUN8='NO'
        ICASL8='UNKN'
        GO TO 9000
      ENDIF
  740 CONTINUE
      IFOUN8='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CKSTAT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IFOUN8,ICASL8,ILOCV,NUMARG
 9014   FORMAT('IFOUN8,ICASL8,ILOCV,NUMARG = ',A4,2X,A4,2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CKSTAT
