      DOUBLE PRECISION FUNCTION CLAUSN(XVALUE)
!
! DESCRIPTION:
!
!   This program calculates Clausen's integral defined by
!
!          CLAUSN(x) = integral 0 to x of (-ln(2*sin(t/2))) dt
!
!   The code uses Chebyshev expansions with the coefficients
!   given to 20 decimal places.
!
!
! ERROR RETURNS:
!
!   If |x| is too large it is impossible to reduce the argument
!   to the range [0,2*pi] with any precision. An error message
!   is printed and the program returns the value 0.0
!
!
! MACHINE-DEPENDENT CONSTANTS:
!
!   NTERMS - INTEGER - the no. of terms of the array ACLAUS
!                      to be used. The recommended value is
!                      such that ABS(ACLAUS(NTERMS)) < EPS/100
!                      subject to 1 <= NTERMS <= 15
!
!   XSMALL - DOUBLE PRECISION - the value below which Cl(x) can be
!                   approximated by x (1-ln x). The recommended
!                   value is pi*sqrt(EPSNEG/2).
!
!   XHIGH - DOUBLE PRECISION - The value of |x| above which we cannot
!                  reliably reduce the argument to [0,2*pi].
!                  The recommended value is   1/EPS.
!
!     For values of EPS and EPSNEG refer to the file MACHCON.TXT
!
!     The machine-dependent constants are computed internally by
!     using the D1MACH subroutine.
!
!
! INTRINSIC FUNCTIONS USED:
!
!   AINT , LOG , SQRT
!
!
!   OTHER MISCFUN SUBROUTINES USED:
!
!          CHEVAL , ERRPRN, D1MACH
!
!
! AUTHOR:  Dr. Allan J. MacLeod,
!          Dept. of Mathematics and Statistics,
!          University of Paisley,
!          High St.
!          PAISLEY
!          SCOTLAND
!
!          ( e-mail: macl_ms0@paisley.ac.uk )
!
!
! LATEST MODIFICATION: 23 January, 1996
!
      INTEGER INDX,NTERMS
      DOUBLE PRECISION ACLAUS(0:15),CHEVAL,HALF,ONE,ONEHUN,PI,PISQ,T,   &
           TWOPI,TWOPIA,TWOPIB,X,XHIGH,XSMALL,XVALUE,ZERO
!CCCC CHARACTER FNNAME*6,ERRMSG*26
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!CCCC DATA FNNAME/'CLAUSN'/
!CCCC DATA ERRMSG/'ARGUMENT TOO LARGE IN SIZE'/
      DATA ZERO,HALF,ONE/0.0D0 , 0.5D0 , 1.0D0/
      DATA ONEHUN/100.0D0/
      DATA PI/3.1415926535897932385D0/
      DATA PISQ/9.8696044010893586188D0/
      DATA TWOPI/6.2831853071795864769D0/
      DATA TWOPIA,TWOPIB/6.28125D0 , 0.19353071795864769253D-2/
      DATA ACLAUS/2.14269436376668844709D0,   &
                  0.7233242812212579245D-1,   &
                  0.101642475021151164D-2,   &
                  0.3245250328531645D-4,   &
                  0.133315187571472D-5,   &
                  0.6213240591653D-7,   &
                  0.313004135337D-8,   &
                  0.16635723056D-9,   &
                  0.919659293D-11,   &
                  0.52400462D-12,   &
                  0.3058040D-13,   &
                  0.181969D-14,   &
                  0.11004D-15,   &
                  0.675D-17,   &
                  0.42D-18,   &
                  0.3D-19/
!
!  Start execution
!
      X = XVALUE
!
!   Compute the machine-dependent constants.
!
      T = D1MACH(3)
      XHIGH = ONE / T
!
!   Error test
!
      IF ( ABS(X) .GT. XHIGH ) THEN
!CCCC    CALL ERRPRN(FNNAME,ERRMSG)
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,101)
         CALL DPWRST('XXX','BUG ')
         CLAUSN = ZERO
         RETURN
      ENDIF
  999 FORMAT(1X)
  101 FORMAT('***** ERROR FROM CLAUSN--ARGUMENT TOO LARGE.  ',   &
             'ARGUMENT = ',G15.7)
!
!   Continue with machine-dependent constants
!
      XSMALL = PI * SQRT ( HALF * T )
      T = T / ONEHUN
      DO 10 NTERMS = 15 , 0 , -1
         IF ( ABS(ACLAUS(NTERMS)) .GT. T ) GO TO  19
 10   CONTINUE
!
!  Continue with computation
!
 19   INDX = 1
      IF ( X .LT. ZERO ) THEN
         X = -X
         INDX = -1
      ENDIF
!
!  Argument reduced using simulated extra precision
!
      IF ( X .GT. TWOPI ) THEN
         T = AINT( X / TWOPI )
         X =  ( X - T * TWOPIA ) - T * TWOPIB
      ENDIF
      IF ( X .GT. PI ) THEN
         X = ( TWOPIA - X ) + TWOPIB
         INDX = -INDX
      ENDIF
!
!  Set result to zero if X multiple of PI
!
      IF ( X .EQ. ZERO ) THEN
         CLAUSN = ZERO
         RETURN
      ENDIF
!
!  Code for X < XSMALL
!
      IF ( X .LT. XSMALL ) THEN
         CLAUSN = X * ( ONE - LOG( X ) )
      ELSE
!
!  Code for XSMALL < =  X < =  PI
!
         T =  ( X * X ) / PISQ - HALF
         T = T + T
         IF ( T .GT. ONE ) T = ONE
         CLAUSN = X * CHEVAL( NTERMS,ACLAUS,T ) - X * LOG( X )
      ENDIF
      IF ( INDX .LT. 0 ) CLAUSN = -CLAUSN
      RETURN
      END FUNCTION CLAUSN
      COMPLEX FUNCTION CLBETA(A,B)
!***BEGIN PROLOGUE  CLBETA
!***DATE WRITTEN   770701   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C7B
!***KEYWORDS  BETA FUNCTION,COMPLETE BETA FUNCTION,COMPLEX,LOGARITHM,
!             SPECIAL FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  CLBETA computes the natural log of the complex valued
!            complete Beta function of complex parameters A and B.
!***DESCRIPTION
!
! CLBETA computes the natural log of the complex valued complete beta
! function of complex parameters A and B.  This is a preliminary version
! which is not accurate.
!
! Input Parameters:
!       A   complex and the real part of A positive
!       B   complex and the real part of B positive
!***REFERENCES  (NONE)
!***ROUTINES CALLED  CLNGAM,XERROR
!***END PROLOGUE  CLBETA
      COMPLEX A, B, CLNGAM
!
      INCLUDE 'DPCOP2.INC'
!
!***FIRST EXECUTABLE STATEMENT  CLBETA
      IF (REAL(A).LE.0.0 .OR. REAL(B).LE.0.0) THEN
!CCCC   CALL XERROR ( 'CLBETA  REA
!CCCC1L PART OF BOTH ARGUMENTS MUST BE GT 0', 48, 1, 2)
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
      ENDIF
   11 FORMAT('***** ERROR FROM CLBETA: REAL PARTS OF PARAMETER',   &
             'MUST BE POSITIVE')
!
      CLBETA = CLNGAM(A) + CLNGAM(B) - CLNGAM(A+B)
!
      RETURN
      END FUNCTION CLBETA
      COMPLEX FUNCTION CLNGAM(ZIN)
!***BEGIN PROLOGUE  CLNGAM
!***DATE WRITTEN   780401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C7A
!***KEYWORDS  ABSOLUTE VALUE,COMPLETE GAMMA FUNCTION,COMPLEX,
!             GAMMA FUNCTION,LOGARITHM,SPECIAL FUNCTION
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  CLNGAM computes the natural log of the complex valued Gamma
!            function at ZIN, where ZIN is a complex number.
!***DESCRIPTION
!
! CLNGAM computes the natural log of the complex valued gamma function
! at ZIN, where ZIN is a complex number.  This is a preliminary version,
! which is not accurate.
!***REFERENCES  (NONE)
!***ROUTINES CALLED  C9LGMC,CARG,CLNREL,R1MACH,XERROR
!***END PROLOGUE  CLNGAM
      COMPLEX ZIN, Z, CORR, CEXP, CLOG, CLNREL, C9LGMC
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      EXTERNAL CARG
      DATA PI / 3.14159265358979324E0 /
      DATA SQ2PIL / 0.91893853320467274E0 /
      DATA BOUND, DXREL / 2*0.0 /
!***FIRST EXECUTABLE STATEMENT  CLNGAM
      IF (BOUND.NE.0.) GO TO 10
      N = INT(-0.30*LOG(R1MACH(3)))
! BOUND = N*(0.1*EPS)**(-1/(2*N-1))/(PI*EXP(1))
      BOUND = 0.1171*FLOAT(N)*(0.1*R1MACH(3))**(-1./(2.*FLOAT(N)-1.))
      DXREL = SQRT (R1MACH(4))
!
 10   Z = ZIN
      X = REAL(ZIN)
      Y = AIMAG(ZIN)
!
      CORR = (0.0, 0.0)
      CABSZ = CABS(Z)
      IF (X.GE.0.0 .AND. CABSZ.GT.BOUND) GO TO 50
      IF (X.LT.0.0 .AND. ABS(Y).GT.BOUND) GO TO 50
!
      IF (CABSZ.LT.BOUND) GO TO 20
!
! USE THE REFLECTION FORMULA FOR REAL(Z) NEGATIVE, CABS(Z) LARGE, AND
! ABS(AIMAG(Y)) SMALL.
!
      IF (Y.GT.0.0) Z = CONJG (Z)
      CORR = CEXP (-CMPLX(0.0,2.0*PI)*Z)
      IF (REAL(CORR).EQ.1.0 .AND. AIMAG(CORR).EQ.0.0) THEN
!CCCC   CALL XERROR ( 'CLN
!CCCC1GAM  Z IS A NEGATIVE INTEGER', 31, 3, 2)
        WRITE(ICOUT,11)
        CALL DPWRST('XXX','BUG ')
      ENDIF
   11 FORMAT('***** ERROR FROM CLNGAM: ARGUMENT IS A NEGATIVE ',   &
             'INTEGER')
!
      CLNGAM = SQ2PIL + 1.0 - CMPLX(0.0,PI)*(Z-0.5) - CLNREL(-CORR)   &
        + (Z-0.5)*CLOG(1.0-Z) - Z - C9LGMC(1.0-Z)
      IF (Y.GT.0.0) CLNGAM = CONJG (CLNGAM)
      RETURN
!
! USE THE RECURSION RELATION FOR CABS(Z) SMALL.
!
 20   IF (X.GE.(-0.5) .OR. ABS(Y).GT.DXREL) GO TO 30
      IF (CABS((Z-AINT(X-0.5))/X).LT.DXREL) THEN
!CCCC   CALL XERROR ( 'CLNGAM  ANSWE
!CCCC1R LT HALF PRECISION BECAUSE Z TOO NEAR NEGATIVE INTEGER', 68,1,1)
        WRITE(ICOUT,21)
        CALL DPWRST('XXX','BUG ')
      ENDIF
   21 FORMAT('***** ERROR FROM CLNGAM: ARGUMENT IS TOO NEAR A ',   &
      'NEGATIVE INTEGER')
!
   30 CONTINUE
      N = INT(SQRT (BOUND**2 - Y**2) - X + 1.0)
      ARGSUM = 0.0
      CORR = (1.0, 0.0)
      DO 40 I=1,N
        ARGSUM = ARGSUM + CARG(Z)
        CORR = Z*CORR
        Z = 1.0 + Z
 40   CONTINUE
!
      IF (REAL(CORR).EQ.0.0 .AND. AIMAG(CORR).EQ.0.0) THEN
!CCCC   CALL XERROR ( 'CLN
!CCCC1GAM  Z IS A NEGATIVE INTEGER', 31, 3, 2)
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
      ENDIF
   31 FORMAT('***** ERROR FROM CLNGAM: ARGUMENT IS A NEGATIVE ',   &
             'INTEGER')
!
      CORR = -CMPLX (LOG(CABS(CORR)), ARGSUM)
!
! USE STIRLING-S APPROXIMATION FOR LARGE Z.
!
 50   CLNGAM = SQ2PIL + (Z-0.5)*CLOG(Z) - Z + CORR + C9LGMC(Z)
      RETURN
!
      END FUNCTION CLNGAM
      COMPLEX FUNCTION CLNREL(Z)
!***BEGIN PROLOGUE  CLNREL
!***DATE WRITTEN   770401   (YYMMDD)
!***REVISION DATE  820801   (YYMMDD)
!***CATEGORY NO.  C4B
!***KEYWORDS  COMPLEX,ELEMENTARY FUNCTION,LOGARITHM,RELATIVE ERROR
!***AUTHOR  FULLERTON, W., (LANL)
!***PURPOSE  Computes the principal value of the complex natural
!            logarithm of 1+Z with relative error accuracy for small
!            CABS(Z).
!***DESCRIPTION
!
! CLNREL(Z) = CLOG(1+Z) with relative error accuracy near Z = 0.
! Let   RHO = CABS(Z)  and
!       R**2 = CABS(1+Z)**2 = (1+X)**2 + Y**2 = 1 + 2*X + RHO**2 .
! Now if RHO is small we may evaluate CLNREL(Z) accurately by
!       CLOG(1+Z) = CMPLX  (LOG(R), CARG(1+Z))
!                 = CMPLX  (0.5*LOG(R**2), CARG(1+Z))
!                 = CMPLX  (0.5*ALNREL(2*X+RHO**2), CARG(1+Z))
!***REFERENCES  (NONE)
!***ROUTINES CALLED  ALNREL,CARG,R1MACH,XERROR
!***END PROLOGUE  CLNREL
      COMPLEX Z, CLOG
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
      EXTERNAL CARG
      DATA SQEPS /0.0/
!
      CLNREL = CMPLX (0.0, 0.0)
!
!***FIRST EXECUTABLE STATEMENT  CLNREL
      IF (SQEPS.EQ.0.) SQEPS = SQRT (R1MACH(4))
!
      IF (CABS(1.+Z).LT.SQEPS) THEN
!CCCC   CALL XERROR ( 'CLNREL  ANSWER LT HALF PRE
!CCCC1CISION BECAUSE Z TOO NEAR -1', 54,    1, 1)
        WRITE(ICOUT,102)
        CALL DPWRST('XXX','BUG ')
      ENDIF
 102  FORMAT('***** INTERNAL WARNING FROM CLNREL: ANSWER IS LESS THAN'   &
      ,' HALF PRECISION BECAUSE ARGUMENT TOO NEAR -1')
!
      RHO = CABS(Z)
      IF (RHO.GT.0.375) CLNREL = CLOG (1.0+Z)
      IF (RHO.GT.0.375) RETURN
!
      X = REAL(Z)
      CLNREL = CMPLX (0.5*ALNREL(2.*X+RHO**2), CARG(1.0+Z))
!
      RETURN
      END FUNCTION CLNREL
      SUBROUTINE CMESUB(X,N,THRESH,SLOPE,R1,X2,R,NX,INDR,SDC)
!
!CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC
!  SUBROUTINE TO COMPUTE CME             C
!  (=MRL) FUNCTION :                     C
!  MAIN FORMULA:                         C
!    E[X-u | X > u] = (A + cu)/(1 - c)   C
!  INPUT ARGUMENTS:                      C
!    X  - ARRAY OF DATA (ALREADY         C
!         SORTED)                        C
!    N  - NUMBER OF POINTS IN X TO       C
!         USE                            C
!  OUTPUT ARGUMENTS:                     C
!    SLOPE  - = c/(1-c)                  C
!             (OR c = SLOPE/(1+SLOPE)    C
!    R1     - R(1) (= INTERCEPT)         C
!  NOTE THAT THE CALLING ROUTINE IS      C
!  REALLY INTERESTED IN A AND C.         C
!    C = SLOPE/(1+SLOPE)                 C
!    A = R(1)*(1 - C)                    C
!  THE CALCULATIONS FOR A AND C ARE DONE C
!  IN THE CALLING ROUTINE FROM THE       C
!  RETURNED VALUES OF SLOPE AND R(1)     C
!                                        C
!  NOTE THAT A AND C ARE THE SCALE AND   C
!  SHAPE PARAMETERS FOR THE GENERALIZED  C
!  PARETO DISTRIBUTION.                  C
!CCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCCC
!
!  MAY 2005: ADD COMPUTATION OF SD(CHAT)
!
!  SD(CHAT) = SQRT(TERM1)*SQRT(TERM2)/(TERM3*TERM4*SQRT(TERM5 - TERM6))
!
!  WHERE
!
!  TERM1 = SUM[i=1 to n-1][n-i]
!  TERM2 = SUM[i=1 to n-1][(n-i)*(y(i) - intercept - x(i)*slope))**2]
!  TERM3 = SQRT(N-3)
!  TERM4 = (1 + SLOPE)**2
!  TERM5 = SUM[i=1 to n-1][n-i]*SUM[i=1 to n-1][(n-i)**x(i)**2]
!  TERM6 = {SUM[i=1 to n-1][(n-i)*x(i)]}**2
!
!  x(i) = INPUT WIND SPEEDS
!  y(i) = R(i)
!
!  REFERENCE: GROSS, HECKERT, LECHNER, AND SIMIU (1995).  "EXTREME
!             WIND ESTIMATES BY THE CONDITIONAL MEAN EXCEEDANCE
!             PROCEDURE", NISTIT 5531.
!
!  OCTOBER 2010: IF X(N-1) = X(N), GET "NAN" IN COMPUTATION.  NEED
!                TO FIND INDEX FOR THE MAXIMUM VALUE OF X(I) THAT IS
!                LESS THAN THE MAXIMUM.
!
      REAL X(*)
      REAL X2(*)
      REAL R(*)
      REAL NX(*)
      INTEGER INDR(*)
!
      INTEGER NM1
      REAL SMALLX,RSUM,NSUM,SLOPE
!
      DOUBLE PRECISION SUMRX
      DOUBLE PRECISION SUMXSQ
      DOUBLE PRECISION SUMI
      DOUBLE PRECISION SUMX
      DOUBLE PRECISION SUMR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DTERM4
      DOUBLE PRECISION DTERM5
      DOUBLE PRECISION DTERM6
      DOUBLE PRECISION DSD
      DOUBLE PRECISION DR1
      DOUBLE PRECISION DSLOPE
      DOUBLE PRECISION DX
      DOUBLE PRECISION DY
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
      IF(ISUBG4.EQ.'ESUB')THEN
        WRITE(ICOUT,12)
   12   FORMAT('FROM THE BEGINNING OF CMESUB')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)N,THRESH
   13   FORMAT('N,THRESH = ',I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 15 I=1,N
          WRITE(ICOUT,14)I,X(I)
   14     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   15   CONTINUE
      ENDIF
!
      DTERM1=0.0D0
      DTERM2=0.0D0
      DTERM3=0.0D0
      DTERM4=0.0D0
      DTERM5=0.0D0
!
      DO 1 I=N,1,-1
        IF(X(I).NE.X(N))THEN
          NLAST=I
          GO TO 9
        ENDIF
1     CONTINUE
      SLOPE=CPUMIN
      R1=CPUMIN
      SDC=CPUMIN
      GO TO 9000
!
9     CONTINUE
!
      NM1=NLAST
!
      DO 10 I=1,N
        INDR(I)=1
10    CONTINUE
!
      DO 11 I=1,NM1
        R(I)=0.
        NX(I)=1.
11    CONTINUE
!C
      DO 50 K=1,NM1
!
        SMALLX=X(K)
!
        NSUM=0.
!
        DO 21 I=K,N
          IF(X(I).GT.SMALLX) NSUM=NSUM+1.
21      CONTINUE
!
        NX(K)=NSUM
!
        DO 22 I=1,N
          X2(I)=X(I)-SMALLX
22      CONTINUE
!
        RSUM=0.
        DO 23 I=K,N
          IF(X(I).GT.SMALLX) RSUM=RSUM+X2(I)
23      CONTINUE
!
        R(K)=RSUM
!C
50    CONTINUE
!C
      DO 60 I=1,NM1
        R(I)=R(I)/NX(I)
60    CONTINUE
!C
!CCCCCCCCCCCCCCCCCCCCCCCCCCCC
!  CME HAVING BEEN COMPUTED C
!  AT THIS POINT, IT REMAINS
!  TO COMPUTE THE TERMINAL  C
!  SLOPE.                   C
!CCCCCCCCCCCCCCCCCCCCCCCCCCCC
!C
!CCCCCCCCCCCCCCCCC
!  DOT PRODUCT   C
!  NUMERATOR &   C
!  SSQ(X) DEN-   C
!  OMINATOR.     C
!CCCCCCCCCCCCCCCCC
!
      SUMI=0.0D0
      SUMX=0.0D0
      SUMR=0.0D0
      SUMRX=0.0D0
      SUMXSQ=0.0D0
!
      DO 100 I=1,NM1
!
        SUMRX=SUMRX+DBLE(R(I))*DBLE(X(I))
        SUMXSQ=SUMXSQ+DBLE(X(I))*DBLE(X(I))
        SUMI = SUMI + 1.0D0
        SUMX = SUMX + DBLE(X(I))
        SUMR = SUMR + DBLE(R(I))
!
100   CONTINUE
!
      DSLOPE=(SUMRX - SUMR*SUMX/SUMI)/(SUMXSQ-SUMX**2/SUMI)
      SLOPE=REAL(DSLOPE)
      R1=R(1)
!
!CCCC MAY 2005.  NOW COMPUTE THE STANDARD DEVIAITION
!
      DR1=DBLE(R(1))
      DSLOPE=DBLE(SLOPE)
!
      DTERM1=0.0D0
      DTERM2=0.0D0
      DTERM3=DSQRT(DBLE(N-3))
      DTERM4=(1.0D0 + DSLOPE)**2
      DTERM6=0.0D0
!
      DO 900 I=1,NM1
!
         DY=DBLE(R(I))
         DX=DBLE(X(I))
!
         DTERM1=DTERM1 + DBLE(N-I)
         DTERM2=DTERM2 + DBLE(N-I)*(DY - DR1 - DSLOPE*DY)**2
         DTERM6=DTERM6 + DBLE(N-I)*DX
         DTERM5=DTERM5 + DBLE(N-I)*DX**2
!
  900 CONTINUE
      DTERM5=DTERM1*DTERM5
      DTERM6=DTERM6*DTERM6
!
      DSD=DSQRT(DTERM1)*DSQRT(DTERM2)/   &
          (DTERM3*DTERM4*DSQRT(DTERM5 - DTERM6))
      SDC=REAL(DSD)
!
!CCCCCCCCCCCCCCCCCCCCCCC
!  RETURN CONTROL TO   C
!  DRIVER ROUTINE      C
!CCCCCCCCCCCCCCCCCCCCCCC
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE CMESUB
      SUBROUTINE CMPDIS(Y,CENSOR,XLEVEL,N,MAXNXT,ICASPL,ICASP2,   &
                        TEMP1,TEMP2,TEMP3,   &
                        DTEMP,DTMP12,DTMP13,ITEMP1,   &
                        ZTEMP1,ZTEMP2,ZTEMP3,ZTEMP4,ZTEMP5,ZTEMP6,   &
                        ZTEMP7,ZTEMP8,ZTEMP9,ZTMP10,ZTMP11,   &
                        YLOWLM,YUPPLM,A,B,MINMAX,NUMSHA,   &
                        SHAP11,SHAP12,SHAP21,SHAP22,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,IGETDF,ICONDF,   &
                        IGOMDF,IKATDF,IGIGDF,IGEODF,IGAUDF,   &
                        IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                        MAXOBV,ICENSO,KSLOC,KSSCAL,IFORSW,ISEED,   &
                        IPPLDP,IMETHD,IPPCBW,IPPCCC,IPPCFO,   &
                        IPPCDP,IPPCAP,IPPCAO,PCHSLM,ILEVEL,   &
                        CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                        SH1,SH2,SH3,SH4,SH5,SH6,SH7,ALOC,ASCALE,STATVA,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--ESTIMATE THE PARAMETERS OF A DISTRIBUTIONS USING ONE
!              OF THE FOLLOWING METHODS:
!
!              1) MAXIMUM LIKELIHOOD
!              2) PPCC/PROBAILITY PLOT
!              3) KOLMOGOROV-SMIRNOV GOODNESS OF FIT
!              4) ANDERSON-DARLING GOODNESS OF FIT
!
!              THIS IS FOR THE RAW DATA CASE AND IS PRIMARILY
!              USED TO OBTAIN THE POINT ESTIMATES.  FOR EXAMPLE,
!              IT IS USED BY THE DISTRIBUTIONAL BOOTSTRAP (DPJBS7)
!              AND THE GOODNESS OF FIT SIMULATIONS (DPGOF2).
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2010/3
!     ORIGINAL VERSION--MARCH     2010.
!     UPDATED         --JULY      2019. CALL LIST TO DPPP2
!     UPDATED         --JULY      2019. CALL LIST TO DPPPC2
!     UPDATED         --JULY      2019. REMOVE ZTMP12, ZTMP13,ZTMP14
!                                       FROM CALL LIST
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 ICASP2
      CHARACTER*4 IFORSW
      CHARACTER*4 IHSTCW
      CHARACTER*4 IHSTOU
      CHARACTER*4 IRELAT
      CHARACTER*4 IRHSTG
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 ICENSO
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 IGAUDF
      CHARACTER*4 IEXPBC
      CHARACTER*4 ICENTY
      CHARACTER*4 IDFTTY
      CHARACTER*4 IWEIBC
      CHARACTER*4 IPPCCC
      CHARACTER*4 IPPCFO
      CHARACTER*4 IPPCAO
      CHARACTER*4 IPPCBW
      CHARACTER*4 IMETHD
      CHARACTER*4 ILEVEL
      CHARACTER*4 IERROR
      CHARACTER*4 IFLAGF
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      REAL KSLOC
      REAL KSSCAL
!
!CCCC DOUBLE PRECISION DM
!CCCC DOUBLE PRECISION DMTEMP
!CCCC DOUBLE PRECISION DTEMP1
!CCCC DOUBLE PRECISION DTEMP2
!CCCC DOUBLE PRECISION DOUT1
!CCCC DOUBLE PRECISION DN
!CCCC DOUBLE PRECISION DCURR
!CCCC DOUBLE PRECISION DCORR
!CCCC DOUBLE PRECISION DPROD
!CCCC DOUBLE PRECISION CDFGLO
!CCCC DOUBLE PRECISION CDFWAK
!CCCC DOUBLE PRECISION XPAR(5)
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION CENSOR(*)
      DIMENSION XLEVEL(*)
!
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
      DIMENSION TEMP3(*)
      DIMENSION ZTEMP1(*)
      DIMENSION ZTEMP2(*)
      DIMENSION ZTEMP3(*)
      DIMENSION ZTEMP4(*)
      DIMENSION ZTEMP5(*)
      DIMENSION ZTEMP6(*)
      DIMENSION ZTEMP7(*)
      DIMENSION ZTEMP8(*)
      DIMENSION ZTEMP9(*)
      DIMENSION ZTMP10(*)
      DIMENSION ZTMP11(*)
!
      DIMENSION CLLIMI(*)
      DIMENSION CLWIDT(*)
!
      DOUBLE PRECISION DTEMP(*)
      DOUBLE PRECISION DTMP12(*)
      DOUBLE PRECISION DTMP13(*)
      INTEGER ITEMP1(*)
!
      INTEGER IPPCAP(2)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      ISUBN1='CMPD'
      ISUBN2='IS  '
      IERROR='NO'
!
!     2012/5: FOR BRITTLE FIBER WEIBULL, THE SECOND SHAPE PARAMETER IS
!             ASSUMED TO BE A KNOWN FIXED CONSTANT.  SO SH2 WILL BE AN
!             INPUT PARAMETER.
!
      ALOC=CPUMIN
      ASCALE=CPUMIN
      SH1=CPUMIN
      IF(ICASPL.NE.'BFWE')SH2=CPUMIN
      SH3=CPUMIN
      SH4=CPUMIN
      SH5=CPUMIN
      SH6=CPUMIN
      SH7=CPUMIN
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PDIS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF CMPDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,ICASP2,IPPCBW,IFORSW,N,MINMAX
   72   FORMAT('ICASPL,ICASP2,IPPCBW,IFORSW,N,MINMAX = ',4(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,75)KSLOC,KSSCAL,NUMSHA,IPPLDP
   75   FORMAT('KSLOC,KSSCAL,NUMSHA,IPPLDP = ',2G15.7,2I8)
        CALL DPWRST('XXX','BUG ')
        IF(N.GE.1)THEN
          DO 85 I=1,N
            WRITE(ICOUT,86)I,Y(I),CENSOR(I)
   86       FORMAT('I,Y(I),CENSOR(I) = ',I8,3G15.7)
            CALL DPWRST('XXX','BUG ')
   85     CONTINUE
        ENDIF
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN ESTIMATING DISTRIBUTION PARAMETERS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 60 I=1,N
        IF(Y(I).NE.HOLD)GO TO 69
   60 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,31)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)HOLD
   62 FORMAT('      ALL ELEMENTS OF THE RESPONSE VARIABLE ARE ',   &
             'IDENTICALLY EQUAL TO ',G15.7)
                                                                                                                                  
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
   69 CONTINUE
!
!               ****************************************************
!               **  STEP 2--                                      **
!               **  GENERATE THE OUTPUT FOR THE DESIRED STATISTIC **
!               **  TO DETERMINE P-VALUES/CONFIDENCE INTERVALS    **
!               **  FOR THE STATISTIC.                            **
!               ****************************************************
!
      IF(ICASP2.EQ.'MLE')THEN
!
!       MAXIMUM LIKELIHOOD FOR RAW (UNBINNED) DATA
!
!       THE NUMSHA PARAMETER WAS BEING OVERWRITTEN ON MY LINUX
!       PLATFORM.  DON'T KNOW IF THIS IS A COMPILER BUG OR A
!       MEMORY OVERWRITE ISSUE.  IN ANY EVENT, SAVING AND RESTORING
!       THIS VALUE SEEMS TO BE A WORKAROUND.
!
        NUMSHZ=NUMSHA
        IFLAGD=0
        CALL DPML1(Y,CENSOR,N,ICASPL,IFLAGD,IFLAG9,   &
                   TEMP1,TEMP2,TEMP3,ZTEMP1,ZTEMP2,ZTEMP3,   &
                   DTEMP,DTMP12,DTMP13,ITEMP1,MAXOBV,   &
                   ALOC,ASCALE,ALOWLI,AUPPLI,   &
                   SH1,SH2,SH3,SH4,   &
                   SH5,SH6,SH7,   &
                   YLOWLM,YUPPLM,A,B,MINMAX,ISEED,   &
                   IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                   ILGADF,ISKNDF,IGLDDF,IGOMDF,IGIGDF,   &
                   IGEODF,IBGEDF,IGAUDF,   &
                   ICENSO,IEXPBC,IWEIBC,ICENTY,IDFTTY,   &
                   CLLIMI,CLWIDT,IHSTCW,IHSTOU,IRELAT,IRHSTG,   &
                   IBUGA3,ISUBRO,IERROR)
        NUMSHA=NUMSHZ
!
!       GOODNESS OF FIT FOR RAW (UNBINNED) CASE.  CURRENTLY
!       PPCC, KOLMOGOROV-SMIRNOV, AND ANDERSON DARLING SUPPORTED,
!       BUT ADDITIONAL GOODNESS OF FIT MAY BE ADDED LATER.
!
      ELSEIF(ICASP2.EQ.'PPCC' .OR. ICASP2.EQ.'KS' .OR.   &
              ICASP2.EQ.'AD')THEN
        NCURVE=1
        IFLAGF='OFF'
        PPLOC=0.0
        PPSCAL=1.0
        NHIGH=0
        NJUNK1=0
        NJUNK2=0
        IF(NUMSHA.EQ.0)THEN
          CALL DPPP2(Y,CENSOR,XLEVEL,N,ICASPL,NHIGH,   &
                     ZTEMP1,ZTEMP2,ZTEMP3,   &
                     YLOWLM,YUPPLM,A,B,MINMAX,   &
                     SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                     SHAPE5,SHAPE6,SHAPE7,   &
                     IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                     ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                     IGETDF,ICONDF,IGOMDF,IKATDF,   &
                     IGIGDF,IGEODF,   &
                     IPPLDP,MAXOBV,ICENSO,IMETHD,ILEVEL,   &
                     PPLOC,PPSCAL,   &
                     PPA0,PPA1,PPCC,SDPPA0,SDPPA1,XRESSD,XRESDF,   &
                     CCALBE,PPA0BW,PPA1BW,   &
                     ZTEMP4,ZTEMP5,   &
                     TEMP1,TEMP2,TEMP3,NJUNK1,NJUNK2,NCURVE,   &
                     IBUGA3,ISUBRO,IERROR)
          IF(IPPCBW.EQ.'BIWE')THEN
            ALOC=PPA0BW
            ASCALE=PPA1BW
          ELSE
            ALOC=PPA0
            ASCALE=PPA1
          ENDIF
          STATVA=PPCC
        ELSEIF(NUMSHA.EQ.1 .OR. NUMSHA.EQ.2)THEN
          IF(KSLOC.EQ.CPUMIN .OR. KSSCAL.EQ.CPUMIN)THEN
            PPLOC=CPUMIN
            PPSCAL=CPUMIN
          ELSE
            PPLOC=KSLOC
            PPSCAL=KSSCAL
          ENDIF
          IF(ICASPL.EQ.'BFWE')SHAPE2=SH2
          CALL DPPPC2(Y,CENSOR,XLEVEL,N,MAXNXT,   &
                      ICASP2,ICASPL,   &
                      SHAP11,SHAP12,SHAP21,SHAP22,   &
                      SHAPE1,SHAPE2,SHAPE3,SHAPE4,SHAPE5,   &
                      YLOWLM,YUPPLM,A,B,MINMAX,   &
                      TEMP1(1),TEMP1(20001),TEMP1(40001),   &
                      TEMP1(60001),NUMSHA,   &
                      ZTEMP1,ZTEMP2,ZTEMP3,ZTEMP4,TEMP1(80001),   &
                      ZTEMP5,ZTEMP6,ZTEMP7,ZTEMP8,ZTEMP9,IPPCBW,   &
                      IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                      ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                      IGETDF,ICONDF,IGOMDF,IKATDF,   &
                      IGIGDF,IGEODF,   &
                      IPPCCC,IPPCFO,IPPLDP,PPLOC,PPSCAL,   &
                      IPPCDP,IPPCAP,IPPCAO,IMETHD,ICENSO,   &
                      IFLAGF,NCURVE,   &
                      PCHSLM,ILEVEL,   &
                      ZTMP10,ZTMP11,TEMP2,TEMP3,NJUNK1,NJUNK2,   &
                      PPCCMX,SHA1MX,SHA2MX,A0SAVE,A1SAVE,A0BWSV,A1BWSV,   &
                      IBUGA3,ISUBRO,IERROR)
          SH1=SHA1MX
          SH2=SHA2MX
          STATVA=PPCCMX
          ALOC=A0SAVE
          ASCALE=A1SAVE
          IF(IPPCBW.EQ.'BIWE')THEN
            ALOC=A0BWSV
            ASCALE=A1BWSV
          ENDIF
          IF(KSLOC.NE.CPUMIN .AND. KSSCAL.NE.CPUMIN)THEN
            ALOC=KSLOC
            ASCALE=KSSCAL
          ENDIF
        ENDIF
      ELSE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8011)
 8011   FORMAT('      THE REQUESTED FITTING METHOD IS NOT SUPPORTED.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8013)ICASP2
 8013   FORMAT('      FITTING METHOD: ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'PDIS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CMPDIS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N,NUMSHA,SHAP11,SHAP12
 9013   FORMAT('N,NUMSHA,SHAP11,SHAP12 = ',2I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)ALOC,ASCALE,SH1,SH2,STATVA
 9015   FORMAT('ALOC,ASCALE,SH1,SH2,STATVA = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CMPDIS
      SUBROUTINE CMPLMT (WPRIME, KPRIME, SUM)
!
!        ALGORITHM AS 304.5 APPL.STATIST. (1996), VOL.45, NO.3
!
!        Reverse and complement the data in WPRIME
!
!        DATAPLOT NOTE: UTILITY ROUTINE USED BY FISHER TWO SAMPLE
!                       RANDOMIZATION TEST
!
      INTEGER KPRIME
      REAL WPRIME(*), SUM
!
      INTEGER I, J
      REAL TEMP
!
      J = KPRIME
      DO 10 I = 1, KPRIME / 2 + MOD(KPRIME, 2)
         TEMP = WPRIME(I)
         WPRIME(I) = REAL(DBLE(SUM) - DBLE(WPRIME(J)))
         WPRIME(J) = REAL(DBLE(SUM) - DBLE(TEMP))
         J = J - 1
   10 CONTINUE
!
      RETURN
      END SUBROUTINE CMPLMT 
      SUBROUTINE CMPSTA(TEMP,TEMPZ,TEMPZ3,XTEMP1,XTEMP2,XTEMP3,   &
                        XTEMP4,XTEMP5,   &
                        MAXNXT,NS2,NSZ,NSZ3,NUMV2,ICASPL,ISTARA,   &
                        ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        RIGHT,   &
                        ISUBRO,IBUGG3,IERROR)
!
!     PURPOSE--COMPUTE THE VALUE OF ONE OF 100+ STATISTICS.  THIS
!              IS A COMMON ROUTINE CALLED BY:
!                1) CKSTAT  = LET A = <STAT>
!                2) DPSP    = <STAT> STATISTIC PLOT
!                3) DPMOSP  = <STAT> CUMULATIVE STATISTIC PLOT
!                4) DPMOSP  = <STAT> MOVING STATISTIC PLOT
!                5) DPMOSP  = <STAT> WINDOW STATISTIC PLOT
!                6) DPCRPL  = CROSS TABULATE <STAT> PLOT
!                7) DPFLUC  = FLUCTUATION PLOT <STAT>
!                8) DPTAPL  = TABULATION PLOT <STAT>
!                9) DPBLOC  = <STAT> BLOCK PLOT
!               10) DPJBSP  = BOOTSTRAP <STAT> PLOT
!               11) DPJBSP  = JACKNIFE <STAT> PLOT
!               12) DPDEXP  = DEX <STAT> PLOT
!               13) DPDEXP  = DEX <STAT> EFFECTS PLOT
!               14) DPDEXP  = DEX <STAT> ABSOLUTE EFFECTS PLOT
!               15) DPDEXP  = DEX <STAT> PARETO PLOT
!               16) DPDEXP  = DEX <STAT> PARETO EFFECTS PLOT
!               17) DPDEXP  = DEX <STAT> PARETO ABSOLUTE EFFECTS PLOT
!               18) DPDEXP  = DEX <STAT> YOUDEN PLOT
!               19) DPISP   = <STAT> INTERACTION PLOT
!               20) DPDEXP  = CLASSIFICATION <STAT> PLOT
!               21) DPINCU  = <STAT> INFLUENCE CURVE
!               22) DPCRTA  = CROSS TABULATE <STAT>
!               23) DPPOTA  = POSITIONAL TABULATION <STAT>
!               24) DPPTES  = TWO SAMPLE <STAT> PERMUTATION TEST
!               25) DPPTES  = K SAMPLE <STAT> PERMUTATION TEST
!               26) CKMATH  = MATRIX COLUMN <STAT>
!               27) CKMATH  = MATRIX ROW <STAT>
!               28) CKMATH  = MATRIX GRAND <STAT>
!               29) CKMATH  = MATRIX PARTITION <STAT>
!               30) CKMATH  = GENERATE MATRIX <STAT>
!               31) CKMATH  = LET V = CROSS TABULATE <STAT>
!               32) CKMATH  = LET V = CROSS TABULATE CUMULATIVE <STAT>
!               33) CKMATH  = LET V = SORT BY <STAT>
!               34) CKMATH  = LET V = MOVING <STAT>
!               35) CKMATH  = LET V = CUMULATIVE <STAT>
!               36) CKMATH  = LET V = WINDOW <STAT>
!
!              NOTE THAT THE DEX ... PLOT, ... BLOCK PLOT, AND
!              ... INFLUENCE CURVE, MATRIX <COLUMN/ROW> ONLY SUPPORT
!              STATISTICS COMPUTED FROM A SINGLE RESPONSE VARIABLE.
!              ALSO, SOME COMMANDS MAY NOT SUPPORT ALL STATISTICS IN
!              THIS LIST (OR, LESS FREQUENTLY, A COMMAND MAY SUPPORT
!              SOME ADDITIONAL STATISTICS NOT COMPUTED HERE).
!
!              USING A COMMON ROUTINE MAKES IT EASIER TO ADD
!              A STATISTIC AND INCORPORATE IT INTO ALL THE
!              RELEVANT PLOTS/TABULATIONS.  SHOULD ALSO REDUCE
!              THE LIKELIHOOD OF BUGS, ETC.
!
!              FOLLOWING STATISTICS ARE SUPPORTED:
!
!              CASE 1: ONE RESPONSE VARIABLE
!
!              LOCATION STATISTICS:  (21)
!                 BIWEIGHT LOCATION
!                 GEOMETRIC MEAN
!                 H10 LOCATION
!                 H12 LOCATION
!                 H15 LOCATION
!                 H17 LOCATION
!                 H20 LOCATION
!                 HARMONIC MEAN
!                 HODGES-LEHMAN
!                 JSCORE
!                 LP LOCATION
!                 MEAN (OR AVERAGE)
!                 MEDIAN
!                 MIDHINGE
!                 MIDMEAN
!                 MIDRANGE
!                 SHANNON ENTROPY
!                 SHANNON ENTROPY MEAN
!                 SHORTEST HALF MIDMEAN
!                 SHORTEST HALF MIDRANGE
!                 STANDARD DEVIATION OF LP LOCATION
!                 STANDARD DEVIATION OF THE MEAN
!                 TRIMEAN
!                 TRIMMED MEAN
!                 TRIMMED MEAN STANDARD ERROR
!                 VARIANCE OF THE MEAN
!                 VARIANCE OF LP LOCATION
!                 WINSORIZED MEAN
!
!              SCALE STATISTICS: (32)
!                 AVERAGE ABSOLUTE DEVIATION (AAD)
!                 AVERAGE ABSOLUTE DEVIATION FROM THE MEDIAN
!                 BIWEIGHT MIDVARIANCE
!                 BIWEIGHT SCALE
!                 COEFFICIENT OF DISPERSION
!                 COEFFICIENT OF INTERQUARTILE DEVIATION
!                 COEFFICIENT OF VARIATION
!                 GEOMETRIC STANDARD DEVIATION
!                 GINI MEAN DIFFERENCE
!                 H10 SCALE
!                 H12 SCALE
!                 H15 SCALE
!                 H17 SCALE
!                 H20 SCALE
!                 INDEX OF DISPERSION
!                 INTERQUARTILE DEVIATION
!                 INTERQUARTILE RANGE
!                 LOGNORMAL COEFFICIENT OF VARIATION
!                 LOWER SEMI-INTERQUARTILE RANGE
!                 MAD TO MEDIAN
!                 MEDIAN ABSOLUTE DEVIATION (MAD)
!                 NORMALIZED INTERQUARTILE RANGE
!                 PERCENTAGE BEND MIDVARIANCE
!                 PRECISION
!                 QN
!                 Q QUANTILE RANGE
!                 QUARTILE COEFFICIENT OF DISPERSION
!                 RANGE
!                 RELATIVE LABORATORY PERFORMANCE (RLP)
!                 RELATIVE SD
!                 RELATIVE VARIANCE
!                 RESCALED SUM
!                 ROBUST POOLED RANGE
!                 ROBUST POOLED STANDARD DEVIATION
!                 ROOT MEAN SQUARE ERROR (OR RMS)
!                 SCALED MEDIAN ABSOLUTE DEVIATION (MADe)
!                 SHANNON ENTROPY STANDARD DEVIATION
!                 SHANNON ENTROPY VARIANCE
!                 SIGNAL TO NOISE RATIO
!                 SN
!                 STANDARD DEVIATION (OR SD)
!                 SUM OF SQUARES
!                 SUM OF SQUARES FROM MEAN
!                 TRIMMED SD
!                 UNBIASED COEFFICIENT OF VARIATION
!                 UPPER SEMI-INTERQUARTILE RANGE
!                 VARIANCE
!                 WINSORIZED STANDARD DEVIATION
!                 WINSORIZED VARIANCE
!
!              PERCENTILE STATISTICS (15)
!                 FIRST/SECOND/THIRD/FOURTH/FIFTH/SIXTH/SEVENTH/
!                 EIGHTH/NINTH DECILE
!                 DECILE RATIO
!                 EXTREME
!                 INDEX MINIMUM
!                 INDEX MAXIMUM
!                 INDEX EXTREME
!                 LOWER HINGE
!                 LOWER QUARTILE
!                 MINIMUM (MIN)
!                 MAXIMUM (MAX)
!                 <VALUE> PERCENTILE
!                 QUANTILE STANDARD ERROR
!                 UPPER HINGE
!                 UPPER QUARTILE
!
!              HIGHER MOMENTS (2)
!                 GALTON SKEWNESS
!                 KURTOSIS
!                 PEARSON TWO SKEWNESS
!                 SKEWNESS
!
!              TIME SERIES STATISTICS (4)
!                 AUTOCORRELATION
!                 AUTOCOVARIANCE
!                 SINE FREQUENCY
!                 SINE AMPLITUDE
!
!              QUALITY CONTROL STATISTICS (15)
!                 CC
!                 CNP
!                 CNPK
!                 CNPM
!                 CNPMK
!                 CP
!                 CPK
!                 CPL
!                 CPM
!                 CPMK
!                 CPU
!                 EXPECTED LOSS
!                 (ACTUAL) PERCENT DEFECTIVE
!                 (THEORETICAL) PERCENT DEFECTIVE
!                 (ACTUAL) PERCENT ACCEPTABLE
!                 (THEORETICAL) PERCENT ACCEPTABLE
!                 TAGUCHI SIGNAL-TO-NOISE (SN+, SN-, SN0, SN00)
!
!              STATISTICAL TESTS:
!                 A BASIS NORMAL
!                 A BASIS LOGNORMAL
!                 A BASIS WEIBULL
!                 A BASIS NONPARAMETRIC
!                 B BASIS NORMAL
!                 B BASIS LOGNORMAL
!                 B BASIS WEIBULL
!                 B BASIS NONPARAMETRIC
!                 ADJACENCY RANDOMNESS TEST   (SYNONM FOR MEAN
!                                             SUCCESSIVE DIFFERENCES)
!                 ADJACENCY RANDOMNESS TEST CDF
!                 ADJACENCY RANDOMNESS TEST PVALUE
!                 ADJACENCY RANDOMNESS TEST CV01
!                 ADJACENCY RANDOMNESS TEST CV05
!                 ADJACENCY RANDOMNESS TEST CV95
!                 ADJACENCY RANDOMNESS TEST CV99
!                 BINOMIAL PROPORTIONS
!                 BINOMIAL PROPORTIONS LOWER CONFIDENCE LIMIT
!                 BINOMIAL PROPORTIONS UPPER CONFIDENCE LIMIT
!                 CHI-SQUARE SD TEST
!                 CHI-SQUARE SD TEST CDF
!                 CHI-SQUARE SD TEST PVALUE
!                 CHI-SQUARE SD TEST LOWER TAIL PVALUE
!                 CHI-SQUARE SD TEST UPPER TAIL PVALUE
!                 CUMULATIVE SUM FORWARD TEST
!                 CUMULATIVE SUM FORWARD TEST PVALUE
!                 CUMULATIVE SUM BACKWARD TEST
!                 CUMULATIVE SUM BACKWARD TEST PVALUE
!                 DAVID
!                 DAVID CDF
!                 DAVID CRITICAL VALUE
!                 DAVID MINIMUM INDEX
!                 DAVID MAXIMUM INDEX
!                 DAVID PVALUE
!                 DIXON TEST
!                 DIXON MINIMUM TEST
!                 DIXON MAXIMUM TEST
!                 EXTREME STUDENTIZED DEVIATE
!                 FREQUENCY TEST
!                 FREQUENCY TEST CDF
!                 FREQUENCY WITHIN A BLOCK TEST
!                 FREQUENCY WITHIN A BLOCK TEST CDF
!                 GRUBB
!                 GRUBB CDF
!                 GRUBB DIRECTION
!                 GRUBB INDEX
!                 JARQUE BERA
!                 JARQUE BERA PVALUE
!                 JARQUE BERA CDF
!                 KURTOSIS OUTLIER
!                 KURTOSIS OUTLIER CDF
!                 KURTOSIS OUTLIER CRITICAL VALUE
!                 KURTOSIS OUTLIER INDEX
!                 KURTOSIS OUTLIER PVALUE
!                 LOWER BONETT STANDARD DEVIATION CONFIDENCE LIMIT
!                 LOWER COEFFICIENT OF DISPERSION CONFIDENCE LIMIT
!                 LOWER COEFFICIENT OF QUARTILE DISPERSION CONFIDENCE LIMIT
!                 LOWER COEFFICIENT OF VARIATION CONFIDENCE LIMIT
!                 LOWER CONFIDENCE LIMIT
!                 LOWER LOGNORMAL COEFFICIENT OF VARIATION CONFIDENCE LIMIT
!                 LOWER PREDICTION BOUND
!                 LOWER PREDICTION LIMIT
!                 LOWER STANDARD DEVIATION CONFIDENCE LIMIT
!                 LOWER STANDARD DEVIATION PREDICTION LIMIT
!                 LJUNG BOX TEST
!                 MCCOOL WEIBULL LOCATION TEST
!                 MCCOOL WEIBULL LOCATION TEST PVALUE
!                 MCCOOL WEIBULL LOCATION TEST CDF
!                 MCCOOL WEIBULL LOCATION TEST CV50
!                 MCCOOL WEIBULL LOCATION TEST CV90
!                 MCCOOL WEIBULL LOCATION TEST CV95
!                 MEAN SUCCESSIVE DIFFERENCE
!                 MEAN SUCCESSIVE DIFFERENCE NORMALIZED
!                 MEAN SUCCESSIVE DIFFERENCE CDF
!                 MEAN SUCCESSIVE DIFFERENCE PVALUE
!                 NORMAL TOLERANCE K FACTOR
!                 NORMAL TOLERANCE LOWER LIMIT
!                 NORMAL TOLERANCE UPPER LIMIT
!                 NORMAL TOLERANCE ONE SIDED K FACTOR
!                 NORMAL TOLERANCE ONE SIDED LOWER LIMIT
!                 NORMAL TOLERANCE ONE SIDED UPPER LIMIT
!                 ONE SAMPLE COEFFICIENT OF VARIATION TEST
!                 ONE SAMPLE COEFFICIENT OF VARIATION TEST CDF
!                 ONE SAMPLE COEFFICIENT OF VARIATION TEST PVALUE
!                 ONE SAMPLE COEFFICIENT OF VARIATION LOWER PVALUE
!                 ONE SAMPLE COEFFICIENT OF VARIATION UPPER PVALUE
!                 ONE SAMPLE SIGN TEST
!                 ONE SAMPLE SIGN TEST CDF
!                 ONE SAMPLE SIGN TEST PVALUE
!                 ONE SAMPLE SIGN TEST LOWER TAIL PVALUE
!                 ONE SAMPLE SIGN TEST UPPER TAIL PVALUE
