      IF(ISTARA.EQ.'ON')ICNTRA=1
!
  100 CONTINUE
!
!     FEBRUARY 2010: CHECK FOR MISSING VALUES IN DATA.  NOTE THAT
!                    THIS STEP SHOULD BE SKIPPED FOR THE "SIZE"
!                    STATISTIC.
!
      NS2SAV=NS2
      NSZSAV=NSZ
      IF(ICASPL.EQ.'NUMB')GO TO 11310
      IF(ICASPL.EQ.'COUN')GO TO 11310
      IF(ICASPL.EQ.'SIZE')GO TO 11310
      IF(ICASPL.EQ.'INTC')GO TO 11312
      IF(ICASPL.EQ.'INMN')GO TO 31760
      IF(ICASPL.EQ.'INMX')GO TO 31770
      IF(ICASPL.EQ.'INEX')GO TO 31780
      IF(ICASPL.EQ.'UNIQ')GO TO 11315
