      IFLAGN=0
      IF(NUMV2.GT.1)THEN
        IF(NSZ.GT.0 .AND. NSZ.NE.NS2)THEN
          IFLAGN=2
        ELSE
          IFLAGN=1
        ENDIF
      ENDIF
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PSTA')THEN
        WRITE(ICOUT,78)IFLAGN
   78   FORMAT('IFLAGN = ',I4)
