      ENDIF
!
      ICNT=0
      DO 110 I=1,NS2
        IF(IFLAGN.EQ.0 .OR. IFLAGN.EQ.2)THEN
          IF(TEMP(I).NE.PSTAMV)THEN
            ICNT=ICNT+1
            TEMP(ICNT)=TEMP(I)
          ENDIF
        ELSEIF(IFLAGN.EQ.1)THEN
          IF(TEMP(I).NE.PSTAMV .AND. TEMPZ(I).NE.PSTAMV)THEN
            ICNT=ICNT+1
            TEMP(ICNT)=TEMP(I)
            TEMPZ(ICNT)=TEMPZ(I)
          ENDIF
        ENDIF
  110 CONTINUE
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PSTA')THEN
        WRITE(ICOUT,79)ICNT
   79   FORMAT('AFTER CHECK FOR MISSING VALUES, ICNT = ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(ICNT.EQ.0)THEN
        RIGHT=PSTAMV
        GO TO 79000
      ENDIF
      NS2=ICNT
!
      IF(IFLAGN.EQ.2)THEN
        ICNT=0
        DO 120 I=1,NSZ
          IF(TEMPZ(I).NE.PSTAMV)THEN
            ICNT=ICNT+1
            TEMPZ(ICNT)=TEMPZ(I)
          ENDIF
  120   CONTINUE
