      ELSEIF(ICASPL.EQ.'PCPV')THEN
        IDF1=1
        IDF2=NS2 - 3
        ANUM=REAL(NS2-3)*RIGHT**2
        DENOM=1.0 - RIGHT**2
        CDF=0.0
        IF(DENOM.NE.0.0D0)THEN
          AVAL=ABS(ANUM/DENOM)
          CALL FCDF(AVAL,IDF1,IDF2,CDF)
        ENDIF
        RIGHT=1.0 - CDF
      ELSEIF(ICASPL.EQ.'PCCD')THEN
        IDF1=1
        IDF2=NS2
        ANUM=REAL(NS2-3)*RIGHT**2
        DENOM=1.0 - RIGHT**2
        CDF=0.0
        IF(DENOM.NE.0.0D0)THEN
          AVAL=ABS(ANUM/DENOM)
          CALL FCDF(AVAL,IDF1,IDF2,CDF)
        ENDIF
        RIGHT=CDF
      ENDIF
      GO TO 79000
