      CALL SUMDP(TEMP,NS2,IWRITE,RIGH1,IBUGG3,IERROR)
      CALL SUMDP(TEMPZ,NS2,IWRITE,RIGH2,IBUGG3,IERROR)
      RIGHT=0.0
      IF(RIGH2.NE.0.0)RIGHT=RIGH1/RIGH2
      GO TO 79000
!
!     BINOMIAL RATIO - FOR CASE WHERE BINOMIAL PROBABILITIES GIVEN
!                      AS NUMBER OF SUCCESSES AND NUMBER OF TRIALS
!                      RATHER THAN A SERIES OF 0/1 VALUES (I.E., DATA
!                      PREVIOUSLY AGGREGATED).  SLIGHTLY DIFFERENT
!                      FROM "RATIO" IN THAT WE NEED TO CHECK THAT
!                      VALUE FOR SECOND VARIABLE ALWAYS > VALUE
!                      FOR FIRST VARIABLE.  ALSO, OMIT ROW IF EITHER
!                      VALUE IS EQUAL TO THE MISSING VALUE.
!
31551 CONTINUE
      RIGHT=PSTAMV
      NTEMP=0
      DO 31552 I=1,NS2
        IVAL1=INT(TEMP(I)+0.1)
        IVAL2=INT(TEMPZ(I)+0.1)
        IF(TEMP(I).EQ.PSTAMV .OR. TEMPZ(I).EQ.PSTAMV)THEN
          GO TO 31552
        ELSEIF(IVAL1.GT.IVAL2)THEN
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31553)
31553     FORMAT('***** ERROR IN CMPSTA')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31554)
31554     FORMAT('      FOR BINOMIAL RATIO, NUMBER OF SUCCESSES IS ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31555)
31555     FORMAT('      GREATER THAN THE NUMBER OF TRIALS.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31556)IVAL1
31556     FORMAT('      THE NUMBER OF SUCCESSES = ',I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,31557)IVAL2
31557     FORMAT('      THE NUMBER OF TRIALS    = ',I8)
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ELSE
          NTEMP=NTEMP+1
          IF(IVAL1.LT.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,31553)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,31558)IVAL1
31558       FORMAT('      THE NUMBER OF SUCCESSES, ',I8,   &
                   ' IS NEGATIVE.')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
          IF(IVAL2.LT.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,31553)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,31559)IVAL2
31559       FORMAT('      THE NUMBER OF TRIALS, ',I8,   &
                   ' IS NEGATIVE.')
            CALL DPWRST('XXX','BUG ')
            IERROR='YES'
            GO TO 9000
          ENDIF
          TEMP(NTEMP)=IVAL1
          TEMPZ(NTEMP)=IVAL2
        ENDIF
31552 CONTINUE
      IF(NTEMP.LE.0)GO TO 79000
      CALL SUMDP(TEMP,NTEMP,IWRITE,RIGH1,IBUGG3,IERROR)
      CALL SUMDP(TEMPZ,NTEMP,IWRITE,RIGH2,IBUGG3,IERROR)
      IF(RIGH2.NE.0.0)RIGHT=RIGH1/RIGH2
      ITEMP1(1)=INT(RIGH2+0.1)
      GO TO 79000
!
31565 CONTINUE
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
