      IF(RIGH1.GE.0.0)THEN
        ASIGN1=1.0
      ELSE
        ASIGN1=-1.0
      ENDIF
      IF(RIGH2.GE.0.0)THEN
        ASIGN2=1.0
      ELSE
        ASIGN2=-1.0
      ENDIF
      RIGH1=ABS(RIGH1)
      RIGH2=ABS(RIGH2)
      IF(RIGH2.GT.RIGH1)THEN
        RIGHT=RIGH2
        RIGHT=ASIGN2*RIGHT
      ELSE
        RIGHT=RIGH1
        RIGHT=ASIGN1*RIGHT
      ENDIF
      GO TO 79000
11935 CONTINUE
      ICASE2='MEAN'
      CALL AAD(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,RIGHT,ICASE2,IBUGG3,IERROR)
      GO TO 79000
11938 CONTINUE
      ICASE2='MEDI'
      CALL AAD(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,RIGHT,ICASE2,IBUGG3,IERROR)
      GO TO 79000
11940 CONTINUE
      CALL MAD(TEMP,NS2,IWRITE,XTEMP1,XTEMP2,MAXNXT,RIGHT,IBUGG3,IERROR)
      IF(ICASPL.EQ.'MADN')RIGHT=RIGHT/0.67449
      GO TO 79000
!
11950 CONTINUE
      CALL GEOMEA(TEMP,NS2,IWRITE,RIGHT,IBUGG3,IERROR)
      GO TO 79000
11960 CONTINUE
      CALL GEOSD(TEMP,NS2,IWRITE,RIGHT,IBUGG3,IERROR)
      GO TO 79000
11970 CONTINUE
      CALL HARMEA(TEMP,NS2,IWRITE,RIGHT,IBUGG3,IERROR)
      GO TO 79000
11980 CONTINUE
      CALL LOWQUA(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,RIGH1,IBUGG3,IERROR)
      CALL UPPQUA(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,RIGH2,IBUGG3,IERROR)
      IF(ICASPL.EQ.'SIQU' .OR. ICASPL.EQ.'SIQL')THEN
        CALL MEDIAN(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,RIGH3,IBUGG3,IERROR)
      ENDIF
      RIGHT=RIGH2-RIGH1
      IF(ICASPL.EQ.'NIQR')THEN
        RIGHT=0.7413*RIGHT
      ELSEIF(ICASPL.EQ.'SIQU')THEN
        RIGHT=RIGH2-RIGH3
      ELSEIF(ICASPL.EQ.'SIQL')THEN
        RIGHT=RIGH3-RIGH1
      ELSEIF(ICASPL.EQ.'IQDV')THEN
        RIGHT=(RIGH2-RIGH1)/2.0
      ELSEIF(ICASPL.EQ.'CIQD')THEN
        RIGHT=100.0*(RIGH2-RIGH1)/(RIGH2+RIGH1)
      ENDIF
      GO TO 79000
11981 CONTINUE
!CCCC 2017/12: ALLOW QUANTILE METHOD TO BE SPECIFIED
!CCCC CALL LOWQUA(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,RQ1,IBUGG3,IERROR)
!CCCC CALL UPPQUA(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,RQ3,IBUGG3,IERROR)
      QNT=0.25
      CALL QUANT(QNT,TEMP,NS2,IWRITE,XTEMP1,MAXNXT,IQUAME,RQ1,   &
                 IBUGG3,IERROR)
      QNT=0.75
      CALL QUANT(QNT,TEMP,NS2,IWRITE,XTEMP1,MAXNXT,IQUAME,RQ3,   &
                 IBUGG3,IERROR)
      RIGHT=(RQ3 - RQ1)/(RQ1 + RQ3)
      GO TO 79000
!
11982 CONTINUE
!
      IHP='QUAN'
      IHP2='T   '
      IHWUSE='P'
      MESSAG='YES'
