      GO TO 79000
!
12115 CONTINUE
      CALL PBNCOR(TEMP,TEMPZ,NS2,IWRITE,XTEMP1,XTEMP2,MAXNXT,   &
                  RIGHT,BETA,   &
                  IBUGG3,IERROR)
      GO TO 79000
!
12120 CONTINUE
      DO 12122 I=1,NS2
        ITEMP1(I)=0
        ITEMP2(I)=0
        ITEMP3(I)=0
12122 CONTINUE
      CALL HLQEST(TEMP,NS2,XTEMP1,ITEMP1,ITEMP2,ITEMP3,ISEED,RIGHT)
      GO TO 79000
