12178 CONTINUE
      RIGHT=QN(TEMP,NS2,XTEMP1,XTEMP2,XTEMP3,   &
              ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6)
      GO TO 79000
!
12180 CONTINUE
      CALL MEAN(TEMP,NS2,IWRITE,RIGH1,IBUGG3,IERROR)
      CALL MEAN(TEMPZ,NSZ,IWRITE,RIGH2,IBUGG3,IERROR)
      RIGHT=RIGH1-RIGH2
      GO TO 79000
!
12182 CONTINUE
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        ALPHA=VALUE(ILOCP)
      ELSE
        ALPHA=0.95
      ENDIF
!
      CALL HEDGEG(TEMP,TEMPZ,NS2,NSZ,IWRITE,STATVA,STATBC,STATSE,   &
                  ALPHA,ALCL,AUCL,   &
                  YMEAN1,YSD1,YMEAN2,YSD2,SPOOL,   &
                  ICASPL,ISUBRO,IBUGG3,IERROR)
      RIGHT=STATVA
      IF(ICASPL.EQ.'BCHG')THEN
