      CALL AAD(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,RIGH1,ICASE2,IBUGG3,IERROR)
      CALL AAD(TEMPZ,NSZ,IWRITE,XTEMP1,MAXNXT,RIGH2,ICASE2,   &
