      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        ALPHA=VALUE(ILOCP)
        IF(ALPHA.GT.1.0 .AND. ALPHA.LT.100.0)THEN
          ALPHA=ALPHA/100.0
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
        ELSEIF(ALPHA.GT.0.0 .AND. ALPHA.LT.1.0)THEN
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
        ELSE
          ALPHA=0.95
        ENDIF
      ELSE
        ALPHA=0.95
      ENDIF
!
      ICASA2='CVLI'
      ICASA3='UPPE'
      ICASA5='TWOS'
      ALPHAT(1)=ALPHA
      NALPHA=1
!
      CALL DPCVC4(TEMP,TEMPZ,NS2,ITEMP1,XTEMP1,XTEMP2,   &
                  ICASA2,ICASA3,ICASA4,ICASA5,   &
                  ALPHAT,NALPHA,ALOWLV,AUPPLV,   &
                  AVAL1,AVAL2,NDIST,NGROUP,   &
                  ISUBRO,IBUGG3,IERROR)
!
      IF(ICASPL.EQ.'CCVA')RIGHT=AVAL1
      IF(ICASPL.EQ.'UCCV')RIGHT=AVAL2
      IF(ICASPL.EQ.'LCCV')RIGHT=ALOWLV(1)
      IF(ICASPL.EQ.'UCC2')RIGHT=AUPPLV(1)
      GO TO 79000
!
32030 CONTINUE
!
      IF(ICASPL.EQ.'DI2S')THEN
        ICASAN='TWOS'
      ELSEIF(ICASPL.EQ.'DIMN')THEN
        ICASAN='MINI'
      ELSEIF(ICASPL.EQ.'DIMX')THEN
        ICASAN='MAXI'
      ENDIF
!
      CALL DPDIX3(TEMP,XTEMP1,NS2,XTEMP2,IWRITE,ICASAN,   &
                  RIGHT,   &
                  ISUBRO,IBUGG3,IERROR)
      GO TO 79000
!
32040 CONTINUE
      EPS=0.1E-05
      XTEMP1(1)=PSTAMV
      XTEMP1(2)=PSTAMV
      CALL DISTIN(TEMP,NS2,IWRITE,XTEMP1,NDIST,IBUGG3,IERROR)
      IF(NDIST.GT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32041)
32041   FORMAT('***** ERROR FROM CMPSTA (AGRESTI-COUL BINOMIAL ',   &
               'LIMITS)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32042)
32042   FORMAT('      FOR AGRESTI-COUL LIMITS CASE, MORE THAN ',   &
               'TWO DISTINCT VALUES DETECTED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32043)NDIST
32043   FORMAT('      NUMBER OF DISTINCT VALUES = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
!
!       IF ALL VALUES ARE EQUAL TO THE "MISSING VALUE",
!       THEN SET VALUE OF STATISTIC TO MISSING VALUE.
!
      ELSEIF(NDIST.EQ.1 .AND. XTEMP1(1).EQ.PSTAMV)THEN
        RIGHT=PSTAMV
        GO TO 79000
      ENDIF
!
      HOLD1=XTEMP1(1)
      HOLD2=XTEMP1(2)
      IF(NDIST.EQ.1)THEN
        IF(XTEMP1(1).GE.0.5)THEN
          XMAX=XTEMP1(1)
          XMIN=CPUMIN
        ELSE
          XMIN=XTEMP1(1)
          XMAX=CPUMAX
        ENDIF
      ELSEIF(NDIST.EQ.2)THEN
        IF(HOLD1.LT.HOLD2)THEN
          XMIN=HOLD1
          XMAX=HOLD2
        ELSE
          XMAX=HOLD1
          XMIN=HOLD2
        ENDIF
      ENDIF
!
      DO 32045 I=1,NS2
        IF(TEMP(I).EQ.XMAX)THEN
          TEMP(I)=1.0
        ELSE
          TEMP(I)=0.0
        ENDIF
32045 CONTINUE
!
      XSUM=0.0
      DO 32048 I=1,NS2
        XSUM=XSUM + TEMP(I)
32048 CONTINUE
      P=XSUM/REAL(NS2)
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ALPHA=VALUE(ILOCP)
!
      IF(ICASPL.EQ.'1LAC')THEN
        IDIR='LOWE'
        CALL DPAGC1(P,NS2,ALPHA,IDIR,IWRITE,RIGHT,IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'1UAC')THEN
        IDIR='UPPE'
        CALL DPAGC1(P,NS2,ALPHA,IDIR,IWRITE,RIGHT,IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'2LAC')THEN
        CALL DPAGCO(P,NS2,ALPHA,IWRITE,ALOWLM,AUPPLM,IBUGG3,IERROR)
        RIGHT=ALOWLM
      ELSEIF(ICASPL.EQ.'2UAC')THEN
        CALL DPAGCO(P,NS2,ALPHA,IWRITE,ALOWLM,AUPPLM,IBUGG3,IERROR)
        RIGHT=AUPPLM
      ENDIF
!
      GO TO 79000
32050 CONTINUE
      EPS=0.1E-05
      XTEMP1(1)=PSTAMV
      XTEMP1(2)=PSTAMV
      CALL DISTIN(TEMP,NS2,IWRITE,XTEMP1,NDIST,IBUGG3,IERROR)
      IF(NDIST.GT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32051)
32051   FORMAT('***** ERROR FROM CMPSTA (EXACT BINOMIAL LIMITS)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32052)
32052   FORMAT('      FOR EXACT BINOMIAL LIMITS CASE, MORE THAN ',   &
               'TWO DISTINCT VALUES DETECTED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32053)NDIST
32053   FORMAT('      NUMBER OF DISTINCT VALUES = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
!
!       IF ALL VALUES ARE EQUAL TO THE "MISSING VALUE",
!       THEN SET VALUE OF STATISTIC TO MISSING VALUE.
!
      ELSEIF(NDIST.EQ.1 .AND. XTEMP1(1).EQ.PSTAMV)THEN
        RIGHT=PSTAMV
        GO TO 79000
      ENDIF
!
      HOLD1=XTEMP1(1)
      HOLD2=XTEMP1(2)
      IF(HOLD1.LT.HOLD2)THEN
        XMIN=HOLD1
        XMAX=HOLD2
      ELSE
        XMAX=HOLD1
        XMIN=HOLD2
      ENDIF
!
      DO 32055 I=1,NS2
        IF(TEMP(I).EQ.XMAX)THEN
          TEMP(I)=1.0
        ELSE
          TEMP(I)=0.0
        ENDIF
32055 CONTINUE
!
      XSUM=0.0
      DO 32058 I=1,NS2
        XSUM=XSUM + TEMP(I)
32058 CONTINUE
      P=XSUM/REAL(NS2)
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ALPHA=VALUE(ILOCP)
!
      IF(ICASPL.EQ.'1LEB')THEN
        CALL DPEBLL(P,NS2,ALPHA,IWRITE,RIGHT,'ONES',IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'1UEB')THEN
        CALL DPEBUL(P,NS2,ALPHA,IWRITE,RIGHT,'ONES',IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'2LEB')THEN
        CALL DPEBLL(P,NS2,ALPHA,IWRITE,RIGHT,'TWOS',IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'2UEB')THEN
        CALL DPEBUL(P,NS2,ALPHA,IWRITE,RIGHT,'TWOS',IBUGG3,IERROR)
      ENDIF
      GO TO 79000
!
32060 CONTINUE
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        ALPHA=0.95
      ELSE
        ALPHA=VALUE(ILOCP)
        IF(ALPHA.LE.0.0)THEN
          ALPHA=0.95
        ELSEIF(ALPHA.GE.1.0 .OR. ALPHA.LE.100.0)THEN
          ALPHA=ALPHA/100.0
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
        ELSEIF(ALPHA.LT.0.5)THEN
          ALPHA=1.0 - ALPHA
        ENDIF
      ENDIF
!
      ALPHAT(1)=100.0*ALPHA
      NUMALP=1
      CALL DPADK3(TEMP,TEMPZ,NS2,ALPHAT,NUMALP,   &
                  XTEMP1,XTEMP2,DTEMP1,DTEMP2,DTEMP3,ITEMP1,ITEMP2,   &
                  ITEMP3,ITEMP4,   &
                  ADKSTA,ADC,DSD,IFLGZZ,NBCH,MINSIZ,MAXSIZ,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'ADKS')RIGHT=ADKSTA
      IF(ICASPL.EQ.'ADKC')RIGHT=ADC(1)
      GO TO 79000
!
32070 CONTINUE
!
!     FOR VARIOUS CONSENSUS MEANS COMMANDS, IF WE HAVE RAW DATA
!     WE FIRST NEED TO CONVERT TO SUMMARY DATA (I.E., MEAN, SD's,
!     AND SAMPLE SIZES) BEFORE CALLING APPROPRIATE METHOD.
!
      CALL DISTIN(TEMPZ,NS2,IWRITE,XTEMP1,NLAB,IBUGG3,IERROR)
!
      DO 32075 I=1,NLAB
        ATEMP=XTEMP1(I)
        NTEMP=0
        DO 32079 J=1,NS2
          IF(TEMPZ(J).EQ.ATEMP)THEN
            NTEMP=NTEMP+1
            TEMPZ3(NTEMP)=TEMP(J)
          ENDIF
32079   CONTINUE
        ITEMP1(I)=NTEMP
!
        CALL MEAN(TEMPZ3,NTEMP,IWRITE,AMEAN,IBUGG3,IERROR)
        CALL SD(TEMPZ3,NTEMP,IWRITE,ASD,IBUGG3,IERROR)
        XTEMP2(I)=AMEAN
        XTEMP3(I)=ASD
!
32075 CONTINUE
!
      DO 32080 I=1,NLAB
        TEMP(I)=XTEMP2(I)
        TEMPZ(I)=XTEMP3(I)
        TEMPZ3(I)=REAL(ITEMP1(I))
32080 CONTINUE
      NS2=NLAB
!
      IF(ICASPL.EQ.'DSLA')GO TO 32100
      IF(ICASPL.EQ.'DHHD')GO TO 32100
      IF(ICASPL.EQ.'DSMM')GO TO 32100
      IF(ICASPL.EQ.'DSSE')GO TO 32100
      IF(ICASPL.EQ.'MPAU')GO TO 32200
      IF(ICASPL.EQ.'MPSE')GO TO 32200
      IF(ICASPL.EQ.'MMPA')GO TO 32200
      IF(ICASPL.EQ.'MMPS')GO TO 32200
      IF(ICASPL.EQ.'VARU')GO TO 32200
      IF(ICASPL.EQ.'VRSE')GO TO 32200
      IF(ICASPL.EQ.'BOB ')GO TO 32300
      IF(ICASPL.EQ.'BOBS')GO TO 32300
      IF(ICASPL.EQ.'GCIN')GO TO 32400
      IF(ICASPL.EQ.'GCIS')GO TO 32400
      IF(ICASPL.EQ.'BCP ')GO TO 32500
      IF(ICASPL.EQ.'BCPS')GO TO 32500
      IF(ICASPL.EQ.'MMEA')GO TO 32600
      IF(ICASPL.EQ.'MMES')GO TO 32600
      IF(ICASPL.EQ.'FAIR')GO TO 32700
      IF(ICASPL.EQ.'FWSE')GO TO 32700
      IF(ICASPL.EQ.'GDEA')GO TO 32800
      IF(ICASPL.EQ.'GDSE')GO TO 32800
      IF(ICASPL.EQ.'GDSN')GO TO 32800
      IF(ICASPL.EQ.'GDZ1')GO TO 32800
      IF(ICASPL.EQ.'GDZ2')GO TO 32800
      IF(ICASPL.EQ.'SCEB')GO TO 32900
      IF(ICASPL.EQ.'SESE')GO TO 32900
      IF(ICASPL.EQ.'LPOO')GO TO 33000
      IF(ICASPL.EQ.'LPSE')GO TO 33000
!
32100 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32101)
32101   FORMAT('***** ERROR FROM CMPSTA (DERSIMONIAN-LAIRD ',   &
               'ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32103)
32103   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32111 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32113)I,TEMPZ(I)
32113     FORMAT('      LAB ',I6,' HAS NON-POSITIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LE.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32118)I
32118     FORMAT('      LAB ',I6,' HAS LESS THAN 2 OBSERVATIONS.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32111 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
!CCCC IOUNI5=-99
!CCCC CALL DPDERS(NPTS,NLAB,
!CCCC1            TEMP,TEMPZ,ITEMP1,
!CCCC1            XTEMP3(1),XTEMP3(MAXNXT/2),ITEMP2,
!CCCC1            XTEMP1,XTEMP2,DTEMP1,
!CCCC1            DTEMP2,DTEMP2(5001),DTEMP3,
!CCCC1            XDL,XDLS2,YDL,SEDLK1,SEDLK2,DLOWDL,DHIGDL,
!CCCC1            SERUK1,SERUK2,DLOWD2,DHIGD2,
!CCCC1            SEHDK1,SEHDK2,DLOWD3,DHIGD3,
!CCCC1            SEBOK1,SEBOK2,DLOWD4,DHIGD4,
!CCCC1            DLOWD5,DHIGD5,DLOWD6,DHIGD6,
!CCCC1            AK2,AK3,
!CCCC1            IWRITE,IOUNI5,
!CCCC1            ICAPSW,ICAPTY,NUMDIG,ISEED,
!CCCC1            ISUBRO,IBUGG3,IERROR)
!CCCC IF(ICASPL.EQ.'DSLA')RIGHT=XDL
!CCCC IF(ICASPL.EQ.'DHHD')RIGHT=SEHDK1
!CCCC IF(ICASPL.EQ.'DSMM')RIGHT=SERUK1
!CCCC IF(ICASPL.EQ.'DSSE')RIGHT=SEDLK1
!CCCC IF(ICASPL.EQ.'DSBO')RIGHT=SEBOK1
      RIGHT=CPUMIN
      GO TO 79000
!
32200 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32201)
32201   FORMAT('***** ERROR FROM CMPSTA (MANDEL-PAULE ',   &
               'ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32203)
32203   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32211 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32201)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32213)I,TEMPZ(I)
32213     FORMAT('      LAB ',I6,' HAS NON-POSITIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LE.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32201)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32218)I
32218     FORMAT('      LAB ',I6,' HAS LESS THAN 2 OBSERVATIONS.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32211 CONTINUE
!
      T0=10000000.D0
      T1=-T0
!
      AMNX=CPUMAX
      AMXX=CPUMIN
      AMNSD=CPUMAX
      AMXSD=CPUMIN
!
      DO 32250 I=1,NLAB
!
        DTEMP1(I)=DBLE(TEMP(I))
        IF(DTEMP1(I).LT.T0) T0=DTEMP1(I)
        IF(DTEMP1(I).GT.T1) T1=DTEMP1(I)
        IF(TEMP(I).GT.AMXX)AMXX=TEMP(I)
        IF(TEMP(I).LT.AMNX)AMNX=TEMP(I)
!
        DTEMP2(I)=DBLE(TEMPZ(I))**2/DBLE(ITEMP1(I))
        IF(TEMPZ(I).GT.0.0)THEN
          IF(TEMPZ(I).LT.AMNSD)AMNSD=TEMPZ(I)
          IF(TEMPZ(I).GT.AMXSD)AMXSD=TEMPZ(I)
        ENDIF
!
32250 CONTINUE
!
      EPS=0.00001
      T0=AMNX - EPS
      T1=AMXX
      DO 32270 I=1,NS2
        DTEMP1(I)=(DTEMP1(I)-T0)/(T1-T0)
        DTEMP2(I)=DTEMP2(I)/((T1-T0)**2)
32270 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
!
      IF(ICASPL.EQ.'MPAU' .OR. ICASPL.EQ.'MPSE' .OR.   &
         ICASPL.EQ.'VARU' .OR. ICASPL.EQ.'VRSE')THEN
        CALL DPMNPL(TEMP,TEMPZ,TEMPZ3,NPTS,NLAB,   &
                    DTEMP1,DTEMP2,ITEMP1,   &
                    XMPS,S2BMPS,SEMP,SEMPK1,SEMPK2,   &
                    DLOWMP,DHIGMP,STXMU,STS2B,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'MMPA' .OR. ICASPL.EQ.'MMPS')THEN
        CALL DPMMPL(TEMP,TEMPZ,TEMPZ3,NPTS,NLAB,   &
                    DTEMP1,DTEMP2,ITEMP1,   &
                    XMMPS,S2BMMP,SEMMP,SEMMP1,SEMMP2,   &
                    DLOWMM,DHIGMM,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGG3,IERROR)
      ENDIF
!
      IF(ICASPL.EQ.'VARU' .OR. ICASPL.EQ.'VRSE')THEN
        CALL DPVRML(NPTS,NLAB,   &
                    TEMP,TEMPZ,ITEMP1,   &
                    XTEMP3(1),XTEMP3(MAXNXT/2),ITEMP2,XTEMP1,XTEMP2,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    DTEMP2(MAXNXT/2),DTEMP3(MAXNXT/2),   &
                    XMLS,S2BMLS,SEML,SEMLK1,SEMLK2,   &
                    DLOWML,DHIGML,STXMU,STS2B,   &
                    SEMLBO,DLOWM2,DHIGM2,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,IOUNI5,NUMDIG,ISEED,   &
                    ISUBRO,IBUGG3,IERROR)
      ENDIF
!
      IF(ICASPL.EQ.'MPAU')RIGHT=XMPS
      IF(ICASPL.EQ.'MPSE')RIGHT=SEMP
      IF(ICASPL.EQ.'VARU')RIGHT=XMLS
      IF(ICASPL.EQ.'VRSE')RIGHT=SEML
      IF(ICASPL.EQ.'MMPA')RIGHT=XMMPS
      IF(ICASPL.EQ.'MMPS')RIGHT=SEMMP
      GO TO 79000
!
32300 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2 .OR. NLAB.GT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32301)
32301   FORMAT('***** ERROR FROM CMPSTA (BOB ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32303)
32303   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO OR ',   &
               'GREATER THAN FIVE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32311 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32301)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32313)I,TEMPZ(I)
32313     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LE.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32301)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32318)I
32318     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32311 CONTINUE
!
      AMNX=CPUMAX
      AMXX=CPUMIN
!
      DSUM1=0.0D0
      DO 32350 I=1,NLAB
        IF(TEMP(I).GT.AMXX)AMXX=TEMP(I)
        IF(TEMP(I).LT.AMNX)AMNX=TEMP(I)
        DSUM1=DSUM1 + DBLE(TEMPZ(I))**2/DBLE(ITEMP1(I))
32350 CONTINUE
      SW=REAL(DSQRT(DSUM1)/DBLE(NLAB))
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
      CALL DPBOB(NPTS,NLAB,   &
                 TEMP,TEMPZ,AMNX,AMXX,SW,   &
                 ASM,ASB,AKU,AKUK1,AKUK2,   &
                 DLOWBO,DHIGBO,   &
                 IWRITE,   &
                 ICAPSW,ICAPTY,NUMDIG,   &
                 ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'BOB ')RIGHT=ASM
      IF(ICASPL.EQ.'BOBS')RIGHT=AKUK1
      GO TO 79000
!
32400 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
                                                                                                                                  
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32401)
32401   FORMAT('***** ERROR FROM CMPSTA (GENERALIZED CONFIDENCE ',   &
               'INTERVAL ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32403)
32403   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32411 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32401)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32413)I,TEMPZ(I)
32413     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LT.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32401)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32418)I
32418     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32411 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
      CALL DPGCI(NPTS,NLAB,   &
                 TEMP,TEMPZ,ITEMP1,   &
                 DTEMP1,DTEMP2,   &
                 XGCI,SEGCI,   &
                 DLOWGC,DHIGGC,   &
                 IWRITE,IOUNI5,   &
                 ICAPSW,ICAPTY,NUMDIG,   &
                 ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'GCIN')RIGHT=XGCI
      IF(ICASPL.EQ.'GCIS')RIGHT=SEGCI
      GO TO 79000
!
32500 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2 .OR. NLAB.GT.6)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32501)
32501   FORMAT('***** ERROR FROM CMPSTA (BCP ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32503)
32503   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO OR ',   &
               'GREATER THAN SIX.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32511 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32501)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32513)I,TEMPZ(I)
32513     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LE.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32501)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32518)I
32518     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32511 CONTINUE
!
      AMNX=CPUMAX
      AMXX=CPUMIN
!
      DO 32550 I=1,NLAB
        IF(TEMP(I).GT.AMXX)AMXX=TEMP(I)
        IF(TEMP(I).LT.AMNX)AMNX=TEMP(I)
32550 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
      CALL DPBCP(NPTS,NLAB,   &
                 TEMP,TEMPZ,ITEMP1,AMNX,AMXX,   &
                 XBCP,XBCPSE,XBCPK1,SBCPK2,   &
                 DLOWBC,DHIGBC,   &
                 IWRITE,   &
                 ICAPSW,ICAPTY,NUMDIG,   &
                 ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'BCP ')RIGHT=XBCP
      IF(ICASPL.EQ.'BCPS')RIGHT=XBCPSE
      GO TO 79000
!
32600 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
                                                                                                                                  
      IPRINT='OFF'
      NLAB=NS2
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32601)
32601   FORMAT('***** ERROR FROM CMPSTA (MEAN OF MEANS ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32603)
32603   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      CALL MEAN(TEMP,NLAB,IWRITE,ASM,IBUGG3,IERROR)
      CALL SD(TEMP,NLAB,IWRITE,ASD,IBUGG3,IERROR)
      IF(ICASPL.EQ.'MMEA')RIGHT=ASM
      IF(ICASPL.EQ.'MMES')RIGHT=ASD/SQRT(REAL(NLAB))
      GO TO 79000
!
32700 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32701)
32701   FORMAT('***** ERROR FROM CMPSTA (FAIRWEATHER ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32703)
32703   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32711 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32701)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32713)I,TEMPZ(I)
32713     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LT.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32701)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32718)I
32718     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32711 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
      CALL DPFAIR(NPTS,NLAB,   &
                  TEMP,TEMPZ,ITEMP1,   &
                  XFW,XFWS2,SEFWK1,SEFWK2,   &
                  DLOWFW,DHIGFW,DLOWF2,DHIGF2,DLOWF3,DHIGF3,   &
                  IWRITE,   &
                  ICAPSW,ICAPTY,IFLAG9,NUMDIG,   &
                  ISUBRO,IBUGG3,IERROR)
      RIGHT=CPUMIN
      IF(IFLAG9)THEN
        IF(ICASPL.EQ.'FAIR')RIGHT=XFW
        IF(ICASPL.EQ.'FWSE')RIGHT=SEFWK1
      ENDIF
      GO TO 79000
!
32800 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32801)
32801   FORMAT('***** ERROR FROM CMPSTA (GRAYBILL-DEAL ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32803)
32803   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32811 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32801)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32813)I,TEMPZ(I)
32813     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LT.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32801)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32818)I
32818     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32811 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
      IOUNI5=-99
      CALL DPGRAY(NPTS,NLAB,   &
                  TEMP,TEMPZ,ITEMP1,   &
                  XGD,XGDS2,SEGDK1,SEGDK2,   &
                  XGDS20,XGDSZ1,XGDSZ2,   &
                  DLOWGD,DHIGGD,   &
                  IWRITE,IOUNI5,   &
                  ICAPSW,ICAPTY,NUMDIG,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'GDEA')RIGHT=XGD
      IF(ICASPL.EQ.'GDSE')RIGHT=SEGDK1
      IF(ICASPL.EQ.'GDSN')RIGHT=SQRT(XGDS20)
      IF(ICASPL.EQ.'GDZ1')RIGHT=SQRT(XGDSZ1)
      IF(ICASPL.EQ.'GDZ2')RIGHT=SQRT(XGDSZ2)
      GO TO 79000
!
32900 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32901)
32901   FORMAT('***** ERROR FROM CMPSTA (SCHILLER-EBERHARDT ',   &
               'ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32903)
32903   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32911 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32901)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32913)I,TEMPZ(I)
32913     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32901)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32918)I
32918     FORMAT('      LAB ',I6,' HAS LESS THAN 2 OBSERVATIONS.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32911 CONTINUE
!
      IHP='SIGM'
      IHP2='AH  '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        SIGMAH=0.0
      ELSE
        SIGMAH=VALUE(ILOCP)
        IF(SIGMAH.LT.0.0)SIGMAH=0.0
      ENDIF
      IHP='DFH '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        IDFH=1
      ELSE
        IDFH=INT(VALUE(ILOCP)+ 0.5)
      ENDIF
      IF(IDFH.LE.0)IDFH=1
!
!     SCHILLER-EBERHARDT NEEDS TO CALL MANDEL-PAULE TO
!     OBTAIN "S2BMPS" VALUE.
!
      T0=10000000.D0
      T1=-T0
!
      AMNX=CPUMAX
      AMXX=CPUMIN
      AMNSD=CPUMAX
      AMXSD=CPUMIN
!
      DO 32950 I=1,NLAB
!
        DTEMP1(I)=DBLE(TEMP(I))
        IF(DTEMP1(I).LT.T0) T0=DTEMP1(I)
        IF(DTEMP1(I).GT.T1) T1=DTEMP1(I)
        IF(TEMP(I).GT.AMXX)AMXX=TEMP(I)
        IF(TEMP(I).LT.AMNX)AMNX=TEMP(I)
!
        DTEMP2(I)=DBLE(TEMPZ(I))**2/DBLE(ITEMP1(I))
        IF(TEMPZ(I).GT.0.0)THEN
          IF(TEMPZ(I).LT.AMNSD)AMNSD=TEMPZ(I)
          IF(TEMPZ(I).GT.AMXSD)AMXSD=TEMPZ(I)
        ENDIF
!
32950 CONTINUE
!
      EPS=0.00001
      T0=AMNX - EPS
      T1=AMXX
      DO 32970 I=1,NS2
        DTEMP1(I)=(DTEMP1(I)-T0)/(T1-T0)
        DTEMP2(I)=DTEMP2(I)/((T1-T0)**2)
32970 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
!
      CALL DPMNPL(TEMP,TEMPZ,TEMPZ3,NPTS,NLAB,   &
                  DTEMP1,DTEMP2,ITEMP1,   &
                  XMPS,S2BMPS,SEMP,SEMPK1,SEMPK2,   &
                  DLOWMP,DHIGMP,STXMU,STS2B,   &
                  IWRITE,   &
                  ICAPSW,ICAPTY,NUMDIG,   &
                  ISUBRO,IBUGG3,IERROR)
      CALL DPSCEB(NPTS,NLAB,   &
                  DTEMP1,ITEMP1,   &
                  TEMP,TEMPZ,S2BMPS,   &
                  XSE,XSES2,IDFH,SIGMAH,   &
                  SESUK1,SESUK2,   &
                  DLOWSE,DHIGSE,   &
                  IWRITE,   &
                  ICAPSW,ICAPTY,NUMDIG,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'SCEB')RIGHT=XSE
      IF(ICASPL.EQ.'SESE')RIGHT=SESUK1
      GO TO 79000
!
33000 CONTINUE
!
!     CHECK FOR LABS WITH NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33001)
33001   FORMAT('***** ERROR FROM CMPSTA (LINEAR POOL ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33003)
33003   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 33011 I=1,NLAB
        IF(TEMPZ(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,33001)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,33013)I,TEMPZ(I)
33013     FORMAT('      LAB ',I6,' HAS NON-POSITIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=INT(TEMPZ3(I)+0.1)
33011 CONTINUE
!
      AVAL=1.0/REAL(NLAB)
      DO 33021 II=1,NLAB
        TEMPZ3(II)=1.0/REAL(NLAB)
33021 CONTINUE
!
      IF(ILIPWT.NE.'OFF ')THEN
        IHP=ILIPWT(1:4)
        IHP2=ILIPWT(5:8)
        IHWUSE='V'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
!
        IF(IERROR.EQ.'NO')THEN
          ICOLQP=IVALUE(ILOCV)
          NTEMP=IN(ILOCV)
          ICNT=0
          DO 33028 I=1,NTEMP
            IJ=MAXN*(ICOLQP-1)+I
            ICNT=ICNT+1
            IF(ICOLQP.LE.MAXCOL)TEMPZ3(ICNT)=V(IJ)
            IF(ICOLQP.EQ.MAXCP1)TEMPZ3(ICNT)=PRED(I)
            IF(ICOLQP.EQ.MAXCP2)TEMPZ3(ICNT)=RES(I)
            IF(ICOLQP.EQ.MAXCP3)TEMPZ3(ICNT)=YPLOT(I)
            IF(ICOLQP.EQ.MAXCP4)TEMPZ3(ICNT)=XPLOT(I)
            IF(ICOLQP.EQ.MAXCP5)TEMPZ3(ICNT)=X2PLOT(I)
            IF(ICOLQP.EQ.MAXCP6)TEMPZ3(ICNT)=TAGPLO(I)
33028     CONTINUE
         ENDIF
      ENDIF
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
!
      IOP='OPEN'
      IFLAG1=0
      IFLAG2=0
      IFLAG3=0
      IFLAG4=0
      IFLAG5=1
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')THEN
        IOUNI5=0
      ENDIF
!
      CALL DPLIPO(NLAB,TEMP,TEMPZ,TEMPZ3,ITEMP1,   &
                  XTEMP1,XTEMP2,XTEMP3,DTEMP1,   &
                  XLP,SELIP1,ALOWLP,AUPPLP,   &
                  IWRITE,IOUNI5,   &
                  ICAPSW,ICAPTY,MAXNXT,NUMDIG,ISEED,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'LPOO')RIGHT=XLP
      IF(ICASPL.EQ.'LPSE')RIGHT=SELIP1
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGG3,ISUBRO,IERROR)
!
      GO TO 79000
!
33100 CONTINUE
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        ALPHA=0.95
      ELSE
        ALPHA=VALUE(ILOCP)
        IF(ALPHA.EQ.90.0 .OR. ALPHA.EQ.0.90)THEN
          ALPHA=0.90
        ELSEIF(ALPHA.EQ.10.0 .OR. ALPHA.EQ.0.10)THEN
          ALPHA=0.90
        ELSEIF(ALPHA.EQ.99.0 .OR. ALPHA.EQ.0.99)THEN
          ALPHA=0.99
        ELSEIF(ALPHA.EQ.1.0 .OR. ALPHA.EQ.0.01)THEN
          ALPHA=0.99
        ELSEIF(ALPHA.EQ.95.0 .OR. ALPHA.EQ.0.95)THEN
          ALPHA=0.95
        ELSEIF(ALPHA.EQ.5.0 .OR. ALPHA.EQ.0.05)THEN
          ALPHA=0.95
        ELSE
          ALPHA=0.95
        ENDIF
      ENDIF
!
      CALL DP2KS3(TEMP,TEMPZ,NS2,NSZ,   &
                  XTEMP1,   &
                  STATVA,STATCD,CUTU90,CUTU95,CUTU99,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'KS2S')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'KSCV')THEN
        IF(ALPHA.EQ.0.90)THEN
          RIGHT=CUTU90
        ELSEIF(ALPHA.EQ.0.99)THEN
          RIGHT=CUTU99
        ELSE
          RIGHT=CUTU95
        ENDIF
      ENDIF
      GO TO 79000
!
33105 CONTINUE
      IDATSW='RAW'
      CLWID=CLWIDT(1)
      XSTART=CLLIMI(1)
      XSTOP=CLLIMI(2)
      MAXOB2=MAXOBV/2
      IINDX=(MAXOBV/2) + 1
      CALL DP2CH3(TEMP,TEMPZ,TEMPZ3,NS2,NSZ,NSZ3,   &
                  IDATSW,IRHSTG,   &
                  CLWID,XSTART,XSTOP,   &
                  CLWID2,DXSTAR,DXSTOP,   &
                  XTEMP1,IHSTCW,IHSTOU,MAXOBV,MAXOB2,   &
                  STATVA,STATCD,STATNU,NCELLS,   &
                  Y1MEAN,Y1SD,Y1MIN,Y1MAX,   &
                  Y2MEAN,Y2SD,Y2MIN,Y2MAX,   &
                  XTEMP2,XTEMP3,XTEMP2(IINDX),XTEMP3(IINDX),M2,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'CS2S')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'CC2S')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'CP2S')THEN
        RIGHT=1.0 - STATCD
      ENDIF
      GO TO 79000
!
33110 CONTINUE
!
      CALL DPWSH3(TEMP,NS2,   &
                  XTEMP1,MAXNXT,   &
                  STATVA,PVAL,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'WSHA')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'WSPV')THEN
        RIGHT=PVAL
      ENDIF
      GO TO 79000
!
33120 CONTINUE
!
      CALL DPCUS3(TEMP,NS2,   &
                  STATVA,STATV2,STATCD,STATC2,PVAL1,PVAL2,   &
                  XTEMP1,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'CSFT')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'CSFP')THEN
        RIGHT=PVAL1
      ELSEIF(ICASPL.EQ.'CSBT')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'CSBP')THEN
        RIGHT=PVAL2
      ENDIF
      GO TO 79000
!
33130 CONTINUE
!
      IF(NUMV2.EQ.1)THEN
        XMEAN=CPUMIN
        XSD=CPUMIN
        AN=CPUMIN
      ELSE
        XMEAN=TEMP(1)
        XSD=TEMPZ(1)
        AN=TEMPZ3(1)
      ENDIF
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        ALPHA=0.95
      ELSE
        ALPHA=VALUE(ILOCP)
      ENDIF
!
      IHP='GAMM'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        GAMMA=0.95
      ELSE
        GAMMA=VALUE(ILOCP)
      ENDIF
!
      CALL DPTOL3(TEMP,NS2,XMEAN,XSD,AN,PTOLDF,   &
                  ICASPL,ALPHA,GAMMA,ITOLGC,ITOLM2,   &
                  AK,ALOWLM,AUPPLM,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'1LNT' .OR. ICASPL.EQ.'2LNT')THEN
        RIGHT=ALOWLM
      ELSEIF(ICASPL.EQ.'1UNT' .OR. ICASPL.EQ.'2UNT')THEN
        RIGHT=AUPPLM
      ELSEIF(ICASPL.EQ.'1KNT' .OR. ICASPL.EQ.'2KNT')THEN
        RIGHT=AK
      ENDIF
      GO TO 79000
!
33140 CONTINUE
!
      IF(IFTESH.EQ.'BONE')THEN
        IHP='ALPH'
        IHP2='A   '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
        ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          ALPHAZ=0.975
        ELSE
          ALPHAZ=VALUE(ILOCP)
        ENDIF
        IF(ALPHAZ.GT.1.0 .AND. ALPHAZ.LT.100.0)THEN
          ALPHAZ=ALPHAZ/100.0
        ELSEIF(ALPHAZ.LE.0.0 .AND. ALPHAZ.GE.100.0)THEN
          ALPHAZ=0.975
        ENDIF
        IF(ALPHAZ.LT.0.5)ALPHAZ=1.0 - ALPHAZ
      ELSE
        ALPHAZ=0.975
      ENDIF
!
      CALL DPFTE3(TEMP,NS2,TEMPZ,NSZ,MAXNXT,                  &
                  IFTESH,IFTEDI,PFTEPV,PFTEPM,                &
                  ALPHAZ,XTEMP1,                              &
                  Y1MEAN,Y1SD,Y2MEAN,Y2SD,                    &
                  SDNUM,SDDEN,IDFNUM,IDFDEN,ADFNUM,ADFDEN,    &
                  STATVA,STANU1,STANU2,POOLSDZ,STATCD,PVAL,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'FTES')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'FTPV')THEN
        RIGHT=PVAL
      ELSEIF(ICASPL.EQ.'FTCD')THEN
        RIGHT=STATCD
      ENDIF
      GO TO 79000
!
33150 CONTINUE
      IHP='MU  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        AMU=0.0
      ELSE
        AMU=VALUE(ILOCP)
      ENDIF
!
      CALL DPSIG3(TEMP,NS2,AMU,IWRITE,   &
                  XTEMP1,XTEMP2,MAXNXT,   &
                  XMEAN,XMED,XSD,XMAD,   &
                  STATV1,STATC1,STATV2,STATC2,RTIES,NTEMP,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'1STE')THEN
        RIGHT=STATV1
      ELSEIF(ICASPL.EQ.'1SCD')THEN
        RIGHT=STATC1
      ELSEIF(ICASPL.EQ.'1S2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'1SLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'1SUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
33160 CONTINUE
      IHP='D0  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        D0=0.0
      ELSE
        D0=VALUE(ILOCP)
      ENDIF
!
      CALL DPSIG4(TEMP,NS2,TEMPZ,NSZ,D0,IWRITE,   &
                  XTEMP1,XTEMP2,MAXNXT,   &
                  X1MEAN,X1MED,X1SD,X1MAD,   &
                  X2MEAN,X2MED,X2SD,X2MAD,   &
                  STATV1,STATC1,STATV2,STATC2,RTIES,NTEMP,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'2STE')THEN
        RIGHT=STATV1
      ELSEIF(ICASPL.EQ.'2SCD')THEN
        RIGHT=STATC1
      ELSEIF(ICASPL.EQ.'2S2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'2SLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'2SUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
33165 CONTINUE
      IF(MAXNXT.GE.1000000)THEN
        MAXSAM=22
      ELSE
        MAXSAM=20
      ENDIF
      SUMX=CPUMIN
      PTEMP=CPUMIN
      CALL FISHER(TEMP,NS2,TEMPZ,NSZ,ITOTAL,POSSIB,PTEMP,   &
                  SUMX,SUMY,XMEAN,YMEAN,   &
                  XTEMP1,XTEMP2,ITEMP1,MAXSAM,MAXNXT,   &
                  IFAULT,IBUGG3)
      IF(IFAULT.GT.0)THEN
        RIGHT=CPUMIN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33166)
33166   FORMAT('****** ERROR IN FISHER TWO-SAMPLE RANDOMIZATION TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33167)
33167   FORMAT('       MAXIMUM STORAGE SPACE EXCEEDED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33168)NS2
33168   FORMAT('       NUMBER OF OBSERVATIONS FOR SAMPLE ONE  = ',I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33169)NSZ
33169   FORMAT('       NUMBER OF OBSERVATIONS FOR SAMPLE TWO  = ',I8)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(ICASPL.EQ.'2FRT')THEN
        RIGHT=SUMX
      ELSEIF(ICASPL.EQ.'2F2P' .AND. NS2.EQ.NSZ)THEN
        RIGHT=2.0*PTEMP
      ELSEIF(ICASPL.EQ.'2F2P' .AND. NS2.NE.NSZ)THEN
        RIGHT=2.0*PTEMP
      ELSEIF(ICASPL.EQ.'2F1P')THEN
        RIGHT=PTEMP
      ENDIF
      GO TO 79000
!
33170 CONTINUE
      IF(ICASPL.EQ.'WABA')THEN
        ICASAN='ABAS'
        ICASDI='WEIB'
      ELSEIF(ICASPL.EQ.'WBBA')THEN
        ICASAN='BBAS'
        ICASDI='WEIB'
      ELSEIF(ICASPL.EQ.'LABA')THEN
        ICASAN='ABAS'
        ICASDI='LOGN'
      ELSEIF(ICASPL.EQ.'LBBA')THEN
        ICASAN='BBAS'
        ICASDI='LOGN'
      ELSEIF(ICASPL.EQ.'NABA')THEN
        ICASAN='ABAS'
        ICASDI='NORM'
      ELSEIF(ICASPL.EQ.'NBBA')THEN
        ICASAN='BBAS'
        ICASDI='NORM'
      ELSEIF(ICASPL.EQ.'ZABA')THEN
        ICASAN='ABAS'
        ICASDI='NONP'
      ELSEIF(ICASPL.EQ.'ZBBA')THEN
        ICASAN='BBAS'
        ICASDI='NONP'
      ENDIF
      CALL DPABA3(TEMP,NS2,   &
                  XTEMP1,MAXNXT,   &
                  ICASAN,ICASDI,   &
                  T10,V10,NDF,GAMMA,ALPHA,YMEAN,YSD,YMIN,YMAX,   &
                  ABASIS,BBASIS,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'WABA')RIGHT=ABASIS
      IF(ICASPL.EQ.'WBBA')RIGHT=BBASIS
      IF(ICASPL.EQ.'LABA')RIGHT=ABASIS
      IF(ICASPL.EQ.'LBBA')RIGHT=BBASIS
      IF(ICASPL.EQ.'NABA')RIGHT=ABASIS
      IF(ICASPL.EQ.'NBBA')RIGHT=BBASIS
      IF(ICASPL.EQ.'ZABA')RIGHT=ABASIS
      IF(ICASPL.EQ.'ZBBA')RIGHT=BBASIS
      GO TO 79000
!
34000 CONTINUE
      IHP='D0  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        D0=0.0
      ELSE
        D0=VALUE(ILOCP)
      ENDIF
!
      ICASAN='ONES'
      IF(ICASPL.EQ.'1WLP')THEN
        ICASA2='LOWE'
      ELSEIF(ICASPL.EQ.'1WUP')THEN
        ICASA2='UPPE'
      ELSE
        ICASA2='TWOT'
      ENDIF
      CALL DPWIL3(TEMP,TEMPZ,NS2,D0,ICASAN,ICASA2,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATV2,STATCD,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  NTEMP,NPLUS,NMINUS,NTIES,   &
                  TPLUS,TMINUS,RSUM,RSUMSQ,   &
                  IBUGG3,ISUBRO,IERROR)
!
!     NOTE: RETURN THE "NORMAL APPROXIMATION" TEST STATISTIC
!
      IF(ICASPL.EQ.'1WTE')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'1WCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'1W2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'1WLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'1WUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34010 CONTINUE
      IHP='D0  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        D0=0.0
      ELSE
        D0=VALUE(ILOCP)
      ENDIF
!
      ICASAN='TWOS'
      IF(ICASPL.EQ.'1WLP')THEN
        ICASA2='LOWE'
      ELSEIF(ICASPL.EQ.'1WUP')THEN
        ICASA2='UPPE'
      ELSE
        ICASA2='TWOT'
      ENDIF
      CALL DPWIL3(TEMP,TEMPZ,NS2,D0,ICASAN,ICASA2,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATV2,STATCD,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  NTEMP,NPLUS,NMINUS,NTIES,   &
                  TPLUS,TMINUS,RSUM,RSUMSQ,   &
                  IBUGG3,ISUBRO,IERROR)
!
!     NOTE: RETURN THE "NORMAL APPROXIMATION" TEST STATISTIC
!
      IF(ICASPL.EQ.'2WTE')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'2WCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'2W2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'2WLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'2WUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34020 CONTINUE
      CALL DPMNN3(TEMP,NS2,TEMPZ,NSZ,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATV1,STATV2,STATV3,STATCD,NTIES,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'MWTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'MWCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'MW2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'MWLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'MWUP')THEN
        RIGHT=PVALUT
      ELSEIF(ICASPL.EQ.'MWUS')THEN
        RIGHT=STATV3
      ENDIF
      GO TO 79000
!
34030 CONTINUE
      CALL DPKLO3(TEMP,NS2,TEMPZ,NSZ,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'KLTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'KLCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'KL2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'KLLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'KLUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34035 CONTINUE
      IKRUGS='OFF'
      CALL DPKRU3(TEMP,TEMPZ,NS2,   &
                  TEMPZ3,XTEMP1,ITEMP1,MAXOBV,   &
                  XTEMP2,XTEMP3,XTEMP4,XTEMP5,DTEMP1,DTEMP2,   &
                  STATVA,STATCD,PVAL2T,NUMDF,NUMDIS,S2,   &
                  IKRUGS,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'KWTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'KWCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'KW2P')THEN
        RIGHT=PVAL2T
      ENDIF
      GO TO 79000
!
34040 CONTINUE
      CALL DPSQR3(TEMP,TEMPZ,NS2,   &
                  XTEMP1,XTEMP2,XTEMP3,TEMPZ3,MAXNXT,   &
                  DTEMP1,DTEMP2,   &
                  STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  IDF,NDIST,D2,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'SRTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'SRCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'SR2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'SRLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'SRUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34050 CONTINUE
      IHP='XQ  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        PMTEQU=0.5
      ELSE
        PMTEQU=VALUE(ILOCP)
        IF(PMTEQU.LE.0.0 .OR. PMTEQU.GE.1.0)PMTEQU=0.5
      ENDIF
      CALL DPMET3(TEMP,TEMPZ,NS2,   &
                  XTEMP1,XTEMP2,XTEMP3,PMTEQU,IQUAME,MAXNXT,   &
                  XMED,XA,XB,IDF,NDIST,   &
                  STATVA,STATCD,PVAL2T,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'METE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'MECD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'ME2P')THEN
        RIGHT=PVAL2T
      ENDIF
      GO TO 79000
!
34060 CONTINUE
      MAXOB2=MAXOBV/2
      IINDX=MAXOB2+1
      CALL DPFRI3(TEMP,TEMPZ,TEMPZ3,NS2,   &
                  XTEMP1,XTEMP1(IINDX),XTEMP2,XTEMP3,XTEMP3(IINDX),   &
                  DTEMP1,   &
                  MAXOBV,MAXOB2,   &
                  STATVA,STATCD,PVAL2T,   &
                  NBLOCK,NTREAT,NUMDF1,NUMDF2,AT1,AT2,A1,C1,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'FZTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'FZCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'FZ2P')THEN
        RIGHT=PVAL2T
      ENDIF
      GO TO 79000
!
34070 CONTINUE
      MAXOB2=MAXOBV/2
      IINDX=MAXOB2+1
      CALL DPQUT3(TEMP,TEMPZ,TEMPZ3,NS2,   &
                  XTEMP1,XTEMP1(IINDX),XTEMP2,XTEMP2(IINDX),   &
                  XTEMP3,XTEMP3(IINDX),   &
                  DTEMP1,   &
                  MAXOBV,MAXOB2,   &
                  STATVA,STATCD,PVAL2T,   &
                  NBLOCK,NTREAT,NUMDF1,NUMDF2,   &
                  AT1,AT2,A1,C1,SSTR,SSTO,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'QUTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'QUCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'QU2P')THEN
        RIGHT=PVAL2T
      ENDIF
      GO TO 79000
!
34075 CONTINUE
      MAXOB2=MAXOBV/2
      IINDX=MAXOB2+1
      CALL DPPAG3(TEMP,TEMPZ,TEMPZ3,NS2,   &
                  XTEMP1,XTEMP1(IINDX),XTEMP2,XTEMP3,XTEMP3(IINDX),   &
                  DTEMP1,   &
                  MAXOBV,MAXOB2,   &
                  STATVA,STATV2,STATCD,PVAL,   &
                  NBLOCK,NTREAT,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'PATE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'PAT2')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'PACD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'PAPV')THEN
        RIGHT=PVAL
      ENDIF
      GO TO 79000
!
34080 CONTINUE
      CALL DPINDM(TEMP,NS2,TEMPZ,NSZ,ICASPL,   &
                  RIGHT,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34090 CONTINUE
      ICASE='SUMM'
      ICASE2='DIVE'
      IF(ICASPL.EQ.'SHEI')ICASE2='EQUI'
      CALL SHANDI(TEMP,NS2,IWRITE,RIGHT,XTEMP1,XTEMP2,ICASE,ICASE2,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34095 CONTINUE
      ICASE='RAW'
      ICASE2='DIVE'
      IF(ICASPL.EQ.'SEII')ICASE2='EQUI'
      CALL SHANDI(TEMP,NS2,IWRITE,RIGHT,XTEMP1,XTEMP2,ICASE,ICASE2,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34100 CONTINUE
      ICASE='SUMM'
      CALL SIMPDI(TEMP,NS2,IWRITE,RIGHT,XTEMP1,XTEMP2,ICASE,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34105 CONTINUE
      ICASE='SUMM'
      CALL SIMPDI(TEMP,NS2,IWRITE,RIGHT,XTEMP1,XTEMP2,ICASE,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34110 CONTINUE
      CALL DPJAB3(TEMP,NS2,ISEED,IRANAL,MAXNXT,   &
                  XTEMP1,XTEMP2,   &
                  XSKEW,XKURT,   &
                  STATVA,PVAL,CDF,   &
                  CUT25,CUT50,CUT75,CUT80,CUT90,   &
                  CUT95,CUT975,CUT99,CUT999,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'JABE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'JAPV')THEN
        RIGHT=PVAL
      ELSEIF(ICASPL.EQ.'JACD')THEN
        RIGHT=CDF
      ENDIF
      GO TO 79000
!
34120 CONTINUE
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ALPHA=VALUE(ILOCP)
      IF(ALPHA.GT.1.0 .AND. ALPHA.LT.100.0)THEN
        ALPHA=ALPHA/100.0
        IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
      ELSEIF(ALPHA.GT.0.0 .AND. ALPHA.LT.1.0)THEN
        IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
      ELSE
        ALPHA=0.95
      ENDIF
!
      IF(ICASPL(1:1).EQ.'S')THEN
        YMEAN=TEMP(1)
        YSD=TEMPZ(1)
        NS2=INT(TEMPZ3(1)+0.5)
      ELSE
        CALL MEAN(TEMP,NS2,IWRITE,YMEAN,IBUGG3,IERROR)
        CALL SD(TEMP,NS2,IWRITE,YSD,IBUGG3,IERROR)
      ENDIF
      YSDMEA=YSD/SQRT(REAL(NS2))
!
      PCONF=ALPHA
      IF(ICASPL.EQ.'LCL ' .OR. ICASPL.EQ.'UCL ' .OR.   &
         ICASPL.EQ.'SLCL' .OR. ICASPL.EQ.'SUCL')THEN
        CDF=0.5+(PCONF/2.0)
      ELSEIF(ICASPL.EQ.'1LCL' .OR. ICASPL.EQ.'1UCL' .OR.   &
             ICASPL.EQ.'SLC1' .OR. ICASPL.EQ.'SUC1')THEN
        CDF=PCONF
      ENDIF
      NM1=NS2-1
      CALL TPPF(CDF,REAL(NM1),TVAL)
      TSDM=TVAL*YSDMEA
      ALOWER=YMEAN-TSDM
      AUPPER=YMEAN+TSDM
      IF(ICASPL.EQ.'LCL ' .OR. ICASPL.EQ.'SLCL')THEN
        RIGHT=ALOWER
      ELSEIF(ICASPL.EQ.'UCL ' .OR. ICASPL.EQ.'SUCL')THEN
        RIGHT=AUPPER
      ELSEIF(ICASPL.EQ.'1LCL' .OR. ICASPL.EQ.'SLC1')THEN
        RIGHT=ALOWER
      ELSEIF(ICASPL.EQ.'1UCL' .OR. ICASPL.EQ.'SUC1')THEN
