                  STATVA,STATCD,STATNU,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'1CTE')RIGHT=STATVA
      IF(ICASPL.EQ.'1CCD')RIGHT=STATCD
      IF(ICASPL.EQ.'1C2P')RIGHT=PVAL2T
      IF(ICASPL.EQ.'1CLP')RIGHT=PVALLT
      IF(ICASPL.EQ.'1CUP')RIGHT=PVALUT
!
      GO TO 79000
!
34290 CONTINUE
!
      IHP='GAMM'
      IHP2='A0  '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
          RIGHT=0.0
          GO TO 9000
      ELSE
        GAMMA0=VALUE(ILOCP)
      ENDIF
!
      ICASA3='SUMM'
      DO 34291 II=1,NS2
        ITEMP1(II)=INT(TEMPZ3(II)+0.5)
34291 CONTINUE
      CALL DPCVT3(TEMP,TEMPZ,ITEMP1,NS2,GAMMA0,IWRITE,ICASA3,   &
                  XTEMP1,XTEMP2,   &
                  NDIST,NGROUP,YMEAN,YSD,YCV,   &
                  STATVA,STATCD,STATNU,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'S1CT')RIGHT=STATVA
      IF(ICASPL.EQ.'S1CC')RIGHT=STATCD
      IF(ICASPL.EQ.'S1CP')RIGHT=PVAL2T
!
      GO TO 79000
!
34300 CONTINUE
      DO 34301 II=1,NS2
        TEMPZ3(II)=1.0
34301 CONTINUE
      DO 34303 II=1,NSZ
        XTEMP3(II)=1.0
34303 CONTINUE
      IF(ICVTTE.EQ.'MILL')THEN
        CALL DPCVT6(TEMP,NS2,TEMPZ,NSZ,IWRITE,   &
                    YMEAN1,YSD1,CV1,YMEAN2,YSD2,CV2,   &
                    STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                    ISUBRO,IBUGG3,IERROR)
      ELSE
        CALL DPCVT4(TEMP,TEMPZ3,NS2,TEMPZ,XTEMP3,NSZ,IWRITE,   &
                    XTEMP1,XTEMP2,NGROU1,NGROU2,   &
                    YMEAN1,YSD1,CV1,YMEAN2,YSD2,CV2,   &
                    STATVA,STATCD,STATN1,STATN2,   &
                    PVAL2T,PVALLT,PVALUT,   &
                    ISUBRO,IBUGG3,IERROR)
      ENDIF
      IF(ICASPL.EQ.'2CTE')RIGHT=STATVA
      IF(ICASPL.EQ.'2CCD')RIGHT=STATCD
      IF(ICASPL.EQ.'2C2P')RIGHT=PVAL2T
      IF(ICASPL.EQ.'2CLP')RIGHT=PVALLT
      IF(ICASPL.EQ.'2CUP')RIGHT=PVALUT
      GO TO 79000
!
34310 CONTINUE
      CALL ENTROP(TEMP,NS2,IWRITE,ICASPL,XE,XMEAN,XVAR,XSD,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'SENT')RIGHT=XE
      IF(ICASPL.EQ.'SEME')RIGHT=XMEAN
      IF(ICASPL.EQ.'SEVA')RIGHT=XVAR
      IF(ICASPL.EQ.'SESD')RIGHT=XSD
      GO TO 79000
!
34320 CONTINUE
!
!       MEDIAN CENTER IF REQUESTED
!
      IF(ISGTMC.EQ.'ON')THEN
        IWRITE='OFF'
        CALL MEDIAN(TEMP,NS2,IWRITE,XTEMP1,MAXNXT,YMED1,IBUGG3,IERROR)
        DO 34321 II=1,NS2
          TEMP(II)=TEMP(II) - YMED1
34321   CONTINUE
        CALL MEDIAN(TEMPZ,NSZ,IWRITE,XTEMP1,MAXNXT,YMED2,IBUGG3,IERROR)
        DO 34323 II=1,NSZ
          TEMPZ(II)=TEMPZ(II) - YMED2
34323   CONTINUE
      ENDIF
!
      CALL DPSGT3(TEMP,NS2,TEMPZ,NSZ,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'SGTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'SGCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'SG2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'SGLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'SGUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34330 CONTINUE
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        ALPHA=VALUE(ILOCP)
      ELSE
        ALPHA=0.95
      ENDIF
      IF(ALPHA.LE.0.0 .OR. ALPHA.GE.100.0)ALPHA=0.95
      ALPHAT(1)=ALPHA
      NUMALP=1
      ICASE2='SD  '
      IF(ICASPL.EQ.'RVLL' .OR. ICASPL.EQ.'RVUL')ICASE2='VARI'
!
      CALL DPSRC3(TEMP,NS2,TEMPZ,NSZ,MAXNXT,   &
                  IFTESH,IFTEDI,PFTEPV,PFTEPM,   &
                  ICASE2,ALPHAT,NUMALP,   &
                  XTEMP1,   &
                  Y1MEAN,Y1SD,Y2MEAN,Y2SD,ALOWLV,AUPPLV,   &
                  IDF1,IDF2,ADF1,ADF2,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'RSLL')THEN
        RIGHT=ALOWLV(1)
      ELSEIF(ICASPL.EQ.'RSUL')THEN
        RIGHT=AUPPLV(1)
      ELSEIF(ICASPL.EQ.'RVLL')THEN
        RIGHT=ALOWLV(1)
      ELSEIF(ICASPL.EQ.'RVUL')THEN
        RIGHT=AUPPLV(1)
      ENDIF
      GO TO 79000
!
34340 CONTINUE
      CALL GINIMD(TEMP,NS2,IWRITE,XTEMP1,RIGHT,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34350 CONTINUE
      CALL GMDRAT(TEMP,NS2,TEMPZ,NSZ,IWRITE,XTEMP1,RIGHT,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34360 CONTINUE
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        ALPHA=VALUE(ILOCP)
      ELSE
        ALPHA=0.95
      ENDIF
      IF(ALPHA.LE.0.0 .OR. ALPHA.GE.100.0)ALPHA=0.95
!
      CALL DPLRS3(TEMP,NS2,TEMPZ,NSZ,ILRASC,TEMPZ3,XTEMP1,   &
                  XTEMP2,XTEMP3,DTEMP1,MAXNXT,   &
                  S,STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  STATEV,STATSD,STATVA,   &
                  ALPHA,ALCL,UCL,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'LRST')RIGHT=STATVA
      IF(ICASPL.EQ.'LRSC')RIGHT=STATCD
      IF(ICASPL.EQ.'LRSP')RIGHT=PVAL2T
      IF(ICASPL.EQ.'LRLP')RIGHT=PVALLT
      IF(ICASPL.EQ.'LRUP')RIGHT=PVALUT
!CCCC IF(ICASPL.EQ.'LRLC')RIGHT=ALCL
!CCCC IF(ICASPL.EQ.'LRUC')RIGHT=UCL
      IF(ICASPL.EQ.'LRSE')RIGHT=STATEV
      IF(ICASPL.EQ.'LRSS')RIGHT=STATSD
      IF(ICASPL.EQ.'LRSV')RIGHT=STATVA
      GO TO 79000
!
34370 CONTINUE
!
      CALL DPFPT3(TEMP,NS2,TEMPZ,NSZ,XTEMP1,XTEMP2,   &
                  STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'FPTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'FPCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'FP2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'FPLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'FPUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34380 CONTINUE
      CALL SSQTOT(TEMP,TEMPZ,NS2,XTEMP1,XTEMP2,XTEMP3,   &
                  XTEMP4,XTEMP5,NLEVEL,   &
                  IWRITE,ICASPL,   &
                  XSSQTO,XSSQTR,XSSQE,XSSX,DFTO,DFTR,DFE,   &
                  AMSTR,AMSE,FVAL,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'SSTO')THEN
        RIGHT=XSSQTO
      ELSEIF(ICASPL.EQ.'SSTR')THEN
        RIGHT=XSSQTR
      ELSEIF(ICASPL.EQ.'SSER')THEN
        RIGHT=XSSQE
      ELSEIF(ICASPL.EQ.'SSX ')THEN
        RIGHT=XSSX
      ELSEIF(ICASPL.EQ.'DFTO')THEN
        RIGHT=DFTO
      ELSEIF(ICASPL.EQ.'DFTR')THEN
        RIGHT=DFTR
      ELSEIF(ICASPL.EQ.'DFER')THEN
        RIGHT=DFE
      ELSEIF(ICASPL.EQ.'MSER')THEN
        RIGHT=AMSE
      ELSEIF(ICASPL.EQ.'MSTR')THEN
        RIGHT=AMSTR
      ELSEIF(ICASPL.EQ.'1ANF')THEN
        RIGHT=FVAL
      ENDIF
      GO TO 79000
!
34390 CONTINUE
      MAXNX2=1000
      CALL DPRCB3(TEMP,TEMPZ,TEMPZ3,NS2,         &
                  XTEMP1,XTEMP2,XTEMP3,XTEMP4,   &
                  XTEMP5(1),XTEMP5(100000),      &
                  MAXNXT,MAXNX2,                 &
                  STATVA,STATCD,PVAL,IREPLT,IRT, &
                  NBLOCK,NTREAT,NUMDF1,NUMDF2,   &
                  AP1,AP2,AP3,AP4,AP5,AP6,       &
                  AP7,AP8,AP9,AP10,              &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'RCBC')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'RCBP')THEN
        RIGHT=PVAL
      ELSE
        RIGHT=STATVA
      ENDIF
      GO TO 79000
!
34400 CONTINUE
      IF(APVAL.GE.0.0 .AND. APVAL.LE.100.0)THEN
        P100=APVAL
      ELSEIF(IPNAM1.NE.'    ')THEN
        IHWUSE='P'
        MESSAG='YES'
        CALL CHECKN(IPNAM1,IPNAM2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        P100=VALUE(ILOCP)
      ELSE
        IHP='P100'
        IHP2='    '
        IHWUSE='P'
        MESSAG='YES'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        P100=VALUE(ILOCP)
      ENDIF
!
      IF(ICASPL.EQ.'GQUA')P100=100.0*P100
      IF(NUMV2.EQ.2)TEMPZ3(1:NS2)=0.0
!
      CALL GRPPER(P100,TEMP,TEMPZ,TEMPZ3,NS2,IWRITE,   &
                  XTEMP1,XTEMP2,RIGHT,                &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34410 CONTINUE
      ICASE1='RAW '
      ICASE2='VARI'
      IF(ICASPL.EQ.'SPVA' .OR. ICASPL.EQ.'SPSD')ICASE1='SUMM'
      IF(ICASPL.EQ.'PSD ' .OR. ICASPL.EQ.'SPSD')ICASE1='SD  '
      CALL POOLSD(TEMP,TEMPZ,NS2,XTEMP1,XTEMP2,ICASE1,ICASE2,IWRITE,  &
                  XVARP,XSDP,ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'SPVA' .OR. ICASPL.EQ.'PVAR')RIGHT=XVARP
      IF(ICASPL.EQ.'SPSD' .OR. ICASPL.EQ.'PSD ')RIGHT=XSDP
      GO TO 79000
!
34420 CONTINUE
      CALL POSSD(TEMP,TEMPZ,XTEMP1,NS2,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                 IWRITE,                                              &
                 SPOS,SPOSMN,SE,IVAL1,AK,                             &
                 FSTAT,IDF1,IDF2,FCDFVAL,PVAL,                        &
                 ISUBRO,IBUGG3,IERROR)
      RIGHT=SPOS
      IF(ICASPL.EQ.'POVA')RIGHT=RIGHT**2
      IF(ICASPL.EQ.'POTS')RIGHT=FSTAT
      IF(ICASPL.EQ.'POCD')RIGHT=FCDFVAL
      IF(ICASPL.EQ.'POPV')RIGHT=PVAL
      IF(ICASPL.EQ.'POSE')RIGHT=SE
      IF(ICASPL.EQ.'POSM')RIGHT=SPOSMN
      GO TO 79000
!
79000 CONTINUE
      NS2=NS2SAV
      NSZ=NSZSAV
!
!     AUGUST 2023: SUPPORT FOR "RATIO OF <STAT>" CASE
!
      IF(ISTARA.EQ.'ON')THEN
        IF(ICNTRA.EQ.1)THEN
          RSAVE=RIGHT
          ICNTRA=2
          DO 79010 II=1,NSZ
            TEMP(II)=TEMPZ(II)
79010     CONTINUE
          NS2=NSZ
          GO TO 100
        ELSEIF(ICNTRA.EQ.2)THEN
          RNUM=RSAVE
          RDEN=RIGHT
          IF(RDEN.NE.0.0)THEN
            RIGHT=RNUM/RDEN
          ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,33001)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,79110)
79110       FORMAT('      FOR THE RATIO OF STATISTIC, THE ',   &
                   'DENOMINATOR IS ZERO.')
            CALL DPWRST('XXX','WRIT')
            RIGHT=CPUMIN
            IERROR='YES'
          ENDIF
        ENDIF
      ENDIF
!
      GO TO 9000
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IPRINT=IPRSAV
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'PSTA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF CMPSTA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)ICASPL,IERROR,NS2,NUMV2,RIGHT
 9013   FORMAT('ICASPL,IERROR,NS2,NUMV2,RIGHT = ',2(A4,2X),2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)XTEMP4(1),XTEMP5(1)
 9014   FORMAT('XTEMP4(1),XTEMP5(1) = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE CMPSTA
      SUBROUTINE CMPST2(TEMP,TEMPZ,TEMPZ3,XTEMP1,XTEMP2,XTEMP3,   &
                        XTEMP4,XTEMP5,   &
                        MAXNXT,NS2,NSZ,NSZ3,NUMV2,ICASPL,ISTARA,   &
                        ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                        DTEMP1,DTEMP2,DTEMP3,   &
                        RIGHT,   &
                        ISUBRO,IBUGG3,IERROR)
!
!     PURPOSE--THIS IS A COPY OF CMPSTA.  IT IS USED BY DPSBEX (USED
!              TO IMPLEMENT STATISTIC BLOCKS) TO AVOID CIRCULAR CALLS.
!              THE ONE DISTINCTION IS THAT CMPST2 DOES NOT CALL OTHER
!              STATISTIC BLOCKS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2016/08
!     ORIGINAL VERSION--AUGUST    2016.
!     UPDATED         --DECEMBER  2016. COEFFICIENT OF VARIATION
!                                       CONFIDENCE LIMITS
!     UPDATED         --JANUARY   2017. UNBIASED COEFFICIENT OF VARIATION
!     UPDATED         --JANUARY   2017. SIGNAL TO NOISE RATIO
!     UPDATED         --JANUARY   2017. QUARTILE COEFFICIENT OF
!                                       DISPERSION
!     UPDATED         --JANUARY   2017. LOGNORMAL COEFFICIENT OF VARIATION
!     UPDATED         --JANUARY   2017. LOGNORMAL COEFFICIENT OF VARIATION
!                                       CONFIDENCE LIMITS
!     UPDATED         --JANUARY   2017. PRECISION
!     UPDATED         --JANUARY   2017. COMMON COEFFICIENT OF VARIATION
!     UPDATED         --JANUARY   2017. COMMON BIAS CORRECTED COEFFICIENT
!                                       OF VARIATION
!     UPDATED         --JANUARY   2017. LOWER COMMON COEFFICIENT OF
!                                       VARIATION CONFIDENCE LIMIT
!     UPDATED         --JANUARY   2017. UPPER COMMON COEFFICIENT OF
!                                       VARIATION CONFIDENCE LIMIT
!     UPDATED         --JANUARY   2017. COEFFICIENT OF DISPERSION
!     UPDATED         --JANUARY   2017. INDEX OF DISPERSION
!     UPDATED         --JANUARY   2017. AAD TO MEDIAN
!     UPDATED         --FEBRUARY  2017. SHORTEST HALF MIDMEAN
!     UPDATED         --FEBRUARY  2017. SHORTEST HALF MIDRANGE
!     UPDATED         --MARCH     2017. COSINE DISTANCE
!     UPDATED         --MARCH     2017. COSINE SIMILARITY
!     UPDATED         --MARCH     2017. ANGULAR COSINE DISTANCE
!     UPDATED         --MARCH     2017. ANGULAR COSINE SIMILARITY
!     UPDATED         --MARCH     2017. MANHATTAN DISTANCE
!     UPDATED         --MARCH     2017. EUCLIDEAN DISTANCE
!     UPDATED         --MARCH     2017. EUCLIDEAN LENGTH (SYNONYM FOR
!                                       SUM OF SQuARES)
!     UPDATED         --MARCH     2017. DOT PRODUCT
!     UPDATED         --MARCH     2017. DIFFERENCE OF PRECISION
!     UPDATED         --MARCH     2017. DIFFERENCE OF SNR
!     UPDATED         --APRIL     2017. ONE SAMPLE COEF OF VARI CDF
!     UPDATED         --APRIL     2017. ONE SAMPLE COEF OF VARI PVALUE
!     UPDATED         --JUNE      2017. PERCENTAGE DIFFERENCE OF MEAN
!     UPDATED         --JUNE      2017. ONE SAMPLE COEF OF VARI TEST
!     UPDATED         --JUNE      2017. ONE SAMPLE COEF OF VARI TEST CDF
!     UPDATED         --JUNE      2017. ONE SAMPLE COEF OF VARI TEST PVALUE
!     UPDATED         --JUNE      2017. ONE SAMPLE COEF OF VARI LOWER PVALUE
!     UPDATED         --JUNE      2017. ONE SAMPLE COEF OF VARI UPPER PVALUE
!     UPDATED         --JUNE      2017. SUMMARY ONE SAMPLE COEF OF VARI TEST
!     UPDATED         --JUNE      2017. SUMMARY ONE SAMPLE COEF OF VARI CDF
!     UPDATED         --JUNE      2017. SUMMARY ONE SAMPLE COEF OF VARI PVALUE
!     UPDATED         --JUNE      2017. TWO SAMPLE COEF OF VARI TEST
!     UPDATED         --JUNE      2017. TWO SAMPLE COEF OF VARI TEST CDF
!     UPDATED         --JUNE      2017. TWO SAMPLE COEF OF VARI TEST PVALUE
!     UPDATED         --JUNE      2017. TWO SAMPLE COEF OF VARI LOWER PVALUE
!     UPDATED         --JUNE      2017. TWO SAMPLE COEF OF VARI UPPER PVALUE
!     UPDATED         --JUNE      2017. DIFFERENCE OF AAD TO MEDIAN
!     UPDATED         --JUNE      2017. DIFFERENCE OF COEFFICIENT OF
!                                                  DISPERSION
!     UPDATED         --JUNE      2017. DIFFERENCE OF INDEX OF DISPERSION
!     UPDATED         --JUNE      2017. DIFFERENCE OF QUARTILE COEFFICIENT
!                                                  OF DISPERSION
!     UPDATED         --JUNE      2017. DIFFERENCE OF SHORTEST HALF
!                                                  MIDMEAN
!     UPDATED         --JUNE      2017. DIFFERENCE OF SHORTEST HALF
!                                                  MIDRANGE
!     UPDATED         --JULY      2017. HEDGES G
!     UPDATED         --JULY      2017. BIAS CORRECTED HEDGES G
!     UPDATED         --JULY      2017. GLASS G
!     UPDATED         --JULY      2017. COHENS D
!     UPDATED         --JULY      2017. MIDHINGE, TRIMEAN
!     UPDATED         --JULY      2017. DIFFERENCE OF MIDHINGE
!     UPDATED         --JULY      2017. DIFFERENCE OF TRIMEAN
!     UPDATED         --AUGUST    2017. PEARSON DISSIMILARITY
!     UPDATED         --AUGUST    2017. SPEARMAN DISSIMILARITY
!     UPDATED         --AUGUST    2017. KENDALL TAU DISSIMILARITY
!     UPDATED         --AUGUST    2017. BINARY MATCH DISSIMILARITY
!     UPDATED         --AUGUST    2017. BINARY MATCH SIMILARITY
!     UPDATED         --AUGUST    2017. BINARY ROGERS DISSIMILARITY
!     UPDATED         --AUGUST    2017. BINARY ROGERS SIMILARITY
!     UPDATED         --AUGUST    2017. BINARY SOKAL DISSIMILARITY
!     UPDATED         --AUGUST    2017. BINARY SOKAL SIMILARITY
!     UPDATED         --AUGUST    2017. BINARY JACCARD DISSIMILARITY
!     UPDATED         --AUGUST    2017. BINARY JACCARD SIMILARITY
!     UPDATED         --AUGUST    2017. BINARY ASYMMETRIC DICE DISSIMILARITY
!     UPDATED         --AUGUST    2017. BINARY ASYMMETRIC DICE SIMILARITY
!     UPDATED         --AUGUST    2017. BINARY ASYMMETRIC SOKAL DISSIMILARITY
!     UPDATED         --AUGUST    2017. BINARY ASYMMETRIC SOKAL SIMILARITY
!     UPDATED         --AUGUST    2017. YULES Q
!     UPDATED         --AUGUST    2017. CHEYSHEV DISTANCE
!     UPDATED         --AUGUST    2017. MINKOWSKI DISTANCE
!     UPDATED         --AUGUST    2017. GENERALIZED JACCARD COEFFICIENT
!     UPDATED         --AUGUST    2017. GENERALIZED JACCARD DISTANCE
!     UPDATED         --NOVEMBER  2017. DIFF OF BINO PROP LOWE CONF LIMI
!     UPDATED         --NOVEMBER  2017. DIFF OF BINO PROP UPPE CONF LIMI
!     UPDATED         --NOVEMBER  2017. BINOMIAL PROP LOWE CONF LIMI
!     UPDATED         --NOVEMBER  2017. BINOMIAL PROP UPPE CONF LIMI
!     UPDATED         --NOVEMBER  2017. COEFFICIENT OF DISPERSION
!                                       CONFIDENCE LIMITS
!     UPDATED         --DECEMBER  2017. LOWER BONETT STANDARD DEVIATION
!                                       CONFIDENCE LIMIT
!     UPDATED         --DECEMBER  2017. UPPER BONETT STANDARD DEVIATION
!                                       CONFIDENCE LIMIT
!     UPDATED         --JULY      2018. WEIGHTED COVARIANCE
!     UPDATED         --JULY      2018. WEIGHTED CORRELATION
!     UPDATED         --AUGUST    2018. HEDGES G STANDARD ERROR
!     UPDATED         --AUGUST    2018. HEDGES G LOWER CONFIDENCE LIMIT
!     UPDATED         --AUGUST    2018. HEDGES G UPPER CONFIDENCE LIMIT
!     UPDATED         --AUGUST    2018. HAMMING DISTANCE
!     UPDATED         --AUGUST    2018. CANBERRA DISTANCE
!     UPDATED         --AUGUST    2018. WEIGHTED COSINE DISTANCE
