      CALL NPV(TEMP,TEMPZ,NS2,IWRITE,XTEMP1,RIGHT,IBUGG3,IERROR)
      GO TO 79000
31685 CONTINUE
      CALL BINMAT(TEMP,TEMPZ,NS2,ICASPL,IWRITE,XTEMP1,RIGHT,   &
