      ISUBRO,IBUGG3,IERROR)
      RIGHT=BETA
      GO TO 79000
!
11745 CONTINUE
      CALL LINFIT(TEMP,TEMPZ,NS2,   &
      ALPHA,BETA,XRESSD,XRESDF,CCXY,SDALPH,SDBETA,CCALBE,   &
      ISUBRO,IBUGG3,IERROR)
      RIGHT=SDBETA
      GO TO 79000
!
11750 CONTINUE
      CALL LINFIT(TEMP,TEMPZ,NS2,   &
      ALPHA,BETA,XRESSD,XRESDF,CCXY,SDALPH,SDBETA,CCALBE,   &
      ISUBRO,IBUGG3,IERROR)
      RIGHT=XRESSD
      GO TO 79000
!
11760 CONTINUE
      CALL LINFIT(TEMP,TEMPZ,NS2,   &
      ALPHA,BETA,XRESSD,XRESDF,CCXY,SDALPH,SDBETA,CCALBE,   &
      ISUBRO,IBUGG3,IERROR)
      RIGHT=CCXY
      GO TO 79000
!
11770 CONTINUE
      CALL REPEAZ(TEMP,TEMPZ,XTEMP1,XTEMP2,NS2,IWRITE,XREP,   &
      ISUBRO,IBUGG3,IERROR)
      RIGHT=XREP
      GO TO 79000
!
11780 CONTINUE
      CALL REPROD(TEMP,TEMPZ,XTEMP1,XTEMP2,XTEMP3,XTEMP4,ITEMP1,NS2,   &
