31840 CONTINUE
      CALL DPTTE4(TEMP,NS2,TEMPZ,NSZ,IWRITE,ITTEVA,  &
                  STATVA,STATCD,STATNU,              &
                  STATV2,STATC2,STATN2,              &
                  Y1MEAN,Y1SD,Y1SDM,                 &
                  Y2MEAN,Y2SD,Y2SDM,                 &
                  DEL,POOLSDZ,DELSD,DELSD2,CDFBAR,   &
                  PVAL2T,PVALLT,PVALUT,              &
                  ISUBRO,IBUGG3,IERROR)
!
!     FOR NOW, JUST RETURN THE "UNEQUAL VARIANCES" CASE.  MAY
!     ADD "EQUAL VARIANCES" CASE LATER (NEED TO ADD "ITTEVA"
!     TO THE CALL LIST.
!
      IF(ICASPL.EQ.'2TTE')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'2TCD')THEN
        RIGHT=STATC2
      ELSEIF(ICASPL.EQ.'2T2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'2TLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'2TUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
31845 CONTINUE
      CALL DPTTE6(TEMP,NS2,TEMPZ,NSZ,XTEMP1,IWRITE,   &
