                  Y1MEAN,Y1SD,Y1SDM,   &
                  Y2MEAN,Y2SD,Y2SDM,   &
                  YDMEAN,YDSD,YDSDM,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'PTTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'PTCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'PT2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'PTLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'PTUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
