      ELSEIF(ICASPL.EQ.'CCDF')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'CSLP')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'CSUP')THEN
        RIGHT=1.0 - STATCD
      ELSEIF(ICASPL.EQ.'CS2P')THEN
        IF(YSD.LE.SIGMA0)THEN
          RIGHT=2.0*STATCD
        ELSE
          RIGHT=2.0*(1.0 - STATCD)
        ENDIF
      ENDIF
      GO TO 79000
