!
      CALL DPTIE3(TEMP,NS2,ICASAN,IR,   &
                  XTEMP1,XTEMP2,XTEMP3,ITEMP1,ITEMP2,   &
                  RIGHT,YMEAN,YSD,YMIN,YMAX,   &
                  ISUBRO,IBUGG3,IERROR)
      GO TO 79000
!
32020 CONTINUE
!
      IHP='NOUT'
      IHP2='LIER'
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        IR=1
      ELSE
        AVAL=VALUE(ILOCP)
        IR=INT(AVAL+0.1)
        IF(IR.LT.1)IR=1
        IF(IR.GT.NS2/2)IR=NS2/2
      ENDIF
!
      CALL DPGES3(TEMP,NS2,IR,   &
                  XTEMP1,XTEMP2,ITEMP1,ITEMP2,   &
                  RIGHT,   &
                  ISUBRO,IBUGG3,IERROR)
      GO TO 79000
