          ITEMP1(II)=0
 3196   CONTINUE
      ELSEIF(NUMV2.EQ.3)THEN
        ICASA4='SUMM'
        DO 3197 II=1,NS2
          ITEMP1(II)=INT(TEMPZ3(II)+0.1)
 3197   CONTINUE
      ENDIF
