        IF(ALPHA.GT.1.0 .AND. ALPHA.LT.100.0)THEN
          ALPHA=ALPHA/100.0
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
        ELSEIF(ALPHA.GT.0.0 .AND. ALPHA.LT.1.0)THEN
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
        ELSE
          ALPHA=0.95
