32030 CONTINUE
!
      IF(ICASPL.EQ.'DI2S')THEN
        ICASAN='TWOS'
      ELSEIF(ICASPL.EQ.'DIMN')THEN
        ICASAN='MINI'
      ELSEIF(ICASPL.EQ.'DIMX')THEN
        ICASAN='MAXI'
      ENDIF
!
      CALL DPDIX3(TEMP,XTEMP1,NS2,XTEMP2,IWRITE,ICASAN,   &
                  RIGHT,   &
                  ISUBRO,IBUGG3,IERROR)
