32040 CONTINUE
      EPS=0.1E-05
      XTEMP1(1)=PSTAMV
      XTEMP1(2)=PSTAMV
      CALL DISTIN(TEMP,NS2,IWRITE,XTEMP1,NDIST,IBUGG3,IERROR)
      IF(NDIST.GT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32041)
32041   FORMAT('***** ERROR FROM CMPSTA (AGRESTI-COUL BINOMIAL ',   &
               'LIMITS)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32042)
32042   FORMAT('      FOR AGRESTI-COUL LIMITS CASE, MORE THAN ',   &
               'TWO DISTINCT VALUES DETECTED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32043)NDIST
32043   FORMAT('      NUMBER OF DISTINCT VALUES = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
!
!       IF ALL VALUES ARE EQUAL TO THE "MISSING VALUE",
!       THEN SET VALUE OF STATISTIC TO MISSING VALUE.
!
      ELSEIF(NDIST.EQ.1 .AND. XTEMP1(1).EQ.PSTAMV)THEN
        RIGHT=PSTAMV
        GO TO 79000
      ENDIF
!
      HOLD1=XTEMP1(1)
      HOLD2=XTEMP1(2)
      IF(NDIST.EQ.1)THEN
        IF(XTEMP1(1).GE.0.5)THEN
          XMAX=XTEMP1(1)
          XMIN=CPUMIN
        ELSE
          XMIN=XTEMP1(1)
          XMAX=CPUMAX
        ENDIF
      ELSEIF(NDIST.EQ.2)THEN
        IF(HOLD1.LT.HOLD2)THEN
          XMIN=HOLD1
          XMAX=HOLD2
        ELSE
          XMAX=HOLD1
          XMIN=HOLD2
        ENDIF
      ENDIF
!
      DO 32045 I=1,NS2
        IF(TEMP(I).EQ.XMAX)THEN
          TEMP(I)=1.0
        ELSE
          TEMP(I)=0.0
        ENDIF
32045 CONTINUE
!
      XSUM=0.0
      DO 32048 I=1,NS2
        XSUM=XSUM + TEMP(I)
32048 CONTINUE
      P=XSUM/REAL(NS2)
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
