      ALPHA=VALUE(ILOCP)
!
      IF(ICASPL.EQ.'1LAC')THEN
        IDIR='LOWE'
        CALL DPAGC1(P,NS2,ALPHA,IDIR,IWRITE,RIGHT,IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'1UAC')THEN
        IDIR='UPPE'
        CALL DPAGC1(P,NS2,ALPHA,IDIR,IWRITE,RIGHT,IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'2LAC')THEN
        CALL DPAGCO(P,NS2,ALPHA,IWRITE,ALOWLM,AUPPLM,IBUGG3,IERROR)
        RIGHT=ALOWLM
      ELSEIF(ICASPL.EQ.'2UAC')THEN
        CALL DPAGCO(P,NS2,ALPHA,IWRITE,ALOWLM,AUPPLM,IBUGG3,IERROR)
        RIGHT=AUPPLM
      ENDIF
!
      GO TO 79000
32050 CONTINUE
      EPS=0.1E-05
      XTEMP1(1)=PSTAMV
      XTEMP1(2)=PSTAMV
      CALL DISTIN(TEMP,NS2,IWRITE,XTEMP1,NDIST,IBUGG3,IERROR)
      IF(NDIST.GT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32051)
32051   FORMAT('***** ERROR FROM CMPSTA (EXACT BINOMIAL LIMITS)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32052)
32052   FORMAT('      FOR EXACT BINOMIAL LIMITS CASE, MORE THAN ',   &
               'TWO DISTINCT VALUES DETECTED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32053)NDIST
32053   FORMAT('      NUMBER OF DISTINCT VALUES = ',I8)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
!
!       IF ALL VALUES ARE EQUAL TO THE "MISSING VALUE",
!       THEN SET VALUE OF STATISTIC TO MISSING VALUE.
!
      ELSEIF(NDIST.EQ.1 .AND. XTEMP1(1).EQ.PSTAMV)THEN
        RIGHT=PSTAMV
        GO TO 79000
      ENDIF
!
      HOLD1=XTEMP1(1)
      HOLD2=XTEMP1(2)
      IF(HOLD1.LT.HOLD2)THEN
        XMIN=HOLD1
        XMAX=HOLD2
      ELSE
        XMAX=HOLD1
        XMIN=HOLD2
      ENDIF
!
      DO 32055 I=1,NS2
        IF(TEMP(I).EQ.XMAX)THEN
          TEMP(I)=1.0
        ELSE
          TEMP(I)=0.0
        ENDIF
32055 CONTINUE
!
      XSUM=0.0
      DO 32058 I=1,NS2
        XSUM=XSUM + TEMP(I)
32058 CONTINUE
      P=XSUM/REAL(NS2)
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ALPHA=VALUE(ILOCP)
!
      IF(ICASPL.EQ.'1LEB')THEN
        CALL DPEBLL(P,NS2,ALPHA,IWRITE,RIGHT,'ONES',IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'1UEB')THEN
        CALL DPEBUL(P,NS2,ALPHA,IWRITE,RIGHT,'ONES',IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'2LEB')THEN
        CALL DPEBLL(P,NS2,ALPHA,IWRITE,RIGHT,'TWOS',IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'2UEB')THEN
        CALL DPEBUL(P,NS2,ALPHA,IWRITE,RIGHT,'TWOS',IBUGG3,IERROR)
      ENDIF
      GO TO 79000
!
32060 CONTINUE
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        ALPHA=0.95
      ELSE
        ALPHA=VALUE(ILOCP)
        IF(ALPHA.LE.0.0)THEN
          ALPHA=0.95
        ELSEIF(ALPHA.GE.1.0 .OR. ALPHA.LE.100.0)THEN
          ALPHA=ALPHA/100.0
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
        ELSEIF(ALPHA.LT.0.5)THEN
          ALPHA=1.0 - ALPHA
        ENDIF
      ENDIF
!
      ALPHAT(1)=100.0*ALPHA
      NUMALP=1
      CALL DPADK3(TEMP,TEMPZ,NS2,ALPHAT,NUMALP,   &
                  XTEMP1,XTEMP2,DTEMP1,DTEMP2,DTEMP3,ITEMP1,ITEMP2,   &
                  ITEMP3,ITEMP4,   &
                  ADKSTA,ADC,DSD,IFLGZZ,NBCH,MINSIZ,MAXSIZ,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'ADKS')RIGHT=ADKSTA
      IF(ICASPL.EQ.'ADKC')RIGHT=ADC(1)
      GO TO 79000
!
32070 CONTINUE
!
!     FOR VARIOUS CONSENSUS MEANS COMMANDS, IF WE HAVE RAW DATA
!     WE FIRST NEED TO CONVERT TO SUMMARY DATA (I.E., MEAN, SD's,
!     AND SAMPLE SIZES) BEFORE CALLING APPROPRIATE METHOD.
!
      CALL DISTIN(TEMPZ,NS2,IWRITE,XTEMP1,NLAB,IBUGG3,IERROR)
!
      DO 32075 I=1,NLAB
        ATEMP=XTEMP1(I)
        NTEMP=0
        DO 32079 J=1,NS2
          IF(TEMPZ(J).EQ.ATEMP)THEN
            NTEMP=NTEMP+1
            TEMPZ3(NTEMP)=TEMP(J)
          ENDIF
32079   CONTINUE
        ITEMP1(I)=NTEMP
!
        CALL MEAN(TEMPZ3,NTEMP,IWRITE,AMEAN,IBUGG3,IERROR)
        CALL SD(TEMPZ3,NTEMP,IWRITE,ASD,IBUGG3,IERROR)
        XTEMP2(I)=AMEAN
        XTEMP3(I)=ASD
!
32075 CONTINUE
!
      DO 32080 I=1,NLAB
        TEMP(I)=XTEMP2(I)
        TEMPZ(I)=XTEMP3(I)
        TEMPZ3(I)=REAL(ITEMP1(I))
32080 CONTINUE
      NS2=NLAB
!
      IF(ICASPL.EQ.'DSLA')GO TO 32100
      IF(ICASPL.EQ.'DHHD')GO TO 32100
      IF(ICASPL.EQ.'DSMM')GO TO 32100
      IF(ICASPL.EQ.'DSSE')GO TO 32100
      IF(ICASPL.EQ.'MPAU')GO TO 32200
      IF(ICASPL.EQ.'MPSE')GO TO 32200
      IF(ICASPL.EQ.'MMPA')GO TO 32200
      IF(ICASPL.EQ.'MMPS')GO TO 32200
      IF(ICASPL.EQ.'VARU')GO TO 32200
      IF(ICASPL.EQ.'VRSE')GO TO 32200
      IF(ICASPL.EQ.'BOB ')GO TO 32300
      IF(ICASPL.EQ.'BOBS')GO TO 32300
      IF(ICASPL.EQ.'GCIN')GO TO 32400
      IF(ICASPL.EQ.'GCIS')GO TO 32400
      IF(ICASPL.EQ.'BCP ')GO TO 32500
      IF(ICASPL.EQ.'BCPS')GO TO 32500
      IF(ICASPL.EQ.'MMEA')GO TO 32600
      IF(ICASPL.EQ.'MMES')GO TO 32600
      IF(ICASPL.EQ.'FAIR')GO TO 32700
      IF(ICASPL.EQ.'FWSE')GO TO 32700
      IF(ICASPL.EQ.'GDEA')GO TO 32800
      IF(ICASPL.EQ.'GDSE')GO TO 32800
      IF(ICASPL.EQ.'GDSN')GO TO 32800
      IF(ICASPL.EQ.'GDZ1')GO TO 32800
      IF(ICASPL.EQ.'GDZ2')GO TO 32800
      IF(ICASPL.EQ.'SCEB')GO TO 32900
      IF(ICASPL.EQ.'SESE')GO TO 32900
      IF(ICASPL.EQ.'LPOO')GO TO 33000
      IF(ICASPL.EQ.'LPSE')GO TO 33000
!
32100 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
