          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32113)I,TEMPZ(I)
32113     FORMAT('      LAB ',I6,' HAS NON-POSITIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LE.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32118)I
32118     FORMAT('      LAB ',I6,' HAS LESS THAN 2 OBSERVATIONS.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32111 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
!CCCC IOUNI5=-99
!CCCC CALL DPDERS(NPTS,NLAB,
!CCCC1            TEMP,TEMPZ,ITEMP1,
!CCCC1            XTEMP3(1),XTEMP3(MAXNXT/2),ITEMP2,
!CCCC1            XTEMP1,XTEMP2,DTEMP1,
!CCCC1            DTEMP2,DTEMP2(5001),DTEMP3,
!CCCC1            XDL,XDLS2,YDL,SEDLK1,SEDLK2,DLOWDL,DHIGDL,
!CCCC1            SERUK1,SERUK2,DLOWD2,DHIGD2,
!CCCC1            SEHDK1,SEHDK2,DLOWD3,DHIGD3,
!CCCC1            SEBOK1,SEBOK2,DLOWD4,DHIGD4,
!CCCC1            DLOWD5,DHIGD5,DLOWD6,DHIGD6,
!CCCC1            AK2,AK3,
!CCCC1            IWRITE,IOUNI5,
!CCCC1            ICAPSW,ICAPTY,NUMDIG,ISEED,
!CCCC1            ISUBRO,IBUGG3,IERROR)
!CCCC IF(ICASPL.EQ.'DSLA')RIGHT=XDL
!CCCC IF(ICASPL.EQ.'DHHD')RIGHT=SEHDK1
!CCCC IF(ICASPL.EQ.'DSMM')RIGHT=SERUK1
!CCCC IF(ICASPL.EQ.'DSSE')RIGHT=SEDLK1
!CCCC IF(ICASPL.EQ.'DSBO')RIGHT=SEBOK1
      RIGHT=CPUMIN
      GO TO 79000
!
32200 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
