      DO 32211 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32201)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32213)I,TEMPZ(I)
32213     FORMAT('      LAB ',I6,' HAS NON-POSITIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LE.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32201)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32218)I
32218     FORMAT('      LAB ',I6,' HAS LESS THAN 2 OBSERVATIONS.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32211 CONTINUE
!
      T0=10000000.D0
      T1=-T0
!
      AMNX=CPUMAX
      AMXX=CPUMIN
      AMNSD=CPUMAX
      AMXSD=CPUMIN
!
      DO 32250 I=1,NLAB
!
        DTEMP1(I)=DBLE(TEMP(I))
        IF(DTEMP1(I).LT.T0) T0=DTEMP1(I)
        IF(DTEMP1(I).GT.T1) T1=DTEMP1(I)
        IF(TEMP(I).GT.AMXX)AMXX=TEMP(I)
        IF(TEMP(I).LT.AMNX)AMNX=TEMP(I)
!
        DTEMP2(I)=DBLE(TEMPZ(I))**2/DBLE(ITEMP1(I))
        IF(TEMPZ(I).GT.0.0)THEN
          IF(TEMPZ(I).LT.AMNSD)AMNSD=TEMPZ(I)
          IF(TEMPZ(I).GT.AMXSD)AMXSD=TEMPZ(I)
        ENDIF
!
32250 CONTINUE
!
      EPS=0.00001
      T0=AMNX - EPS
      T1=AMXX
      DO 32270 I=1,NS2
        DTEMP1(I)=(DTEMP1(I)-T0)/(T1-T0)
        DTEMP2(I)=DTEMP2(I)/((T1-T0)**2)
32270 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
!
      IF(ICASPL.EQ.'MPAU' .OR. ICASPL.EQ.'MPSE' .OR.   &
         ICASPL.EQ.'VARU' .OR. ICASPL.EQ.'VRSE')THEN
        CALL DPMNPL(TEMP,TEMPZ,TEMPZ3,NPTS,NLAB,   &
                    DTEMP1,DTEMP2,ITEMP1,   &
                    XMPS,S2BMPS,SEMP,SEMPK1,SEMPK2,   &
                    DLOWMP,DHIGMP,STXMU,STS2B,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGG3,IERROR)
      ELSEIF(ICASPL.EQ.'MMPA' .OR. ICASPL.EQ.'MMPS')THEN
        CALL DPMMPL(TEMP,TEMPZ,TEMPZ3,NPTS,NLAB,   &
                    DTEMP1,DTEMP2,ITEMP1,   &
                    XMMPS,S2BMMP,SEMMP,SEMMP1,SEMMP2,   &
                    DLOWMM,DHIGMM,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,NUMDIG,   &
                    ISUBRO,IBUGG3,IERROR)
      ENDIF
!
      IF(ICASPL.EQ.'VARU' .OR. ICASPL.EQ.'VRSE')THEN
        CALL DPVRML(NPTS,NLAB,   &
                    TEMP,TEMPZ,ITEMP1,   &
                    XTEMP3(1),XTEMP3(MAXNXT/2),ITEMP2,XTEMP1,XTEMP2,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    DTEMP2(MAXNXT/2),DTEMP3(MAXNXT/2),   &
                    XMLS,S2BMLS,SEML,SEMLK1,SEMLK2,   &
                    DLOWML,DHIGML,STXMU,STS2B,   &
                    SEMLBO,DLOWM2,DHIGM2,   &
                    IWRITE,   &
                    ICAPSW,ICAPTY,IOUNI5,NUMDIG,ISEED,   &
                    ISUBRO,IBUGG3,IERROR)
      ENDIF
!
      IF(ICASPL.EQ.'MPAU')RIGHT=XMPS
      IF(ICASPL.EQ.'MPSE')RIGHT=SEMP
      IF(ICASPL.EQ.'VARU')RIGHT=XMLS
      IF(ICASPL.EQ.'VRSE')RIGHT=SEML
      IF(ICASPL.EQ.'MMPA')RIGHT=XMMPS
      IF(ICASPL.EQ.'MMPS')RIGHT=SEMMP
      GO TO 79000
!
32300 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2 .OR. NLAB.GT.5)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32301)
32301   FORMAT('***** ERROR FROM CMPSTA (BOB ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32303)
32303   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO OR ',   &
               'GREATER THAN FIVE.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32311 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32301)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32313)I,TEMPZ(I)
32313     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LE.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32301)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32318)I
32318     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32311 CONTINUE
!
      AMNX=CPUMAX
      AMXX=CPUMIN
!
      DSUM1=0.0D0
      DO 32350 I=1,NLAB
        IF(TEMP(I).GT.AMXX)AMXX=TEMP(I)
        IF(TEMP(I).LT.AMNX)AMNX=TEMP(I)
        DSUM1=DSUM1 + DBLE(TEMPZ(I))**2/DBLE(ITEMP1(I))
32350 CONTINUE
      SW=REAL(DSQRT(DSUM1)/DBLE(NLAB))
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
      CALL DPBOB(NPTS,NLAB,   &
                 TEMP,TEMPZ,AMNX,AMXX,SW,   &
                 ASM,ASB,AKU,AKUK1,AKUK2,   &
                 DLOWBO,DHIGBO,   &
                 IWRITE,   &
                 ICAPSW,ICAPTY,NUMDIG,   &
                 ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'BOB ')RIGHT=ASM
      IF(ICASPL.EQ.'BOBS')RIGHT=AKUK1
      GO TO 79000
!
32400 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
                                                                                                                                  
      IPRINT='OFF'
      NLAB=NS2
