          WRITE(ICOUT,32401)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32418)I
32418     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32411 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
