      CALL DPGCI(NPTS,NLAB,   &
                 TEMP,TEMPZ,ITEMP1,   &
                 DTEMP1,DTEMP2,   &
                 XGCI,SEGCI,   &
                 DLOWGC,DHIGGC,   &
                 IWRITE,IOUNI5,   &
                 ICAPSW,ICAPTY,NUMDIG,   &
                 ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'GCIN')RIGHT=XGCI
      IF(ICASPL.EQ.'GCIS')RIGHT=SEGCI
      GO TO 79000
