        WRITE(ICOUT,32501)
32501   FORMAT('***** ERROR FROM CMPSTA (BCP ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32503)
32503   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO OR ',   &
               'GREATER THAN SIX.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
