      CALL DPBCP(NPTS,NLAB,   &
                 TEMP,TEMPZ,ITEMP1,AMNX,AMXX,   &
                 XBCP,XBCPSE,XBCPK1,SBCPK2,   &
                 DLOWBC,DHIGBC,   &
