          WRITE(ICOUT,32701)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32718)I
32718     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32711 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
