      CALL DPFAIR(NPTS,NLAB,   &
                  TEMP,TEMPZ,ITEMP1,   &
                  XFW,XFWS2,SEFWK1,SEFWK2,   &
                  DLOWFW,DHIGFW,DLOWF2,DHIGF2,DLOWF3,DHIGF3,   &
                  IWRITE,   &
                  ICAPSW,ICAPTY,IFLAG9,NUMDIG,   &
                  ISUBRO,IBUGG3,IERROR)
      RIGHT=CPUMIN
      IF(IFLAG9)THEN
        IF(ICASPL.EQ.'FAIR')RIGHT=XFW
        IF(ICASPL.EQ.'FWSE')RIGHT=SEFWK1
      ENDIF
      GO TO 79000
!
32800 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32801)
32801   FORMAT('***** ERROR FROM CMPSTA (GRAYBILL-DEAL ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32803)
32803   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32811 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32801)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32813)I,TEMPZ(I)
32813     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LT.1)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32801)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32818)I
32818     FORMAT('      LAB ',I6,' HAS LESS THAN 1 OBSERVATION.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32811 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
      IOUNI5=-99
      CALL DPGRAY(NPTS,NLAB,   &
                  TEMP,TEMPZ,ITEMP1,   &
                  XGD,XGDS2,SEGDK1,SEGDK2,   &
                  XGDS20,XGDSZ1,XGDSZ2,   &
                  DLOWGD,DHIGGD,   &
                  IWRITE,IOUNI5,   &
                  ICAPSW,ICAPTY,NUMDIG,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'GDEA')RIGHT=XGD
      IF(ICASPL.EQ.'GDSE')RIGHT=SEGDK1
      IF(ICASPL.EQ.'GDSN')RIGHT=SQRT(XGDS20)
      IF(ICASPL.EQ.'GDZ1')RIGHT=SQRT(XGDSZ1)
      IF(ICASPL.EQ.'GDZ2')RIGHT=SQRT(XGDSZ2)
      GO TO 79000
!
32900 CONTINUE
!
!     CHECK FOR LABS WITH LESS THAN 2 OBSERVATIONS OR WITH
!     NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32901)
32901   FORMAT('***** ERROR FROM CMPSTA (SCHILLER-EBERHARDT ',   &
               'ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,32903)
32903   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 32911 I=1,NLAB
        ITEMP9=INT(TEMPZ3(I)+0.1)
        IF(TEMPZ(I).LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32901)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32913)I,TEMPZ(I)
32913     FORMAT('      LAB ',I6,' HAS NEGATIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(ITEMP9.LT.2)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32901)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,32918)I
32918     FORMAT('      LAB ',I6,' HAS LESS THAN 2 OBSERVATIONS.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=ITEMP9
        NPTS=NPTS+ITEMP9
32911 CONTINUE
!
      IHP='SIGM'
      IHP2='AH  '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        SIGMAH=0.0
      ELSE
        SIGMAH=VALUE(ILOCP)
        IF(SIGMAH.LT.0.0)SIGMAH=0.0
      ENDIF
      IHP='DFH '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        IDFH=1
      ELSE
        IDFH=INT(VALUE(ILOCP)+ 0.5)
      ENDIF
      IF(IDFH.LE.0)IDFH=1
!
!     SCHILLER-EBERHARDT NEEDS TO CALL MANDEL-PAULE TO
!     OBTAIN "S2BMPS" VALUE.
!
      T0=10000000.D0
      T1=-T0
!
      AMNX=CPUMAX
      AMXX=CPUMIN
      AMNSD=CPUMAX
      AMXSD=CPUMIN
!
      DO 32950 I=1,NLAB
!
        DTEMP1(I)=DBLE(TEMP(I))
        IF(DTEMP1(I).LT.T0) T0=DTEMP1(I)
        IF(DTEMP1(I).GT.T1) T1=DTEMP1(I)
        IF(TEMP(I).GT.AMXX)AMXX=TEMP(I)
        IF(TEMP(I).LT.AMNX)AMNX=TEMP(I)
!
        DTEMP2(I)=DBLE(TEMPZ(I))**2/DBLE(ITEMP1(I))
        IF(TEMPZ(I).GT.0.0)THEN
          IF(TEMPZ(I).LT.AMNSD)AMNSD=TEMPZ(I)
          IF(TEMPZ(I).GT.AMXSD)AMXSD=TEMPZ(I)
        ENDIF
!
32950 CONTINUE
!
      EPS=0.00001
      T0=AMNX - EPS
      T1=AMXX
      DO 32970 I=1,NS2
        DTEMP1(I)=(DTEMP1(I)-T0)/(T1-T0)
        DTEMP2(I)=DTEMP2(I)/((T1-T0)**2)
32970 CONTINUE
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
!
      CALL DPMNPL(TEMP,TEMPZ,TEMPZ3,NPTS,NLAB,   &
                  DTEMP1,DTEMP2,ITEMP1,   &
                  XMPS,S2BMPS,SEMP,SEMPK1,SEMPK2,   &
                  DLOWMP,DHIGMP,STXMU,STS2B,   &
                  IWRITE,   &
                  ICAPSW,ICAPTY,NUMDIG,   &
                  ISUBRO,IBUGG3,IERROR)
      CALL DPSCEB(NPTS,NLAB,   &
                  DTEMP1,ITEMP1,   &
                  TEMP,TEMPZ,S2BMPS,   &
                  XSE,XSES2,IDFH,SIGMAH,   &
                  SESUK1,SESUK2,   &
                  DLOWSE,DHIGSE,   &
                  IWRITE,   &
                  ICAPSW,ICAPTY,NUMDIG,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'SCEB')RIGHT=XSE
      IF(ICASPL.EQ.'SESE')RIGHT=SESUK1
      GO TO 79000
!
33000 CONTINUE
!
!     CHECK FOR LABS WITH NON-POSITIVE STANDARD DEVIATION.
!
      IPRINT='OFF'
      NLAB=NS2
      NPTS=0
      IF(NLAB.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33001)
33001   FORMAT('***** ERROR FROM CMPSTA (LINEAR POOL ESTIMATION)--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33003)
33003   FORMAT('      THE NUMBER OF LABS IS LESS THAN TWO.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
      DO 33011 I=1,NLAB
        IF(TEMPZ(I).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,33001)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,33013)I,TEMPZ(I)
33013     FORMAT('      LAB ',I6,' HAS NON-POSITIVE STANDARD ',   &
                 'DEVIATION (= ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
        ITEMP1(I)=INT(TEMPZ3(I)+0.1)
33011 CONTINUE
!
      AVAL=1.0/REAL(NLAB)
      DO 33021 II=1,NLAB
        TEMPZ3(II)=1.0/REAL(NLAB)
33021 CONTINUE
!
      IF(ILIPWT.NE.'OFF ')THEN
        IHP=ILIPWT(1:4)
        IHP2=ILIPWT(5:8)
        IHWUSE='V'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
             IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
             ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
!
        IF(IERROR.EQ.'NO')THEN
          ICOLQP=IVALUE(ILOCV)
          NTEMP=IN(ILOCV)
          ICNT=0
          DO 33028 I=1,NTEMP
            IJ=MAXN*(ICOLQP-1)+I
            ICNT=ICNT+1
            IF(ICOLQP.LE.MAXCOL)TEMPZ3(ICNT)=V(IJ)
            IF(ICOLQP.EQ.MAXCP1)TEMPZ3(ICNT)=PRED(I)
            IF(ICOLQP.EQ.MAXCP2)TEMPZ3(ICNT)=RES(I)
            IF(ICOLQP.EQ.MAXCP3)TEMPZ3(ICNT)=YPLOT(I)
            IF(ICOLQP.EQ.MAXCP4)TEMPZ3(ICNT)=XPLOT(I)
            IF(ICOLQP.EQ.MAXCP5)TEMPZ3(ICNT)=X2PLOT(I)
            IF(ICOLQP.EQ.MAXCP6)TEMPZ3(ICNT)=TAGPLO(I)
33028     CONTINUE
         ENDIF
      ENDIF
!
      ICAPSW='XXXX'
      ICAPTY='XXXX'
      NUMDIG=-99
      IWRITE='OFF'
      IOUNI5=0
!
      CALL DPLIPO(NLAB,TEMP,TEMPZ,TEMPZ3,ITEMP1,   &
                  XTEMP1,XTEMP2,XTEMP3,DTEMP1,   &
                  XLP,SELIP1,ALOWLP,AUPPLP,   &
                  IWRITE,IOUNI5,   &
                  ICAPSW,ICAPTY,MAXNXT,NUMDIG,ISEED,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'LPOO')RIGHT=XLP
      IF(ICASPL.EQ.'LPSE')RIGHT=SELIP1
!
      GO TO 79000
!
33100 CONTINUE
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        ALPHA=0.95
      ELSE
        ALPHA=VALUE(ILOCP)
        IF(ALPHA.EQ.90.0 .OR. ALPHA.EQ.0.90)THEN
          ALPHA=0.90
        ELSEIF(ALPHA.EQ.10.0 .OR. ALPHA.EQ.0.10)THEN
          ALPHA=0.90
        ELSEIF(ALPHA.EQ.99.0 .OR. ALPHA.EQ.0.99)THEN
          ALPHA=0.99
        ELSEIF(ALPHA.EQ.1.0 .OR. ALPHA.EQ.0.01)THEN
          ALPHA=0.99
        ELSEIF(ALPHA.EQ.95.0 .OR. ALPHA.EQ.0.95)THEN
          ALPHA=0.95
        ELSEIF(ALPHA.EQ.5.0 .OR. ALPHA.EQ.0.05)THEN
          ALPHA=0.95
        ELSE
          ALPHA=0.95
        ENDIF
      ENDIF
!
      CALL DP2KS3(TEMP,TEMPZ,NS2,NSZ,   &
                  XTEMP1,   &
                  STATVA,STATCD,CUTU90,CUTU95,CUTU99,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'KS2S')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'KSCV')THEN
        IF(ALPHA.EQ.0.90)THEN
          RIGHT=CUTU90
        ELSEIF(ALPHA.EQ.0.99)THEN
          RIGHT=CUTU99
        ELSE
          RIGHT=CUTU95
        ENDIF
      ENDIF
      GO TO 79000
!
33105 CONTINUE
      IDATSW='RAW'
      CLWID=CLWIDT(1)
      XSTART=CLLIMI(1)
      XSTOP=CLLIMI(2)
      MAXOB2=MAXOBV/2
      IINDX=(MAXOBV/2) + 1
      CALL DP2CH3(TEMP,TEMPZ,TEMPZ3,NS2,NSZ,NSZ3,   &
                  IDATSW,IRHSTG,   &
                  CLWID,XSTART,XSTOP,   &
                  CLWID2,DXSTAR,DXSTOP,   &
                  XTEMP1,IHSTCW,IHSTOU,MAXOBV,MAXOB2,   &
                  STATVA,STATCD,STATNU,NCELLS,   &
                  Y1MEAN,Y1SD,Y1MIN,Y1MAX,   &
                  Y2MEAN,Y2SD,Y2MIN,Y2MAX,   &
                  XTEMP2,XTEMP3,XTEMP2(IINDX),XTEMP3(IINDX),M2,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'CS2S')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'CC2S')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'CP2S')THEN
        RIGHT=1.0 - STATCD
      ENDIF
      GO TO 79000
!
33110 CONTINUE
!
      CALL DPWSH3(TEMP,NS2,   &
                  XTEMP1,MAXNXT,   &
                  STATVA,PVAL,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'WSHA')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'WSPV')THEN
        RIGHT=PVAL
      ENDIF
      GO TO 79000
!
33120 CONTINUE
!
      CALL DPCUS3(TEMP,NS2,   &
                  STATVA,STATV2,STATCD,STATC2,PVAL1,PVAL2,   &
                  XTEMP2,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'CSFT')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'CSFP')THEN
        RIGHT=PVAL1
      ELSEIF(ICASPL.EQ.'CSBT')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'CSBP')THEN
        RIGHT=PVAL2
      ENDIF
      GO TO 79000
!
33130 CONTINUE
!
      IF(NUMV2.EQ.1)THEN
        XMEAN=CPUMIN
        XSD=CPUMIN
        AN=CPUMIN
      ELSE
        XMEAN=TEMP(1)
        XSD=TEMPZ(1)
        AN=TEMPZ3(1)
      ENDIF
!
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        ALPHA=0.95
      ELSE
        ALPHA=VALUE(ILOCP)
      ENDIF
!
      IHP='GAMM'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        GAMMA=0.95
      ELSE
        GAMMA=VALUE(ILOCP)
      ENDIF
!
      CALL DPTOL3(TEMP,NS2,XMEAN,XSD,AN,PTOLDF,   &
                  ICASPL,ALPHA,GAMMA,ITOLGC,ITOLM2,   &
                  AK,ALOWLM,AUPPLM,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'1LNT' .OR. ICASPL.EQ.'2LNT')THEN
        RIGHT=ALOWLM
      ELSEIF(ICASPL.EQ.'1UNT' .OR. ICASPL.EQ.'2UNT')THEN
        RIGHT=AUPPLM
      ELSEIF(ICASPL.EQ.'1KNT' .OR. ICASPL.EQ.'2KNT')THEN
        RIGHT=AK
      ENDIF
      GO TO 79000
!
33140 CONTINUE
!
      IF(IFTESH.EQ.'BONE')THEN
        IHP='ALPH'
        IHP2='A   '
        IHWUSE='P'
        MESSAG='NO'
        CALL CHECKN(IHP,IHP2,IHWUSE,   &
        IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
        ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
        IF(IERROR.EQ.'YES')THEN
          ALPHAZ=0.975
        ELSE
          ALPHAZ=VALUE(ILOCP)
        ENDIF
        IF(ALPHAZ.GT.1.0 .AND. ALPHAZ.LT.100.0)THEN
          ALPHAZ=ALPHAZ/100.0
        ELSEIF(ALPHAZ.LE.0.0 .AND. ALPHAZ.GE.100.0)THEN
          ALPHAZ=0.975
        ENDIF
        IF(ALPHAZ.LT.0.5)ALPHAZ=1.0 - ALPHAZ
      ELSE
        ALPHAZ=0.975
      ENDIF
!
      CALL DPFTE3(TEMP,NS2,TEMPZ,NSZ,MAXNXT,                 &
                  IFTESH,IFTEDI,PFTEPV,PFTEPM,               &
                  ALPHAZ,XTEMP1,                             &
                  Y1MEAN,Y1SD,Y2MEAN,Y2SD,                   &
                  SDNUM,SDDEN,IDFNUM,IDFDEN,ADFNUM,ADFDEN,   &
                  STATVA,STANU1,STANU2,POOLSDZ,STATCD,PVAL,  &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'FTES')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'FTPV')THEN
        RIGHT=PVAL
      ELSEIF(ICASPL.EQ.'FTCD')THEN
        RIGHT=STATCD
      ENDIF
      GO TO 79000
!
33150 CONTINUE
      IHP='MU  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        AMU=0.0
      ELSE
        AMU=VALUE(ILOCP)
      ENDIF
!
      CALL DPSIG3(TEMP,NS2,AMU,IWRITE,   &
                  XTEMP1,XTEMP2,MAXNXT,   &
                  XMEAN,XMED,XSD,XMAD,   &
                  STATV1,STATC1,STATV2,STATC2,RTIES,NTEMP,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'1STE')THEN
        RIGHT=STATV1
      ELSEIF(ICASPL.EQ.'1SCD')THEN
        RIGHT=STATC1
      ELSEIF(ICASPL.EQ.'1S2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'1SLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'1SUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
33160 CONTINUE
      IHP='D0  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        D0=0.0
      ELSE
        D0=VALUE(ILOCP)
      ENDIF
!
      CALL DPSIG4(TEMP,NS2,TEMPZ,NSZ,D0,IWRITE,   &
                  XTEMP1,XTEMP2,MAXNXT,   &
                  X1MEAN,X1MED,X1SD,X1MAD,   &
                  X2MEAN,X2MED,X2SD,X2MAD,   &
                  STATV1,STATC1,STATV2,STATC2,RTIES,NTEMP,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'2STE')THEN
        RIGHT=STATV1
      ELSEIF(ICASPL.EQ.'2SCD')THEN
        RIGHT=STATC1
      ELSEIF(ICASPL.EQ.'2S2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'2SLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'2SUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
33165 CONTINUE
      IF(MAXNXT.GE.1000000)THEN
        MAXSAM=22
      ELSE
        MAXSAM=20
      ENDIF
      SUMX=CPUMIN
      PTEMP=CPUMIN
      CALL FISHER(TEMP,NS2,TEMPZ,NSZ,ITOTAL,POSSIB,PTEMP,   &
                  SUMX,SUMY,XMEAN,YMEAN,   &
                  XTEMP1,XTEMP2,ITEMP1,MAXSAM,MAXNXT,   &
                  IFAULT,IBUGG3)
      IF(IFAULT.GT.0)THEN
        RIGHT=CPUMIN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33166)
33166   FORMAT('****** ERROR IN FISHER TWO-SAMPLE RANDOMIZATION TEST--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33167)
33167   FORMAT('       MAXIMUM STORAGE SPACE EXCEEDED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33168)NS2
33168   FORMAT('       NUMBER OF OBSERVATIONS FOR SAMPLE ONE  = ',I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,33169)NSZ
33169   FORMAT('       NUMBER OF OBSERVATIONS FOR SAMPLE TWO  = ',I8)
        CALL DPWRST('XXX','WRIT')
      ELSEIF(ICASPL.EQ.'2FRT')THEN
        RIGHT=SUMX
      ELSEIF(ICASPL.EQ.'2F2P' .AND. NS2.EQ.NSZ)THEN
        RIGHT=2.0*PTEMP
      ELSEIF(ICASPL.EQ.'2F2P' .AND. NS2.NE.NSZ)THEN
        RIGHT=2.0*PTEMP
      ELSEIF(ICASPL.EQ.'2F1P')THEN
        RIGHT=PTEMP
      ENDIF
      GO TO 79000
!
33170 CONTINUE
      IF(ICASPL.EQ.'WABA')THEN
        ICASAN='ABAS'
        ICASDI='WEIB'
      ELSEIF(ICASPL.EQ.'WBBA')THEN
        ICASAN='BBAS'
        ICASDI='WEIB'
      ELSEIF(ICASPL.EQ.'LABA')THEN
        ICASAN='ABAS'
        ICASDI='LOGN'
      ELSEIF(ICASPL.EQ.'LBBA')THEN
        ICASAN='BBAS'
        ICASDI='LOGN'
      ELSEIF(ICASPL.EQ.'NABA')THEN
        ICASAN='ABAS'
        ICASDI='NORM'
      ELSEIF(ICASPL.EQ.'NBBA')THEN
        ICASAN='BBAS'
        ICASDI='NORM'
      ELSEIF(ICASPL.EQ.'ZABA')THEN
        ICASAN='ABAS'
        ICASDI='NONP'
      ELSEIF(ICASPL.EQ.'ZBBA')THEN
        ICASAN='BBAS'
        ICASDI='NONP'
      ENDIF
      CALL DPABA3(TEMP,NS2,   &
                  XTEMP1,MAXNXT,   &
                  ICASAN,ICASDI,   &
                  T10,V10,NDF,GAMMA,ALPHA,YMEAN,YSD,YMIN,YMAX,   &
                  ABASIS,BBASIS,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'WABA')RIGHT=ABASIS
      IF(ICASPL.EQ.'WBBA')RIGHT=BBASIS
      IF(ICASPL.EQ.'LABA')RIGHT=ABASIS
      IF(ICASPL.EQ.'LBBA')RIGHT=BBASIS
      IF(ICASPL.EQ.'NABA')RIGHT=ABASIS
      IF(ICASPL.EQ.'NBBA')RIGHT=BBASIS
      IF(ICASPL.EQ.'ZABA')RIGHT=ABASIS
      IF(ICASPL.EQ.'ZBBA')RIGHT=BBASIS
      GO TO 79000
!
34000 CONTINUE
      IHP='D0  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        D0=0.0
      ELSE
        D0=VALUE(ILOCP)
      ENDIF
!
      ICASAN='ONES'
      IF(ICASPL.EQ.'1WLP')THEN
        ICASA2='LOWE'
      ELSEIF(ICASPL.EQ.'1WUP')THEN
        ICASA2='UPPE'
      ELSE
        ICASA2='TWOT'
      ENDIF
      CALL DPWIL3(TEMP,TEMPZ,NS2,D0,ICASAN,ICASA2,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATV2,STATCD,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  NTEMP,NPLUS,NMINUS,NTIES,   &
                  TPLUS,TMINUS,RSUM,RSUMSQ,   &
                  IBUGG3,ISUBRO,IERROR)
!
!     NOTE: RETURN THE "NORMAL APPROXIMATION" TEST STATISTIC
!
      IF(ICASPL.EQ.'1WTE')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'1WCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'1W2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'1WLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'1WUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34010 CONTINUE
      IHP='D0  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        D0=0.0
      ELSE
        D0=VALUE(ILOCP)
      ENDIF
!
      ICASAN='TWOS'
      IF(ICASPL.EQ.'1WLP')THEN
        ICASA2='LOWE'
      ELSEIF(ICASPL.EQ.'1WUP')THEN
        ICASA2='UPPE'
      ELSE
        ICASA2='TWOT'
      ENDIF
      CALL DPWIL3(TEMP,TEMPZ,NS2,D0,ICASAN,ICASA2,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATV2,STATCD,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  NTEMP,NPLUS,NMINUS,NTIES,   &
                  TPLUS,TMINUS,RSUM,RSUMSQ,   &
                  IBUGG3,ISUBRO,IERROR)
!
!     NOTE: RETURN THE "NORMAL APPROXIMATION" TEST STATISTIC
!
      IF(ICASPL.EQ.'2WTE')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'2WCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'2W2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'2WLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'2WUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34020 CONTINUE
      CALL DPMNN3(TEMP,NS2,TEMPZ,NSZ,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATV1,STATV2,STATV3,STATCD,NTIES,   &
                  PVAL2T,PVALLT,PVALUT,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'MWTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'MWCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'MW2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'MWLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'MWUP')THEN
        RIGHT=PVALUT
      ELSEIF(ICASPL.EQ.'MWUS')THEN
        RIGHT=STATV3
      ENDIF
      GO TO 79000
!
34030 CONTINUE
      CALL DPKLO3(TEMP,NS2,TEMPZ,NSZ,   &
                  XTEMP1,XTEMP2,XTEMP3,MAXNXT,   &
                  STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'KLTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'KLCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'KL2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'KLLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'KLUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34035 CONTINUE
      IKRUGS='OFF'
      CALL DPKRU3(TEMP,TEMPZ,NS2,   &
                  TEMPZ3,XTEMP1,ITEMP1,MAXOBV,   &
                  XTEMP2,XTEMP3,XTEMP4,XTEMP5,DTEMP1,DTEMP2,   &
                  STATVA,STATCD,PVAL2T,NUMDF,NUMDIS,S2,   &
                  IKRUGS,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'KWTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'KWCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'KW2P')THEN
        RIGHT=PVAL2T
      ENDIF
      GO TO 79000
!
34040 CONTINUE
      CALL DPSQR3(TEMP,TEMPZ,NS2,   &
                  XTEMP1,XTEMP2,XTEMP3,TEMPZ3,MAXNXT,   &
                  DTEMP1,DTEMP2,   &
                  STATVA,STATCD,PVAL2T,PVALLT,PVALUT,   &
                  IDF,NDIST,D2,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'SRTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'SRCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'SR2P')THEN
        RIGHT=PVAL2T
      ELSEIF(ICASPL.EQ.'SRLP')THEN
        RIGHT=PVALLT
      ELSEIF(ICASPL.EQ.'SRUP')THEN
        RIGHT=PVALUT
      ENDIF
      GO TO 79000
!
34050 CONTINUE
      IHP='XQ  '
      IHP2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        PMTEQU=0.5
      ELSE
        PMTEQU=VALUE(ILOCP)
        IF(PMTEQU.LE.0.0 .OR. PMTEQU.GE.1.0)PMTEQU=0.5
      ENDIF
      CALL DPMET3(TEMP,TEMPZ,NS2,   &
                  XTEMP1,XTEMP2,XTEMP3,PMTEQU,IQUAME,MAXNXT,   &
                  XMED,XA,XB,IDF,NDIST,   &
                  STATVA,STATCD,PVAL2T,   &
                  IBUGG3,ISUBRO,IERROR)
!
      IF(ICASPL.EQ.'METE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'MECD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'ME2P')THEN
        RIGHT=PVAL2T
      ENDIF
      GO TO 79000
!
34060 CONTINUE
      MAXOB2=MAXOBV/2
      IINDX=MAXOB2+1
      CALL DPFRI3(TEMP,TEMPZ,TEMPZ3,NS2,   &
                  XTEMP1,XTEMP1(IINDX),XTEMP2,XTEMP3,XTEMP3(IINDX),   &
                  DTEMP1,   &
                  MAXOBV,MAXOB2,   &
                  STATVA,STATCD,PVAL2T,   &
                  NBLOCK,NTREAT,NUMDF1,NUMDF2,AT1,AT2,A1,C1,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'FZTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'FZCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'FZ2P')THEN
        RIGHT=PVAL2T
      ENDIF
      GO TO 79000
!
34070 CONTINUE
      MAXOB2=MAXOBV/2
      IINDX=MAXOB2+1
      CALL DPQUT3(TEMP,TEMPZ,TEMPZ3,NS2,   &
                  XTEMP1,XTEMP1(IINDX),XTEMP2,XTEMP2(IINDX),   &
                  XTEMP3,XTEMP3(IINDX),   &
                  DTEMP1,   &
                  MAXOBV,MAXOB2,   &
                  STATVA,STATCD,PVAL2T,   &
                  NBLOCK,NTREAT,NUMDF1,NUMDF2,   &
                  AT1,AT2,A1,C1,SSTR,SSTO,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'QUTE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'QUCD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'QU2P')THEN
        RIGHT=PVAL2T
      ENDIF
      GO TO 79000
!
34075 CONTINUE
      MAXOB2=MAXOBV/2
      IINDX=MAXOB2+1
      CALL DPPAG3(TEMP,TEMPZ,TEMPZ3,NS2,   &
                  XTEMP1,XTEMP1(IINDX),XTEMP2,XTEMP3,XTEMP3(IINDX),   &
                  DTEMP1,   &
                  MAXOBV,MAXOB2,   &
                  STATVA,STATV2,STATCD,PVAL,   &
                  NBLOCK,NTREAT,   &
                  IBUGG3,ISUBRO,IERROR)
      IF(ICASPL.EQ.'PATE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'PAT2')THEN
        RIGHT=STATV2
      ELSEIF(ICASPL.EQ.'PACD')THEN
        RIGHT=STATCD
      ELSEIF(ICASPL.EQ.'PAPV')THEN
        RIGHT=PVAL
      ENDIF
      GO TO 79000
!
34080 CONTINUE
      CALL DPINDM(TEMP,NS2,TEMPZ,NSZ,ICASPL,   &
                  RIGHT,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34090 CONTINUE
      ICASE='SUMM'
      ICASE2='DIVE'
      IF(ICASPL.EQ.'SHEI')ICASE2='EQUI'
      CALL SHANDI(TEMP,NS2,IWRITE,RIGHT,XTEMP1,XTEMP2,ICASE,ICASE2,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34095 CONTINUE
      ICASE='RAW'
      ICASE2='DIVE'
      IF(ICASPL.EQ.'SEII')ICASE2='EQUI'
      CALL SHANDI(TEMP,NS2,IWRITE,RIGHT,XTEMP1,XTEMP2,ICASE,ICASE2,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34100 CONTINUE
      ICASE='SUMM'
      CALL SIMPDI(TEMP,NS2,IWRITE,RIGHT,XTEMP1,XTEMP2,ICASE,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34105 CONTINUE
      ICASE='SUMM'
      CALL SIMPDI(TEMP,NS2,IWRITE,RIGHT,XTEMP1,XTEMP2,ICASE,   &
                  IBUGG3,ISUBRO,IERROR)
      GO TO 79000
!
34110 CONTINUE
      CALL DPJAB3(TEMP,NS2,ISEED,IRANAL,MAXNXT,   &
                  XTEMP1,XTEMP2,   &
                  XSKEW,XKURT,   &
                  STATVA,PVAL,CDF,   &
                  CUT25,CUT50,CUT75,CUT80,CUT90,   &
                  CUT95,CUT975,CUT99,CUT999,   &
                  ISUBRO,IBUGG3,IERROR)
      IF(ICASPL.EQ.'JABE')THEN
        RIGHT=STATVA
      ELSEIF(ICASPL.EQ.'JAPV')THEN
        RIGHT=PVAL
      ELSEIF(ICASPL.EQ.'JACD')THEN
        RIGHT=CDF
      ENDIF
      GO TO 79000
!
34120 CONTINUE
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ALPHA=VALUE(ILOCP)
      IF(ALPHA.GT.1.0 .AND. ALPHA.LT.100.0)THEN
        ALPHA=ALPHA/100.0
        IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
      ELSEIF(ALPHA.GT.0.0 .AND. ALPHA.LT.1.0)THEN
        IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
      ELSE
        ALPHA=0.95
      ENDIF
!
      IF(ICASPL(1:1).EQ.'S')THEN
        YMEAN=TEMP(1)
        YSD=TEMPZ(1)
        NS2=INT(TEMPZ3(1)+0.5)
      ELSE
        CALL MEAN(TEMP,NS2,IWRITE,YMEAN,IBUGG3,IERROR)
        CALL SD(TEMP,NS2,IWRITE,YSD,IBUGG3,IERROR)
      ENDIF
      YSDMEA=YSD/SQRT(REAL(NS2))
!
      PCONF=ALPHA
      IF(ICASPL.EQ.'LCL ' .OR. ICASPL.EQ.'UCL ' .OR.   &
         ICASPL.EQ.'SLCL' .OR. ICASPL.EQ.'SUCL')THEN
        CDF=0.5+(PCONF/2.0)
      ELSEIF(ICASPL.EQ.'1LCL' .OR. ICASPL.EQ.'1UCL' .OR.   &
             ICASPL.EQ.'SLC1' .OR. ICASPL.EQ.'SUC1')THEN
        CDF=PCONF
      ENDIF
      NM1=NS2-1
      CALL TPPF(CDF,REAL(NM1),TVAL)
      TSDM=TVAL*YSDMEA
      ALOWER=YMEAN-TSDM
      AUPPER=YMEAN+TSDM
      IF(ICASPL.EQ.'LCL ' .OR. ICASPL.EQ.'SLCL')THEN
        RIGHT=ALOWER
      ELSEIF(ICASPL.EQ.'UCL ' .OR. ICASPL.EQ.'SUCL')THEN
        RIGHT=AUPPER
      ELSEIF(ICASPL.EQ.'1LCL' .OR. ICASPL.EQ.'SLC1')THEN
        RIGHT=ALOWER
      ELSEIF(ICASPL.EQ.'1UCL' .OR. ICASPL.EQ.'SUC1')THEN
        RIGHT=AUPPER
      ENDIF
      GO TO 79000
!
34130 CONTINUE
      IHP='ALPH'
      IHP2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'NO')THEN
        ALPHA=VALUE(ILOCP)
        IF(ALPHA.GT.1.0 .AND. ALPHA.LT.100.0)THEN
          ALPHA=ALPHA/100.0
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
        ELSEIF(ALPHA.GT.0.0 .AND. ALPHA.LT.1.0)THEN
          IF(ALPHA.LT.0.5)ALPHA=1.0 - ALPHA
        ELSE
          ALPHA=0.95
        ENDIF
      ELSE
        ALPHA=0.95
      ENDIF
